INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `creator_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at`, `file_key`, `references`, `links`) VALUES
(885587, 44374271, 96815475, 96815475, 89904399, 17687999, 'le-livre-express-regional-se-reinvente-en-ligne', '{\"fr\":\"Le livre express régional se réinvente en ligne\"}', '{\"fr\":\"La seconde édition du Livre Express régional se réinvente et se présente cette année sous la forme de quatre conférences en ligne. Inscrivez-vous dès maintenant !\"}', '{\"fr\":\"La seconde édition du Livre Express régional se réinvente et se présente cette année sous la forme de quatre conférences en ligne, quatre arrêts sur quatre jours différents qui permettront à tous de découvrir le programme. [Inscrivez-vous dès maintenant !](https://docs.google.com/forms/d/e/1FAIpQLSdV6ulNE3Kbx1YAPPyCXx2ykYtHVZiqDluLv0FgAalj92HrPQ/viewform)\\n[Découvrez le programme](http://www.ar2l-hdf.fr/le-livre-express-regional-se-reinvente-en-conference-en-ligne-actualite-931.html?fbclid=IwAR2jmorw3pUajIY1uJYzBQU_3CfURi8j5Of77d9dHNyEoM-p1wR6OVsHqRo)\"}', '{}', '{\"fr\":\"Sur inscription\"}', '{\"filename\":\"8e0e992f5b3e4b8d9260f7307c88b7bc.base.image.jpg\",\"size\":{\"width\":700,\"height\":522},\"variants\":[{\"filename\":\"8e0e992f5b3e4b8d9260f7307c88b7bc.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":252,\"height\":188}},{\"filename\":\"8e0e992f5b3e4b8d9260f7307c88b7bc.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-11-19T09:00:00.000Z\",\"end\":\"2020-11-19T11:00:00.000Z\"},{\"begin\":\"2020-11-24T09:00:00.000Z\",\"end\":\"2020-11-24T11:00:00.000Z\"},{\"begin\":\"2020-11-26T09:00:00.000Z\",\"end\":\"2020-11-26T11:00:00.000Z\"},{\"begin\":\"2020-12-01T09:00:00.000Z\",\"end\":\"2020-12-01T11:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"vielitteraire@ar2l-hdf.fr\"]', '2020-11-13 09:57:22', '2020-11-13 09:57:22', NULL, NULL, '[]', '[{\"link\":\"https://docs.google.com/forms/d/e/1FAIpQLSdV6ulNE3Kbx1YAPPyCXx2ykYtHVZiqDluLv0FgAalj92HrPQ/viewform\",\"data\":{\"url\":\"https://docs.google.com/forms/d/e/1FAIpQLSdV6ulNE3Kbx1YAPPyCXx2ykYtHVZiqDluLv0FgAalj92HrPQ/viewform?embedded=true\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"INCRIPTION AU LIVRE EXPRESS REGIONAL\",\"provider_name\":\"Google Docs\",\"description\":\"Bonjour à toutes et tous,  Le Livre Express Regional, initialement prévu le 19 novembre à la médiathèque de Tergnier se réinvente pour vous proposer plusieurs rendez-vous numériques.       Arrêt 1 : le 19 novembre de 10h à 12h – présentation des dispositifs vie littéraire avec la région HDF – La Drac HDF et l’AR2L + Zoom sur la médiathèque de Tergnier qui devait nous accueillir ;      Arrêt 2 : le mardi 24 novembre de 10 h à 12h – présentation des nouveautés éditeurs ;      Arrêt 3 : le jeudi 26 novembre de 10h à 12h – table ronde 1 – auteurs et prescripteurs : présentation de nouveautés d\'auteurs de la région ;      Arrêt 4 : mardi 1 décembre de 10h à 12h – table ronde 2 – auteurs et prescripteurs : présentation de nouveautés d\'auteurs de la région.  Nous vous invitons à vous inscrire en complétant le formulaire suivant.   Pour tout complément d\'information, vous pouvez nous contacter à l\'adresse suivante : vielitteraire@ar2l-hdf.fr   Au plaisir de vous retrouver,    Julien Dollet - Chargé de mission Vie littéraire Adeline Poivre - Chargé de projet Vie littéraire\",\"thumbnail_url\":\"https://lh4.googleusercontent.com/kygXoUmZax8taDAFERLYSioyvoQWM4Tt-z5EfhX0Sf50Yhsg0IlmIDUrF78nv8jlfKkBaoE=w1200-h630-p\",\"thumbnail_width\":200,\"thumbnail_height\":200,\"height\":2523,\"html\":\"<iframe src=\\\"https://docs.google.com/forms/d/e/1FAIpQLSdV6ulNE3Kbx1YAPPyCXx2ykYtHVZiqDluLv0FgAalj92HrPQ/viewform?embedded=true&amp;usp=embed_googleplus\\\" style=\\\"border: 0; width: 100%; height: 2523px;\\\" allowfullscreen></iframe>\",\"cache_age\":86400},\"type\":\"oembed\"}]'),
(877069, 2667961, 96815475, 96815475, 89904399, 46457931, 'jeux-de-piste_939150', '{\"fr\":\"Jeux de piste\"}', '{\"fr\":\"Le Collectif de la Girafe propose un jeu de pistes afin de découvrir le patrimoine de la ville  d’Hellemmes.\"}', '{\"fr\":\"Le Collectif de la Girafe propose un jeu de pistes afin de découvrir le patrimoine de la ville d’Hellemmes. Prenez votre téléphone portable et partez en quête des QR codes dissimulés sur les bâtiments hellemmois. A chaque étape, un morceau d’histoire décalé par l’historien du Collectif de la Girafe : Jacques Tremolo. Seul ou en famille, rendez-vous à l’espace des\\nacacias!\\nMasque obligatoire.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T12:30:00.000Z\",\"end\":\"2020-10-10T16:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"http://hellemmes.fr\",\"03 20 41 82 50\",\"resanuitbibliohellemmes@mairie-lille.fr\"]', '2020-10-09 07:24:54', '2020-10-09 08:35:43', NULL, NULL, '[]', '[]'),
(877066, 79463902, 96815475, 96815475, 89904399, 46457931, 'danse_779068', '{\"fr\":\"Danse\"}', '{\"fr\":\"La compagnie Korzeam, présente spectacle autour des percussions et chants d’Afrique intitulé «AfroTrad».\"}', '{\"fr\":\"La compagnie Korzeam, présente spectacle autour des percussions et chants d’Afrique intitulé «AfroTrad». Les musiciens percussionnistes, accordéoniste et danseur(e)s de la compagnie vous transporteront à travers le continent africain afin de vous faire découvrir l’origine de l’homme nous sommes tous originaires de la terre Mère.\\nMasque obligatoire. 30 personnes maximum par représentation\"}', '{\"fr\":[\"Nuit des bibliothèques\",\"resanuitbibliohellemmes@mairie-lille.fr\",\"03 20 41 82 50\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-11T15:00:00.000Z\",\"end\":\"2020-10-11T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"http://hellemmes.fr\",\"0320418250\"]', '2020-10-09 07:20:48', '2020-10-09 08:36:14', NULL, NULL, '[]', '[]'),
(877064, 66661749, 96815475, 96815475, 89904399, 46457931, 'danse_754745', '{\"fr\":\"Marionnettes et musique\"}', '{\"fr\":\"Imaginez un immense livre en relief d’où jaillissent au gré des pages tournées des décors  de brousse ou de savane dans lesquels s’animent les marionnettes à fils.\"}', '{\"fr\":\"Imaginez un immense livre en relief d’où jaillissent au gré des pages tournées des décors de brousse ou de savane dans lesquels s’animent les marionnettes à fils. Savez-vous que l’éléphant n’a pas toujours été pourvu d’une trompe ? Il lui a fallu vivre de curieuses aventures\\npour acquérir une telle bizarrerie... Le conteur vous captive et vous narre cette histoire accompagné par un musicien qui assure en direct et devant le public l’illustration musicale, les chansons et les bruitages. Entrons dans l’univers de Rudyard Kipling (l’auteur du Livre de la jungle) illustré par Justine Brax. Adaptation, texte et mise en scène : Ulrich Vanacker -\\nCréation musicale : Jay Gimenez. Avec l’aimable autorisation des éditions Milan Jeunesse. 30 personnes maximum par représentation.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-11T09:00:00.000Z\",\"end\":\"2020-10-11T14:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"http://hellemmes.fr\",\"03 20 41 82 50\",\"resanuitbibliohellemmes@mairie-lille.fr\"]', '2020-10-09 07:18:35', '2020-10-09 08:37:05', NULL, NULL, '[]', '[]'),
(877063, 88377468, 96815475, 96815475, 89904399, 46457931, 'jeux-de-piste_972633', '{\"fr\":\"Contes\"}', '{\"fr\":\"Venez découvrir le continent du peuple africain à travers leurs divers jeux.\"}', '{\"fr\":\"La Création Continue, Compagnie hellemmoise de spectacles et de formation au conte, réunit pour vous ses Compagnons.\\nPlongez avec eux dans l’humour, la poésie et les surprises des contes africains. Voyagez à travers tout le continent. Et laissez-vous emporter au rythme mélodieux de la flûte peule.\\nCar les conteurs ont invité pour l’occasion un musicien qui les accompagnera pour ce grand voyage. »\\nMasque obligatoire. 30 personnes maximum par représentation.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:00:00.000Z\",\"end\":\"2020-10-10T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"http://hellemmes.fr\",\"resanuitbibliohellemmes@mairie-lille.fr\",\"03 20 41 82 50\"]', '2020-10-09 07:16:39', '2020-10-09 08:37:33', NULL, NULL, '[]', '[]'),
(877062, 69348305, 96815475, 96815475, 89904399, 46457931, 'jeux-africains', '{\"fr\":\"Jeux africains\"}', '{\"fr\":\"Venez découvrir le continent du peuple africain à travers leurs divers jeux.\"}', '{\"fr\":\"Du Senet égyptien au jeu de Man cala, du Yoté au Seega... et tellement d’autres jusqu’au Damma, venez découvrir le continent du peuple africain à travers leurs divers jeux.\\nMasque obligatoire. 10 personnes maximum dans l’espace jeux.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T12:30:00.000Z\",\"end\":\"2020-10-10T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"http://hellemmes.fr\",\"03 20 41 82 50\",\"resanuitbibliohellemmes@mairie-lille.fr\"]', '2020-10-09 07:15:50', '2020-10-09 08:37:57', NULL, NULL, '[]', '[]'),
(875546, 15785811, 96815475, 96815475, 89904399, 36223087, 'salon-science-en-livre', '{\"fr\":\"Salon Science en livre\"}', '{\"fr\":\"1ère édition du Salon Science en livre : toutes les sciences et scientifictions\"}', '{\"fr\":\"Le 10 octobre de 10h à 21h, à LILLIAD Learning center Innovation, Villeneuve d\'Ascq (sous réserve des évolutions de la situation sanitaire)  \\n16 rencontres, conférences, ateliers animeront le Salon tout au long de cette journée, autour de la Grande librairie éphémère de toutes les sciences et scientifictions qui se déploiera dans le Pôle événementiel de LILLIAD, proposée par la [librairie Les Lisières](https://www.leslisieres.com/)\\n\\nCette 1re édition du salon Science en livre se déroule à l’occasion de la Fête de la science 2020 qui a lieu du 2 au 12 octobre 2020 autour du thème «Quelle relation entre l’Homme et son environnement ?» et de la Nuit des Bibliothèques, coordonnée par la Métropole Européenne de Lille autour du thème «AfriqueS».\"}', '{}', '{}', '{\"filename\":\"860ff0902f14486b9181efe913ab6e59.base.image.jpg\",\"credits\":null,\"size\":{\"height\":1090,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"860ff0902f14486b9181efe913ab6e59.full.image.jpg\",\"size\":{\"height\":515,\"width\":331}},{\"type\":\"thumbnail\",\"filename\":\"860ff0902f14486b9181efe913ab6e59.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:00:00.000Z\",\"end\":\"2020-10-10T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.eventbrite.fr/e/billets-salon-science-en-livre-122233558865\",\"salon@scienceenlivre.org\"]', '2020-10-06 12:37:44', '2020-10-06 12:39:21', NULL, NULL, '[]', '[]'),
(875109, 79061025, 96815475, 96815475, 89904399, 66136370, 'contes-aux-couleurs-dafrique', '{\"fr\":\"Contes aux couleurs d’Afrique\"}', '{\"fr\":\"La compagnie Chats pitres & rats conteurs joue avec les mots, les notes, les objets… pour nous emmener en voyage avec chaleur et émotion.\"}', '{\"fr\":\"La compagnie Chats pitres & rats conteurs joue avec les mots, les notes, les objets… pour nous emmener en voyage avec chaleur et émotion.\\nà 10h00 (pour les 4-6 ans) et 11h00 (pour les 6-9 ans)\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"réservation indispensable, gratuit\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-11T08:00:00.000Z\",\"end\":\"2020-10-11T09:00:00.000Z\"},{\"begin\":\"2020-10-11T09:00:00.000Z\",\"end\":\"2020-10-11T10:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 46 88 27\",\"http://bpt.neuville.free.fr\"]', '2020-10-05 11:47:45', '2020-10-05 11:47:45', NULL, NULL, '[]', '[]'),
(875108, 3345407, 96815475, 96815475, 89904399, 14322600, 'soiree-lecture-groove-beatbox-et-bien-plus', '{\"fr\":\"Soirée \\\"lecture, groove, beatbox et bien plus\\\"\"}', '{\"fr\":\"Trois artistes pour une rencontre au rythme de racines africaines bantoues, vie française et culture musicale afro-américaine.\"}', '{\"fr\":\"PLDG (Pour L’amour Du Groove / Mystraw & AI20) et James Izcray puisent dans leurs influences et références pour livrer des œuvres musicales uniques. A savourer sans modération.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"réservation conseillée, gratuit\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-09T18:00:00.000Z\",\"end\":\"2020-10-09T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 46 88 27\",\"http://bpt.neuville.free.fr\"]', '2020-10-05 11:46:27', '2020-10-05 11:49:26', NULL, NULL, '[]', '[]'),
