(860568, 77692185, 96815475, 96815475, 89904399, 40636251, 'reporte-restauration-avec-la-friterie-les-chtis-bubu-et-concert-afrique-en-chanson-par-alex-et-shane', '{\"fr\":\"REPORTÉ : Restauration avec la friterie « Les Ch’tis BuBu» et concert Afrique en chanson par Alex et Shane\"}', '{\"fr\":\"Restauration et concert reportés. Restauration sur place avec la friterie « Les Ch’tis BuBu» Tout l’après-midi : Afrique en chanson par Alex et Shane\"}', '{\"fr\":\"Restauration et concert : reportés\\ndès 11h45 : Restauration sur place avec la friterie « Les Ch’tis BuBu»  \\nTout l’après-midi : Afrique en chanson par Alex et Shane\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T09:45:00.000Z\",\"end\":\"2020-10-10T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"f.flament@houplin-ancoisne.fr\",\"0320321496\"]', '2020-09-10 06:37:05', '2020-09-10 06:37:41', NULL, NULL, '[]', '[]'),
(855551, 8610548, 89371029, 89371029, 89904399, 20612150, 'la-journee-des-oppportunites', '{\"fr\":\"La journée des oppportunités\"}', '{\"fr\":\"Un événement dédié à l\'entrepreneuriat étudiant.\"}', '{\"fr\":\"Participez à la journée des opportunités !\\n------------------------------------------\\n\\n### Nous sommes tous acteurs du monde de demain, alors pourquoi ne pas créer ses propres opportunités ?\\n\\nÀ travers la journée des opportunités, nous allons vous faire voyager vers une expérience unique, valorisante, et ludique : celle de la prise d\'initiative(s).\\n\\nC\'est parce que nous avons tous des idées, des visions de ce que nous voulons apporter à nos sociétés, que la MEL et ses partenaires, ont décidé de créer la journée des opportunités, pour que chacun puisse mener à bien ses projets.\\n\\nNous sommes tous concernés par l\'évolution des modes de travail, par les transitions écologiques, sociales, technologiques... Nous avons tous, dans un coin de notre tête, une idée, une ambition, une envie de monter des projets. Figure toi que ce sera l\'événement de cette fin d\'année, où tu retrouveras tous les acteurs qui te permettront de prendre des initiatives !\\n\\nAu programme :\\n\\n*   Découverte de l\'écosystème de la prise d\'initiative, de l\'entrepreneuriat\\n*   Concours d\'éloquence dans un format innovant et ludique (avec des récompenses financières à la clef)\\n*   Exposition d\'artistes-étudiants\\n*   Conférences de pépites Lilloises ayant réussi leur projet avec, entre autres, Lamia Mialet de Cozy Air et Gaudrey Chokoté des Tontons Afros, etc.\\n*   Challenge de votre idée/projet par des professionnels\\n*   Lab\' étudiants-entrepreneurs et présentation de leur produit(s) - service(s) avec Les Lunettes de Zac, La Petite Boucle, Octavio et bien d\'autres !\\n\\nEt des surprises à découvrir sur place ...\\n\\nCette manifestation se tiendra dans le respect des gestes barrières et avec le port du masque obligatoire.\"}', '{\"fr\":[\"#entrepreneuriat\",\"#emploi\",\"#etudiant\",\"#innovation\",\"#tech\",\"#entrepreneur\",\"#success\",\"#experience\",\"#decouverte\"]}', '{\"fr\":\"Inscription obligatoire\"}', '{\"filename\":\"c05c29d09e6b45ff8d6cbfefb0130152.base.image.jpg\",\"size\":{\"width\":700,\"height\":218},\"variants\":[{\"filename\":\"c05c29d09e6b45ff8d6cbfefb0130152.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":4229,\"height\":1313}},{\"filename\":\"c05c29d09e6b45ff8d6cbfefb0130152.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"Métropole Européenne de Lille\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-08T12:30:00.000Z\",\"end\":\"2020-10-08T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.eventbrite.fr/e/billets-la-journee-des-opportunites-ljdo-117427923079\"]', '2020-09-03 13:45:24', '2020-09-03 13:45:24', NULL, NULL, '[]', '[]'),
(852201, 49679987, 52630919, 52630919, 89904399, 4907947, 'collecte-de-dechets-chimiques-des-particuliers_914244', '{\"fr\":\"Collecte de déchets chimiques des particuliers\"}', '{\"fr\":\"Des collectes exceptionnelles et gratuites sont organisées pour récolter les déchets chimiques des particuliers.\"}', '{\"fr\":\"Vous avez des déchets chimiques chez vous ? Ils peuvent être dangereux pour votre santé et pour l\'environnement. C\'est pourquoi il est important de les apporter en déchèteries ou aux lieux de collecte et ne plus les jeter à la poubelle ou dans les canalisations. Profitez des journées de collectes gratuites et exceptionnelles pour les jeter.\\nRendez-vous sur le parking du magasin Leroy Merlin de Lesquin le samedi 26 septembre 2020, entre 10h et 17h.  \\nRetrouvez la liste des produits acceptés sur le site [www.ecodds.com](http://www.ecodds.com)\"}', '{\"fr\":[\"déchets chimiques\",\"collecte\"]}', '{\"fr\":\"Gratuit\"}', '{\"filename\":\"041e263cf3ef4ce298efd3ed5c311c62.base.image.jpg\",\"size\":{\"width\":700,\"height\":989},\"variants\":[{\"filename\":\"041e263cf3ef4ce298efd3ed5c311c62.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":592,\"height\":836}},{\"filename\":\"041e263cf3ef4ce298efd3ed5c311c62.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"EcoDDS\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-09-26T08:00:00.000Z\",\"end\":\"2020-09-26T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[]', '2020-08-28 13:08:31', '2020-08-28 13:08:31', NULL, NULL, '[]', '[]'),
