(842618, 80209919, 96815475, 96815475, 89904399, 16144216, 'rencontre-dauteurs-et-seance-de-dedicaces', '{\"fr\":\"Rencontre d’auteurs et séance de dédicaces\"}', '{\"fr\":\"Dans le cadre de l’exposition « Kong Crew », la bibliothèque et l’association « Bulles Carrées » invitent l’auteur de bande dessinée Eric Hérenguel.\"}', '{\"fr\":\"Celui-ci viendra dédicacer ses albums, en compagnie de deux autres auteurs « surprise ». Cette séance de dédicaces sera précédée d’une rencontre avec l’auteur qui évoquera son travail mais aussi ses influences et ses projets.\"}', '{}', '{}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:00:00.000Z\",\"end\":\"2020-10-10T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320816638\",\"bibanim@ville-wattrelos.fr\"]', '2020-08-20 07:10:19', '2020-08-20 07:10:19', NULL, NULL, '[]', '[]'),
