(841790, 16436428, 96815475, 96815475, 89904399, 88587419, 'soiree-cabaret-lectures-autour-des-afriques', '{\"fr\":\"Soirée « Cabaret lectures… autour des AfriqueS »\"}', '{\"fr\":\"Le FCP (Formation Culture Prévention) Secteur Atelier, vous concocte une soirée de découverte d’auteurs et récits africains, de mets à grignoter et de chants pour rythmer le tout. À partir de 8 ans.\"}', '{}', '{}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T17:30:00.000Z\",\"end\":\"2020-10-10T19:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":8,\"max\":99}', '[\"03 28 38 84 53\",\"culture@wambrechies.fr\"]', '2020-08-18 14:43:07', '2020-08-18 14:43:07', NULL, NULL, '[]', '[]');
