(841788, 65741814, 96815475, 96815475, 89904399, 88587419, 'lectures-dafriques', '{\"fr\":\"Lectures d\'Afriques\"}', '{\"fr\":\"Dans les histoires de Matthieu, il y a différents coins du monde et notamment des aventures qui se déroulent sur ce grand continent qu’est l’Afrique !\"}', '{\"fr\":\"Des déserts aux jungles, des enfants turbulents aux adultes sages (ou le contraire), en passant par de nombreux animaux féroces et mignons, faites le plein de voyages dans les quatre coins de l’Afrique.\\nÀ partir de 5 ans.\"}', '{}', '{}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T13:00:00.000Z\",\"end\":\"2020-10-10T14:00:00.000Z\"},{\"begin\":\"2020-10-10T14:00:00.000Z\",\"end\":\"2020-10-10T15:00:00.000Z\"},{\"begin\":\"2020-10-10T15:00:00.000Z\",\"end\":\"2020-10-10T16:00:00.000Z\"}]', NULL, '{\"min\":5,\"max\":99}', '[\"03 28 38 84 53\",\"culture@wambrechies.fr\"]', '2020-08-18 14:41:56', '2020-08-18 14:41:56', NULL, NULL, '[]', '[]'),
(841785, 49613997, 96815475, 96815475, 89904399, 88587419, 'braderie-du-livre', '{\"fr\":\"Braderie du livre\"}', '{\"fr\":\"La bibliothèque sort de ses collections régulièrement de nombreux livres pour laisser places aux nouveautés !\"}', '{\"fr\":\"Cette Nuit des Bibliothèques est l’occasion d’en acquérir, d’en discuter, autour d’un café… et de prolonger le plaisir de la lecture à petits prix !\"}', '{}', '{}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:00:00.000Z\",\"end\":\"2020-10-10T10:00:00.000Z\"},{\"begin\":\"2020-10-10T12:00:00.000Z\",\"end\":\"2020-10-10T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 28 38 84 53\",\"culture@wambrechies.fr\"]', '2020-08-18 14:40:30', '2020-08-18 14:40:30', NULL, NULL, '[]', '[]'),
(841782, 62670779, 96815475, 96815475, 89904399, 36223087, 'le-salon-science-en-livre-toutes-les-sciences-et-scientifictions', '{\"fr\":\"Le salon Science en livre  : «  toutes les sciences et scientifictions »\"}', '{\"fr\":\"Autour d’une grande librairie éphémère, une programmation qui répondra à la curiosité de tous.\"}', '{\"fr\":\"Autour d’une grande librairie éphémère, une programmation qui répondra à la curiosité de non-spécialistes, jeunes et adultes, en les invitant à rencontrer chercheurs, passeurs et raconteurs de sciences pour partager la richesse et la diversité de la matière à penser le monde d’aujourd’hui et de demain. Le programme détaillé du salon Science en livre est en ligne sur les sites de LILLIAD et de l’ASEL.\\n\\nLe temps d’une journée, en un seul lieu, LILLIAD vous propose une moisson de rencontres, d’échanges, de découvertes au cœur de l’actualité de la science et de ses enjeux, pour trouver matière à penser le monde et saisir la science sous toutes ses facettes.\"}', '{}', '{}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:00:00.000Z\",\"end\":\"2020-10-10T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 43 44 20\",\"helene.deleuze@univ-lille.fr\"]', '2020-08-18 14:37:10', '2020-08-18 14:44:10', NULL, NULL, '[]', '[]'),
(841777, 41644659, 96815475, 96815475, 89904399, 36223087, 'lancement-de-la-saison-4-dxperium-kaleidoscope-limage-dans-toutes-les-sciences', '{\"fr\":\"Lancement de la saison 4 d’Xperium : Kaléidoscope ! L’image dans toutes les sciences\"}', '{\"fr\":\"Une occasion exceptionnelle de découvrir la recherche en train de se faire dans les laboratoires de l’Université de Lille\"}', '{\"fr\":\"Et les multiples facettes de l’image, qui fait l’objet de nombreuses études et innovations.\\n\\nLe temps d’une journée, en un seul lieu, LILLIAD vous propose une moisson de rencontres, d’échanges, de découvertes au cœur de l’actualité de la science et de ses enjeux, pour trouver matière à penser le monde et saisir la science sous toutes ses facettes.\"}', '{}', '{}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:00:00.000Z\",\"end\":\"2020-10-10T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 43 44 20\",\"helene.deleuze@univ-lille.fr\"]', '2020-08-18 14:31:39', '2020-08-18 14:43:27', NULL, NULL, '[]', '[]'),
(841099, 81378296, 96815475, 96815475, 89904399, 92031237, 'mystere-a-la-doc', '{\"fr\":\"« Mystère à la Doc’ »\"}', '{\"fr\":\"Spectacle déambulatoire familial : depuis quelques temps, il se passe des choses étranges dans la Doc’, les livres se vident de leur sens, des mots s’effacent et les histoires disparaissent.\"}', '{\"fr\":\"D’aucuns affirment qu’un fantôme rôde dès la fermeture. Le personnel est terrifié, les usagers désertent les lieux. Devant la menace, la Doc’ risque de fermer définitivement ses portes... Face à ces étranges événements, le public est invité à mener l’enquête en compagnie de Nestor Watson, usager féru de romans policiers\"}', '{}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T17:30:00.000Z\",\"end\":\"2020-10-10T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 59 73 95 66\",\"accueil-forumdessciences@lenord.fr\"]', '2020-08-17 14:10:56', '2020-08-17 14:10:56', NULL, NULL, '[]', '[]'),
(841096, 80218397, 96815475, 96815475, 89904399, 92031237, 'les-contes-de-lhyper-climat', '{\"fr\":\"« Les contes de l’hyper climat »\"}', '{\"fr\":\"Conte musical : Blanche Neige sans neige et sans nains dans la forêt moussue ne sera plus jamais la même !\"}', '{\"fr\":\"Et que dire des petits cochons, des loups voraces, du petit Poucet et des ogres de nos forêts séculaires ? Face aux nouveaux enjeux du XXIe\\nsiècle, tout est à réinventer… Ludiques, parfois décalés et conçus sur\\nla volonté de sensibiliser le public au réchauffement climatique, des contes et histoires traditionnels ont été revisités par Armel Richard dans un climat à +20°C. À partir de 6 ans.\"}', '{}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T14:00:00.000Z\",\"end\":\"2020-10-10T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":6,\"max\":99}', '[\"03 59 73 95 66\",\"accueil-forumdessciences@lenord.fr\"]', '2020-08-17 14:09:31', '2020-08-17 14:09:31', NULL, NULL, '[]', NULL),
(841094, 53212641, 96815475, 96815475, 89904399, 92031237, 'planetarium_278751', '{\"fr\":\"Planétarium\"}', '{\"fr\":\"Séances de planétarium : partez à la découverte du ciel, émerveillez-vous devant plus de 4 000 étoiles et rêvez devant le spectacle du ciel étoilé…\"}', '{\"fr\":\"Séances « Poussières de Lune », « Le ciel ce soir vu de chez nous et vu d’Afrique »... À partir de 6 ans (en fonction des séances proposées)\"}', '{}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T12:00:00.000Z\",\"end\":\"2020-10-10T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 59 73 95 66\",\"accueil-forumdessciences@lenord.fr\"]', '2020-08-17 14:07:50', '2020-08-17 14:07:50', NULL, NULL, '[]', '[]'),
(841093, 6277531, 96815475, 96815475, 89904399, 92031237, 'tous-sportifs-la-science-occupe-le-terrain', '{\"fr\":\"« Tous sportifs ! La science occupe le terrain »\"}', '{\"fr\":\"Exposition. Venez participer à une grande épreuve sportive et ludique : un décathlon réinventé !\"}', '{\"fr\":\"Conçue autour d’une piste d’athlétisme, chaque étape invite à découvrir les pratiques sportives par le prisme des sciences. Tout en vous amusant, vous apprendrez au fil de votre parcours des informations passionnantes sur la physiologie, la biologie, la physique, l’histoire ou encore la mécanique du sport.\\nVisite de 30 min à 14h30, 15h30, 16h30, 17h30, 18h45 et 19h45.\"}', '{}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T12:30:00.000Z\",\"end\":\"2020-10-10T18:15:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 59 73 95 66\",\"accueil-forumdessciences@lenord.fr\"]', '2020-08-17 14:06:31', '2020-08-17 14:06:31', NULL, NULL, '[]', '[]'),
(841089, 62297614, 96815475, 96815475, 89904399, 92031237, 'mon-dodo', '{\"fr\":\"« Mon dodo »\"}', '{\"fr\":\"Exposition et ateliers. Vos paupières sont lourdes... À quoi sert de dormir ? Que se passe-t-il quand je dors ? Pourquoi je rêve ?\"}', '{\"fr\":\"Telles sont les questions que peuvent se poser les enfants lorsqu’ils vont se coucher pour la sieste ou pour la nuit. Séances de 45 min toutes les heures de 14h15 à 18h15.\\nPour les enfants de 5 à 7 ans.\"}', '{}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T12:15:00.000Z\",\"end\":\"2020-10-10T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 59 73 95 66\",\"accueil-forumdessciences@lenord.fr\"]', '2020-08-17 14:02:37', '2020-08-17 14:03:06', NULL, NULL, '[]', '[]'),
