(841067, 67072442, 96815475, 96815475, 89904399, 46084324, 'quelle-agriculture-aujourdhui-pour-conduire-a-lautosuffisance-alimentaire-en-afrique-rencontredebat_419117', '{\"fr\":\"Quelle agriculture aujourd’hui pour conduire à l’autosuffisance alimentaire en Afrique ? Rencontre/débat\"}', '{\"fr\":\"’Afrique est un grand continent agricole et pourtant régulièrement confronté à des problèmes d’approvisionnement alimentaire.\"}', '{\"fr\":\"Comment améliorer les politiques agricoles, rééquilibrer cultures ’exportation et cultures vivrières, se diriger vers un développement durable et une indépendance alimentaire ? Venez échanger sur ces thématiques avec Siradiou Bah, professeur d’économie et spécialiste de ces questions. Echange précédé d’un film court. À partir de 14 ans\"}', '{}', '{}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T18:00:00.000Z\",\"end\":\"2020-10-10T19:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":14,\"max\":99}', '[\"03 59 63 43 00\",\"mediatheque@ville-tourcoing.fr\"]', '2020-08-17 13:41:59', '2020-08-17 13:41:59', NULL, NULL, '[]', '[]'),
