(841061, 54969267, 96815475, 96815475, 89904399, 46084324, 'atelier-portage-denfant-invitation-a-un-voyage-etonnant-embarquez-au-pays-du-portage', '{\"fr\":\"atelier portage d’enfant Invitation à un voyage étonnant : embarquez au pays du portage !\"}', '{\"fr\":\"Lors de cette rencontre, retraçons ensemble les traditions.\"}', '{\"fr\":\"Échangeons, racontons, tissons des liens. Parcourons le chemin de l’écharpe de portage, de l’Orient à l’Occident. Lors de cet atelier, venez découvrir les outils existants aujourd’hui, pour porter bébé, en toute sécurité ! Chaque participant pourra repartir avec un livret explicatif.\\nPour les parents accompagnés (ou non) de leur bébé.\"}', '{}', '{}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T15:30:00.000Z\",\"end\":\"2020-10-10T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 59 63 43 00\",\"mediatheque@ville-tourcoing.fr\"]', '2020-08-17 13:38:16', '2020-08-17 13:38:16', NULL, NULL, '[]', '[]'),
