(840988, 48448360, 96815475, 96815475, 89904399, 12341872, 'musiques-electroniques-et-cinema', '{\"fr\":\"ANNULE : Musiques électroniques et cinéma\"}', '{\"fr\":\"Conférence d’Olivier Pernot, journaliste culturel, qui vous montrera comment le cinéma a su utiliser à l’écran toute la richesse mélodique et la force dramatique de la musique électronique.\"}', '{\"fr\":\"Plusieurs films cultes de cette époque sont rythmés par des bandes originales utilisant des synthétiseurs : Orange mécanique, Midnight Express, Blade Runner… Dès lors et jusqu’à aujourd’hui, la musique électronique va avoir une place de choix au cinéma, remplaçant parfois les orchestres, trop coûteux. À partir de 12 ans.\"}', '{}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T17:30:00.000Z\",\"end\":\"2020-10-10T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":12,\"max\":99}', '[\"0606437983\",\"bibliosailly@outlook.fr\"]', '2020-08-17 12:36:34', '2020-09-28 07:33:27', NULL, NULL, '[]', '[]'),
