(840983, 93222164, 96815475, 96815475, 89904399, 4821230, 'contes-musicaux-africains-par-la-compagnie-les-margouillats', '{\"fr\":\"Contes musicaux africains par la compagnie « Les margouillats »\"}', '{\"fr\":\"Au son d’un djembé, d’une sensa et de quelques chékérés,  partez à la découverte de contes traditionnels africains. Des histoires pour s’évader, des histoires pour appréhender la vie, autrement...\"}', '{}', '{}', '{\"fr\":\"sur réservation uniquement\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:30:00.000Z\",\"end\":\"2020-10-10T17:15:00.000Z\"},{\"begin\":\"2020-10-10T17:30:00.000Z\",\"end\":\"2020-10-10T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":5,\"max\":99}', '[\"03 20 66 45 00\",\"mediatheque@ville-roubaix.fr\"]', '2020-08-17 12:31:00', '2020-09-24 13:40:57', NULL, NULL, '[]', '[]'),
