(840891, 98089054, 96815475, 96815475, 89904399, 65320576, 'concert-dessine-avec-nawel-louerrad-et-maryline-pruvost', '{\"fr\":\"Concert dessiné avec Nawel Louerrad et Maryline Pruvost\"}', '{\"fr\":\"Dans le cadre du festival « Littérature, etc » et en partenariat avec la MEL. Nawel Louerrad vit et travaille à Alger.\"}', '{\"fr\":\"Elle a publié deux bandes dessinées : Les vêpres algériennes et Regretter l’absence de l’astre, aux éditions Dalimen. À l’occasion de la Nuit des bibliothèques et du festival « Littérature, etc », elle dessine devant vous, mêlant son trait sensible et puissant à une performance improvisée de la musicienne et chanteuse Maryline Pruvost\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T17:00:00.000Z\",\"end\":\"2020-10-10T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320818745\",\"corderie@marcq-en-baroeul.fr\"]', '2020-08-17 09:02:04', '2020-08-17 09:02:04', NULL, NULL, '[]', '[]'),
