(840078, 69498595, 96815475, 96815475, 89904399, 47715652, 'projection-du-film-mia-et-le-lion-blanc', '{\"fr\":\"Projection du film Mia et le Lion blanc\"}', '{\"fr\":\"Mia a onze ans lorsqu’elle noue une relation hors du commun avec Charlie, un lion blanc né dans la ferme de félins de ses parents en Afrique du Sud\"}', '{\"fr\":\"Tous deux grandissent comme frère et sœur et deviennent vite inséparables. Trois ans plus tard, Charlie est devenu un lion imposant. Mia découvre alors le secret que cache la ferme : son père vend les lions à des chasseurs de trophées. Mia n’aura désormais qu’une obsession, sauver\\nCharlie, à tout prix.\\nTarif unique à 5€.\"}', '{}', '{}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:00:00.000Z\",\"end\":\"2020-10-10T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320256430\",\"bibliotheque@roncq.fr\"]', '2020-08-14 13:47:53', '2020-08-14 13:47:53', NULL, NULL, '[]', '[]'),
