(840063, 47307091, 96815475, 96815475, 89904399, 47715652, 'association-roncqselinkegny', '{\"fr\":\"ANNULÉ : Exposition Mali : Scènes de villages\"}', '{\"fr\":\"Les photos de Françoise Pochon révèlent un Mali hors du temps, paisible, évocateur du style orientaliste des panoramiques du 18e siècle.\"}', '{\"fr\":\"Les photos de Françoise Pochon révèlent un Mali hors du temps, paisible, évocateur du style orientaliste des panoramiques du 18e siècle.\\nPour mettre en valeur ces délicates photos monochromes, nous avons choisi des tons sourds nés de la terre d\'Afrique en nous inspirant de techniques de dessin traditionnelles, des éléments graphiques des photos et de la luxuriance végétale qui y est célébrée.\\nAgathe Braun et Constance Rondeau\\nJardins Bénéfiques\"}', '{}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:00:00.000Z\",\"end\":\"2020-10-10T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320256430\",\"bibliotheque@roncq.fr\"]', '2020-08-14 13:35:57', '2020-10-10 05:10:14', NULL, NULL, '[]', '[]'),
