(840034, 39218326, 96815475, 96815475, 89904399, 73205657, 'loulou-contes-comptines-et-objets-par-sophie-verdier', '{\"fr\":\"Loulou : contes, comptines et objets, par Sophie Verdier\"}', '{\"fr\":\"Loulou a faim... Que voulez-vous, c’est un loup  !\"}', '{\"fr\":\"Mais tout grand loup qu’il soit, il ne peut pas se remplir le ventre comme ça. S’il veut manger la petite fille, il doit d’abord manger les patates, les carottes... S’il veut manger la mémé, il doit attendre l’heure du souper. S’il veut croquer les cochons, il doit casser leurs maisons. Et s’il grogne un peu\\ntrop... à la trois, à la deux, à la une... on le lancera sur la lune !\\nÀ 18h30, séance de 25 min. Pour les enfants de 1 à 3 ans.\\nÀ 20h, séance de 35 min. Pour les enfants de 3 à 6 ans\"}', '{}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:30:00.000Z\",\"end\":\"2020-10-10T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":1,\"max\":6}', '[\"0320166028\",\"bibliotheque@ville-ronchin.fr\"]', '2020-08-14 13:05:57', '2020-08-14 13:05:57', NULL, NULL, '[]', '[]'),
