(839984, 21021222, 96815475, 96815475, 89904399, 90509828, 'ole-mains', '{\"fr\":\"ANNULE : Olé mains\"}', '{\"fr\":\"Ateliers découvertes de signes associés à la parole.\"}', '{\"fr\":\"Bébé ne parle pas encore, pourtant il a tellement de chose à nous dire. Venez découvrir en petit groupe, un outil ludique et accessible pour communiquer avec votre enfant avant qu’il ne sache parler.\\nParents-enfants (limité à 7 places).\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:00:00.000Z\",\"end\":\"2020-10-10T09:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320661370\",\"bilbiotheque@mairie-lyslezlannoy.com\"]', '2020-08-14 10:57:15', '2020-10-01 07:27:58', NULL, NULL, '[]', '[]'),
(839929, 18947325, 96815475, 96815475, 89904399, 76607321, 'le-tam-tam-de-bouki-conte-anime-par-ondine-desbonnets-de-la-compagnie-on-mange-des-echarpes', '{\"fr\":\"Le Tam-tam de Bouki conte animé par Ondine Desbonnets de la compagnie « On mange des écharpes »\"}', '{\"fr\":\"Dans un théâtre d’ombres recréant l’univers de la savane, venez écouter ce conte drôle et généreux en famille.\"}', '{\"fr\":\"Dans la chaleur énergisante de l’Afrique, vous suivrez Gayé-le-lion et Bouki-la-hyène : ils partent à la rencontre des nombreux habitants de la savane. Que mijotent-ils ?\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:30:00.000Z\",\"end\":\"2020-10-10T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":6,\"max\":99}', '[\"biblio@ville-loos.fr\",\"0320104065\"]', '2020-08-14 09:17:50', '2020-08-14 09:17:50', NULL, NULL, '[]', '[]'),
