(839912, 15712150, 96815475, 96815475, 89904399, 79306424, 'concert-lecture-publique-exposition-et-dons-de-livres', '{\"fr\":\"ANNULE : Concert, lecture publique, exposition et dons de livres\"}', '{\"fr\":\"Concert, lecture publique, exposition et dons de livres\"}', '{}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T11:00:00.000Z\",\"end\":\"2020-10-10T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320446491\",\"delegationculture@chru-lille.fr\"]', '2020-08-14 09:00:21', '2020-10-09 11:35:17', NULL, NULL, '[]', '[]'),
(839909, 50216343, 96815475, 96815475, 89904399, 99994062, 'dest-en-ouest-une-balade-sans-pretention-au-coeur-de-lafrique-sauvage', '{\"fr\":\"D’Est en Ouest, une balade sans prétention au cœur de l’Afrique sauvage\"}', '{\"fr\":\"Récit de voyage sur la faune africaine.\"}', '{\"fr\":\"Qu’il s’agisse d’espèces « stars » du monde animal ou d’illustres inconnues,\\nelles ont toutes quelque chose de passionnant à nous raconter.\\nPar Rudy Pischiutta, naturaliste émérite, directeur du GON, Groupe Ornithologique et Naturaliste du Nord**.**\\n\\n**Nature africaine**  \\nSa seule évocation nous plonge dans le souvenir d’incalculables heures de lecture. Qu’on l’aborde par la bande dessinée, le roman d’aventures, le récit de voyage, l’ouvrage encyclopédique, le témoignage ethnographique ou l’album de photographies... l’Afrique, avec ses vastes plaines et ses sombres forêts, fait toujours rêver. À l’occasion de la Nuit des bibliothèques et de la Fête de la Nature, la Maison Régionale de l’Environnement et des solidarités  \\nvous propose de la découvrir sous l’angle de son incroyable biodiversité.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T18:00:00.000Z\",\"end\":\"2020-10-10T19:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320521202\",\"a.menu@mres-asso.fr\"]', '2020-08-14 08:57:16', '2020-08-14 08:57:16', NULL, NULL, '[]', '[]'),
(839906, 67030917, 96815475, 96815475, 89904399, 99994062, 'histoires-dafrique', '{\"fr\":\"Histoires d’Afrique\"}', '{\"fr\":\"Des lectures proposées par Marie-Christine Blayac.\"}', '{\"fr\":\"**Nature africaine**\\nSa seule évocation nous plonge dans le souvenir d’incalculables heures de lecture. Qu’on l’aborde par la bande dessinée, le roman d’aventures, le récit de voyage, l’ouvrage encyclopédique, le témoignage ethnographique ou l’album de photographies... l’Afrique, avec ses vastes plaines et ses sombres forêts, fait toujours rêver. À l’occasion de la Nuit des bibliothèques et de la Fête de la Nature, la Maison Régionale de l’Environnement et des solidarités\\nvous propose de la découvrir sous l’angle de son incroyable biodiversité.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T17:10:00.000Z\",\"end\":\"2020-10-10T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320521202\",\"a.menu@mres-asso.fr\"]', '2020-08-14 08:55:52', '2020-08-14 08:55:52', NULL, NULL, '[]', '[]'),
(839903, 97764400, 96815475, 96815475, 89904399, 99994062, 'animal-dafrique', '{\"fr\":\"Animal d’Afrique\"}', '{\"fr\":\"Atelier familial d’initiation au dessin animalier animé par Vincent Gavériaux, illustrateur naturaliste professionnel.\"}', '{\"fr\":\"**Nature africaine**\\nSa seule évocation nous plonge dans le souvenir d’incalculables heures de lecture. Qu’on l’aborde par la bande dessinée, le roman d’aventures, le récit de voyage, l’ouvrage encyclopédique, le témoignage ethnographique ou l’album de photographies... l’Afrique, avec ses vastes plaines et ses sombres forêts, fait toujours rêver. À l’occasion de la Nuit des bibliothèques et de la Fête de la Nature, la Maison Régionale de l’Environnement et des solidarités\\nvous propose de la découvrir sous l’angle de son incroyable biodiversité.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:00:00.000Z\",\"end\":\"2020-10-10T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320521202\",\"a.menu@mres-asso.fr\"]', '2020-08-14 08:55:00', '2020-08-14 08:55:00', NULL, NULL, '[]', '[]'),
(839896, 66040146, 96815475, 96815475, 89904399, 27422735, 'dedicace-des-livres-congo-in-limbo-et-land-of-cush-suivie-dune-visite-de-lexposition-realites-donnees-en-presence-du-photographe', '{\"fr\":\"Dédicace des livres Congo in Limbo et Land of Cush, suivie d’une visite de l’exposition « Réalités données  », en présence du photographe\"}', '{\"fr\":\"Cédric Gerbehaye s’est rendu à plusieurs reprises au Lycée Maurice Duhamel de Loos pour aller à la rencontre des mineurs exilés d’Afrique subsaharienne ou orientale que cet établissement accueille.\"}', '{\"fr\":\"Leurs différents échanges autour de leur parcours passés, présents et\\nfuturs ont donné lieu à la série « Odyssées et horizons », présentée à l’Institut.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T17:30:00.000Z\",\"end\":\"2020-10-10T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0678052362\",\"msancandi@institut-photo.com\"]', '2020-08-14 08:43:41', '2020-08-14 08:43:41', NULL, NULL, '[]', '[]'),
(839894, 6520190, 96815475, 96815475, 89904399, 27422735, 'rencontre-avec-cedric-gerbehaye-autour-de-ses-livres-congo-in-limbo-et-land-of-cush', '{\"fr\":\"Rencontre avec Cédric Gerbehaye autour de ses livres Congo in Limbo et Land of Cush\"}', '{\"fr\":\"L’Institut pour la photographie vous convie à une rencontre avec le photographe Cédric Gerbehaye autour de deux de ses livres plusieurs fois primés : Congo in Limbo (2010)\"}', '{\"fr\":\"né de trois années de voyages en République démocratique du Congo et Land of Cush (2013), consacré au Sud Soudan\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:00:00.000Z\",\"end\":\"2020-10-10T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0678052362\",\"msancandi@institut-photo.com\"]', '2020-08-14 08:41:54', '2020-08-14 08:41:54', NULL, NULL, '[]', '[]'),
(839893, 47165756, 96815475, 96815475, 89904399, 84802184, 'atelier-conte-plurilingue-par-lassociation-dulala_814233', '{\"fr\":\"Atelier conte plurilingue par l’association « Dulala »\"}', '{\"fr\":\"Les enfants sont amenés à découvrir un conte (très célèbre) dans une autre langue que le français et à deviner de quel conte il s’agit.\"}', '{\"fr\":\"Ils seront ensuite amenés à créer collectivement un « memory » plurilingue du conte, en s’essayant ainsi à la calligraphie dans d’autres systèmes d’écriture.\\nPour les enfants de 4 à 7 ans.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T13:00:00.000Z\",\"end\":\"2020-10-10T14:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":4,\"max\":7}', '[\"0320128468\",\"lpatte@mairie-lille.fr\"]', '2020-08-14 08:39:18', '2020-08-14 08:39:18', NULL, NULL, '[]', '[]'),
(839892, 31668095, 96815475, 96815475, 89904399, 53683014, 'projection-du-film-oulinine-imdanate-et-decouverte-de-ce-jeu-touareg', '{\"fr\":\"Projection du film Oulinine Imdanate et découverte de ce jeu touareg\"}', '{\"fr\":\"Un film réalisé par Michel K. Zongo et produit par « Écouter jouer ».\"}', '{\"fr\":\"Au Mali, les enfants touaregs, pour jouer à Oulinine Imdanate, se distribuent les rôles du chevrier, de ses chèvres, du chacal et du juge. À l’issue de la projection, Françoise Soavi (productrice et conteuse) et Mamko Cissoko (compositeur et virtuose de la Kora) proposent d’initier les enfants à ce jeu.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T13:00:00.000Z\",\"end\":\"2020-10-10T14:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":13,\"max\":99}', '[\"0320475514\",\"bibfives@mairie-lille.fr\"]', '2020-08-14 08:36:45', '2020-08-14 08:36:45', NULL, NULL, '[]', '[]'),
(839887, 41695606, 96815475, 96815475, 89904399, 17654400, 'ppectacle-conte-le-pecheur-et-le-genie', '{\"fr\":\"Ppectacle conté « Le pêcheur et le génie »\"}', '{\"fr\":\"Des contes égyptiens par Chirine El Ansary.\"}', '{\"fr\":\"Un classique des Mille et Une Nuits plein de rebondissements, de personnages inattendus, loin des versions exotiquement édulcorées qu’on vous a trop souvent servi.\\nPour les adultes\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T19:00:00.000Z\",\"end\":\"2020-10-10T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":13,\"max\":99}', '[\"bibjeanlevy@mairie-lille.fr\",\"0320159720\"]', '2020-08-14 08:33:58', '2020-08-14 08:33:58', NULL, NULL, '[]', '[]'),
(839885, 97096485, 96815475, 96815475, 89904399, 17654400, 'lectures-dafrique-en-pyjama', '{\"fr\":\"Lectures d’Afrique en pyjama\"}', '{\"fr\":\"Le très attendu moment des lectures en pyjama, au cours duquel vos enfants, accompagnés de leur doudou, pourront découvrir de magnifiques histoires pour visiter un continent multiple et surprenant.\"}', '{\"fr\":\"Pour les plus jeunes\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T18:00:00.000Z\",\"end\":\"2020-10-10T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":0,\"max\":15}', '[\"bibjeanlevy@mairie-lille.fr\",\"0320159720\"]', '2020-08-14 08:32:16', '2020-08-14 08:32:16', NULL, NULL, '[]', '[]'),
(839884, 47945590, 96815475, 96815475, 89904399, 17654400, 'projection-du-film-soodo-initiation-a-ce-jeu-de-savane-du-burkina-faso', '{\"fr\":\"Projection du film Söodo, initiation à ce jeu de savane du Burkina Faso\"}', '{\"fr\":\"Film produit par l’association « Écouter jouer » et réalisé par Michel K. Zongo.\"}', '{\"fr\":\"Dans la savane du Burkina Faso, pour jouer au Söodo, les enfants s’asseyent autour d’une spirale. Ne pas être Söodo (sorcier ou sorcière) est le but de ce jeu. À l’issue de la projection, Françoise Soavi (productrice et conteuse) et Mamko Cissoko (compositeur et virtuose de la Kora) proposent d’initier les enfants à ce jeu.\\nÀ partir de 6 ans\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:00:00.000Z\",\"end\":\"2020-10-10T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":6,\"max\":99}', '[\"bibjeanlevy@mairie-lille.fr\",\"0320159720\"]', '2020-08-14 08:30:50', '2020-08-14 08:30:50', NULL, NULL, '[]', '[]'),
(839882, 16325394, 96815475, 96815475, 89904399, 17654400, 'afrique-50', '{\"fr\":\"Afrique 50\"}', '{\"fr\":\"Projection-débat du film anticolonialiste de René Vautier, Afrique 50 (17 mn),longtemps soumis à la censure\"}', '{\"fr\":\"Envoyé en Afrique pour un film documentaire, le réalisateur en revient\\npour pousser un cri anticolonialiste inédit pour l’époque. Le film sera alors censuré pendant 40 années. À l’issue de la projection, un temps d’échanges sur le documentaire et le parcours de René Vautier s’ouvrira.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:00:00.000Z\",\"end\":\"2020-10-10T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"bibjeanlevy@mairie-lille.fr\",\"0320159720\"]', '2020-08-14 08:29:27', '2020-08-14 08:29:27', NULL, NULL, '[]', '[]'),
(839878, 97847751, 96815475, 96815475, 89904399, 17654400, 'atelier-conte-plurilingue-par-lassociation-dulala', '{\"fr\":\"Atelier conte plurilingue, par l’association « Dulala »\"}', '{\"fr\":\"Les enfants sont amenés à découvrir un conte dans une autre langue que le français et à deviner de quel conte il s’agit.\"}', '{\"fr\":\"Ils seront ensuite amenés à créer collectivement un « memory » plurilingue du conte, en s’essayant ainsi à la calligraphie dans d’autres systèmes d’écriture. En partenariat avec le festival « D’un pays l’autre ».\\nPour les enfants de 4 à 7 ans\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T15:00:00.000Z\",\"end\":\"2020-10-10T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":4,\"max\":7}', '[\"bibjeanlevy@mairie-lille.fr\",\"0320159720\"]', '2020-08-14 08:27:55', '2020-08-14 08:27:55', NULL, NULL, '[]', '[]'),
(839875, 37706586, 96815475, 96815475, 89904399, 17654400, 'des-mots-dafrique', '{\"fr\":\"Des mots d’Afrique\"}', '{\"fr\":\"Fatou Diome, Alain Mabanckou ou Maïssa Bey, à écouter en live !\"}', '{\"fr\":\"Laissez-vous surprendre par les extraits de textes écrits par des auteurs africains ou évoquant leur continent, lors d’une lecture offerte par les bibliothécaires.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T15:00:00.000Z\",\"end\":\"2020-10-10T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"bibjeanlevy@mairie-lille.fr\",\"0320159720\"]', '2020-08-14 08:26:37', '2020-08-14 08:26:37', NULL, NULL, '[]', '[]'),
(839874, 8621904, 96815475, 96815475, 89904399, 17654400, 'good-morning-africa_744051', '{\"fr\":\"Good morning, Africa !\"}', '{\"fr\":\"Sélection dans notre immense collection des musiques du monde d’artistes du continent africain, de courants, d’époques. L’occasion de réviser ses bases ou de démarrer un voyage\"}', '{}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T12:00:00.000Z\",\"end\":\"2020-10-10T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"bibjeanlevy@mairie-lille.fr\",\"0320159720\"]', '2020-08-14 08:25:35', '2020-08-14 08:25:35', NULL, NULL, '[]', '[]'),
(839873, 82037344, 96815475, 96815475, 89904399, 17654400, 'conference-la-francophonie-en-question-par-didier-niewiadoski', '{\"fr\":\"Conférence « La francophonie en question » par Didier Niewiadoski\"}', '{\"fr\":\"La notion de francophonie est évolutive,  et le continent africain en est l’un des principaux témoins et acteurs.\"}', '{\"fr\":\"Histoire(s), panorama et prospective. En partenariat avec l’Université du Temps Libre.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:30:00.000Z\",\"end\":\"2020-10-10T10:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"bibjeanlevy@mairie-lille.fr\",\"0320159720\"]', '2020-08-14 08:24:43', '2020-08-14 08:24:43', NULL, NULL, '[]', '[]'),
(839865, 61680032, 96815475, 96815475, 89904399, 17654400, 'exposition-afriques-deugenie-baccot', '{\"fr\":\"Exposition «  AfriqueS » d’Eugénie Baccot\"}', '{\"fr\":\"À mi-chemin entre le photoreportage et la photographie d’auteur.\"}', '{\"fr\":\"Plusieurs éléments de reportages en Afrique sont rassemblés, qui\\ndocumentent le quotidien de communautés peu conventionnelles ou alternatives parfois en lien avec des questions identitaires et leurs\\nreprésentations. L’occasion de découvrir un continent créatif et inattendu. Visite, échanges, tout au long de la journée. Rencontre avec la photographe le samedi 10 octobre.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sous réserve\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-05T07:00:00.000Z\",\"end\":\"2020-10-05T17:00:00.000Z\"},{\"begin\":\"2020-10-06T07:00:00.000Z\",\"end\":\"2020-10-06T17:00:00.000Z\"},{\"begin\":\"2020-10-07T07:00:00.000Z\",\"end\":\"2020-10-07T17:00:00.000Z\"},{\"begin\":\"2020-10-08T07:00:00.000Z\",\"end\":\"2020-10-08T17:00:00.000Z\"},{\"begin\":\"2020-10-09T07:00:00.000Z\",\"end\":\"2020-10-09T17:00:00.000Z\"},{\"begin\":\"2020-10-10T07:00:00.000Z\",\"end\":\"2020-10-10T17:00:00.000Z\"},{\"begin\":\"2020-10-11T07:00:00.000Z\",\"end\":\"2020-10-11T17:00:00.000Z\"},{\"begin\":\"2020-10-12T07:00:00.000Z\",\"end\":\"2020-10-12T17:00:00.000Z\"},{\"begin\":\"2020-10-13T07:00:00.000Z\",\"end\":\"2020-10-13T17:00:00.000Z\"},{\"begin\":\"2020-10-14T07:00:00.000Z\",\"end\":\"2020-10-14T17:00:00.000Z\"},{\"begin\":\"2020-10-15T07:00:00.000Z\",\"end\":\"2020-10-15T17:00:00.000Z\"},{\"begin\":\"2020