(838804, 54739839, 96815475, 96815475, 89904399, 32646413, 'lecture-animee-la-grenouille-a-grande-bouche-dapres-lalbum-de-francine-vidal-et-elodie-nouhen', '{\"fr\":\"Lecture animée La grenouille à grande bouche d’après l’album de Francine Vidal et Elodie Nouhen\"}', '{\"fr\":\"La fameuse histoire d’une grenouille trop curieuse mais très maligne. Elle veut tout savoir. Elle croise des animaux et leur demande: « Salut, toi, qui tu es, toi ? »...\"}', '{\"fr\":\"Boîte à conte prêtée par la Médiathèque Départementale du Nord.\\nPour les enfants de 3 à 6 ans\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-07T14:00:00.000Z\",\"end\":\"2020-10-07T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":3,\"max\":6}', '[\"03 20 77 67 92\",\"mediatheque@lemaisnil.fr\"]', '2020-08-11 14:41:43', '2020-08-14 13:42:46', NULL, NULL, '[]', '[]');
