(838769, 56497476, 96815475, 96815475, 89904399, 4128039, 'conference-le-concept-art-une-mise-en-monde-des-jeux-video-de-marine-macq', '{\"fr\":\"Conférence « Le concept Art : une mise en monde des jeux vidéo » de Marine Macq\"}', '{\"fr\":\"Comment les univers de jeux vidéo sont-ils conçus ? Le « concept art » est l’une des premières étapes artistiques de la conception générale d’un jeu vidéo.\"}', '{\"fr\":\"Il s’agit pour les artistes de créer des « artworks », c’est-à-dire des prototypes visuels capables de traduire ce à quoi va ressembler l’univers d’un jeu. En d’autres termes, une phase de design dont les œuvres numériques ou traditionnelles se devront d’exprimer l’essence du projet. Cette conférence vise à faire découvrir cette étape clé de la création.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T13:00:00.000Z\",\"end\":\"2020-10-10T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":4,\"max\":99}', '[\"03 59 09 59 09\",\"mediatheque@ville-lamadeleine.fr\"]', '2020-08-11 14:12:07', '2020-08-11 14:12:07', NULL, NULL, '[]', '[]'),
(838763, 31882802, 96815475, 96815475, 89904399, 4128039, 'spectacle-les-ptits-malins-de-la-brousse-de-christel-delpeyroux', '{\"fr\":\"Spectacle « Les P’tits malins de la brousse »  de Christel Delpeyroux\"}', '{\"fr\":\"Tout le monde à l’aéroport et hop ! Avion, taxi-brousse ou bateau : nous voilà arrivés...  « Lebon ! Lippon ! »\"}', '{\"fr\":\"Tout est prêt pour accueillir les héros du jour, les petits malins, les futés de la brousse, ceux qui agacent parfois les grands avec leurs questions incessantes, leurs insolences et qui, souvent, les roulent dans la farine… de manioc !\\nÀ partir de 4 ans.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:30:00.000Z\",\"end\":\"2020-10-10T09:20:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":4,\"max\":99}', '[\"03 59 09 59 09\",\"mediatheque@ville-lamadeleine.fr\"]', '2020-08-11 14:06:51', '2020-08-11 14:06:51', NULL, NULL, '[]', '[]'),
(838760, 80169480, 96815475, 96815475, 89904399, 4128039, 'atelier-character-design', '{\"fr\":\"Atelier \\\"character design\\\"\"}', '{\"fr\":\"atelier « character design » animé par Marine Macq\"}', '{\"fr\":\"Découvrez la manière dont sont créés les personnages de jeux vidéo. L’atelier se déroule en deux temps : les secrets du « character design » (conception de personnages) avec un petit quiz et la réalisation d’une figurine d’argile à l’effigie d’un personnage de jeu vidéo, à peindre à la maison\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:00:00.000Z\",\"end\":\"2020-10-10T10:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":8,\"max\":12}', '[\"03 59 09 59 09\",\"mediatheque@ville-lamadeleine.fr\"]', '2020-08-11 14:03:56', '2020-08-11 14:03:56', NULL, NULL, '[]', '[]'),
(838726, 66724283, 61944322, 61944322, 89904399, 64768116, 'le-marche-fermier-made-in-mel', '{\"fr\":\"Le marché fermier made in MEL\"}', '{\"fr\":\"Venez profiter des stands des producteurs locaux et des nombreuses animations autour de l\'alimentation et de l\'agriculture au \\\"marché fermier made in MEL\\\"\"}', '{\"fr\":\"Rendez-vous au marché fermier \\\" made in MEL\\\" pour découvrir les stands des artisans et agriculteurs locaux, les circuits-courts, les initiatives locales et les magasins de vente directe.  \\n**Fruits et légumes, produits laitiers, pains et pâtisseries, viandes, glaces, boissons, épices, spiruline, plantes ornementales, miel... : vous pourrez faire votre marché auprès de producteurs du territoire !**\\n\\n**De nombreuses animations gratuites seront également proposées à toute la famille.**  \\nAu programme : découverte de l\'apiculture, atelier sur la cuisine végétale et contre le gaspillage, blind test sur les eaux aromatisées, apprentissage de la musique avec des fruits et légumes, fabrication de pain au four à pierre et de moulins à vent... Pour les plus jeunes, un atelier est prévu avec de la pâte à modeler écologique.\"}', '{\"fr\":[\"marché\",\"agriculture\"]}', '{\"fr\":\"Entrée libre. Port du masque sur le marché\"}', '{\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-09-06T08:00:00.000Z\",\"end\":\"2020-09-06T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[]', '2020-08-11 13:40:04', '2020-08-12 07:31:47', NULL, NULL, '[]', '[]'),
(833182, 53773799, 96815475, 96815475, 89904399, 36425869, 'atelier-contes-africains-centre-culturel-dhouplines', '{\"fr\":\"Atelier contes africains - Centre culturel d\'Houplines\"}', '{\"fr\":\"Pénétrez dans l’univers fascinant des contes africains avec Wakirath d’origine béninoise et ses amis musiciens et chanteurs.\"}', '{\"fr\":\"Des histoires passionnantes qui parlent autant de la nature et des animaux\\nque des hommes. Wakirath nourrit ses récits de bruitages et de musique douce et rythmée, alternant entre talking drum, gon et castagnettes.\\nÀ partir de 4 ans.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T18:00:00.000Z\",\"end\":\"2020-10-10T18:45:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":4,\"max\":99}', '[\"0320779049\",\"centre-culturel@ville-houplines.fr\"]', '2020-08-03 14:14:31', '2020-08-03 14:14:31', NULL, NULL, '[]', '[]'),
(833181, 52062264, 96815475, 96815475, 89904399, 36425869, 'atelier-percussions-centre-culturel-dhouplines', '{\"fr\":\"Atelier percussions - Centre culturel d\'Houplines\"}', '{\"fr\":\"Découvertes de différents instruments de musique\"}', '{\"fr\":\"Venez découvrir de nouveaux sons, apprendre à reproduire des rythmes et\\naboutir à une détente musicale.  \\nÀ partir de 8 ans.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:30:00.000Z\",\"end\":\"2020-10-10T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":8,\"max\":99}', '[\"0320779049\",\"centre-culturel@ville-houplines.fr\"]', '2020-08-03 14:13:00', '2020-08-03 14:13:00', NULL, NULL, '[]', '[]'),
(833179, 23627886, 96815475, 96815475, 89904399, 36425869, 'atelier-dinitiation-aux-danses-traditionnelles-centre-culturel-dhouplines', '{\"fr\":\"Atelier d’initiation aux danses traditionnelles - Centre culturel d\'Houplines\"}', '{\"fr\":\"Animé par l’association ASE (Action pour la Santé et l’Éducation)\"}', '{\"fr\":\"Venez tester votre rythme et laissez parler votre créativité.\\nÀ partir de 8 ans.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T15:00:00.000Z\",\"end\":\"2020-10-10T16:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":8,\"max\":99}', '[\"0320779049\",\"centre-culturel@ville-houplines.fr\"]', '2020-08-03 14:11:49', '2020-08-03 14:11:49', NULL, NULL, '[]', '[]'),
(833175, 15914561, 96815475, 96815475, 89904399, 36425869, 'realisation-delephants-en-origami-centre-culturel-dhouplines', '{\"fr\":\"Réalisation d’éléphants en origami- Centre culturel d\'Houplines\"}', '{\"fr\":\"Atelier animé par « Les fées mains créatives ».\"}', '{\"fr\":\"Dès 16h : début de la Nuit !\\nPrésentation d’ouvrages en lien avec l’Afrique. Coloriages pour les enfants\\n\\n16h - 16h30 : réalisation d’éléphants en origami\\nAtelier animé par « Les fées mains créatives ».\\nÀ partir de 4 ans. Les enfants doivent être accompagnés d’un adulte.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T14:00:00.000Z\",\"end\":\"2020-10-10T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":4,\"max\":99}', '[\"0320779049\",\"centre-culturel@ville-houplines.fr\"]', '2020-08-03 14:10:27', '2020-08-03 14:10:27', NULL, NULL, '[]', '[]'),
(833167, 30542243, 96815475, 96815475, 89904399, 40636251, 'defile-et-concours-de-deguisements-sur-le-theme-de-lafrique-mediatheque-dhouplin-ancoisne', '{\"fr\":\"ANNULÉ : Défilé et concours de déguisements sur le thème de l’Afrique - Médiathèque d\'Houplin-Ancoisne\"}', '{\"fr\":\"Petit parcours dans la médiathèque sur le thème de l’Afrique.\"}', '{\"fr\":\"Restauration et concert : reportés\\ndès 11h45 : Restauration sur place avec la friterie « Les Ch’tis BuBu»  \\nTout l’après-midi : Afrique en chanson par Alex et Shane\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T12:30:00.000Z\",\"end\":\"2020-10-10T16:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"f.flament@houplin-ancoisne.fr\",\"0320321496\"]', '2020-08-03 14:01:53', '2020-09-08 15:12:48', NULL, NULL, '[]', '[]'),
