(833145, 88620626, 96815475, 96815475, 89904399, 62369775, 'on-a-slame-sur-la-lune-bibliotheque-dhem', '{\"fr\":\"On a slamé sur la lune - Bibliothèque d\'Hem\"}', '{\"fr\":\"Restitution des ateliers d’écriture offerts par la MEL en partenariat avec le Labo des histoires. Ateliers slam animés par le collectif « On a slamé sur la lune ».\"}', '{}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T15:30:00.000Z\",\"end\":\"2020-10-10T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0230665868\",\"contact@ville-hem.fr\"]', '2020-08-03 13:45:38', '2020-08-03 13:45:38', NULL, NULL, '[]', '[]'),
(833141, 45171193, 96815475, 96815475, 89904399, 46457931, 'braderie-de-livres-bibliotheque-dhellemmes', '{\"fr\":\"Braderie de livres - Bibliothèque d\'Hellemmes\"}', '{\"fr\":\"Animations\"}', '{\"fr\":\"En raison des travaux de la future médiathèque, rendez-vous cette année à\\nl’espace des Acacias. Le programme détaillé est disponible sur le\\nsite internet et la page Facebook\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T08:00:00.000Z\",\"end\":\"2020-10-10T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"http://hellemmes.fr\"]', '2020-08-03 13:42:20', '2020-10-09 07:13:58', NULL, NULL, '[]', '[]'),
(833127, 6648260, 96815475, 96815475, 89904399, 58582733, 'escape-game-panique-dans-la-bibliotheque-bibliotheque-dhaubourdin', '{\"fr\":\"Escape game : panique dans la bibliothèque ! - Bibliothèque d\'Haubourdin\"}', '{\"fr\":\"Mêlant sciences et investigation, cette enquête grandeur nature invite tous les curieux et curieuses, petits et grands, à vivre une expérience originale et ludique.\"}', '{\"fr\":\"Votre mission ? Vous appuyer sur votre sens de l’observation, le travail d’équipe et un esprit critique pour déconstruire une vague d’idées reçues. Mais attention, l’horloge tourne… Il vous faudra aller vite pour achever ce défi !\\nÀ partir de 11 ans.\\nEt aussi...  \\nSamedi 10 octobre  \\n14h - 18h : l’équipe de la bibliothèque vous accueille pour un prêt de livres en continu, mais aussi pour de la convivialité et de la bonne humeur.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T17:00:00.000Z\",\"end\":\"2020-10-10T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":11,\"max\":99}', '[\"0320440292\",\"bibliotheque@haubourdin.fr\"]', '2020-08-03 13:34:03', '2020-08-03 13:34:03', NULL, NULL, '[]', '[]'),
(833124, 99857516, 96815475, 96815475, 89904399, 58582733, 'decouverte-de-la-science-bibliotheque-dhaubourdin', '{\"fr\":\"Découverte de la science - Bibliothèque d\'Haubourdin\"}', '{\"fr\":\"L’équipe de la bibliothèque et les bénévoles de l’association « Les petits débrouillards » vous proposent de réaliser des expériences scientifiques en manipulant les objets du quotidien.\"}', '{\"fr\":\"Et aussi...\\nSamedi 10 octobre\\n14h - 18h : l’équipe de la bibliothèque vous accueille pour un prêt de livres en continu, mais aussi pour de la convivialité et de la bonne humeur.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T12:00:00.000Z\",\"end\":\"2020-10-10T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320440292\",\"bibliotheque@haubourdin.fr\"]', '2020-08-03 13:32:27', '2020-08-03 13:32:27', NULL, NULL, '[]', '[]'),
