(833099, 93210752, 96815475, 96815475, 89904399, 48005910, 'contes-dalgerie-mediatheque-de-fromelles', '{\"fr\":\"Contes d’Algérie - Médiathèque de Fromelles\"}', '{\"fr\":\"Lectures à voix haute de contes algériens qui transporteront les enfants dans des histoires pleines de surprises et de rebondissements\"}', '{\"fr\":\"Lectures à voix haute de contes algériens qui transporteront les enfants dans des histoires pleines de surprises et de rebondissements, avec des sultans, des voleurs, des animaux extraordinaires, des djinns et des princesses.\\nPour les enfants de 4 à 10 ans.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:00:00.000Z\",\"end\":\"2020-10-10T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":4,\"max\":10}', '[\"0320351267\",\"mediatheque@fromelles.fr\"]', '2020-08-03 13:08:29', '2020-08-03 13:08:29', NULL, NULL, '[]', '[]'),
(833097, 89388013, 96815475, 96815475, 89904399, 48005910, 'lalgerie-de-camus-mediatheque-de-fromelles', '{\"fr\":\"L’Algérie de Camus - Médiathèque de Fromelles\"}', '{\"fr\":\"Lectures à voix haute de textes d’Albert Camus évoquant la beauté des paysages d’Algérie.\"}', '{\"fr\":\"Pour ados et adultes.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T16:00:00.000Z\",\"end\":\"2020-10-10T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":12,\"max\":99}', '[\"0320351267\",\"mediatheque@fromelles.fr\"]', '2020-08-03 13:05:50', '2020-08-03 13:05:50', NULL, NULL, '[]', '[]'),
(833095, 64899700, 96815475, 96815475, 89904399, 48005910, 'atelier-de-dessin-mediatheque-de-fromelles', '{\"fr\":\"ANNULE : Atelier de dessin - Médiathèque de Fromelles\"}', '{\"fr\":\"Atelier de dessin avec Nawel Louerrad\"}', '{\"fr\":\"Dans le cadre du festival « Littérature, etc » et en partenariat avec la MEL.\\nÀ l’occasion de la Nuit des bibliothèques et de la 9e édition du festival « Littérature, etc », la dessinatrice Nawel Louerrad imagine un atelier de dessin inspiré de l’OuBaPo (Ouvroir de bande dessinée potentielle). Nawel Louerrad vit et travaille à Alger. Architecte de formation, elle poursuit des études de scénographie, puis des études théâtrales en France. De retour\\nen Algérie en 2009, elle travaille successivement dans le milieu théâtral et la presse écrite avant de publier ses premières bandes dessinées. Les vêpres algériennes évoque la révolte ou le refus au sens le plus intime et le moins guerrier du terme et Regretter l’absence de l’astre est un récit qui réfléchit la blessure d’abandon.\\nÀ partir de 12 ans.\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T12:00:00.000Z\",\"end\":\"2020-10-10T14:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":12,\"max\":99}', '[\"0320351267\",\"mediatheque@fromelles.fr\"]', '2020-08-03 13:04:05', '2020-09-28 12:50:05', NULL, NULL, '[]', '[]'),
