(832007, 18823660, 96815475, 96815475, 89904399, 35276656, 'concert-a-la-mediatheque-de-faches-thumesnil', '{\"fr\":\"ANNULÉ : Concert à la médiathèque de Faches-Thumesnil\"}', '{\"fr\":\"concert de Babacar Mbaye\"}', '{\"fr\":\"Babacar Mbaye est un chanteur sénégalais, joueur de Kora et percussionniste. Fidèle à la tradition des musiciens griots africains, il chante l’espoir, les valeurs du partage, la joie de vivre. Un concert à écouter avec les oreilles, le reste du corps...et le reste du cœur ! Babacar Mbaye sera accompagné d’un percussionniste\\n\\nEt de 10h à 12h et de 14h à 18h : la médiathèque vous réserve des surprises !\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"sur réservation\"}', '{\"filename\":\"177810e0bd5247f293b21392b7f64deb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"177810e0bd5247f293b21392b7f64deb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T17:00:00.000Z\",\"end\":\"2020-10-10T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"0320961244\",\"mediatheque@ville-fachesthumesnil.fr\"]', '2020-07-31 13:41:53', '2020-09-10 11:52:17', NULL, NULL, '[]', '[]'),
