(831686, 35305056, 96815475, 96815475, 89904399, 34342835, 'contes-africians-a-la-mediatheque-dannoeullin', '{\"fr\":\"ANNULÉ : Contes africains à la Médiathèque d\'Annoeullin\"}', '{\"fr\":\"Contes africains revisités par les comédiens de la compagnie « La Belle Histoire »\"}', '{\"fr\":\"La médiathèque d\'Annoeullin en partenariat avec Allennes-les -Marais, Carnin et Provin proppose une soirée contes africains revisités par les comédiens de la compagnie « La Belle Histoire »\"}', '{\"fr\":[\"écriture\",\"ateliers\",\"lecture\",\"nuit des bibliothèques\"]}', '{\"fr\":\"Sur inscriptions, sous réserve\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-09T18:00:00.000Z\",\"end\":\"2020-10-09T19:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 16 15 90\",\"contact@mediatheques-haute-deule.fr\"]', '2020-07-31 08:08:07', '2020-09-08 14:56:27', NULL, NULL, '[]', '[]'),
(831657, 27563822, 96815475, 96815475, 89904399, 60932961, 'atelier-ecriture-et-broderie-mediatheque-la-grand-plage_848421', '{\"fr\":\"Atelier \\\"Ecriture et broderie\\\" - Médiathèque La Grand Plage\"}', '{\"fr\":\"Atelier « Ecriture et broderie » de 2h animés par Rozenn Le Berre et Souleymane Baldé.\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\n### **Atelier \\\"Ecriture et broderie\\\"**\\n\\nAtelier « Ecriture et broderie » de 2h animé par Rozenn Le Berre et Souleymane Baldé.  \\nCet atelier organisé avec la Médiathèque La Grand-Plage se déroulera au centre social de l\'Hommelet.\\n\\nRestition le samedi 10 octobre à partir de 18h.\"}', '{\"fr\":[\"Nuit des bibliothèques\",\"lecture\",null]}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-07T13:00:00.000Z\",\"end\":\"2020-10-07T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":8,\"max\":25}', '[\"hauts-de-france@labodeshistoires.com\",\"acases@ville-roubaix.fr\"]', '2020-07-31 06:50:07', '2020-07-31 06:50:07', NULL, NULL, '[]', '[]'),
(831656, 78479081, 96815475, 96815475, 89904399, 60932961, 'atelier-ecriture-et-broderie-mediatheque-la-grand-plage', '{\"fr\":\"Atelier \\\"Ecriture et broderie\\\" - Médiathèque La Grand Plage\"}', '{\"fr\":\"Atelier « Ecriture et broderie » de 2h animés par Rozenn Le Berre et Souleymane Baldé.\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\n### **Atelier \\\"Ecriture et broderie\\\"**\\n\\nAtelier « Ecriture et broderie » de 2h animé par Rozenn Le Berre et Souleymane Baldé.  \\nCet atelier organisé avec la Médiathèque La Grand-Plage se déroulera au centre social de l\'Hommelet.\\n\\nRestition le samedi 10 octobre à partir de 18h.\"}', '{\"fr\":[\"Nuit des bibliothèques\",\"lecture\",null]}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-09-30T13:00:00.000Z\",\"end\":\"2020-09-30T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":8,\"max\":25}', '[\"hauts-de-france@labodeshistoires.com\",\"acases@ville-roubaix.fr\"]', '2020-07-31 06:49:07', '2020-07-31 06:50:35', NULL, NULL, '[]', '[]'),
(831654, 36342789, 96815475, 96815475, 89904399, 62369775, 'atelier-slam-espace-culturel-franchomme_69067', '{\"fr\":\"Atelier Slam - Espace culturel Franchomme\"}', '{\"fr\":\"Atelier slam de 1h30 animé par le collectif « On a slamé sur la lune ».\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\n### **Atelier slam**\\n\\n« Ecrire le monde, dire le monde, lire le monde.\\nEt l’Afrique, au cœur du cœur du monde.\\nOffrir en partage la littérature, ses marqueuses et ses marqueurs de paroles anciennes, contemporaines, éternelles.\\nPartager des mots, encore et toujours des mots, d’orage, d’amour et d’espérance, des mots qui poussent à l’acte de vivre libre et digne, à hauteur de femmes et d’hommes.\\nDe plein vent.\\nDonner à entendre et ressentir, l’émotion bleu du poème, le feu de la langue, transmettre aux jeunes publics la passion des belles lettres, un désir de beauté qui « écoute aux portes de la justice », toute la puissance de l’imaginaire qui sauve et élève l’âme. Vers elle-même, soleil debout ! »\\nAlbert Morisseau-Leroy animera ces ateliers slam à l’espace culturel Franchomme de Hem.\\n\\nRestition en musique le samedi 10 octobre à 17h30.\"}', '{\"fr\":[\"Nuit des bibliothèques\",\"lecture\",null]}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T13:00:00.000Z\",\"end\":\"2020-10-10T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":9,\"max\":15}', '[\"hauts-de-france@labodeshistoires.com\",\"vianney.motte@ville-hem.fr\"]', '2020-07-31 06:42:34', '2020-07-31 06:42:34', NULL, NULL, '[]', '[]');
