mb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-03T13:00:00.000Z\",\"end\":\"2020-10-03T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":9,\"max\":15}', '[\"hauts-de-france@labodeshistoires.com\",\"vianney.motte@ville-hem.fr\"]', '2020-07-31 06:41:59', '2020-07-31 06:41:59', NULL, NULL, '[]', '[]'),
