(831348, 48346652, 96815475, 96815475, 89904399, 34342835, 'ateliers-nouvelles-de-montaubout-a-la-mediatheque-dannoeullin_320845', '{\"fr\":\"ANNULÉ : Ateliers « Nouvelles de Montaubout »  à la Médiathèque d\'Annoeullin\"}', '{\"fr\":\"L’écrivain Thierry Moral vous invite à entrer dans l’univers de son dernier livre Dernières nouvelles de Montaubout pour créer des scènes de vie quotidienne au sein de la République de Montaubout.\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\n### Ateliers « Nouvelles de Montaubout »\\n\\nL’écrivain Thierry Moral vous invite à entrer dans l’univers de son dernier livre Dernières nouvelles de Montaubout pour créer des scènes de vie quotidienne au sein de la République Indépendante et Autonome de Montaubout, située quelque part en Afrique. Accompagné du « Professeur Tout-de-Biais », incarné par l’auteur lui-même, les participants se verront imaginer et raconter la vie dans ce singulier endroit.\\n\\nRestitution le samedi 10 octobre à 19h.\"}', '{\"fr\":[\"écriture\",\"ateliers\",\"lecture\",\"nuit des bibliothèques\"]}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-09T16:00:00.000Z\",\"end\":\"2020-10-09T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":12,\"max\":16}', '[\"hauts-de-france@labodeshistoires.com\",\"contact@mediatheques-haute-deule.fr\"]', '2020-07-30 14:09:03', '2020-09-08 14:55:13', NULL, NULL, '[]', '[]'),
