\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":12,\"max\":16}', '[\"hauts-de-france@labodeshistoires.com\",\"contact@mediatheques-haute-deule.fr\"]', '2020-07-30 13:59:40', '2020-09-08 14:52:47', NULL, NULL, '[]', '[]'),
(831262, 34358039, 96815475, 96815475, 89904399, 52958872, 'latelier-abecedaire-a-la-bibliotheque-mediatheque-de-fretin_402766', '{\"fr\":\"L’atelier Abécédaire à la bibliothèque - Médiathèque de Fretin\"}', '{\"fr\":\"Création d’un conte oral Africain\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\n### **L\'atelier Abécédaire**\\n\\nNotre intervenant Olivier Pernot proposera pour ce projet la création d’un conte oral Africain. En commençant par dresser un abécédaire des animaux d’Afrique puis des pays du continent, les participants pourront ensuite imaginer une courte histoire à partir d’un animal et d’un pays choisis. Ce conte résumera une situation, un moment, à la manière d’une photographie. Un moyen idéal pour voyager au travers de la fiction.\\n\\nRestition le samedi 10 octobre à 17h\"}', '{\"fr\":[\"Nuit des bibliothèques\",\"lecture\",null]}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T13:00:00.000Z\",\"end\":\"2020-10-10T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":9,\"max\":12}', '[\"hauts-de-france@labodeshistoires.com\",\"service.mediatheque@ville-fretin.fr\"]', '2020-07-30 13:28:27', '2020-07-31 06:27:33', NULL, NULL, '[]', '[]'),
