(831252, 48214102, 96815475, 96815475, 89904399, 52958872, 'latelier-abecedaire-a-la-bibliotheque-a-la-mediatheque-de-fretin', '{\"fr\":\"L’atelier Abécédaire à la bibliothèque - Médiathèque de Fretin\"}', '{\"fr\":\"Création d’un conte oral Africain\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\n### **L\'atelier Abécédaire**\\n\\nNotre intervenant Olivier Pernot proposera pour ce projet la création d’un conte oral Africain. En commençant par dresser un abécédaire des animaux d’Afrique puis des pays du continent, les participants pourront ensuite imaginer une courte histoire à partir d’un animal et d’un pays choisis. Ce conte résumera une situation, un moment, à la manière d’une photographie. Un moyen idéal pour voyager au travers de la fiction.\\n\\nRestition le samedi 10 octobre à 17h\"}', '{\"fr\":[\"Nuit des bibliothèques\",null]}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-09-12T13:00:00.000Z\",\"end\":\"2020-09-12T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":9,\"max\":12}', '[\"hauts-de-france@labodeshistoires.com\",\"service.mediatheque@ville-fretin.fr\"]', '2020-07-30 13:22:07', '2020-07-31 06:29:24', NULL, NULL, '[]', '[]'),
(831244, 7090085, 96815475, 96815475, 89904399, 6991197, 'latelier-monotype-a-la-mediatheque-denglos_933907', '{\"fr\":\"L’atelier Monotype à la Médiathèque d’Englos\"}', '{\"fr\":\"L’objectif est de dessiner et d’inventer l’histoire d’une plante ou d’un animal d’Afrique pour en imprimer, grâce à la technique du monotype, une création unique\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\n### L’atelier Monotype – Médiathèque d’Englos\\n\\n  \\nCes ateliers seront proposés par l’illustratrice Anaïs Ruch, qui vous plongera au cœur de la technique du monotype. L’objectif sera alors de dessiner et d’inventer l’histoire d’une plante ou d’un animal d’Afrique pour en imprimer, grâce à cette technique singulière, une création unique.  \\nRestitution le 10 octobre\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-10T15:00:00.000Z\",\"end\":\"2020-10-10T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":9,\"max\":12}', '[\"hauts-de-france@labodeshistoires.com\",\"mediatheque@englos.fr\"]', '2020-07-30 13:17:44', '2020-07-31 06:30:27', NULL, NULL, '[]', '[]'),
(831242, 72971567, 96815475, 96815475, 89904399, 6991197, 'latelier-monotype-a-la-mediatheque-denglos_243079', '{\"fr\":\"L’atelier Monotype à la Médiathèque d’Englos\"}', '{\"fr\":\"L’objectif est de dessiner et d’inventer l’histoire d’une plante ou d’un animal d’Afrique pour en imprimer, grâce à la technique du monotype, une création unique\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\n### L’atelier Monotype – Médiathèque d’Englos\\n\\n  \\nCes ateliers seront proposés par l’illustratrice Anaïs Ruch, qui vous plongera au cœur de la technique du monotype. L’objectif sera alors de dessiner et d’inventer l’histoire d’une plante ou d’un animal d’Afrique pour en imprimer, grâce à cette technique singulière, une création unique.  \\nRestitution le 10 octobre\"}', '{\"fr\":[\"Nuit des bibliothèques\"]}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-10-07T13:30:00.000Z\",\"end\":\"2020-10-07T15:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":9,\"max\":12}', '[\"hauts-de-france@labodeshistoires.com\",\"mediatheque@englos.fr\"]', '2020-07-30 13:16:46', '2020-07-31 06:31:08', NULL, NULL, '[]', '[]'),
