(831236, 9049145, 96815475, 96815475, 89904399, 6991197, 'latelier-monotype-a-la-mediatheque-denglos_827678', '{\"fr\":\"L’atelier Monotype à la Médiathèque d’Englos\"}', '{\"fr\":\"L’objectif est de dessiner et d’inventer l’histoire d’une plante ou d’un animal d’Afrique pour en imprimer, grâce à la technique du monotype, une création unique\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\nL’atelier Monotype – Médiathèque d’Englos\\nCes ateliers seront proposés par l’illustratrice Anaïs Ruch, qui vous plongera au cœur de la technique du monotype. L’objectif sera alors de dessiner et d’inventer l’histoire d’une plante ou d’un animal d’Afrique pour en imprimer, grâce à cette technique singulière, une création unique.\\nRestitution le 10 octobre\"}', '{}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-09-16T13:30:00.000Z\",\"end\":\"2020-09-16T15:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":9,\"max\":12}', '[\"hauts-de-france@labodeshistoires.com\",\"mediatheque@englos.fr\"]', '2020-07-30 13:15:04', '2020-07-30 13:15:04', NULL, NULL, '[]', '[]'),
(831233, 98962545, 96815475, 96815475, 89904399, 6991197, 'latelier-monotype-a-la-mediatheque-denglos', '{\"fr\":\"L’atelier Monotype à la Médiathèque d’Englos\"}', '{\"fr\":\"L’objectif est de dessiner et d’inventer l’histoire d’une plante ou d’un animal d’Afrique pour en imprimer, grâce à la technique du monotype, une création unique\"}', '{\"fr\":\"En partenariat avec le Labo des Histoires et dans le cadre de la Nuit des bibliothèques, la MEL offre aux médiathèques du territoire métropolitain des ateliers d\'écriture gratuits à destination des jeunes de 8 à 25 ans. A la suite de plusieurs ateliers en médiathèque animés par des professionnels de l\'écriture, les travaux sont restitués lors de la Nuit des bibliothèques sous forme de lectures, expositions et concerts.\\n\\nL’atelier Monotype – Médiathèque d’Englos\\nCes ateliers seront proposés par l’illustratrice Anaïs Ruch, qui vous plongera au cœur de la technique du monotype. L’objectif sera alors de dessiner et d’inventer l’histoire d’une plante ou d’un animal d’Afrique pour en imprimer, grâce à cette technique singulière, une création unique.\\nRestitution le 10 octobre\"}', '{}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"950de3a396df447dbb66364d036e0067.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":344,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"950de3a396df447dbb66364d036e0067.full.image.jpg\",\"size\":{\"height\":344,\"width\":700}},{\"type\":\"thumbnail\",\"filename\":\"950de3a396df447dbb66364d036e0067.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-09-09T13:30:00.000Z\",\"end\":\"2020-09-09T15:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":9,\"max\":12}', '[\"hauts-de-france@labodeshistoires.com\",\"mediatheque@englos.fr\"]', '2020-07-30 13:13:06', '2020-07-30 13:13:48', NULL, NULL, '[]', '[]'),
(810159, 12040383, 21162788, 21162788, 89904399, 50651588, 'biere-experience-lille-2020', '{\"fr\":\"Bière Expérience Lille 2020\"}', '{\"fr\":\"Une découverte ludique et instructive de l\'histoire de la bière durant tout l\'été, à Lille Grand Palais\"}', '{\"fr\":\"Du 3 juillet au 30 août, L’Echappée Bière, Culture B et Lille Grand Palais organisent une grande exposition sur la bière. Au programme, un circuit de découverte de 5000 ans d\'histoire de la bière, articulé autour d\'espaces d\'expositions, d\'expériences ludiques et immersives, d\'ateliers sensoriels, de dégustations et d’un programme d\'animations sur tout l’été.\\n\\n\\\"Bière Expérience\\\" propose un circuit de découverte de la bière, depuis l\'Antiquité (Mésopotamie, Egypte et Gaule), le Moyen-âge (apparition du houblon dans la bière, rôle clé des abbayes), la révolution technique du XIXe siècle (maîtrise des levures par Pasteur, découverte du froid industriel, apparition des brasseries industrielles...), le XXIe siècle (révolution des micro-brasseries, apparition de styles nouveaux, le marketing & l’importance de l’image dans la bière) et ouvre une porte sur ce que sera la bière demain (question du recyclage et réemploi, tourisme brassicole…).\\n\\nVous découvrirez notamment :\\n\\\\- Une houblonnière indoor expérimentale & un champ d\'orge de brasserie ;\\n\\\\- La reproduction et la dégustation de cervoise et bière antique (sikaru) ;\\n\\\\- L’exposition d\'oeuvres d\'art & street art en lien avec la bière\\n\\\\- La reconstitution d’un laboratoire et d\'une brasserie fin XIXe-début XXe, et d’une brasserie contemporaine avec atelier de concassage du malt ;\\n\\\\- Un jacuzzi aux huiles essentielles de houblon (prévoir maillot et serviette de bain !) ;\\n\\\\- Un beer wall géant ;\\n\\\\- De nombreux films d\'archives ;\\n\\\\- Un Escape Game brassicole ;\\n\\\\- Un parcours destiné aux enfants\\n\\nLe parcours se clôt par une dégustation dans l\'espace bar géré par les équipes de La Capsule, bar à bières artisanales lillois incontournable à Lille. Un espace boutique est aussi proposé. Enfin, Bière Expérience transformera Lille Grand Palais en un véritable lieu de vie et de rendez-vous tout au long de l’été à travers un programme événementiel et des soirées thématiques (semaine spéciale pour la Fête Nationale belge, nocturnes, etc.)\"}', '{\"fr\":[\"tourisme brassicole\",\"bière\",\"lille grand palais\",\"culture b\",\"echappée bière\",\"MEL\"]}', '{\"fr\":\"Entrée payante et visites payantes - gratuit pour les enfants // tarifs préférentiels en achetant vos billets en prévente en ligne\"}', '{\"filename\":\"08bb1900bfe9487d9305426ad4f29b84.base.image.jpg\",\"size\":{\"width\":700,\"height\":983},\"variants\":[{\"filename\":\"08bb1900bfe9487d9305426ad4f29b84.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":520,\"height\":730}},{\"filename\":\"08bb1900bfe9487d9305426ad4f29b84.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-07-03T12:00:00.000Z\",\"end\":\"2020-07-03T19:00:00.000Z\"},{\"begin\":\"2020-07-04T09:00:00.000Z\",\"end\":\"2020-07-04T19:00:00.000Z\"},{\"begin\":\"2020-07-05T09:00:00.000Z\",\"end\":\"2020-07-05T17:00:00.000Z\"},{\"begin\":\"2020-07-07T09:00:00.000Z\",\"end\":\"2020-07-07T17:00:00.000Z\"},{\"begin\":\"2020-07-08T09:00:00.000Z\",\"end\":\"2020-07-08T17:00:00.000Z\"},{\"begin\":\"2020-07-09T09:00:00.000Z\",\"end\":\"2020-07-09T19:00:00.000Z\"},{\"begin\":\"2020-07-10T09:00:00.000Z\",\"end\":\"2020-07-10T19:00:00.000Z\"},{\"begin\":\"2020-07-11T09:00:00.000Z\",\"end\":\"2020-07-11T19:00:00.000Z\"},{\"begin\":\"2020-07-12T09:00:00.000Z\",\"end\":\"2020-07-12T17:00:00.000Z\"},{\"begin\":\"2020-07-14T09:00:00.000Z\",\"end\":\"2020-07-14T17:00:00.000Z\"},{\"begin\":\"2020-07-15T09:00:00.000Z\",\"end\":\"2020-07-15T17:00:00.000Z\"},{\"begin\":\"2020-07-16T09:00:00.000Z\",\"end\":\"2020-07-16T19:00:00.000Z\"},{\"begin\":\"2020-07-17T09:00:00.0