(709252, 68273129, 34181411, 34181411, 89904399, 78093466, 'signature-de-la-charte-metropolitaine-pour-lemploi-des-seniors', '{\"fr\":\"Signature de la charte métropolitaine pour l\'emploi des séniors\"}', '{\"fr\":\"L\'emploi des séniors : un enjeu à la fois économique et social\"}', '{\"fr\":\"Ce temps fort ouvrira la campagne de signature de la charte métropolitaine pour l\'emploi des séniors par les entreprises. Au programme : signature, témoignages d\'entreprises et échanges autour de l\'enjeu de l\'emploi des séniors sur notre territoire.\"}', '{}', '{\"fr\":\"sur inscriptions\"}', '{\"filename\":\"af98c82342df457dabd1d47c482f3e90.base.image.jpg\",\"size\":{\"width\":700,\"height\":468},\"variants\":[{\"filename\":\"af98c82342df457dabd1d47c482f3e90.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":5140,\"height\":3433}},{\"filename\":\"af98c82342df457dabd1d47c482f3e90.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-12-10T16:45:00.000Z\",\"end\":\"2019-12-10T21:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"contact@competencesetemplois.org\"]', '2019-12-03 15:11:44', '2019-12-03 15:11:44', NULL, NULL, '[]', '[]'),
(705696, 87032484, 34181411, 34181411, 89904399, 48372730, 'le-grand-rendez-vous-pour-rester-connecte', '{\"fr\":\"Le grand rendez-vous pour rester connecté\"}', '{\"fr\":\"Les Centres Sociaux Connectés vous invitent à leur événement « Le Grand Rendez-vous pour rester connecté » qui se déroulera le Mardi 10 Décembre de 9h30 à 16h30 au Grand Mix à Tourcoing.\"}', '{\"fr\":\"Au programme ?\\n\\n4 espaces pour rester connecté, découvrir et partager les réussites du projet !\\n\\n**#1 Conférences**\\n\\nAutour d’experts de l’inclusion numérique venez (re)découvrir 3 années d’expérimentation « Centres Sociaux Connectés » autour de différentes thématiques :\\n\\n• 09h30 : Ouverture de la journée\\n\\n• 10h45 – 11h30 : « Centres Sociaux Connectés », les nouveaux tiers-lieux d’inclusion numérique\\n\\n• 14h – 15h : Le numérique, nouveau facteur d’exclusion ?\\n\\n• 15h – 16h : Être parent à l’heure du numérique\\n\\n• 16h : Conclusion de la journée\\n\\n**#2 Formations**\\n\\nVenez vous former aux solutions numériques émergentes de nos ateliers collaboratifs et des projets de nos partenaires. Attention, places limitées et sur inscription.\\n\\nNous proposerons des formations en lien avec certains prototypes représentés dans le village numérique réalisés durant les trois années d’expérimentation.\\n\\n• 11h – 12h : Les Alertes SMS > Une solution numérique pour accompagner les habitants dans leurs démarches administratives\\n\\n• 13h – 14h : HelloAsso > Des outils gratuits pour les associations afin de gagner un temps précieux dans l’organisation de leurs activités\\n\\n• 14h – 15h : La plateforme des animateurs > Un outil pour partager et créer des plannings d’activités pour les centres de loisirs et temps périscolaires\\n\\n• 15h – 16h : GEA > La plateforme de gestion administrative des ateliers « Centres Sociaux Connectés »\\n\\n**#3 - Le village des initiatives numériques**\\n\\nPour vous, un parc d’exposition immersif au cœur des initiatives du projet sera créé, vous y retrouverez l’ensemble les prototypes majeurs du projet des prototypes CSC tels que : la boussole parentale, la plateforme des animateurs, le sac à dos solidaire et numérique, quand les enfants deviennent profs, les alertes SMS, les bornes d\'accès aux droits, Chill, le portail de l’emploi, Check, Co-mains et bien plus encore... expositions, des projections vidéos, de la réalité virtuelle...\\n\\nLe village des initiatives numériques sera également représenté par un grand nombre d\'acteurs de l\'inclusion numérique sur les Hauts de France : les nouvelles dynamiques Centres Sociaux Connectés essaimées en région, la Fédération des Centres Sociaux, le Hub Numérique Inclusif, Simplon, le SIILAB, Emmaüs Connect, l’APF, Quartiers #Douai 3.0, Level-up, Hello-Asso, Reconnect…\\n\\n**#4 - Acculturation : Innovons et créons ensemble**\\n\\nNous vous proposerons d’être acteur de l\'événement avec au programme un FAB LAB géant et des ateliers collaboratifs.\"}', '{}', '{\"fr\":\"Inscription obligatoire\"}', '{\"filename\":\"d3763e530573463faf2b7c4a932b40a9.base.image.jpg\",\"size\":{\"width\":700,\"height\":466},\"variants\":[{\"filename\":\"d3763e530573463faf2b7c4a932b40a9.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":800,\"height\":532}},{\"filename\":\"d3763e530573463faf2b7c4a932b40a9.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"MEL\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-12-10T08:30:00.000Z\",\"end\":\"2019-12-10T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://legrandrdv.csconnectes.eu\"]', '2019-11-25 14:42:01', '2019-11-25 15:39:14', NULL, NULL, '[]', '[]'),
(692124, 97513730, 60654151, 60654151, 89904399, 48558824, 'foot-us-france-serbie', '{\"fr\":\"Foot US - Rencontre France VS Serbie\"}', '{\"fr\":\"Match de qualification aux play-off de la Ligue européenne 2020 !\"}', '{\"fr\":\"Les Français, champions d’Europe 2018, affronteront la Serbie dans le cadre des qualifications aux play-off de la Ligue européenne 2020.\\n\\n### **Samedi 9 novembre**\\n\\n### **à 16 h, au Stadium Lille Métropole**\\n\\n### Match FRANCE - SERBIE\\n\\n### Football Américain\\n\\nAssistez au premier de match l\'équipe de France seniors de Football Américain à domicile depuis leur titre de Champion d\'Europe et leur victoire au World Bowl !\\n\\n\\\\-----------------------\\n\\n**Infos pratiques**\\n\\nAnimations tout au long de l\'après-midi avec des voitures américaines, fanfares, food truck\\n\\nOuverture des portes à 13h et match à 16h\\n\\n\\\\-----------------------\\n\\nDécouvrir  [**le Stadium**](http://www.stadium-lillemetropole.fr/)\"}', '{\"fr\":[\"sport\",\"foot US\",\"play off\",\"ligue européenne 2020\"]}', '{\"fr\":\"Tarif : 7€ / VIP : 95€. Billetterie en ligne\"}', '{\"filename\":\"f02197bba33647e787d7fdbd6b91b644.base.image.jpg\",\"credits\":null,\"size\":{\"height\":472,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"f02197bba33647e787d7fdbd6b91b644.full.image.jpg\",\"size\":{\"height\":509,\"width\":755}},{\"type\":\"thumbnail\",\"filename\":\"f02197bba33647e787d7fdbd6b91b644.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-11-09T12:00:00.000Z\",\"end\":\"2019-11-09T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.weezevent.com/footus-france-vs-serbie-qualification-ligue-europeenne-2020?fbclid=IwAR1TCNAYrOqX0KUhmpxY8bDYidHDaX-5GIDsQXjfkhyh13n7zcnpyh8jNNQ\"]', '2019-10-18 07:54:15', '2019-10-21 08:57:51', NULL, NULL, '[]', '[]'),
(692030, 39758916, 60654151, 60654151, 89904399, 19436497, 'concerts-de-poche-hiver-2020_32897', '{\"fr\":\"Concerts de poche # hiver 2020\"}', '{\"fr\":\"Concert de Michel Moraguès (flûte), David Walter (hautbois), Quatuor Akilone (cordes) à Saint-André-lez-Lille\"}', '{\"fr\":\"Fondés en 2005, les Concerts de Poche sont engagés dans un projet à la fois social et artistique. Ils s\'appuient sur un dispositif inédit d’ateliers et de concerts indissociables. Leur mission contribue au rapprochement des générations et à l’épanouissement de chacun en partageant la musique classique, le jazz et l’opéra avec tous les publics.\\n\\n### **Vendredi 14 février à 20h**\\n\\n### **Concert de**\\n\\n### **Michel MORAGUÈS, flûte**\\n\\n### **David WALTER, hautbois**\\n\\n### **et du Quatuor AKILONE, cordes**\\n\\n### _**Mozart**_\\n\\nChaque concert est précédé de nombreux ateliers musicaux qui s\'adressent à tous les habitants du territoire.\\n\\n**En savoir plus** [**sur le concert**](https://www.concertsdepoche.com/concert-de-poche/david-walter-michel-moragues-quatuor-akilone/)\\n\\n**Retrouvez toutes les dates** [**sur le site des Concerts de Poche**](https://www.concertsdepoche.com/)\"}', '{\"fr\":[\"musique\",\"concert\",\"concert de poche\",\"flûte\",\"hautbois\",\"cordes\",\"Mozart\"]}', '{\"fr\":\"Tarifs: 10€ / 6€ tarif réduit / 1 Crédit-Loisirs\"}', '{\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.base.image.jpg\",\"credits\":null,\"size\":{\"height\":546,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.full.image.jpg\",\"size\":{\"height\":308,\"width\":395}},{\"type\":\"thumbnail\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-02-14T19:00:00.000Z\",\"end\":\"2020-02-14T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"06 76 61 83 91\",\"https://www.concertsdepoche.com/billetterie-en-ligne/\"]', '2019-10-17 16:08:26', '2019-10-17 16:08:26', NULL, NULL, '[]', '[]'),
(692027, 11941605, 60654151, 60654151, 89904399, 30471973, 'concerts-de-poche-hiver-2020_509846', '{\"fr\":\"Concerts de poche # hiver 2020\"}', '{\"fr\":\"Concert de Gaëtane Prouvost (violon) et de Cyril Dupuy (cymbalum) à Ronchin\"}', '{\"fr\":\"Fondés en 2005, les Concerts de Poche sont engagés dans un projet à la fois social et artistique. Ils s\'appuient sur un dispositif inédit d’ateliers et de concerts indissociables. Leur mission contribue au rapprochement des générations et à l’épanouissement de chacun en partageant la musique classique, le jazz et l’opéra avec tous les publics.\\n\\n### **Vendredi 7 février à 20h**\\n\\n### **Concert du duo**\\n\\n### **Gaëtane PROUVOST, violon**\\n\\n### **et Cyril DUPUY, cymbalum**\\n\\n### _**Vents d’Est : Brahms, Sarasate, Bartók, Braye-Weppe...**_\\n\\nChaque concert est précédé de nombreux ateliers musicaux qui s\'adressent à tous les habitants du territoire.\\n\\n**En savoir plus** [**sur le concert**](https://www.concertsdepoche.com/concert-de-poche/gaetane-prouvost-violon-et-cyril-dupuy-cymbalum/)\\n\\n**Retrouvez toutes les dates** [**sur le site des Concerts de Poche**](https://www.concertsdepoche.com/)\"}', '{\"fr\":[\"musique\",\"concert\",\"concert de poche\",\"violon\",\"cymbalum\",\"Brahms\"]}', '{\"fr\":\"Tarifs: 10€ / 6€ tarif réduit / 1 Crédit-Loisirs\"}', '{\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.base.image.jpg\",\"credits\":null,\"size\":{\"height\":546,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.full.image.jpg\",\"size\":{\"height\":308,\"width\":395}},{\"type\":\"thumbnail\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-02-07T19:00:00.000Z\",\"end\":\"2020-02-07T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"06 76 61 83 91\",\"https://www.concertsdepoche.com/billetterie-en-ligne/\"]', '2019-10-17 16:03:14', '2019-10-17 16:03:14', NULL, NULL, '[]', '[]'),
(692024, 89802609, 60654151, 60654151, 89904399, 61846142, 'concerts-de-poche-hiver-2020_229873', '{\"fr\":\"Concerts de poche # hiver 2020\"}', '{\"fr\":\"Concert de l\'ensemble OURANOS (vents) à Houplines\"}', '{\"fr\":\"Fondés en 2005, les Concerts de Poche sont engagés dans un projet à la fois social et artistique. Ils s\'appuient sur un dispositif inédit d’ateliers et de concerts indissociables. Leur mission contribue au rapprochement des générations et à l’épanouissement de chacun en partageant la musique classique, le jazz et l’opéra avec tous les publics.\\n\\n### **Samedi 25 janvier à 20h**\\n\\n### **Concert de l\'Ensemble OURANOS, vents**\\n\\n### **_Ravel, Haydn, Ligeti, De Falla, Dvořák ..._**\\n\\n_Avec la participation d’habitants en lever de rideau_\\n\\nChaque concert est précédé de nombreux ateliers musicaux qui s\'adressent à tous les habitants du territoire.\\n\\n**En savoir plus** [**sur le concert**](https://www.concertsdepoche.com/concert-de-poche/ensemble-ouranos-vent-2/)\\n\\n**Retrouvez toutes les dates** [**sur le site des Concerts de Poche**](https://www.concertsdepoche.com/)\"}', '{\"fr\":[\"musique\",\"concert\",\"concert de poche\",\"vents\"]}', '{\"fr\":\"Tarifs: 10€ / 6€ tarif réduit / 1 Crédit-Loisirs\"}', '{\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.base.image.jpg\",\"credits\":null,\"size\":{\"height\":546,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.full.image.jpg\",\"size\":{\"height\":308,\"width\":395}},{\"type\":\"thumbnail\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-01-25T19:00:00.000Z\",\"end\":\"2020-01-25T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"06 76 61 83 91\",\"https://www.concertsdepoche.com/billetterie-en-ligne/\"]', '2019-10-17 15:56:34', '2019-10-17 15:56:34', NULL, NULL, '[]', '[]