(692021, 15168830, 60654151, 60654151, 89904399, 33479698, 'concerts-de-poche-hiver-2020', '{\"fr\":\"Concerts de poche # hiver 2020\"}', '{\"fr\":\"Concert d\'Adam Laloum (piano) à Wambrechies\"}', '{\"fr\":\"Fondés en 2005, les Concerts de Poche sont engagés dans un projet à la fois social et artistique. Ils s\'appuient sur un dispositif inédit d’ateliers et de concerts indissociables. Leur mission contribue au rapprochement des générations et à l’épanouissement de chacun en partageant la musique classique, le jazz et l’opéra avec tous les publics.\\n\\n### **Vendredi 24 janvier à 20h**\\n\\n### Concert d\'Adam Laloum, piano\\n\\n### _Schubert_\\n\\nChaque concert est précédé de nombreux ateliers musicaux qui s\'adressent à tous les habitants du territoire.\\n\\n**En savoir plus** [**sur le concert**](https://www.concertsdepoche.com/concert-de-poche/adam-laloum-piano-3/)\\n\\n**Retrouvez toutes les dates** [**sur le site des Concerts de Poche**](https://www.concertsdepoche.com/)\"}', '{\"fr\":[\"musique\",\"concert\",\"concert de poche\",\"piano\",\"Schubert\"]}', '{\"fr\":\"Tarifs: 10€ / 6€ tarif réduit / 1 Crédit-Loisirs\"}', '{\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.base.image.jpg\",\"credits\":null,\"size\":{\"height\":546,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.full.image.jpg\",\"size\":{\"height\":308,\"width\":395}},{\"type\":\"thumbnail\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2020-01-24T19:00:00.000Z\",\"end\":\"2020-01-24T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"06 76 61 83 91\",\"https://www.concertsdepoche.com/billetterie-en-ligne/\"]', '2019-10-17 15:50:26', '2019-10-17 15:50:26', NULL, NULL, '[]', '[]'),
(692018, 59093383, 60654151, 60654151, 89904399, 83776800, 'concerts-de-poche-automne-hiver-2019_691398', '{\"fr\":\"Concerts de poche # automne-hiver 2019\"}', '{\"fr\":\"Concert du trio Miguel Da Silva (alto), Xavier Phillips (violoncelle), François-Frédéric Guy (piano) à Hantay\"}', '{\"fr\":\"Fondés en 2005, les Concerts de Poche sont engagés dans un projet à la fois social et artistique. Ils s\'appuient sur un dispositif inédit d’ateliers et de concerts indissociables. Leur mission contribue au rapprochement des générations et à l’épanouissement de chacun en partageant la musique classique, le jazz et l’opéra avec tous les publics.\\n\\n### **Mardi 17 décembre à 20h**\\n\\n### Concert du trio\\n\\n### Miguel DA SILVA, alto\\n\\n### Xavier PHILLIPS, violoncelle\\n\\n### François-Frédéric GUY, piano\\n\\n### _Brahms : trio, sonates_\\n\\nChaque concert est précédé de nombreux ateliers musicaux qui s\'adressent à tous les habitants du territoire.\\n\\n**En savoir plus** [**sur le concert**](https://www.concertsdepoche.com/concert-de-poche/miguel-da-silva-alto-xavier-phillips-violoncelle-francois-frederic-guy-piano/)\\n\\n**Retrouvez toutes les dates** [**sur le site des Concerts de Poche**](https://www.concertsdepoche.com/)\"}', '{\"fr\":[\"musique\",\"concert\",\"concert de poche\",\"alto\",\"violoncelle\",\"piano\",\"Brahms\"]}', '{\"fr\":\"Tarifs: 10€ / 6€ tarif réduit / 1 Crédit-Loisirs\"}', '{\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.base.image.jpg\",\"credits\":null,\"size\":{\"height\":546,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.full.image.jpg\",\"size\":{\"height\":308,\"width\":395}},{\"type\":\"thumbnail\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-12-17T19:00:00.000Z\",\"end\":\"2019-12-17T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"06 76 61 83 91\",\"https://www.concertsdepoche.com/billetterie-en-ligne/\"]', '2019-10-17 15:44:20', '2019-10-17 15:44:20', NULL, NULL, '[]', '[]'),
(692010, 83798491, 60654151, 60654151, 89904399, 52381295, 'concerts-de-poche-automne-hiver-2019_143267', '{\"fr\":\"Concerts de poche # automne-hiver 2019\"}', '{\"fr\":\"Concert du Quatuor ZAHIR (saxophones) à La Madeleine\"}', '{\"fr\":\"Fondés en 2005, les Concerts de Poche sont engagés dans un projet à la fois social et artistique. Ils s\'appuient sur un dispositif inédit d’ateliers et de concerts indissociables. Leur mission contribue au rapprochement des générations et à l’épanouissement de chacun en partageant la musique classique, le jazz et l’opéra avec tous les publics.\\n\\n### **Dimanche 24 novembre à 16h**\\n\\n### Concert du **Quatuor ZAHIR**, saxophones\\n\\n### _Dvořák, Gershwin, Barber, Bernstein_\\n\\nChaque concert est précédé de nombreux ateliers musicaux qui s\'adressent à tous les habitants du territoire.\\n\\n**En savoir plus** [**sur le concert**](https://www.concertsdepoche.com/concert-de-poche/quatuor-zahir-saxophones-3/)\\n\\n**Retrouvez toutes les dates** [**sur le site des Concerts de Poche**](https://www.concertsdepoche.com/)\"}', '{\"fr\":[\"musique\",\"concert\",\"concert de poche\"]}', '{\"fr\":\"Tarifs: 10€ / 6€ tarif réduit / 1 Crédit-Loisirs\"}', '{\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.base.image.jpg\",\"credits\":null,\"size\":{\"height\":546,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.full.image.jpg\",\"size\":{\"height\":308,\"width\":395}},{\"type\":\"thumbnail\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-11-24T15:00:00.000Z\",\"end\":\"2019-11-24T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"06 76 61 83 91\",\"https://www.concertsdepoche.com/billetterie-en-ligne/\"]', '2019-10-17 15:25:48', '2019-10-17 15:28:15', NULL, NULL, '[]', '[]'),
(692006, 44749407, 60654151, 60654151, 89904399, 30471973, 'concerts-de-poche-automne-hiver-2019', '{\"fr\":\"Concerts de poche # automne-hiver 2019\"}', '{\"fr\":\"Concert d\'Augustin Dumay (violon) et Jean-François Heisser (piano) à Ronchin\"}', '{\"fr\":\"Fondés en 2005, les Concerts de Poche sont engagés dans un projet à la fois social et artistique. Ils s\'appuient sur un dispositif inédit d’ateliers et de concerts indissociables. Leur mission contribue au rapprochement des générations et à l’épanouissement de chacun en partageant la musique classique, le jazz et l’opéra avec tous les publics.\\n\\n### **Vendredi 18 octobre à 20h**\\n\\n### Concert d\'Augustin DUMAY, violon\\n\\n### et Jean-François HEISSER, piano\\n\\n### Mozart ...\\n\\nChaque concert est précédé de nombreux ateliers musicaux qui s\'adressent à tous les habitants du territoire.\\n\\nEn savoir plus [sur le concert](https://www.concertsdepoche.com/concert-de-poche/augustin-dumay-violon-jean-francois-heisser-piano/)\\n\\nRetrouvez toutes les dates sur [le site des Concerts de Poche](https://www.concertsdepoche.com/concerts-a-venir/)\"}', '{\"fr\":[\"musique\",\"concert\",\"concert de poche\",\"Mozart\",\"piano\",\"violon\"]}', '{\"fr\":\"Tarifs: 10€ / 6€ tarif réduit / 1 Crédit-Loisirs\"}', '{\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.base.image.jpg\",\"credits\":null,\"size\":{\"height\":546,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.full.image.jpg\",\"size\":{\"height\":308,\"width\":395}},{\"type\":\"thumbnail\",\"filename\":\"5372c0e68b214c67a0e0f324b1706e9d.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-18T18:00:00.000Z\",\"end\":\"2019-10-18T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"06 76 61 83 91\",\"https://www.concertsdepoche.com/billetterie-en-ligne/\"]', '2019-10-17 15:15:11', '2019-10-17 15:32:53',