(690932, 16782275, 60654151, 60654151, 89904399, 56396637, 'laero-fete-ses-30-ans', '{\"fr\":\"L\'aéro fête ses 30 ans\"}', '{\"fr\":\"30 heures de musique en continu pour fêter les 30 ans de l\'Aéronef !\"}', '{\"fr\":\"Performance d’artistes plasticiens, restaurant scénique bistronomique, expositions, concerts en pagaille … préparez-vous !\\n\\n\\\\------------------------------------------------------------------\\n\\n### **Vendredi 18 octobre**\\n\\n**Entrée payante. 19h > 9h**\\n\\nAutomatic - Wooze - The Slow Readers Club - Life - The YD - Brandt Brauer Frick - Tshegue - French 79 dj set - Rubin Steiner - Mathieu Harlaut (Chamberlain) - Ordalie\\n\\n**Silent Disco !**\\n\\nDeux dj mixent simultanément et un petit bouton pour passer d’un mix à l’autre. Il n’y a plus qu’à choisir !\\n\\n*   21h20 : Afrojaws / 2 Girls 1 Beat\\n*   23h : Stuntman Dave / Blondin\\n\\n### **Samedi 19 octobre**\\n\\n**En entrée libre. 10h > 17h30**\\n\\n*   Compagnie DUT : Manège Fitness – Top Prénom\\n*   Stand de jeux flamands\\n*   Atelier 0 déchet\\n*   Stand d’échange de CD et de vyniles.\\n*   Sieste musicale : Le Comte\\n\\n**Entrée payante. 17h30 > 02h**\\n\\nMario Batkovi - YellowStraps - Namdose - Jonathan Jeremiah - Flèche Love - Le 77 - La Fine Équipe - ZOMBIE ZOMBIE - Nihiloxica – Silent Disco !\\n\\n**Silent Disco !**\\n\\nDeux dj mixent simultanément et un petit bouton pour passer d’un mix à l’autre. Il n’y a plus qu’à choisir !\\n\\n*   00h40 : Sylvie Cious / Venga Venga\\n*   17h30 : Not Cat / Kubebe\\n*   19h10 : Prieur de la Marne / Rubin Steiner\\n*   20h50 : A Boy Named Sue / Dj Wallace\\n\\n\\\\-------------------------------------------------------------------\\n\\n### Billetterie\\n\\n**Pass 2 jours** – Tarifs : 37€ / 25€ abonné.e\\n\\n[http://bit.ly/30heures2jours](http://bit.ly/30heures2jours)\\n\\n**Pass Vendredi** – Tarifs : 21€ / 14€ abonné.e\\n\\n[http://bit.ly/30heuresvendredi](http://bit.ly/30heuresvendredi)\\n\\n**Pass Samedi** – Tarifs : 21€ / 14€ abonné.e\\n\\n[http://bit.ly/30heuressamedi](http://bit.ly/30heuressamedi)\\n\\n\\\\-------------------------------------------------------------------\\n\\n### Toutes les infos [sur le site de l\'Aéronef](https://aeronef.fr/agenda/30-ans-30-heures18-octobre-2019/)\"}', '{\"fr\":[\"musique\",\"concert\",\"aéronef\",\"disco\"]}', '{\"fr\":\"Billetterie en ligne\"}', '{\"filename\":\"4b3c5e8630a64919be0b8a7e8921b62f.base.image.jpg\",\"credits\":null,\"size\":{\"height\":278,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"4b3c5e8630a64919be0b8a7e8921b62f.full.image.jpg\",\"size\":{\"height\":301,\"width\":758}},{\"type\":\"thumbnail\",\"filename\":\"4b3c5e8630a64919be0b8a7e8921b62f.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-18T17:00:00.000Z\",\"end\":\"2019-10-19T04:00:00.000Z\"},{\"begin\":\"2019-10-19T08:00:00.000Z\",\"end\":\"2019-10-19T15:30:00.000Z\"},{\"begin\":\"2019-10-19T15:30:00.000Z\",\"end\":\"2019-10-20T00:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://billetterie.aeronef.fr/\"]', '2019-10-15 09:58:33', '2019-10-15 16:12:46', NULL, NULL, '[]', '[]'),
(690711, 70245292, 60654151, 60654151, 89904399, 78917675, 'course-du-chicon', '{\"fr\":\"Course du Chicon\"}', '{\"fr\":\"A l\'occasion de la Course du Chicon, tentez une course ou une marche !\"}', '{\"fr\":\"### **Course du Chicon**\\n\\n### **dimanche 27 octobre à Baisieux**\\n\\nÉvènement organisé par l\'association \\\"Courir à Baisieux\\\". Chaussez vos baskets et participez à une course ou une marche !\\n\\n\\\\-------------------------------------------------------\\n\\n### **Les courses \\\"adulte\\\"**\\n\\n3 distances sont proposées : **15 km - 10 km et 5 km**\\n\\n**Top départ :**\\n\\n*   **à 9h35** pour la Course du 5 km\\n*   **à 9h50** pour la Course du 10 km\\n*   **à 10h05** pour la Course du 15 km\\n\\n### **Les courses \\\"enfant\\\"**\\n\\n4 distances sont proposées : **2 km - 1,5 km - 1 km et 500 m**\\n\\n**Top départ :**\\n\\n*   **à 11h40** pour la Course du Chicon de 2 km\\n*   **à 11h55** pour la Course du Chicon du 1,5 km\\n*   **à 12h05** pour la Galopade du 1 km\\n*   **et à 12h15** pour la Galopade de 1 km\\n\\n### **Marche nordique et marche familiale**\\n\\n3 distances vous sont proposées : **14 km - 9 km et 6 km**\\n\\n**Top départ :**\\n\\n*   **Départ libre à partir de 8h30 jusque 10h30** pour la Marche familiale\\n*   **Départ groupé à 9h** pour la Marche active (marche nordique)\\n\\n\\\\--------------------------------------------\\n\\n### Infos pratiques\\n\\nUn certificat médical peut vous être demandé suivant l\'activité.\\n\\nQuelques \\\" plus \\\" pour donner le maximum de confort aux participants :\\n\\n*   une restauration sur place\\n*   un service de bagagerie\\n*   une garderie pour les enfants jusque 10 ans\\n*   des massages par les kinésithérapeutes de l’école de IKPO Lille. Idéal pour récupérer après l’effort !\\n\\n\\\\-------------------------------------------\\n\\n### Tout savoir sur [la Course du Chicon](http://courirabaisieux.fr/)\"}', '{\"fr\":[\"course\",\"chicon\",\"course enfant\",\"marche\",\"marche nordique\",\"Baisieux\"]}', '{\"fr\":\"Sur inscription. Tarifs : 2,50€ pour les marches ; 3€ pour les Galopades ; 4 € pour les courses du Chicon enfant ; 7 € pour la course du 5 km ; 9 € pour la course du 10 km et 10 € pour la course du 15 km ;\"}', '{\"filename\":\"83fe0212b9e44fed99eb9105813a7355.base.image.jpg\",\"credits\":null,\"size\":{\"height\":700,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"83fe0212b9e44fed99eb9105813a7355.full.image.jpg\",\"size\":{\"height\":225,\"width\":225}},{\"type\":\"thumbnail\",\"filename\":\"83fe0212b9e44fed99eb9105813a7355.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-27T08:00:00.000Z\",\"end\":\"2019-10-27T14:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://courirabaisieux.fr/\",\"info@courseduchicon.fr\",\"06.95.09.47.20\"]', '2019-10-14 16:16:35', '2019-10-14 16:53:36', NULL, NULL, '[]', '[]'),
(689711, 5056950, 60654151, 60654151, 89904399, 77607806, 'festival-pas-cap-hermann-loup-noir', '{\"fr\":\"Festival Pas Cap ? - Hermann Loup Noir\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Mardi 19 novembre à 19h30**\\n\\n### \\\" Hermann Loup Noir \\\"\\n\\n**Conte et musique par Manuel Paris**\\n\\n**Durée : 1h | Dès 8 ans**\\n\\n_Et si le Grand Méchant Loup nous racontait sa version de l’histoire, cela donnerait quoi ?_\\n\\n_Hermann Loup Noir, c’est la rencontre de deux mythes. D’une part, ce loup terrifiant, redouté de tous et qui pourtant n’existe que pour incarner la sauvagerie des hommes. D’autre part, le bluesman errant, traînant sa « musique du diable » le long des routes, un étui de guitare à la main et des complaintes plein la tête. Deux solitaires, deux mal-aimés ; voici l’histoire de l’éternel méchant à qui on laisse enfin la parole._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [billetterie-spectacles.lille.fr](https://billetterie-spectacles.lille.fr/fr-FR/accueil) - 03 20 22 93 66\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"musique\"]}', '{\"fr\":\"Tarif 3,20 € ou 1 crédit-loisirs\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-11-19T18:30:00.000Z\",\"end\":\"2019-11-19T19:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 22 93 66\"]', '2019-10-10 17:35:36', '2019-10-10 17:35:36', NULL, NULL, '[]', '[]'),
(689708, 50521435, 60654151, 60654151, 89904399, 7072417, 'festival-pas-cap-doktorevich', '{\"fr\":\"Festival Pas Cap ? - Doktorevich\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Mardi 19 novembre à 19h**\\n\\n### \\\" Doktorevich \\\"\\n\\n**Théâtre par la Compagnie** **_La Mécanique du fluide_**\\n\\n**Durée : 1h | Dès 12 ans**\\n\\n_Pouls ? Rien ! Saturation ? Ça chute..._\\n\\n_On ne va pas le laisser partir comme ça ! Attention, on s’écarte !_\\n\\n_Au crépuscule de sa vie, le passé du Dr Mikhaïlovitch pèse trop sur sa conscience pour le laisser partir en paix. Défiant tous les protocoles, une urgentiste se lie d’affection pour ce personnage attachant et mélancolique, et entreprend de soigner son âme à défaut de pouvoir le faire pour son corps. S’appuyant sur le carnet de ses mémoires, toute l’équipe médicale va alors s’ingénier à mettre en scène les débuts hésitants et maladroits du tout jeune Mikhaïlovitch, propulsé par la révolution bolchevique comme seul médecin d’un hôpital perdu dans la steppe, alors qu’il n’a jamais touché un patient !_\\n\\nDans ce troisième spectacle, la Mécanique du Fluide s’intéresse à notre (in)capacité à trouver notre place dans le monde, et ouvre une réflexion joyeuse et déjantée sur l’acceptation de nos faiblesses et de l’aide des autres.\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [billetterie.monsenbaroeul.fr](https://billetterie.monsenbaroeul.fr/index-css5-monsenbaroeul-pg1.html) - 03 28 77 44 35\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\"]}', '{\"fr\":\"Tarif plein 8€ / tarif réduit 6€ / tarif -12 ans 4€ / Monsois : 5€ / tarif -12 ans 3€.\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-11-19T18:00:00.000Z\",\"end\":\"2019-11-19T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 28 77 44 35\"]', '2019-10-10 17:27:19', '2019-10-10 17:27:19', NULL, NULL, '[]', '[]'),
(689703, 54577778, 60654151, 60654151, 89904399, 15395390, 'festival-pas-cap-jimmy-et-ses-soeurs', '{\"fr\":\"Festival Pas Cap ? - Jimmy et ses soeurs\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Jeudi 7 et vendredi 8 nov. à 10h et 14h30**\\n\\n### **Samedi 9 novembre à 19h**\\n\\n### **\\\" Jimmy et ses soeurs \\\"**\\n\\n**Théâtre par La Compagnie de Louise**\\n\\n**Durée : 1h | Dès 8 ans**\\n\\nUne réflexion sensible sur la famille et la place des femmes dans un monde régenté par les hommes.\\n\\n_Imaginons… Un monde qui bascule. Où les filles n’ont pas le droit de sortir seules, où, séparées des hommes, les femmes deviennent invisibles. Dans une fratrie de trois filles, l’une d’elle décide alors de devenir, aux yeux des autres, un garçon. Ainsi naît Jimmy Fisher, et la fillette prend vite goût à cette identité qui rime avec liberté._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [legrandbleu.com](http://www.legrandbleu.com/) - [billetterie@legrandbleu.com](mailto:billetterie@legrandbleu.com) - 03 20 09 88 44\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\"]}', '{\"fr\":\"Tarif de 5 à 13€ ou 1 crédit-loisirs\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-11-07T09:00:00.000Z\",\"end\":\"2019-11-07T10:00:00.000Z\"},{\"begin\":\"2019-11-07T13:30:00.000Z\",\"end\":\"2019-11-07T14:30:00.000Z\"},{\"begin\":\"2019-11-08T09:00:00.000Z\",\"end\":\"2019-11-08T10:00:00.000Z\"},{\"begin\":\"2019-11-08T13:30:00.000Z\",\"end\":\"2019-11-08T14:30:00.000Z\"},{\"begin\":\"2019-11-09T18:00:00.000Z\",\"end\":\"2019-11-09T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 09 88 44\"]', '2019-10-10 17:07:31', '2019-10-10 17:15:10', NULL, NULL, '[]', '[]'),
(689702, 72639500, 60654151, 60654151, 89904399, 26884249, 'festival-pas-cap-ces-filles-la', '{\"fr\":\"Festival Pas Cap ? - Ces filles-là\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Vendredi 8 novembre à 20h**\\n\\n### **\\\" Ces filles-là \\\"**\\n\\n**Théâtre sportif et féministe**\\n\\n**Durée : 1h15 | À partir de 13 ans**\\n\\nProposé dans le cadre du mois contre les violences faites aux femmes organisé par la Ville de Lille et lors de la journée professionnelle \\\"C\'est pour bientôt\\\" en collaboration avec le Collectif Jeune Public Hauts-de-France et Le Grand Bleu.\\n\\n_Elles sont 20 qui ont grandi ensemble, toujours dans la même classe depuis la maternelle jusqu’au lycée. Elles forment un groupe uni où l’ordre hiérarchique est clairement défini. Dans les souvenirs communs Scarlett semble toujours avoir été celle d’en bas. Elles ont développé des amitiés éternelles. Sauf que… Un jour, en plein cours, toute la classe reçoit un texto avec une photo de Scarlett, nue. Insultes, jugements, rumeurs… C’est le début d’un match impitoyable au cours duquel un groupe de filles en affronte une seule. À l’époque du cyber, la dimension prise par le harcèlement d’une adolescente transforme radicalement la figure du bouc émissaire. Ce texte est un portrait de l’adolescence et un beau traité féministe._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\nRéservations, info et billetterie au : [resagrandsud@mairie-lille.fr](mailto:resagrandsud@mairie-lille.fr)\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jjeune public\"]}', '{\"fr\":\"Gratuit\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-11-08T19:00:00.000Z\",\"end\":\"2019-11-08T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 88 89 90\"]', '2019-10-10 17:01:10', '2019-10-11 08:11:31', NULL, NULL, '[]', '[]'),
(689696, 94996364, 60654151, 60654151, 89904399, 58238624, 'festival-pas-cap-lartefact-merveilleux', '{\"fr\":\"Festival Pas Cap ? - L\'artefact merveilleux\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Mardi 29 octobre à 15h**\\n\\n### **\\\" L\'artefact merveilleux \\\"**\\n\\n**Magie par Stéphane Damour**\\n\\n**Durée : 1h | Dès 8 ans**\\n\\nPrécédé d\'une visite guidée de l’exposition Lesage, Simon, Crépin. Peintres, spirites et guérisseurs de 14 h à 15 h.\\n\\n_Le Magicien manipule des symboles pour nous enchanter et nous offrir une autre vision du monde. Stéphane Damour est illusionniste et étudie la Magie à travers l’histoire et les civilisations. Dans son spectacle, il emmène petits et grands dans une quête de l’émotion magique. A travers contes et légendes où se mêlent objets mystérieux et artefacts merveilleux, Stéphane révélera le potentiel magique qui sommeille en vous._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [ctomczak@musee-lam.fr](mailto:ctomczak@musee-lam.fr)  \\\\- 03 20 19 68 68\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jeune public\",\"enfant\",\"magie\"]}', '{\"fr\":\"Tarif plein 8€\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-29T14:00:00.000Z\",\"end\":\"2019-10-29T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 19 68 68\"]', '2019-10-10 16:47:12', '2019-10-10 16:47:12', NULL, NULL, '[]', '[]'),
(689675, 92368201, 60654151, 60654151, 89904399, 32731788, 'festival-pas-cap-un-petit-moment-dabsence', '{\"fr\":\"Festival Pas Cap ? - Un petit moment d\'absence\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Jeudi 24 et vendredi 25 octobre**\\n\\n### **à 10h, 14h, 15h30 et 17h**\\n\\n### **\\\" Un petit moment d\'absence \\\"**\\n\\n**Vidéo et musique par la Compagnie** **_De sa couleur préférée_**\\n\\n**Durée : 20 mn | Dès 4 ans**\\n\\n_Une porte qui se ferme, des pas qui s’éloignent. Nous sommes dans une pièce vide de ses occupants. Des meubles, un paravent, un poisson, qui tourne dans son bocal. Et tout se met en mouvement, peu à peu… Un petit moment d’absence, c’est un univers fait d’objets inanimés, un fond sonore, une musique composée en direct, avec de la vidéo et quelques effets spéciaux bricolés, tout prend vie._\\n\\n_Un petit moment doux et apaisant, pour s’absenter du monde extérieur, une parenthèse sonore et visuelle, à partager en famille. Un moment unique d’une vingtaine de minutes, conçu par un plasticien vidéaste Philippe Martini et un musicien Gilles Gauvin…_\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [resa@verriere.org](mailto:resa@verriere.org) - 03 20 54 96 75\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jeune public\",\"enfant\",\"vidéo\"]}', '{\"fr\":\"Tarif plein 8€ / tarif réduit 6€ / tarif -10 ans et groupes d’enfants 3€ ou 1 crédit-loisirs\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-24T08:00:00.000Z\",\"end\":\"2019-10-24T08:30:00.000Z\"},{\"begin\":\"2019-10-24T12:00:00.000Z\",\"end\":\"2019-10-24T12:30:00.000Z\"},{\"begin\":\"2019-10-24T13:30:00.000Z\",\"end\":\"2019-10-24T14:00:00.000Z\"},{\"begin\":\"2019-10-24T15:00:00.000Z\",\"end\":\"2019-10-24T15:30:00.000Z\"},{\"begin\":\"2019-10-25T08:00:00.000Z\",\"end\":\"2019-10-25T08:30:00.000Z\"},{\"begin\":\"2019-10-25T12:00:00.000Z\",\"end\":\"2019-10-25T12:30:00.000Z\"},{\"begin\":\"2019-10-25T13:30:00.000Z\",\"end\":\"2019-10-25T14:00:00.000Z\"},{\"begin\":\"2019-10-25T15:00:00.000Z\",\"end\":\"2019-10-25T15:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 54 96 75\"]', '2019-10-10 16:05:03', '2019-10-10 17:45:31', NULL, NULL, '[]', '[]'),
(689668, 27696424, 60654151, 60654151, 89904399, 70387622, 'festival-pas-cap-lhomme-qui-plantait-des-arbres_106238', '{\"fr\":\"Festival Pas Cap ? - Mangeuse de terre\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Samedi 26 et dimanche 27 octobre**\\n\\n### **à 16h15**\\n\\n### **\\\" Mangeuse de terre \\\"**\\n\\n**Théâtre d’objet par la Compagnie** **de Fil et d\'Os**\\n\\n**Durée : 55 mn | Dès 8 ans**\\n\\n_Le spectateur est invité à prendre place dans le cabinet de consultation de Pilar, une diseuse de bonne-aventure qui, en tirant les cartes, se souvient peu à peu de l’histoire de son village et de cette mystérieuse jeune fille Marcelina. Arrivée un jour sur le pas de la porte d’Enrique, chargée d’une mallette, d’une lettre et d’une bourse dans laquelle claquettent les os de ses parents, morts depuis peu._\\n\\n_Marcelina mange de la terre et ne dort pas. Les os de ses parents dérangent, ils sont trop bruyants. Sans cesse on les déplace, on les cache. Et Marcelina continue de manger de la terre._\\n\\n_Bientôt, on comprend qu’elle est atteinte d’une maladie : la peste de l’insomnie. Et que cette maladie est contagieuse… peu à peu tout le village est contaminé, et à force d’insomnies ses habitants en viennent à oublier le nom, le passé, l’utilité de chaque chose._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [maisonsfolie.lille.fr](https://maisonsfolie.lille.fr/) - 03 20 95 08 82\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jeune public\",\"enfant\",\"objet\"]}', '{\"fr\":\"Tarif plein 5€ / tarif réduit 3€ / tarif -12 ans 2€ ou 1 crédit-loisirs.\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-26T14:15:00.000Z\",\"end\":\"2019-10-26T15:15:00.000Z\"},{\"begin\":\"2019-10-27T15:15:00.000Z\",\"end\":\"2019-10-27T16:15:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 95 08 82\"]', '2019-10-10 15:53:01', '2019-10-10 15:53:43', NULL, NULL, '[]', '[]'),
(689660, 4796032, 60654151, 60654151, 89904399, 70387622, 'festival-pas-cap-lhomme-qui-plantait-des-arbres', '{\"fr\":\"Festival Pas Cap ? - L\'homme qui plantait des arbres\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Jeudi 24 octobre à 20h**\\n\\n### **\\\" L’homme qui plantait des arbres \\\"**\\n\\n**Théâtre d’ombres et de bouts de scotch**\\n\\n**Compagnie** **_Les Chiennes Savantes_**\\n\\n**Durée : 45 mn | Dès 7 ans**\\n\\n_La nouvelle de Jean Giono raconte l’histoire d’un vieux berger, Elzeard Bouffier, qui passa sa vie à planter des arbres pour faire revivre son petit coin de Haute-Provence. La compagnie Les Chiennes Savantes monte ce manifeste pour la planète, conte philosophique et écologiste avant l’heure pour s’adresser aux enfants bientôt responsables d’un monde fragile à préserver._\\n\\n_Accompagné de musique et de bruitage, ce spectacle se veut être une petite graine à planter dans les esprits pour y faire pousser de belles idées._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [maisonsfolie.lille.fr](https://maisonsfolie.lille.fr/) - 03 20 95 08 82\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jeune public\",\"enfant\",\"conte\"]}', '{\"fr\":\"Tarif plein 5€ / tarif réduit 3€ / tarif -12 ans 2€ ou 1 crédit-loisirs.\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-24T18:00:00.000Z\",\"end\":\"2019-10-24T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 95 08 82\"]', '2019-10-10 15:44:59', '2019-10-10 15:44:59', NULL, NULL, '[]', '[]'),
(689655, 17873831, 60654151, 60654151, 89904399, 24021956, 'festival-pas-cap-a-la-derive', '{\"fr\":\"Festival Pas Cap ? - À la dérive\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Mercredi 23 octobre à 16h**\\n\\n### **\\\" À la dérive \\\"**\\n\\n**Conte musical par la Compagnie** **_La Rustine_**\\n\\n**Durée : 45 mn | Dès 3 ans**\\n\\n_Félix n’a jamais vu les vagues, il ne connaît qu’une mer calme et lisse à l’horizon. Lorsqu’il était petit, son grand-père lui racontait l’histoire du grand cachalot, si grand qu’il entraîne la houle à chaque éclat de rire. Aujourd’hui c’est décidé, Félix prend la mer, pour trouver le grand cétacé et percer le mystère des vagues._\\n\\n_Un conte en musique teinté de poésie où un abat-jour devient poulpe, une baignoire, chaloupe de fortune, un drap image l’océan. Embarquez avec Félix à travers les mers, à la dérive !_\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [billetterie@haubourdin.fr](https://www.haubourdin.fr/billetterie/) - 03 20 44 06 74\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jeune public\",\"enfant\",\"conte\"]}', '{\"fr\":\"Tarif plein 8€ / tarif réduit 6€ / tarif -6 ans 4€ ou 1 crédit-loisirs\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-23T14:00:00.000Z\",\"end\":\"2019-10-23T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 44 06 74\"]', '2019-10-10 15:37:06', '2019-10-10 15:45:58', NULL, NULL, '[]', '[]'),
(689648, 69409562, 60654151, 60654151, 89904399, 63647343, 'festival-pas-cap-radio-minus-sound-system', '{\"fr\":\"Festival Pas Cap ? - Radio Minus Sound System\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Mercredi 23 octobre à 10h et 16h**\\n\\n### **\\\" Radio Minus Sound System \\\"**\\n\\n**Musique et dancefloor par la Compagnie Gangpol um Mit**\\n\\n**Durée : 1h | Dès 5 ans**\\n\\n_Webradio atypique pour jeunes aventuriers, Radio Minus a pour vocation de trouver, archiver et diffuser auprès du plus grand nombre les trésors cachés de la création musicale pour et par les enfants : musiques de tous pays, tous styles et toutes époques, de bon comme de mauvais goût._\\n\\n_Animée par une équipe de mélomanes en pointe sur le créneau, collectionnant depuis plus de dix ans les disques improbables glanés au fil des déplacements, cette station collective téléporte également volontiers sa collection dans le cadre de DJ sets vinyliques, appuyés par un dispositif vidéoludique._\\n\\n_Le challenge : faire danser tous les public sur une sélection de morceaux littéralement inouïs : « Ce que vous allez entendre maintenant, jamais vous ne l’avez entendu ! »._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [caveauxpoetes.com](https://www.caveauxpoetes.com/)  \\\\- 03 20 27 70 10\\n\\n\\\\_\\\\_\\\\_\\\\_\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jeune public\",\"enfant\",\"musique\",\"dancefloor\"]}', '{\"fr\":\"Sur réservation. Tarif : 6€ ou 1 crédit-loisirs\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-23T08:00:00.000Z\",\"end\":\"2019-10-23T09:00:00.000Z\"},{\"begin\":\"2019-10-23T14:00:00.000Z\",\"end\":\"2019-10-23T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 27 70 10\"]', '2019-10-10 15:27:39', '2019-10-10 15:27:39', NULL, NULL, '[]', '[]'),
(689451, 34544288, 60654151, 60654151, 89904399, 31680504, 'festival-pas-cap-citron', '{\"fr\":\"Festival Pas Cap ? - Des traces et des formes\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Lundi 21 octobre à 14h**\\n\\n### **\\\" Des traces et des formes \\\"**\\n\\n**Petite Forme Audiovisuelle, ciné-danse**\\n\\n**Durée : 2h | Dès 7 ans**\\n\\n_De la lumière, des sons, des corps et des formes : quand la danse rencontre le cinéma ! Suite à un programme de courts-métrages qui invitent au mouvement, la danseuse Françoise Rognerud proposera un atelier de danse parents-enfants. Un goûter clôturera la séance._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Nombre très limité de places :** 8 enfants et leurs parents.\\n\\n**Info et billetterie :** [cinema@lunivers.org](mailto:cinema@lunivers.org) - 03 20 52 73 48\\n\\n\\\\_\\\\_\\\\_\\\\_\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jeune public\",\"enfant\",\"cinéma\",\"danse\"]}', '{\"fr\":\"Sur réservation. Tarif enfant 2€ / gratuit pour l’accompagnateur.trice\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-21T12:00:00.000Z\",\"end\":\"2019-10-21T14:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 52 73 48\"]', '2019-10-10 11:46:29', '2019-10-10 15:16:40', NULL, NULL, '[]', '[]'),
(689449, 83499922, 60654151, 60654151, 89904399, 70387622, 'festival-pas-cap-bibliocitron_668289', '{\"fr\":\"Festival Pas Cap ? - Citron\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### Samedi 19 octobre & Dimanche 20 octobre à 15h, 16h30 et 18h\\n\\n### **\\\" Citron \\\"**\\n\\n**Marionnettes par la Compagnie Le Bruit des Casseroles**\\n\\n**Durée : 20 mn | Dès 3 ans**\\n\\n_Citron, c’est comme observer une créature avec un télescope. Passant du chiot au chat, de l’oiseau à l’araignée, parfois créature abstraite, il traverse différents comportements, différents états, différentes formes. Ce personnage découvre la vie, son corps, l’espace, puis prend conscience des limites qui le sépare du monde, lui qui est une marionnette posé sur une table._\\n\\n_C\'est le parcours d\'un être à la fois étrange et familier. Curieux et naïf, il met à découvert le connu, laisse apparaître l’inattendu, vit de grandes aventures sur de petits sentiers. On y parle d’humains aussi, eux qui aiment tellement leurs histoires qu’ils en oublient qu’ils les ont inventées._\\n\\n_Avec la force de la simplicité, Citron nous emmène dans un voyage absurde et tendre, partageant une attention à l’infiniment petit, où naît le rire, l’émerveillement._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [maisonsfolie.lille.fr](https://maisonsfolie.lille.fr/) _\\\\-_ 03 20 95 08 82\\n\\n**Accès :** Métro Porte d’Arras ou Bus ligne 14\\n\\n\\\\_\\\\_\\\\_\\\\_\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jeune public\",\"enfant\",\"marionnette\"]}', '{\"fr\":\"Sur réservation. Tarif plein 5€ / tarif réduit 3€ / tarif -12 ans 2€ ou 1 crédit-loisirs.\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-19T13:00:00.000Z\",\"end\":\"2019-10-19T13:30:00.000Z\"},{\"begin\":\"2019-10-19T14:30:00.000Z\",\"end\":\"2019-10-19T15:00:00.000Z\"},{\"begin\":\"2019-10-19T16:00:00.000Z\",\"end\":\"2019-10-19T16:30:00.000Z\"},{\"begin\":\"2019-10-20T13:00:00.000Z\",\"end\":\"2019-10-20T13:30:00.000Z\"},{\"begin\":\"2019-10-20T14:30:00.000Z\",\"end\":\"2019-10-20T15:00:00.000Z\"},{\"begin\":\"2019-10-20T16:00:00.000Z\",\"end\":\"2019-10-20T16:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 95 08 82\"]', '2019-10-10 11:36:27', '2019-10-10 11:39:21', NULL, NULL, '[]', '[]'),
(689443, 85877939, 60654151, 60654151, 89904399, 4191893, 'festival-pas-cap-bibliocitron', '{\"fr\":\"Festival Pas Cap ? - Bibliocitron\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### Vendredi 18 octobre à 14h30 et à 19h30\\n\\n### \\\" Bibliocitron \\\"\\n\\n**Marionnettes et livres découpés par Luc-Vincent Perche**\\n\\n**Durée : 35 mn | Dès 7 ans**\\n\\n_Petite forme quasi-scientifique pour marionnettes et livres découpés._\\n\\n_Il parait que le Bibliotron fonctionne. Deux scientifiques - probablement des amateurs - Hervé Dubois et Michel Dupuis vont tenter de nous en faire la démonstration._\\n\\n_Marchant sur les Traces de Robert Sharley Jr, le fondateur de la Bibliotronique, il semblerait que ces deux chercheurs soient parvenus à donner vie à des livres grâce à une étrange machine._\\n\\n_L’Expérience peut enfin commencer… mais les créatures qui émergent de la machine s’avèrent… comment dire… légèrement incontrôlables._\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Info et billetterie :** [mediation@theatre-aventure.fr](mailto:mediation@theatre-aventure.fr) - 03 20 75 27 01\\n\\n**Accès :** Bus 16 Place St Joseph ou bus 37 Lionderie.\\n\\n\\\\_\\\\_\\\\_\\\\_\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jjeune public\"]}', '{\"fr\":\"Sur réservation. Tarif plein 8€ / tarif réduit 6€ / 3€ ou 1 crédit-loisirs\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-18T12:30:00.000Z\",\"end\":\"2019-10-18T13:00:00.000Z\"},{\"begin\":\"2019-10-18T17:30:00.000Z\",\"end\":\"2019-10-18T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 75 27 01\",\"mediation@theatre-aventure.fr\"]', '2019-10-10 11:17:17', '2019-10-10 17:19:58', NULL, NULL, '[]', '[]');
INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `creator_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at`, `file_key`, `references`, `links`) VALUES
(689435, 65026554, 60654151, 60654151, 89904399, 64034541, 'festival-pas-cap-les-chroniques-dun-pied-heroique_643253', '{\"fr\":\"Festival Pas Cap ? - Les Goûters d\'Alice\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n**Mercredi 13 novembre de 15h à 18h**\\n\\n**\\\" Les Goûters d\'Alice \\\"**\\n\\nCompagnie Diptyque Théâtre\\n\\nThéâtre et atelier | Pour les petites filles entre 7 et 10 ans\\n\\n_Pendant un après-midi, nous invitons des petites filles pour un goûter festif et inventif ! Nous y lirons des passages d’Alice au pays des Merveilles, nous discuterons ensemble de rêves, de cauchemars, de quand on se sent seules et nous jouerons à « si les adultes étaient des animaux… » en mangeant des gâteaux !_\\n\\n_Ce goûter nourrira la création du futur spectacle de la compagnie \\\"Je m’appelle Alice ou la parole des petites filles\\\"_\\n\\n\\\\--------\\n\\n**Infos pratiques**\\n\\nRéservation en ligne via ce formulaire :\\n\\n[Réserver](https://docs.google.com/forms/d/e/1FAIpQLSdiSkvVmpXssrDEAzGhzxdyz-lvpAShFqd8n_TxpQd94r3K1w/viewform)\\n\\n\\\\--------\\n\\n**Contact :** 03 20 04 81 65 (répondeur), au 06 31 98 64 87 ou à [accueil@theatre-massenet.com](mailto:accueil@theatre-massenet.com)\\n\\n\\\\-------\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"atelier\",\"enfant\",\"jeune public\"]}', '{\"fr\":\"Gratuit. Réservation conseillée\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-11-13T14:00:00.000Z\",\"end\":\"2019-11-13T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 04 81 65\",\"accueil@theatre-massenet.com\"]', '2019-10-10 10:55:18', '2019-10-11 08:04:17', NULL, NULL, '[]', '[{\"link\":\"https://docs.google.com/forms/d/e/1FAIpQLSdiSkvVmpXssrDEAzGhzxdyz-lvpAShFqd8n_TxpQd94r3K1w/viewform\",\"data\":{\"url\":\"https://docs.google.com/forms/d/e/1FAIpQLSdiSkvVmpXssrDEAzGhzxdyz-lvpAShFqd8n_TxpQd94r3K1w/viewform?embedded=true\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Les Goûters d\'Alice, cie Diptyque Théâtre | mercredi 13 novembre de 15h à 18h | pour les petites filles entre 7 et 10 ans\",\"provider_name\":\"Google Docs\",\"description\":\"Réservez vos places en ligne ici ! Vous ne recevrez pas de mail de confirmation mais nous avons votre réservation !  Si besoin, vous pouvez nous contacter au 03 20 04 81 65 (répondeur), au 06 31 98 64 87 ou à accueil@theatre-massenet.com\",\"thumbnail_url\":\"https://lh5.googleusercontent.com/UlBQFDtGru4VTpfNdlO5e3G1h35TcG70agLj--9KTAfsvHjFwOnP9eFTLAbvV2BJbjY=w1200-h630-p\",\"thumbnail_width\":1200,\"thumbnail_height\":630,\"height\":2292,\"html\":\"<iframe src=\\\"https://docs.google.com/forms/d/e/1FAIpQLSdiSkvVmpXssrDEAzGhzxdyz-lvpAShFqd8n_TxpQd94r3K1w/viewform?embedded=true&amp;usp=embed_googleplus\\\" style=\\\"border: 0; width: 100%; height: 2292px;\\\" allowfullscreen></iframe>\",\"cache_age\":86400},\"type\":\"oembed\"}]'),
(689418, 57180502, 60654151, 60654151, 89904399, 7301242, 'festival-pas-cap-les-chroniques-dun-pied-heroique', '{\"fr\":\"Festival Pas Cap ? - Les chroniques d\'un pied héroïque\"}', '{\"fr\":\"Festival jeune public & jeune création avec théâtre, danse, arts plastiques, cinéma, marionnettes, théâtre d\'objet, magie et musique\"}', '{\"fr\":\"**5ème édition du festival** **_Pas Cap ?_** **du 15/10 au 19/11**\\n\\nOrganisé par le théâtre Massenet de Lille-Fives, le festival est accessible aux enfants de 3 à 16 ans, mais aussi aux adultes !\\n\\nArpentez 7 villes de la métropole en famille et faites le pari de la jeune création !\\n\\n\\\\--------\\n\\n### **Mardi 15 octobre à 14h et à 20h**\\n\\n### **\\\" Les chroniques d\'un pied héroïque \\\"**\\n\\n**Duo chorégraphique et pédestre par la Compagnie** **_La Ruse_**\\n\\n**Durée : 40 mn | Dès 7 ans**\\n\\n_« Bête comme ses pieds ! » Parce qu’ils sont situés à l’opposé de la tête pensante, les pieds seraient dénués de tout intérêt ? Pourtant ces héros du quotidien nous portent, supportent, transportent. Bien plus que pour d’autres parties du corps, leur potentiel sensoriel et transmetteur devrait naturellement faire se lever les foules. Hélas, notre regard à leur égard est bien moins flatteur. Deux danseuses partagent théories loufoques et partitions dansées, faisant le pari d’une reconquête podalo-pédestre. Du petons aux panards, tous les pieds se sentiront pousser des ailes !_\\n\\n\\\\--------\\n\\n### Infos pratiques\\n\\n**Représentation de 14h complète !**\\n\\n**Inscrivez-vous en liste d\'attente pour la séance de 20h :**\\n\\n[Inscrivez-vous en liste d\'attente pour la séance de 20h.](https://docs.google.com/forms/d/e/1FAIpQLSdKPmtukxTBcwc-uhgfJQAASlu7P1OWHg-AGEJHFgEnqA3y6w/viewform)\\n\\n\\\\-------\\n\\nRéservations, info et billetterie au : 03 20 04 81 65\\n\\n[Retrouvez toute la programmation du festival](https://www.theatre-massenet.com/festival-pas-cap-5/)\"}', '{\"fr\":[\"festival\",\"théâtre\",\"jjeune public\"]}', '{\"fr\":\"Sur réservation. Tarif plein 10€ / tarif réduit 6€ / tarif groupe 3€ ou 1 crédit-loisirs\"}', '{\"filename\":\"a0e9df70581b476ba8939e5721509a9b.base.image.jpg\",\"credits\":null,\"size\":{\"height\":304,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.full.image.jpg\",\"size\":{\"height\":372,\"width\":858}},{\"type\":\"thumbnail\",\"filename\":\"a0e9df70581b476ba8939e5721509a9b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-15T12:00:00.000Z\",\"end\":\"2019-10-15T13:00:00.000Z\"},{\"begin\":\"2019-10-15T18:00:00.000Z\",\"end\":\"2019-10-15T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 04 81 65\"]', '2019-10-10 10:12:16', '2019-10-10 11:41:41', NULL, NULL, '[]', '[{\"link\":\"https://docs.google.com/forms/d/e/1FAIpQLSdKPmtukxTBcwc-uhgfJQAASlu7P1OWHg-AGEJHFgEnqA3y6w/viewform\",\"data\":{\"url\":\"https://docs.google.com/forms/d/e/1FAIpQLSdKPmtukxTBcwc-uhgfJQAASlu7P1OWHg-AGEJHFgEnqA3y6w/viewform?embedded=true\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Les chroniques d\'un pied héroïque, cie La Ruse | mardi 15 octobre 2019 à 20h à la Salle des Fêtes de Fives\",\"provider_name\":\"Google Docs\",\"description\":\"Réservez vos places en ligne ici ! Vous ne recevrez pas de mail de confirmation mais nous avons votre réservation !  Si besoin, vous pouvez nous contacter au 03 20 04 81 65 (répondeur), au 06 31 98 64 87 ou à accueil@theatre-massenet.com  Les places seront à retirer directement en billetterie le soir du spectacle à partir de 19h30 (nous acceptons uniquement les chèques et les espèces).   ATTENTION : ce spectacle se déroule à la Salle des Fêtes de Fives, 91 rue de Lannoy à Lille !\",\"height\":2535,\"html\":\"<iframe src=\\\"https://docs.google.com/forms/d/e/1FAIpQLSdKPmtukxTBcwc-uhgfJQAASlu7P1OWHg-AGEJHFgEnqA3y6w/viewform?embedded=true&amp;usp=embed_googleplus\\\" style=\\\"border: 0; width: 100%; height: 2535px;\\\" allowfullscreen></iframe>\",\"cache_age\":86400},\"type\":\"oembed\"}]'),
(688938, 49005908, 60654151, 60654151, 89904399, 72777047, 'cloture-du-festival-litterature-reproduction-etc', '{\"fr\":\"Clôture du festival Littérature, Reproduction, etc.\"}', '{\"fr\":\"Ce festival thématique, cousu main dans les Hauts-de-France par l\'association \\\" Littérature, etc. \\\", diffuse des littératures concernant tout le monde.\"}', '{\"fr\":\"**Du 18 au 20 octobre,** le festival organisé par l\'association **Littérature, etc.** se termine par un week-end de clôture à l\'Église désacralisée Marie Madeleine à Lille.\\n\\n\\\\-------\\n\\n### **Vendredi 18 octobre**\\n\\n**20h**\\n\\n**Lecture bilingue** **de** **_Body Clock_**, par la poétesse américaine Eleni Sikelianos, accompagnée de sa traductrice Béatrice Trotignon. Suivie d\'une rencontre avec Olivier Brossard, maître de conférences en littérature américaine.\\n\\n**21h30**\\n\\n**Lecture musicale** **de** **_La femme brouillon_**, par son autrice Amandine Dhée et Timothée Couteau, musicien.\\n\\n\\\\-------\\n\\n### **Samedi 19 octobre**\\n\\n**10h30 – 12h30**\\n\\n**Atelier de traduction** animé par Eleni Sikelianos et Béatrice Trotignon, autour de _Body Clock_. En partenariat avec le festival D’un Pays l’autre, organisé par [La Contre Allée](https://www.lacontreallee.com/residences/dun-pays-lautre).\\n\\nSur inscription : [contactlacontreallee@gmail.com](mailto:contactlacontreallee@gmail.com)\\n\\n**10h30 – 12h30**\\n\\n**Reproduction − Illustration** par Julien Martinière, auteur-illustrateur et [l\'association Perluette](http://perluette.xyz/) (atelier pour les 6-12 ans)\\n\\nNombre de places limité. Sur inscription au : 06 79 21 09 27 ou [association.perluette@gmail.com](mailto:association.perluette@gmail.com)\\n\\n**14h**\\n\\n**Présentation de** **_Pas d’enfant, la volonté de ne pas engendrer_** par Anne Gotman , sociologue, directrice de recherche au CNRS et autrice de nombreux ouvrages.\\n\\n**15h**\\n\\n**Lecture de** _**Genèse**_ par son auteur, Emmanuel Adely, suivie d’une conversation avec François Annycke , directeur de l’association [Colères du présent.](https://www.coleresdupresent.com/)\\n\\n**16h30**\\n\\n**Lecture de** **_La robe blanche_** par son autrice Nathalie Léger suivie d’une conversation avec Virginie Leblanc, pour les _Causeurs du lundi ,_ membre de ce collectif de psychanalystes qui croient ferme que l’art et la littérature éclairent leur pratique.\\n\\n**17h30**\\n\\n**Lecture bilingue de** **_Discipline_** par son autrice Dawn Lundy Martin, accompagnée de ses traducteurs Marie de Quatrebarbes et Maël Guesdon. Suivie d\'une conversation animée par Olivier Brossard.\\n\\n**18h45 – 19h45 (en continu)**\\n\\n**Projection de** _**L’Opéra-Mouffe**_ d’Agnès Varda | France | 1958 | fiction-documentaire | 17 min.\\n\\n_L’Opéra-Mouffe_ est le carnet de notes d’une femme enceinte dans le quartier de la Mouffe en 1958 (la rue Mouffetard, à Paris).\\n\\n**¡¡¡ Soirée autodétermination !!!** (Pour public averti)\\n\\n**20h - Performance** Reproduction par RER Q\\n\\n**21h - Concert** de rap érotique du groupe LAW\\n\\n\\\\-------\\n\\n### **Dimanche 20 octobre**\\n\\n**10h30 – 12h30**\\n\\n**Atelier d’écriture explicite spécial ,** reproduction avec le collectif RER Q\\n\\nSur inscription : [contact@litterature-etc.com](mailto:contact@litterature-etc.com)\\n\\n**10h30 ‒ 11h30 ou 11h30 ‒ 12h30**\\n\\n**Atelier Modulographe,** avec les éditions PPAF et l\'association Perluette (pour les 6-12 ans). Nombre de places (très) limité . Sur inscription au : 06 79 21 09 27 ou [association.perluette@gmail.com](mailto:association.perluette@gmail.com)\\n\\n**14h**\\n\\n**Lecture ‒ Rencontre autour de La fabrique des transclasses,** avec Gérard Bras.\\n\\n**15h**\\n\\n**Lecture de** **_La Nuit sauve_**, avec son autrice Hélène Frédérick, accompagnée par le comédien Sylvain Pottiez,. Suivie d’une conversation avec Milady Renoir .\\n\\n**16h30**\\n\\n**Lecture de** _**Là où les chiens aboient par la queue**_ par son autrice Estelle-Sarah Bulle, accompagnée de Lyly Chartiez Mignaw. Suivie d’une conversation avec Milady Renoir .\\n\\n**18h**\\n\\n**Projection** **de** **_800 km de différence / Romance_**\\n\\nde Claire Simon | 2001 | 78 min | France\\n\\n**19h30**\\n\\n**Performance** « Le léger malaise »\\n\\npar Aurélie William Levaux et Baptiste Brunello .\\n\\n_\\\\------------------------------------------------------------------------------------------------------_\\n\\n**Tous les détails de la programmation sur** [le site du festival](http://litterature-etc.com/)\"}', '{\"fr\":[\"festival\",\"littérature\",\"naissance\",\"femme\",\"rencontre\",\"bibliothèque\"]}', '{\"fr\":\"Entrée libre ou sur inscription suivant les évènements\"}', '{\"filename\":\"1cbe2272590445768c3c2026e89a612e.base.image.jpg\",\"credits\":null,\"size\":{\"height\":373,\"width\":701},\"variants\":[{\"type\":\"full\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.full.image.jpg\",\"size\":{\"height\":636,\"width\":1196}},{\"type\":\"thumbnail\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-18T18:00:00.000Z\",\"end\":\"2019-10-18T22:00:00.000Z\"},{\"begin\":\"2019-10-19T08:30:00.000Z\",\"end\":\"2019-10-19T21:00:00.000Z\"},{\"begin\":\"2019-10-20T08:30:00.000Z\",\"end\":\"2019-10-20T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"contact@litterature-etc.com\"]', '2019-10-09 09:31:04', '2019-10-17 14:34:30', NULL, NULL, '[]', '[]'),
(688927, 65922134, 60654151, 60654151, 89904399, 72777047, 'festival-litterature-reproduction-etc_190243', '{\"fr\":\"Festival Littérature, Reproduction, etc.\"}', '{\"fr\":\"Ce festival thématique, cousu main dans les Hauts-de-France par l\'association \\\" Littérature, etc. \\\", diffuse des littératures concernant tout le monde.\"}', '{\"fr\":\"**Du 20 septembre au 20 octobre,** l\'association **Littérature, etc.** propose une programmation insoluble, poétique et internationale conçue pour toutes et tous, faisant la place belle aux performances, lectures, conférences, ateliers, conversations, concerts, installations sonores, films dans une quinzaine de villes de la région. En métropole, retrouvez les évènements à Lille, Roubaix et Faches-Thumesnil.\\n\\n**Vendredi 18 octobre de 14h à 18h**\\n------------------------------------\\n\\n### **La bibliothèque : lieu de reproduction des inégalités ?**\\n\\n**Évènement réservé aux professionnels**, en partenariat avec la MEL\\n\\n\\\\----\\n\\n**14h – 15h**\\n\\n**Présentation : Comment imaginer une bibliothèque non sexiste ?**\\n\\nPar **Sylvie Cromer** , maîtresse de conférences en sociologie, à l’université de Lille, chercheure associée à l’INED, et directrice de l’Institut du Genre.\\n\\nPour cette après-midi destinée aux professionnel·les, elle propose d’une part de revenir sur la genèse des recherches sur la socialisation sexuée et d’autre part de lancer des pistes de réflexion sur les projets de bibliothèques non sexistes.\\n\\n**15h – 16h**\\n\\n**Atelier pour découvrir la grille représentativité de l’association Diveka**\\n\\n**Avec Diariatou Kebe**, présidente de l’association, et autrice du livre _Maman noire et invisible : grossesse, maternité et réflexion d’une maman noire dans un monde blanc_ (éd. la Boîte à Pandore, 2015).\\n\\nCréée en 2016, l’association Diveka propose de mettre en avant, de promouvoir et valoriser les livres faisant la part belle à la diversité.\\n\\nLa grille Diveka permet d’évaluer la représentativité dans les fictions à destination de la jeunesse.\\n\\n**16h30 – 18h**\\n\\n**Atelier Apprentissage de la lecture par arpentage**\\n\\nCette méthode de lecture permet de lire en profondeur et de partager la lecture d’un livre en entier, en un temps limité et collectif.\\n\\n_\\\\----------------_\\n\\n**Pour en savoir plus, consultez** [le site du festival](http://litterature-etc.com/)\"}', '{\"fr\":[\"festival\",\"littérature\",\"naissance\",\"femme\",\"rencontre\",\"bibliothèque\"]}', '{\"fr\":\"Évènement réservé aux professionnels\"}', '{\"filename\":\"1cbe2272590445768c3c2026e89a612e.base.image.jpg\",\"credits\":null,\"size\":{\"height\":373,\"width\":701},\"variants\":[{\"type\":\"full\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.full.image.jpg\",\"size\":{\"height\":636,\"width\":1196}},{\"type\":\"thumbnail\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-18T11:30:00.000Z\",\"end\":\"2019-10-18T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"contact@litterature-etc.com\"]', '2019-10-09 09:25:25', '2019-10-09 09:25:25', NULL, NULL, '[]', '[]'),
(688878, 14497987, 60654151, 60654151, 89904399, 37900576, 'festival-litterature-reproduction-etc_914630', '{\"fr\":\"Festival Littérature, Reproduction, etc.\"}', '{\"fr\":\"Ce festival thématique, cousu main dans les Hauts-de-France par l\'association \\\" Littérature, etc. \\\", diffuse des littératures concernant tout le monde.\"}', '{\"fr\":\"**Du 20 septembre au 20 octobre,** l\'association **Littérature, etc.** propose une programmation insoluble, poétique et internationale conçue pour toutes et tous, faisant la place belle aux performances, lectures, conférences, ateliers, conversations, concerts, installations sonores, films dans une quinzaine de villes de la région.\\n\\nEn métropole, retrouvez les événements à Lille, Roubaix et Faches-Thumesnil.\\n\\n**Samedi 12 octobre de 11h à 13h**\\n----------------------------------\\n\\n### **Médiathèque Jean Levy à Lille**\\n\\n**Atelier – échanges «Donner naissance »**\\n\\nL\'autrice Alana Apfel et le traducteur Adel Tincelin proposent d’engager une discussion qui touchera aux questions d’accompagnement à la naissance, de parentalité queer, des différences entre les cultures de la naissance aux États-Unis, en France et en Grande-Bretagne, des collectifs d’activistes autour de la naissance …\\n\\n_\\\\----------------_\\n\\nÉvènement en partenariat avec La Nuit des Bibliothèques\\n\\n\\\\----------------\\n\\n**Pour en savoir plus, consultez** [le site du festival](http://litterature-etc.com/)\"}', '{\"fr\":[\"festival\",\"littérature\",\"naissance\",\"femme\",\"rencontre\"]}', '{\"fr\":\"Sur inscription. Nombre de places limité.\"}', '{\"filename\":\"1cbe2272590445768c3c2026e89a612e.base.image.jpg\",\"credits\":null,\"size\":{\"height\":373,\"width\":701},\"variants\":[{\"type\":\"full\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.full.image.jpg\",\"size\":{\"height\":636,\"width\":1196}},{\"type\":\"thumbnail\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-12T09:00:00.000Z\",\"end\":\"2019-10-12T11:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"contact@litterature-etc.com\"]', '2019-10-09 08:52:07', '2019-10-09 08:53:53', NULL, NULL, '[]', '[]'),
(688869, 92584501, 60654151, 60654151, 89904399, 7707910, 'festival-litterature-reproduction-etc', '{\"fr\":\"Festival Littérature, Reproduction, etc.\"}', '{\"fr\":\"Ce festival thématique, cousu main dans les Hauts-de-France par l\'association \\\" Littérature, etc. \\\", diffuse des littératures concernant tout le monde.\"}', '{\"fr\":\"**Du 20 septembre au 20 octobre,** l\'association **Littérature, etc.** propose une programmation insoluble, poétique et internationale conçue pour toutes et tous, faisant la place belle aux performances, lectures, conférences, ateliers, conversations, concerts, installations sonores, films dans une quinzaine de villes de la région.\\n\\nEn métropole, retrouvez les événements à Lille, Roubaix et Faches-Thumesnil.\\n\\n**Vendredi 11 octobre à 19h**\\n-----------------------------\\n\\n### **Médiathèque, salle Jacques Brel à Faches-Thumesnil**\\n\\n**Rencontre avec l’autrice Alana Apfel et le traducteur Adel Tincelin autour de** **_Donner Naissance_**\\n\\nLa discussion explorera l’intersection entre travail d’accompagnement à la naissance et justice sociale, démontrant que la naissance a été et reste une question profondément politique et féministe et nous invitera à nous demander qui contrôle ce qui arrive à nos corps sexuels et reproductifs?\\n\\n_\\\\----------------_\\n\\nÉvènement en partenariat avec La Nuit des Bibliothèques\\n\\n\\\\----------------\\n\\n**Pour en savoir plus, consultez** [le site du festival](http://litterature-etc.com/)\"}', '{\"fr\":[\"festival\",\"littérature\",\"naissance\",\"femme\",\"rencontre\"]}', '{}', '{\"filename\":\"1cbe2272590445768c3c2026e89a612e.base.image.jpg\",\"credits\":null,\"size\":{\"height\":373,\"width\":701},\"variants\":[{\"type\":\"full\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.full.image.jpg\",\"size\":{\"height\":636,\"width\":1196}},{\"type\":\"thumbnail\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-11T17:00:00.000Z\",\"end\":\"2019-10-11T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"contact@litterature-etc.com\"]', '2019-10-09 08:40:03', '2019-10-09 08:43:35', NULL, NULL, '[]', '[]'),
(688831, 68728443, 60654151, 60654151, 89904399, 33448838, '248607', '{\"fr\":\"Festival Littérature, Reproduction, etc.\"}', '{\"fr\":\"Ce festival thématique, cousu main dans les Hauts-de-France par l\'association \\\" Littérature, etc. \\\", diffuse des littératures concernant tout le monde.\"}', '{\"fr\":\"**Du 20 septembre au 20 octobre,** l\'association **Littérature, etc.** propose une programmation insoluble, poétique et internationale conçue pour toutes et tous, faisant la place belle aux performances, lectures, conférences, ateliers, conversations, concerts, installations sonores, films dans une quinzaine de villes de la région.\\n\\nEn métropole, retrouvez les événements à Lille, Roubaix et Faches-Thumesnil.\\n\\n**Jeudi 10 octobre à 19h**\\n--------------------------\\n\\n### **Médiathèque La Grand Plage à Roubaix**\\n\\n**Rencontre avec l’autrice Alana Apfel et le traducteur Adel Tincelin autour de** **_Donner Naissance_**\\n\\nLa discussion explorera l’intersection entre travail d’accompagnement à la naissance et justice sociale, démontrant que la naissance a été et reste une question profondément politique et féministe et nous invitera à nous demander qui contrôle ce qui arrive à nos corps sexuels et reproductifs?\\n\\n_\\\\----------------_\\n\\nÉvènement en partenariat avec La Nuit des Bibliothèques\\n\\n\\\\----------------\\n\\n**Pour en savoir plus, consultez** [le site du festival](http://litterature-etc.com/)\"}', '{\"fr\":[\"festival\",\"littérature\",\"femme\",\"naissance\",\"rencontre\"]}', '{}', '{\"filename\":\"1cbe2272590445768c3c2026e89a612e.base.image.jpg\",\"credits\":null,\"size\":{\"height\":373,\"width\":701},\"variants\":[{\"type\":\"full\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.full.image.jpg\",\"size\":{\"height\":636,\"width\":1196}},{\"type\":\"thumbnail\",\"filename\":\"1cbe2272590445768c3c2026e89a612e.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-10T17:00:00.000Z\",\"end\":\"2019-10-10T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"contact@litterature-etc.com\"]', '2019-10-09 08:01:14', '2019-10-09 08:44:48', NULL, NULL, '[]', '[]'),
(684157, 51216581, 60654151, 60654151, 89904399, 82791038, 'marche-aux-tissus_560408', '{\"fr\":\"Marché aux tissus\"}', '{\"fr\":\"Collection Automne-Hiver 2019 au Marché aux Tissus à La Manufacture de Roubaix\"}', '{\"fr\":\"Ils sont tous là ! Coton, lin, tissu africain ou japonais, liberty, dentelle, voilage, organza, soie… Pour de l\'habillement ou de l\'ameublement, pour tous les projets et tous les budgets, on trouve tous les tissus au Marché aux Tissus.\\n\\nAu cœur d’un site industriel, dans une ambiance authentique, retrouvez les stands des négociants en tissus, venus de toute la région et de Belgique pour vous présenter leurs collections Automne-Hiver 2019.\\n\\nTout en côtoyant les métiers à tisser de La Manufacture, retrouvez aussi des librairies textiles, des stands mercerie et une boutique de créateurs.\\n\\nTous les détails [**sur le site de La Manufacture**](http://lamanufacture-roubaix.com/programmation/marche-aux-tissus-hiver/) !\"}', '{\"fr\":[\"LaManuf\",\"marché\",\"tissus\",\"marché aux tissus\",\"La Manufacture\",\"Roubaix\"]}', '{\"fr\":\"Entrée libre, restauration sur place (sandwicherie, crêperie)\"}', '{\"filename\":\"8feecafba6554788ac010a213e29f1c7.base.image.jpg\",\"credits\":\"LaManufacture\",\"size\":{\"height\":391,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"8feecafba6554788ac010a213e29f1c7.full.image.jpg\",\"size\":{\"height\":308,\"width\":552}},{\"type\":\"thumbnail\",\"filename\":\"8feecafba6554788ac010a213e29f1c7.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-11-17T08:00:00.000Z\",\"end\":\"2019-11-17T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 20 98 92\",\"contact@lamanufacture-roubaix.fr\"]', '2019-09-27 15:47:59', '2019-09-27 16:03:24', NULL, NULL, '[]', '[]'),
(683670, 19003469, 60654151, 60654151, 89904399, 71947591, '12e-edition-swing-ton-handicap', '{\"fr\":\"12e édition Swing ton Handicap\"}', '{\"fr\":\"Les 12 et 13 octobre, se tient la nouvelle édition de Swing ton Handicap au Golf Lille Métropole.\"}', '{\"fr\":\"Le golf est un des rares sports où les valides et les non valides jouent avec des règles identiques, quel que soit leur index, leur âge ou leur force.\\n\\nAvec **\\\" Swing ton handicap \\\",** c’est l’occasion de :\\n\\n*   découvrir le golf de façon ludique\\n*   connaître le handigolf dans la Région Hauts-de-France et être sensibilisé au handicap grâce aux rencontre de différents publics\\n*   développer une cohésion d’équipe par la formule de jeu Scramble à 4 en créant des équipes composées d’un handigolfeur, d’un partenaire, d’un étudiant et d’un membre du Golf Lille métropole.\\n\\nVenez partager un moment de convivialité autour de nombreuses animations, jeux, concours avec de nombreux lots à gagner !\\n\\n\\\\------------------------------------------------------------------------------------------------------\\n\\n### **PROGRAMME 2019**\\n\\n**Samedi 12 octobre**\\n\\n**9h :** Scramble à 4, avec un étudiant, un partenaire, un membre du golf et un handigolfeur (sur inscription)\\n\\n**15h :** Initiations gratuites et jeux concours ouverts à tous\\n\\n**17h30 :** Démonstration des handigolfeurs\\n\\n**18h30 :** Remise des prixInitiations et cocktail.\\n\\n**Et dimanche 13 octobre**\\n\\n**8h30 à 12h :** Compétition réservée aux handigolfeurs et membres du club.\\n\\n\\\\------------------------------------------------------------------------------------------------------\\n\\n### **EN SAVOIR PLUS**\\n\\nRetrouvez toutes les informations [sur le site de l\'Université de Lille.](http://swing.univ-lille.fr/)\"}', '{\"fr\":[\"sport\",\"handicap\",\"festivité\",\"rencontre sportive\"]}', '{}', '{\"filename\":\"3b0efc0dc08040a08715daa504cc9a13.base.image.jpg\",\"credits\":\"Université de Lille\",\"size\":{\"height\":335,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"3b0efc0dc08040a08715daa504cc9a13.full.image.jpg\",\"size\":{\"height\":170,\"width\":356}},{\"type\":\"thumbnail\",\"filename\":\"3b0efc0dc08040a08715daa504cc9a13.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-12T07:00:00.000Z\",\"end\":\"2019-10-12T16:30:00.000Z\"},{\"begin\":\"2019-10-13T06:30:00.000Z\",\"end\":\"2019-10-13T10:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"willart.justine@gmail.com\"]', '2019-09-26 15:47:45', '2019-09-26 16:14:34', NULL, NULL, '[]', '[]'),
(677910, 50959696, 60654151, 60654151, 89904399, 5657513, 'fete-de-la-citrouille_685622', '{\"fr\":\"Fête de la citrouille\"}', '{\"fr\":\"Tenue de la 19ème édition de la fête de la citrouille et des coloquintes à Marquillies.\"}', '{\"fr\":\"Venez découvrir les goûts et saveurs d\'une grande variété de courges, de potirons et rencontrer les artisans - producteurs de ce secteur.\\n\\nCette nouvelle édition de la fête de la citrouille est en collaboration avec l\'association l\'Imaginaire de Marie-Groëtte et l\'exploitation agricole La Ferme des Mottes.\\n\\n**Rendez-vous ce samedi 28 et dimanche 29 septembre**\\n\\n**de 10h à 18h**\\n\\n**A la ferme des Mottes de Marquillies**\\n\\n\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\n\\n### **Au programme**\\n\\n*   **marché champêtre**\\n\\nGrand choix de citrouilles, coloquintes, fruits, légumes, produits à base de lait d\'ânesse et bière fermière (brassée sur place).\\n\\n*   **nombreuses animations pour les enfants à partir de 14h**\\n\\nLecture vagabonde, jeux autour du rugby, atelier pain, bus info tri, tracteurs à pédales, maquillages, ferronnier, jeux traditionnels en bois, etc.\\n\\n\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\n\\n### **Plus d\'infos**\\n\\n[**Facebook de l\'association L\'imaginaire de Marie - Gröette**](https://www.facebook.com/imaginairedemariegroette/)\"}', '{\"fr\":[\"fête\",\"marché\",\"citrouille\",\"ferme\",\"animation enfants\"]}', '{\"fr\":\"Entrée libre, gratuit.\"}', '{\"filename\":\"c39857b0393f4708bb629483b8c239af.base.image.jpg\",\"credits\":null,\"size\":{\"height\":267,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"c39857b0393f4708bb629483b8c239af.full.image.jpg\",\"size\":{\"height\":312,\"width\":820}},{\"type\":\"thumbnail\",\"filename\":\"c39857b0393f4708bb629483b8c239af.thumb.image.jpg\",\"size\":{\"height\":201,\"width\":201}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-28T08:00:00.000Z\",\"end\":\"2019-09-28T16:00:00.000Z\"},{\"begin\":\"2019-09-29T08:00:00.000Z\",\"end\":\"2019-09-29T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.facebook.com/imaginairedemariegroette/\",\"imaginairedemariegroette@gmail.com\",\"07 83 77 97 99\"]', '2019-09-16 10:19:56', '2019-09-16 10:41:56', NULL, NULL, '[]', '[]'),
(677246, 52990051, 60654151, 60654151, 89904399, 54864347, 'urban-trail_110494', '{\"fr\":\"Urban Trail\"}', '{\"fr\":\"Tenue de la deuxième édition du trail nocturne, organisé par la ligue Hauts-de-France d’athlétisme. Tentez de battre votre record !\"}', '{\"fr\":\"Courez ou marchez dans un décor traversant les plus beaux monuments de la ville. Le Palais des Beaux arts, l\'Opéra de Lille, la Vieille Bourse, l\'Hospice Comtesse, le Tripostal..., ouverts rien que pour vous !\\n\\n### **Course du 5 km**\\n\\nTentez de battre votre record du monde du 5 km lors d’une course officielle, mesurée et chronométrée avec classement !\\n\\nDépart 18 h – tarif 5 € - inscriptions jusqu’au 4 novembre midi.\\n\\n### **Urban trail du 10 km**\\n\\nParcours non chronométré et sans classement\\n\\nPremière vague réservée aux marcheurs et seconde vague aux coureurs\\n\\nDépart 19 h – tarif 10€ - inscriptions jusqu’au 7 novembre minuit.\\n\\n### **\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-**\\n\\n### **Infos pratiques**\\n\\nDépart et arrivée place de la République à Lille\\n\\nPlus d\'infos sur les courses sur [**urbantraildelille.fr**](urbantraildelille.fr)\"}', '{\"fr\":[\"course\",\"trail\",\"culture\",\"course nocturne\",\"marche\",\"visite insolite\"]}', '{\"fr\":\"Sur inscription, tarifs 5 € et 10 €\"}', '{\"filename\":\"79bd0c9711ac4b35bb34c7c720f6eb44.base.image.jpg\",\"credits\":null,\"size\":{\"height\":669,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"79bd0c9711ac4b35bb34c7c720f6eb44.full.image.jpg\",\"size\":{\"height\":342,\"width\":358}},{\"type\":\"thumbnail\",\"filename\":\"79bd0c9711ac4b35bb34c7c720f6eb44.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-11-09T17:00:00.000Z\",\"end\":\"2019-11-09T23:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://urbantraildelille.fr/\"]', '2019-09-13 16:25:49', '2019-09-13 16:30:58', NULL, NULL, '[]', '[]'),
(676527, 73763043, 60654151, 60654151, 89904399, 76299606, '12e-salon-du-polar-de-la-metropole-lilloise', '{\"fr\":\"12e Salon du polar à Templemars\"}', '{\"fr\":\"Manifestation littéraire consacrée à la littérature policière, le « Salon du polar de Templemars » a lieu chaque année le dernier samedi de septembre.\"}', '{\"fr\":\"Lancé en 2008 par l’écrivain Jean-Marc Demetz et la mairie de Templemars, ce salon du polar est devenu au fil des ans une référence pour les amateurs de roman policier du Nord de la France. 35 auteurs vous attendent pour une journée de dédicaces et de rencontres !\\n\\n\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\n\\n**Particularité de l’édition 2019**\\n\\n1/3 des auteurs invités sont des femmes : Danielle Thiéry, Elena Piacentini, Amélie Antoine, Céline Denjean, Julie Ewa, Christine Desrousseaux, Marie Compagne, Josette Wouters, Isabelle Mariault, Anabelle Read et Virginie Singeot.\\n\\n\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\n\\n### Programme du Salon du Polar\\n\\n**Côté médiathèque** _(rue du Chevalier de la Barre à Templemars)_\\n\\n**Vendredi 27 septembre**\\n\\n**à 18h30**\\n\\nPrésentation de _Remue-Méninges_ à Templemars, roman policier écrit par les élèves de CM2 de l’école Pasteur de Templemars en collaboration avec l’auteure Josette Wouters.\\n\\n**à 20h00**\\n\\nSoirée jeux de société policiers (Cluedo).\\n\\n**.........**\\n\\n**Samedi 28 septembre en journée**\\n\\n**Mini cafés littéraires** (Un café avec…) avec six nouveaux auteurs prometteurs à découvrir.\\n\\n\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\n\\n**Côté Salle Desbonnet** _(4 rue Jules Guesde à Templemars)_\\n\\n**Samedi 28 septembre**\\n\\n**de 10h à 18h**\\n\\n**Journée rencontres et dédicaces avec les 35 auteurs invités :**\\n\\nOlivier Norek, Danièle Thiery, Céline Denjean, Julie Ewa, Jacques Vandroux, Pierre Pouchairet, Paul Colize, Amélie Antoine, Jean-Christophe Macquet, Patrick Amand, Christine Desrousseaux, Patrick-S. Vast, Bob Garcia, Cicéron Angledroit, Marc Masse, Marc Falvo, Marie Compagne, Bruno Vanlan, Philippe Waret, Franck Thilliez, François Lange, Christophe Dubourg, Jean-François Pré, Anabelle Read, Josette Wouters, Ludovic Bertin, Eric Callens, Virginie Singeot-Fabre, Isabelle Mariault, Ian Manook, Thierry Declercq, Elena Piacentini, Jean-Pierre Bocquet, Hervé Hernu et Jean-Marc Demetz.\\n\\n**Exposition de portraits d’auteurs de polars**, oeuvres de Joaquim de Freitas (Hall).\\n\\n**Vente du Calendrier du Noir 2020**, réalisée au profit d’associations caritatives (Hall).\\n\\n**Stand de l’Association 813, amis de la littérature policière** (Hall).\\n\\n\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\n\\n### En savoir plus\\n\\n[Facebook du salon du polar](https://fr-fr.facebook.com/groups/105003179587164/)\\n\\n[polartemplemars@orange.fr](mailto:polartemplemars@orange.fr)\\n\\nMédiathèque de Templemars au 03.20.58.70.82\"}', '{\"fr\":[\"livre\",\"salon\",\"polar\",\"littérature\"]}', '{\"fr\":\"Entrée libre. Gratuit.\"}', '{\"filename\":\"01de5adf43a041299144f5ec73c6cae9.base.image.jpg\",\"credits\":null,\"size\":{\"height\":990,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"01de5adf43a041299144f5ec73c6cae9.full.image.jpg\",\"size\":{\"height\":2976,\"width\":2105}},{\"type\":\"thumbnail\",\"filename\":\"01de5adf43a041299144f5ec73c6cae9.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-27T16:30:00.000Z\",\"end\":\"2019-09-27T22:00:00.000Z\"},{\"begin\":\"2019-09-28T08:00:00.000Z\",\"end\":\"2019-09-28T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/groups/105003179587164/\"]', '2019-09-12 15:57:32', '2019-09-12 16:44:14', NULL, NULL, '[]', '[]'),
(671255, 91924580, 60654151, 60654151, 89904399, 78093466, 'conference-les-eaux-pluviales-un-atout-pour-le-cadre-de-vie', '{\"fr\":\"Conférence : \\\" Les eaux pluviales, un atout pour le cadre de vie \\\"\"}', '{\"fr\":\"Le 1er octobre, la MEL accueillera une conférence-débat sur la gestion durable des eaux pluviales : l’une des solutions pour adapter notre cadre de vie aux enjeux de demain.\"}', '{\"fr\":\"[**L\'association ADOPTA**](https://adopta.fr/) (Association pour le Développement Opérationnel et la Promotion des Techniques Alternatives) en partenariat avec la MEL, adhérente de l\'association, organise :\\n\\nConférence - débat :\\n--------------------\\n\\nLes eaux pluviales,\\n-------------------\\n\\nun atout pour le cadre de vie\\n-----------------------------\\n\\nMardi 1er octobre de 14h à 17h30\\n\\nau siège de la MEL, rue du Ballon à Lille\\n\\n\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\n\\nExemples de projets de requalification, valorisation des espaces verts, biodiversité sur les systèmes de gestion des eaux pluviales, adaptation des plantations aux projets, et bien d\'autres sujets seront abordés lors de la conférence - débat.\\n\\n\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\\\-\\n\\n[**Découvrez le programme en détails**](https://adopta.fr/wp-content/uploads/2019/08/Invitation-conference-eaux-pluviales-MEL-web.pdf)\\n\\nEntrée sur réservation : **inscription possible jusqu\'au lundi 23 septembre 2019 !**\"}', '{\"fr\":[\"eaux pluviales\",\"débat\",\"eau\",\"cadre de vie\",\"conférence\"]}', '{\"fr\":\"Sur inscription\"}', '{\"filename\":\"8b128752ecba46e8b7f56de9af8d4fc3.base.image.jpg\",\"credits\":\"Adopta\",\"size\":{\"height\":273,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"8b128752ecba46e8b7f56de9af8d4fc3.full.image.jpg\",\"size\":{\"height\":408,\"width\":1047}},{\"type\":\"thumbnail\",\"filename\":\"8b128752ecba46e8b7f56de9af8d4fc3.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-01T12:00:00.000Z\",\"end\":\"2019-10-01T15:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://docs.google.com/forms/d/e/1FAIpQLSc79wwL9MRRpHnipi42WA19Fll_0A4FVHf7ryf1PA7qgoYJ3g/viewform\"]', '2019-09-04 12:17:15', '2019-09-04 12:54:30', NULL, NULL, '[]', '[]'),
(667845, 4536852, 60654151, 60654151, 89904399, 46245376, 'defile-48h-maisons-de-mode_615599', '{\"fr\":\"Braderie des créateurs - 48H Maisons de Mode\"}', '{\"fr\":\"Le festival des jeunes marques créateurs est organisé du 12 au 15 sept. par le label Maisons de Mode. Cet événement soutient une trentaine de marques-créateurs dans le nord de la France.\"}', '{\"fr\":\"Pour cette édition 2019, retrouvez nocturne des commerçants, défilés, braderie des créateurs, street style casting, glam run ... Cette année, les 48H Maisons de Mode se mettront aux couleurs de l\'Europe et accueilleront pour l\'occasion de nombreux créateurs du projet européen [**United Fashion**](https://www.united-fashion.eu/).\\n\\n**Week-end Braderie des Créateurs à Saint So**\\n\\n**Samedi 14 septembre**\\n\\n**14h à 19h**\\n\\n*   Braderie des créateurs (outlet géant de 70 marques émergentes françaises et européennes)\\n*   Casting mannequins Exception model management\\n*   Street Style Casting par le photographe chasseurs de looks, Homardpayette\\n\\n**19h30 à minuit**\\n\\n*   Dj set Radioclub sur la terrasse du Bistrot Saint So\\n\\n**Et dimanche 15 septembre**\\n\\n**11h30 à 13h**\\n\\n*   Yogathon au Cours St-So au profit de l\'Association Louise Michel (association qui lutte contre la violence faite aux femmes) avec [**Julie Cousin (Julyoga).**](https://www.facebook.com/events/675422726255339/) Participation facultative : 8 euros, reversés à l\'association.\\n\\n**12h à 19h**\\n\\n*   Braderie des créateurs\\n*   Casting mannequins\\n*   Street Style Casting par le photographe chasseurs de looks, Homardpayette\\n\\n**14h à 15h**\\n\\n*   Chaussez vos plus beaux talons et tentez la Glam Run (course en talons aiguilles ouverte aux filles et aux garçons). [**Sur inscription.**](https://www.billetweb.fr/glam-run-2019-11eme-edition-de-la-course-a-talons-pour-filles-et-garcons-a-lille)\\n\\n[**Retrouvez le programme complet des festivités.**](http://www.maisonsdemode.com/)\"}', '{\"fr\":[\"mode\",\"festival\",\"défilé\",\"casting\",\"créateurs\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"5e0752e1fd6348209e3b9f7c1c2527e2.base.image.jpg\",\"credits\":null,\"size\":{\"height\":396,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"5e0752e1fd6348209e3b9f7c1c2527e2.full.image.jpg\",\"size\":{\"height\":406,\"width\":719}},{\"type\":\"thumbnail\",\"filename\":\"5e0752e1fd6348209e3b9f7c1c2527e2.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-14T12:00:00.000Z\",\"end\":\"2019-09-14T17:00:00.000Z\"},{\"begin\":\"2019-09-14T17:30:00.000Z\",\"end\":\"2019-09-14T22:00:00.000Z\"},{\"begin\":\"2019-09-15T09:30:00.000Z\",\"end\":\"2019-09-15T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-08-28 08:40:31', '2019-08-30 12:27:20', NULL, NULL, '[]', '[]'),
(667814, 81910219, 60654151, 60654151, 89904399, 13830403, 'defile-48h-maisons-de-mode', '{\"fr\":\"Défilé - 48H Maisons de Mode\"}', '{\"fr\":\"Le festival des jeunes marques créateurs est organisé du 12 au 15 sept. par le label Maisons de Mode. Cet événement soutient une trentaine de marques-créateurs dans le nord de la France.\"}', '{\"fr\":\"Pour cette édition 2019, retrouvez nocturne des commerçants, défilés, braderie des créateurs, street style casting, ... Cette année, les 48H Maisons de Mode se mettront aux couleurs de l\'Europe et accueilleront pour l\'occasion de nombreux créateurs [**du projet européen United Fashion**](https://www.united-fashion.eu/)**.**\\n\\n**Défilé Grand Public**\\n\\n**Vendredi 13 sept de 18h à 19h30**\\n\\nVotez pour votre créateur de prêt-à-porter et votre créateur d\'accessoires préféré !\\n\\nDécouvrez tous [**les portraits des créateurs**](http://www.maisonsdemode.com/createur/) et [**le programme complet des festivités.**](http://www.maisonsdemode.com/2019/07/48h-maisons-de-mode-2019-demandez-programme/)\"}', '{\"fr\":[\"mode\",\"festival\",\"créateurs\",\"défilé\",\"casting\"]}', '{\"fr\":\"Sur réservation. Tarif 6€.\"}', '{\"filename\":\"35ad102428724b34b3ac30546a990269.base.image.jpg\",\"credits\":null,\"size\":{\"height\":396,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"35ad102428724b34b3ac30546a990269.full.image.jpg\",\"size\":{\"height\":406,\"width\":719}},{\"type\":\"thumbnail\",\"filename\":\"35ad102428724b34b3ac30546a990269.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-13T16:00:00.000Z\",\"end\":\"2019-09-13T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.billetweb.fr/defile-48h-maisons-de-mode-soutenez-vos-createurs-preferes-2019#eventdefile-48h-maisons-de-mode-soutenez-vos-createurs-preferes-2019\"]', '2019-08-28 08:19:20', '2019-08-30 12:26:30', NULL, NULL, '[]', '[]'),
(667597, 77356126, 60654151, 60654151, 89904399, 29763115, 'defile-48h-maison-des-modes', '{\"fr\":\"Lille Fashion Night - 48h Maisons de Mode\"}', '{\"fr\":\"Le festival des jeunes marques créateurs est organisé du 12 au 15 sept. par le label Maisons de Mode. Cet événement  soutient une trentaine de marques-créateurs dans le nord de la France.\"}', '{\"fr\":\"Pour cette édition 2019, retrouvez nocturne des commerçants, défilés, braderie des créateurs, street style casting, glam run ... Cette année, les 48H Maisons de Mode se mettront aux couleurs de l\'Europe et accueilleront pour l\'occasion de nombreux créateurs [**du projet européen United Fashion**](https://www.united-fashion.eu/)**.**\\n\\n**Lille Fashion Night à Lille**\\n\\n**Jeudi 12 sept de 18h à 22h**\\n\\nNocturne des commerçants mode et tendance du Vieux-Lille dans une ambiance festive !\\n\\n[**Retrouvez tout le programme des festivités.**](http://www.maisonsdemode.com/2019/07/48h-maisons-de-mode-2019-demandez-programme/)\"}', '{\"fr\":[\"mode\",\"défilé\",\"créateurs\",\"festival\"]}', '{}', '{\"filename\":\"203cb5f356af4bc188dcc3807fdcb31f.base.image.jpg\",\"credits\":null,\"size\":{\"height\":396,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"203cb5f356af4bc188dcc3807fdcb31f.full.image.jpg\",\"size\":{\"height\":406,\"width\":719}},{\"type\":\"thumbnail\",\"filename\":\"203cb5f356af4bc188dcc3807fdcb31f.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-12T16:00:00.000Z\",\"end\":\"2019-09-12T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.facebook.com/events/606957003087230/\"]', '2019-08-27 14:54:29', '2019-08-30 12:26:01', NULL, NULL, '[]', '[]');
INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `creator_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at`, `file_key`, `references`, `links`) VALUES
(661034, 27499108, 10265018, 10265018, 89904399, 89561040, '25e-edition-des-pyramides-de-chaussures-handicap-international', '{\"fr\":\"25e édition des Pyramides de chaussures - Handicap International\"}', '{\"fr\":\"À vos chaussures ! L\'ONG Handicap International organise la 25e édition des Pyramides de chaussures.\"}', '{\"fr\":\"Vous avez prévu de faire du tri dans vos chaussures ? Profitez-en pour répondre à l’invitation de l’ONG Handicap International, à l’occasion de la 25e édition des Pyramides de chaussures. Ces événements citoyens sont devenus le symbole du soutien aux victimes de conflits armés. Munissez-vous d’une paire de tongs ou de baskets pour rejoindre la mobilisation. Le combat continue samedi 28 septembre à Lille. Rendez-vous sur la place Richebé à 10 h.\\n\\n[handicap-international.fr](handicap-international.fr)\"}', '{}', '{}', '{\"filename\":\"4a3c69b8f23b4c5da719df3f9c76f875.base.image.jpg\",\"size\":{\"width\":700,\"height\":941},\"variants\":[{\"filename\":\"4a3c69b8f23b4c5da719df3f9c76f875.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":475,\"height\":638}},{\"filename\":\"4a3c69b8f23b4c5da719df3f9c76f875.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-28T08:00:00.000Z\",\"end\":\"2019-09-28T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-08-06 09:29:22', '2019-08-06 09:29:22', NULL, NULL, '[]', '[]'),
(658997, 86906427, 10265018, 10265018, 89904399, 87279703, 'foulees-lambersartoises-2019', '{\"fr\":\"Foulées lambersartoises 2019\"}', '{\"fr\":\"Les inscriptions sont ouvertes pour les Foulées lambersartoises 2019 ! À vos marques, prêts, partez !\"}', '{\"fr\":\"**Foulées lambersartoises 2019 : les inscriptions en ligne sont ouvertes !**\\n\\nLes Foulées lambersartoises sont organisées par la Ville de Lambersart, l\'Office Municipal de la Jeunesse et des Sports de Lambersart et Lambersart athlétisme. Elle se dérouleront le 22 septembre.\\n\\nTrois courses sont proposées aux adultes : le 2 km, le 5 km et le 10 km (qui détient le label régional et course classante qualifiante championnat départementale 2019).\\n\\nDeux courses sont proposées aux scolaires : 1 km et 2 km.\\n\\nLes épreuves sont ouvertes à toutes les personnes remplissant les conditions suivantes :\\n\\n• né(e) en 2003 et avant : 10 km\\n\\n• né(e) en 2005 et avant : 5 km\\n\\n• né(e) en 2007 et avant (et collégiens) : 2 km\\n\\n• ouvert aux enfants de niveaux CE et CM scolarisés à Lambersart : 1 km\\n\\nLe départ des courses des 5 et 10km est donné sur l\'avenue du Colysée à proximité de l\'entrée du stade Guy Lefort. Le départ des courses des 1 et 2km est donné sur l\'avenue de l\'Hippodrome, à proximité du domaine de l\'Hippodrome au droit du 223. Les arrivées auront lieux sur la piste d’athlétisme du stade Guy Lefort.\\n\\n**Les horaires**\\n\\n• course de 2 km : 9h00 5 km : 9h15 10 km : 10h\\n\\n• randonnée Roller : le départ est donné sur l\'avenue du Colysée à 10h35 précises pour une randonnée de 5 ou 10 km. Inscription le jour même à partir de 10h\\n\\n• marche nordique : départ à 10h40. Inscription le jour même, à partir de 10h.\\n\\nLa facilité pour l’inscription\\n\\nLes inscriptions pour les courses adultes sont possibles dès maintenant sur le site [omjslambersart.fr](http://omjslambersart.fr/)\\n\\nToutes les informations, les modalités pratiques dont les parcours sont disponibles sur le site : [omjslambersart.fr](http://omjslambersart.fr/)\\n\\nLe jour J, la course sera retransmise en direct sur notre page Facebook [OMJSLAMBERSART](https://www.facebook.com/OMJSLAMBERSART/)\"}', '{}', '{}', '{\"filename\":\"ee29947eda1c4c6f8cd94a75e9c8ade9.base.image.jpg\",\"size\":{\"width\":700,\"height\":993},\"variants\":[{\"filename\":\"ee29947eda1c4c6f8cd94a75e9c8ade9.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":1386,\"height\":1966}},{\"filename\":\"ee29947eda1c4c6f8cd94a75e9c8ade9.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-22T07:00:00.000Z\",\"end\":\"2019-09-22T13:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"contact@omjslambersart.fr\",\"http://omjslambersart.fr/\"]', '2019-07-30 12:08:24', '2019-07-30 12:08:24', NULL, NULL, '[]', '[]'),
(655355, 39456301, 60654151, 60654151, 89904399, 46700263, 'marche-fermier_432639', '{\"fr\":\"Marché fermier\"}', '{\"fr\":\"Une douzaine de marchés fermiers durables se déroulent sur quatre sites en métropole. Dernière session de l\'année aux serres horticoles de Wambrechies.\"}', '{\"fr\":\"MEL et CIVAM Hauts-de-France sont partenaires pour la tenue des marchés fermiers en métropole.\\n\\nCes marchés visent à promouvoir et rendre accessibles les produits fermiers de notre région, en prônant les savoir-faire locaux et le développement d’une agriculture durable. A chaque marché, une dizaine de producteurs viennent vendre leur propre production : produits laitiers, viandes, pains, miel, confiture, produits maraîchers …\\n\\n**Pour en savoir plus**\\n\\nAccédez [au site du CIVAM Hauts de France](http://www.civam-hautsdefrance.fr/les-marches-fermiers/)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"cb95170b29de4c6a83b2b7392702faeb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":467,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"cb95170b29de4c6a83b2b7392702faeb.full.image.jpg\",\"size\":{\"height\":3840,\"width\":5760}},{\"type\":\"thumbnail\",\"filename\":\"cb95170b29de4c6a83b2b7392702faeb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-12-15T09:00:00.000Z\",\"end\":\"2019-12-15T10:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-07-23 09:50:54', '2019-07-23 13:53:21', NULL, NULL, '[]', '[]'),
(655300, 21197655, 60654151, 60654151, 89904399, 46700263, 'marche-fermier_719068', '{\"fr\":\"Marché fermier\"}', '{\"fr\":\"Une douzaine de marchés fermiers durables se déroulent sur quatre sites en métropole. Retour des marchés dès la rentrée de septembre 2019\"}', '{\"fr\":\"MEL et CIVAM Hauts-de-France sont partenaires pour la tenue des marchés fermiers en métropole.\\n\\nCes marchés visent à promouvoir et rendre accessibles les produits fermiers de notre région, en prônant les savoir-faire locaux et le développement d’une agriculture durable. A chaque marché, une dizaine de producteurs viennent vendre leur propre production : produits laitiers, viandes, pains, miel, confiture, produits maraîchers …\\n\\n**Pour en savoir plus**\\n\\nAccédez [au site du CIVAM Hauts de France](http://www.civam-hautsdefrance.fr/les-marches-fermiers/)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"cb95170b29de4c6a83b2b7392702faeb.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":467,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"cb95170b29de4c6a83b2b7392702faeb.full.image.jpg\",\"size\":{\"height\":3840,\"width\":5760}},{\"type\":\"thumbnail\",\"filename\":\"cb95170b29de4c6a83b2b7392702faeb.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-20T08:00:00.000Z\",\"end\":\"2019-10-20T09:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-07-23 09:18:02', '2019-07-23 13:55:17', NULL, NULL, '[]', '[]'),
(651457, 71398229, 24129771, 24129771, 89904399, 10145234, 'visite-insolite_273161', '{\"fr\":\"Visite Insolite\"}', '{\"fr\":\"Samedi 21 septembre, à l’occasion des Journées européennes du patrimoine, le service des archives de la MEL ouvre ses portes au public.\"}', '{\"fr\":\"Des visites guidées pour découvrir les missions et actions du service, les fonds d’archives. Mais aussi des contenus poétiques et vidéo inédits.\\n\\nDeux visites guidées d\'une heure sont organisées le samedi 21 septembre :\\n\\n*   14h30\\n*   16h30\\n\\nGratuit, sur réservation\\n\\n**Retrouvez le programme à compter de mi-août 2019 sur** [**archives-lillemetropole.fr**](http://www.archives-lillemetropole.fr/n/journees-europeennes-du-patrimoine/n:219)\"}', '{\"fr\":[\"Visite\",\"Journées Européennes du Patrimoine\",\"Métropole Européenne de Lille\",\"Archives\"]}', '{\"fr\":\"Gratuit, sur réservation\"}', '{\"filename\":\"7864c214d8d544af819bf61e26d52406.base.image.jpg\",\"credits\":null,\"size\":{\"height\":368,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"7864c214d8d544af819bf61e26d52406.full.image.jpg\",\"size\":{\"height\":630,\"width\":1200}},{\"type\":\"thumbnail\",\"filename\":\"7864c214d8d544af819bf61e26d52406.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-21T12:30:00.000Z\",\"end\":\"2019-09-21T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"archives@lillemetropole.fr\",\"0320212128\"]', '2019-07-16 14:31:01', '2019-09-16 09:40:10', NULL, NULL, '[]', '[]'),
(651424, 83073323, 24129771, 24129771, 89904399, 86363801, 'ekiden-cofidis_700652', '{\"fr\":\"Ekiden Cofidis\"}', '{\"fr\":\"Marathon-relais par équipe,  à parcourir entre amis ou collègues.\"}', '{\"fr\":\"L’idée et le nom viennent du Japon. Les participants courent la distance de 42,195 km sous forme de relais de six équipiers, sur des distances réduites, de 5 à 10 km. L’épreuve est donc accessible au plus grand nombre. Pas bêtes les Nippons.\"}', '{\"fr\":[\"Course\",\"Villeneuve d\'Ascq\"]}', '{\"fr\":\"Inscription payante\"}', '{\"filename\":\"c615f286972842acbf96ad3831f74e78.base.image.jpg\",\"credits\":\"©Ekiden\",\"size\":{\"height\":467,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"c615f286972842acbf96ad3831f74e78.full.image.jpg\",\"size\":{\"height\":1200,\"width\":1800}},{\"type\":\"thumbnail\",\"filename\":\"c615f286972842acbf96ad3831f74e78.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-10-06T05:30:00.000Z\",\"end\":\"2019-10-06T06:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":16,\"max\":99}', '[\"http://ekidenvdascq.fr\"]', '2019-07-16 14:13:46', '2019-07-16 14:16:57', NULL, NULL, '[]', '[]'),
(651410, 94379420, 24129771, 24129771, 89904399, 29601992, 'les-foulees-lambersartoises', '{\"fr\":\"Les Foulées Lambersartoises\"}', '{\"fr\":\"Créées en 1985 par la ville, les Foulées Lambersartoises vous acceuille pour une 34e édition.\"}', '{\"fr\":\"Elles ont été créées en 1985 par la ville, l\'office municipal de la jeunesse et des sports, et les clubs d\'athlétisme et de roller.\\n\\nL\'objectif : proposer un événement ouvert au plus grand nombre.\\n\\nIl est atteint puisque plus de 2 000 participants sont enregistrés chaque année.\\n\\nPlusieurs courses sont organisées : 10 km (labellisée régionale, elle compte pour le championnat régional), 5 km, 2 km, 1 km scolaire (niveau CE et CM), randonnée marche nordique et roller.\"}', '{\"fr\":[\"Lambersart\",\"Sport\",\"Courses\",\"Scolaire\"]}', '{\"fr\":\"Inscription en ligne\"}', '{\"filename\":\"672a1fe81edf45869b319723e16b13b5.base.image.jpg\",\"credits\":null,\"size\":{\"height\":217,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"672a1fe81edf45869b319723e16b13b5.full.image.jpg\",\"size\":{\"height\":173,\"width\":560}},{\"type\":\"thumbnail\",\"filename\":\"672a1fe81edf45869b319723e16b13b5.thumb.image.jpg\",\"size\":{\"height\":201,\"width\":201}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-22T07:30:00.000Z\",\"end\":\"2019-09-22T15:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://lambersart.fr/bien-vivre/sport\"]', '2019-07-16 14:02:05', '2019-07-16 14:03:37', NULL, NULL, '[]', '[]'),
(651367, 9107612, 24129771, 24129771, 89904399, 63552532, 'on-marche-a-roubaix', '{\"fr\":\"On marche à Roubaix\"}', '{\"fr\":\"Les 28 heures de Roubaix, épreuve de marche de grand fond imaginée et crée par Louis Bourgeois, se dérouleront les 14 et 15 septembre pour leur 66e édition.\"}', '{\"fr\":\"Cette 66e édition verra s\'affronter 70 à 80 concurrents français, polonais, hongrois, tchèques, russes, biélorusses, ukrainiens, hollandais, suisses, britanniques et américains.\\n\\nIl s\'agit des meilleurs spécialistes mondiaux de la discipline.\\n\\nCette épreuve est reconnue par la Fédération Française d\'Athlétisme comme sélective pour l\'édition 2020 du Paris-Alsace à la marche féminins et masculins (436 km).\\n\\nDépart : 11 heures pour les 28 heures en individuel\\n\\n15 heures pour les 24 heures par équipe\"}', '{\"fr\":[\"Marche\",\"Course\",\"Roubaix\"]}', '{\"fr\":\"Sur inscription pour les concurrents / Entrée libre pour les spectateurs\"}', '{\"filename\":null,\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-14T08:30:00.000Z\",\"end\":\"2019-09-14T09:30:00.000Z\"},{\"begin\":\"2019-09-14T12:30:00.000Z\",\"end\":\"2019-09-14T13:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://marchons.com\"]', '2019-07-16 13:32:18', '2019-07-16 13:33:44', NULL, NULL, '[]', '[]'),
(651245, 14715316, 24129771, 24129771, 89904399, 63552532, 'courrez-pour-une-bonne-cause', '{\"fr\":\"Courrez pour une bonne cause\"}', '{\"fr\":\"Participez aux Foulées de Ludopital et vous ferez une bonne action !\"}', '{\"fr\":\"Depuis 1987, cette association mène des actions pour rendre plus agréable et plus chaleureux le séjour des enfants à l’hôpital. Par exemple en distribuant des jouets ou en aménageant les lieux de vie. Au programme, de la marche, de la course, pour tous les âges.\\n\\nLa totalité des droits d\'inscription aux épreuves va aux actions hospitalières de Ludopital.\"}', '{\"fr\":[\"Sport\",\"Course\",\"Hôpital\",\"Enfant\"]}', '{\"fr\":\"Inscriptions en ligne\"}', '{\"filename\":\"04af507b33be4586a0a57571c7d7da69.base.image.jpg\",\"size\":{\"width\":700,\"height\":993},\"variants\":[{\"filename\":\"04af507b33be4586a0a57571c7d7da69.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":722,\"height\":1024}},{\"filename\":\"04af507b33be4586a0a57571c7d7da69.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-08T06:30:00.000Z\",\"end\":\"2019-09-08T07:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://ludopital.fr\"]', '2019-07-16 12:17:55', '2019-07-16 12:21:39', NULL, NULL, '[]', '[]'),
(651040, 81208766, 24129771, 24129771, 89904399, 45370732, 'et-vous-trouvez-ca-drole', '{\"fr\":\"Et vous trouvez ça drôle ?\"}', '{\"fr\":\"Le festival CineComedies revient, avec, pour sa seconde édition, un riche programme dédié à la comédie sur grand écran.\"}', '{\"fr\":\"Cette année, l’événement met à l’honneur la Belgique et son cinéma comique. Au programme de ce festival du « rire ensemble » : projections, avant-premières, rétrospectives, masterclass, conférences et animations en tout genre. 12 000 visiteurs avaient profité de la première édition de ce grand rendez-vous en septembre 2018, dont l’acteur Pierre Richard était le parrain. Soyez plus nombreux encore en 2019 et venez (re)découvrir les plus grandes comédies du cinéma belge des années 1950 à nos jours. Nouveauté cette année, le festival lance le CineComedies Talents, un concours vidéo ouvert à tous. Faites appel à votre imagination en réalisant une vidéo sur le thème de l’« arroseur arrosé », inspiré par le film du même nom des frères Lumière. 20 court-métrages de 3 minutes maximum seront sélectionnés et projetés lors du festival. Une cérémonie de remise de prix se tiendra le 6 octobre et viendra récompenser les nouveaux talents de la comédie. Moteur, action !\"}', '{\"fr\":[\"Festival\",\"Comédie\"]}', '{\"fr\":\"Entrée libre sur reservation\"}', '{\"filename\":\"ca05847d6521463ca04dde71cbd7454e.base.image.jpg\",\"size\":{\"width\":700,\"height\":581},\"variants\":[{\"filename\":\"ca05847d6521463ca04dde71cbd7454e.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":1400,\"height\":1162}},{\"filename\":\"ca05847d6521463ca04dde71cbd7454e.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-23T07:00:00.000Z\",\"end\":\"2019-09-23T20:00:00.000Z\"},{\"begin\":\"2019-09-30T07:00:00.000Z\",\"end\":\"2019-09-30T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://festival-cinecomedies.com\"]', '2019-07-16 08:42:07', '2019-07-16 08:42:07', NULL, NULL, '[]', '[]'),
(650807, 8517863, 24129771, 24129771, 89904399, 82791038, 'oeuvre-dart-a-porter', '{\"fr\":\"Oeuvre d\'art à porter\"}', '{\"fr\":\"À la rentrée, direction la Manufacture de Roubaix où l’association Universal Love et sa créatrice Isabelle Quéhée vous proposent de découvrir Passion parures, une exposition consacrée… aux parures.\"}', '{\"fr\":\"Simples ou sophistiqués, discrets ou tape-à-l’œil, les bijoux exposés sont de véritables objets d’art à porter, capables de métamorphoser une tenue. Du 6 septembre au 25 octobre 2019, apprenez-en plus sur cet accessoire en découvrant les savoir-faire traditionnels de sa fabrication au travers d’ateliers et de conférences.\\n\\nPour plus d\'informations, rendez-vous sur : **lamanufacture-roubaix.com**\"}', '{\"fr\":[\"Exposition\",\"Roubaix\"]}', '{\"fr\":\"Accès libre et gratuit\"}', '{\"filename\":\"01986221e8ab456fab7370ac4158bdc4.base.image.jpg\",\"credits\":null,\"size\":{\"height\":700,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"01986221e8ab456fab7370ac4158bdc4.full.image.jpg\",\"size\":{\"height\":984,\"width\":984}},{\"type\":\"thumbnail\",\"filename\":\"01986221e8ab456fab7370ac4158bdc4.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-06T12:00:00.000Z\",\"end\":\"2019-09-06T16:00:00.000Z\"},{\"begin\":\"2019-09-07T12:00:00.000Z\",\"end\":\"2019-09-07T16:00:00.000Z\"},{\"begin\":\"2019-09-10T12:00:00.000Z\",\"end\":\"2019-09-10T16:00:00.000Z\"},{\"begin\":\"2019-09-11T12:00:00.000Z\",\"end\":\"2019-09-11T16:00:00.000Z\"},{\"begin\":\"2019-09-12T12:00:00.000Z\",\"end\":\"2019-09-12T16:00:00.000Z\"},{\"begin\":\"2019-09-13T12:00:00.000Z\",\"end\":\"2019-09-13T16:00:00.000Z\"},{\"begin\":\"2019-09-14T12:00:00.000Z\",\"end\":\"2019-09-14T16:00:00.000Z\"},{\"begin\":\"2019-09-17T12:00:00.000Z\",\"end\":\"2019-09-17T16:00:00.000Z\"},{\"begin\":\"2019-09-18T12:00:00.000Z\",\"end\":\"2019-09-18T16:00:00.000Z\"},{\"begin\":\"2019-09-19T12:00:00.000Z\",\