(650734, 60550763, 24129771, 24129771, 89904399, 89561040, 'a-vos-chaussures', '{\"fr\":\"A vos chaussures !\"}', '{\"fr\":\"Vous avez prévu de faire du tri dans vos chaussures ? Profitez-en pour répondre à l\'invitation de l\'ONG Handicap International à l\'occasion de la 25e édition des Pyramides de chaussures !\"}', '{\"fr\":\"Ces événements citoyens sont devenus le symbole du soutien aux victimes de conflits armés. Munissez-vous d\'une paire de tongs ou de baskets pour rejoindre la mobilisation.\\n\\nLe combat continue !\"}', '{\"fr\":[\"Evénement\",\"Citoyen\",\"Mobilisation\",\"Handicap\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"250759c8bf3a435897765629fead9fca.base.image.jpg\",\"credits\":null,\"size\":{\"height\":934,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"250759c8bf3a435897765629fead9fca.full.image.jpg\",\"size\":{\"height\":2000,\"width\":1500}},{\"type\":\"thumbnail\",\"filename\":\"250759c8bf3a435897765629fead9fca.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-28T08:00:00.000Z\",\"end\":\"2019-09-28T09:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-07-15 14:19:06', '2019-07-15 14:20:15', NULL, NULL, '[]', '[]'),
(650705, 38512115, 24129771, 24129771, 89904399, 21780640, 'juste-pour-rire', '{\"fr\":\"Juste pour rire\"}', '{\"fr\":\"Le festival Clef de soleil, pour sa 18e édition, vous propose des notes d’humour.\"}', '{\"fr\":\"Quel mystère peut donc pousser les compositeurs à baigner dans une certaine joie après une vie de souffrance ? Le secret, c’est peut-être que l’humour en musique a toujours existé. À vérifier, en quelques concerts de musique de chambre, à Lille et à Hallennes-lez-Haubourdin.\\n\\nProchain concert à Lille !\"}', '{\"fr\":[\"Festival\",\"Musique de chambre\",\"Lille\",\"Hallennes-lez-haubourdin\"]}', '{\"fr\":\"Payant\"}', '{\"filename\":\"f91a7d7a869846b19ab3ba76e0b94b25.base.image.jpg\",\"credits\":null,\"size\":{\"height\":991,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"f91a7d7a869846b19ab3ba76e0b94b25.full.image.jpg\",\"size\":{\"height\":1191,\"width\":842}},{\"type\":\"thumbnail\",\"filename\":\"f91a7d7a869846b19ab3ba76e0b94b25.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-07-18T17:00:00.000Z\",\"end\":\"2019-07-18T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://clefdesoleil.com\"]', '2019-07-15 13:56:19', '2019-07-15 13:58:36', NULL, NULL, '[]', '[]'),
(642876, 98651348, 10265018, 10265018, 89904399, 75315013, '27eme-salon-eurotoy', '{\"fr\":\"27ème salon EUROTOY\"}', '{\"fr\":\"Cet événement, consacré aux poupées et jouets anciens, rassemble plus de 1 000 personnes chaque année. Au programme : achat/vente et expositions !\"}', '{\"fr\":\"Rendez-vous le dimanche 29 septembre de 9 h à 17 h à la salle Gilles Allain Billiet de Wambrechies pour une bourse internationale de poupées et jouets anciens. Deux expositions sont également programmées : « Les poupées de Femmes d’Aujourd’hui » et « la Collection Meccano de Mr Riff ».\\n\\nLe musée sera également ouvert au Château de Robersart.\"}', '{}', '{\"fr\":\"Entrée 2€/enfant de plus de 4 ans et 4€/adulte (salon Eurotoy et Musée)\"}', '{\"filename\":\"48df09f4355c4bac81fa672db0d0bfd4.base.image.jpg\",\"size\":{\"width\":700,\"height\":1390},\"variants\":[{\"filename\":\"48df09f4355c4bac81fa672db0d0bfd4.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":833,\"height\":1654}},{\"filename\":\"48df09f4355c4bac81fa672db0d0bfd4.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-29T07:00:00.000Z\",\"end\":\"2019-09-29T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"0328188421\",\"https://www.wambrechies.fr/sur-votre-agenda/eurotoy-0\"]', '2019-07-08 07:43:56', '2019-07-08 07:43:56', NULL, NULL, '[]', '[]'),
(600410, 37289254, 60654151, 60654151, 89904399, 74521541, 'cafe-citoyen-sur-la-transition-ecologique', '{\"fr\":\"Café citoyen sur la transition écologique\"}', '{\"fr\":\"La MEL s\'engage pour le climat. Elle invite les habitants du territoire à des cafés citoyens.\"}', '{\"fr\":\"La Métropole Européenne de Lille invite les habitants à des cafés citoyens pour réfléchir à un nouveau projet de société. L\'idée est de partager en toute convivialité des points de vue, des idées, des propositions sur la transition énergétique et climatique pour enrichir le Plan Climat Air Energie Territorial de la MEL.\\n\\n**Café citoyen : un sujet, un intervenant, un café !**\\n\\nUne dizaine de cafés citoyens sont organisés entre mars et juillet 2019.\\n\\nLe prochain café se déroule le 8 juillet.\\n\\n**Café transition écologique avec Algoé**\\n\\n**\\\" Comment dépasser les contradictions du quotidien pour s\'engager dans la transition écologique ? \\\"**\\n\\n**8 juillet à 18h30 - Maison Stéphane Hessel à Lille**\\n\\n_Algoé_ est une société d’accompagnement en développement territorial, qui s’est spécialisée sur les problématiques de concertation, d’énergie et d’environnement.\\n\\nAu quotidien, nos pratiques de consommation présentent de multiples paradoxes. Acheter ses fruits et légumes bio mais emballés dans du plastique, consommer local mais acheter ses vêtements sur Internet, éteindre la lumière mais laisser ses appareils électroménagers branchés … Débattons et agissons ensemble pour aller au-delà de ces contradictions !\"}', '{}', '{\"fr\":\"Gratuit. Entrée libre.\"}', '{\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":400,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.full.image.jpg\",\"size\":{\"height\":3417,\"width\":5126}},{\"type\":\"thumbnail\",\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-07-08T16:30:00.000Z\",\"end\":\"2019-07-08T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"0359006474\"]', '2019-06-26 09:11:18', '2019-06-26 09:12:48', NULL, NULL, '[]', '[]'),
(589567, 21882227, 10265018, 10265018, 89904399, 17513977, 'handball-feminin-belgique-usa-a-lomme', '{\"fr\":\"Handball Féminin : Belgique - USA à Lomme\"}', '{\"fr\":\"L\'équipe nationale féminine de Handball Belge affrontera l\'équipe des États-Unis le vendredi 5 juillet.\"}', '{\"fr\":\"Le Lomme Lille Métropole Handball a le plaisir d\'accueillir le vendredi 5 juillet prochain à 19h à la salle du parc un match opposant l\'équipe nationale féminine de Handball Belge à l\'équipe des États-Unis. #BELUSA\\n\\n[Plus d\'informations sur la page Facebook de Lomme Lille Métropole Handball](https://www.facebook.com/LommeHandball/)\"}', '{}', '{\"fr\":\"5€, réservez vos billets sur https://www.weezevent.com/belgique-usa / Gratuit pour les licenciés FFHB - Réservations à faire sur le lien billetterie\"}', '{\"filename\":\"59f9b7e534c84160ad0f33a512d53758.base.image.jpg\",\"credits\":null,\"size\":{\"height\":1012,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"59f9b7e534c84160ad0f33a512d53758.full.image.jpg\",\"size\":{\"height\":3250,\"width\":2250}},{\"type\":\"thumbnail\",\"filename\":\"59f9b7e534c84160ad0f33a512d53758.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-07-05T17:00:00.000Z\",\"end\":\"2019-07-05T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.weezevent.com/belgique-usa\"]', '2019-06-17 08:35:56', '2019-06-17 08:36:45', NULL, NULL, '[]', '[]'),
(589477, 89334997, 10265018, 10265018, 89904399, 44070371, 'faitrarissime-2019', '{\"fr\":\"FAITRARISSIME 2019\"}', '{\"fr\":\"100 voitures exceptionnelles seront exposées à Linselles. Au programme : stands, animations, baptêmes et parades.\"}', '{\"fr\":\"Le dimanche 15 septembre 2019 à Linselles, Métropole Lilloise, de 10h à 18h\\n\\n100 voitures exceptionnelles : des Ferrari et autres sportives rares\\n\\nUne exposition et des baptêmes en parades dans la campagne linselloise\\n\\nDes stands dédiés à l’automobile, des modèles réduits,\\n\\nDes animations pour les enfants : des châteaux gonflables, des balades en poney, etc.\\n\\nUn village des associations\\n\\nDe la petite restauration : frites, gaufres, bars\\n\\nEntrées: Adulte 5 € et Gratuit pour les enfants de moins de un mètre.\\n\\nBaptêmes à partir de 50€ selon les modèles de voiture\\n\\nL\'événement est organisé par le Rotary Club de Linselles.\"}', '{}', '{\"fr\":\"Entrées: Adulte 5 € et Gratuit pour les enfants de moins de un mètre.\"}', '{\"filename\":\"f8e9c3d446994d2f8867fce73a6b6ab3.base.image.jpg\",\"size\":{\"width\":700,\"height\":991},\"variants\":[{\"filename\":\"f8e9c3d446994d2f8867fce73a6b6ab3.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":724,\"height\":1024}},{\"filename\":\"f8e9c3d446994d2f8867fce73a6b6ab3.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-15T08:00:00.000Z\",\"end\":\"2019-09-15T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-06-17 07:35:19', '2019-06-17 07:35:19', NULL, NULL, '[]', '[]'),
(586798, 74107209, 60654151, 60654151, 89904399, 79759308, 'cafe-sante-environnementale_791684', '{\"fr\":\"Café santé environnementale\"}', '{\"fr\":\"La MEL s\'engage pour le climat. Elle invite les habitants du territoire à des cafés citoyens.\"}', '{\"fr\":\"La Métropole Européenne de Lille invite les habitants à des cafés citoyens pour réfléchir à un nouveau projet de société. L\'idée est de partager en toute convivialité des points de vue, des idées, des propositions sur la transition énergétique et climatique pour enrichir le Plan Climat Air Energie Territorial de la MEL.\\n\\n**Café citoyen : un sujet, un intervenant, un café !**\\n\\nUne dizaine de cafés citoyens sont organisés entre mars et juillet 2019. Poursuite en juin de ces rendez-vous convivaux ouverts à tous.\\n\\n**Café santé environnementale**\\n\\n**\\\" Quels liens entre les pollutions atmosphériques et la santé ? \\\"**\\n\\n**17 juin à 18h30**\\n\\n**au Forum des Sciences à Villeneuve d\'Ascq**\\n\\nAvec les interventions de Damien Cuny et Florent Occelli chercheurs à l\'Université de Lille et membres de l\'équipe porteuse du programme SIGLES. Ce programme cherche à déterminer si les populations présentant un état de santé amoindri vivent dans un environnement dégradé (air, eau, sol).\\n\\nDéfaisons ensemble les idées reçues sur la pollution de l\'air, les polluants et leurs origines, les impacts de la pollution de l\'air sur la santé.\"}', '{}', '{\"fr\":\"Gratuit. Entrée libre.\"}', '{\"filename\":\"6ac7c9a7243a4b3c940eac9f3c39a6af.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":743,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"6ac7c9a7243a4b3c940eac9f3c39a6af.full.image.jpg\",\"size\":{\"height\":405,\"width\":382}},{\"type\":\"thumbnail\",\"filename\":\"6ac7c9a7243a4b3c940eac9f3c39a6af.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-17T16:30:00.000Z\",\"end\":\"2019-06-17T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"0359006474\"]', '2019-06-13 15:40:58', '2019-06-13 15:53:06', NULL, NULL, '[]', '[]'),
(586546, 65736495, 10265018, 10265018, 89904399, 18406207, 'journees-nationales-de-larcheologie-au-musee-de-fromelles', '{\"fr\":\"Journées nationales de l\'archéologie au Musée de Fromelles\"}', '{\"fr\":\"Le Musée de la Bataille de Fromelles se propose de montrer aux visiteurs le caractère exceptionnel des découvertes archéologiques faites à Fromelles.\"}', '{\"fr\":\"Dans le cadre des Journées Nationales de l’Archéologie les les 14, 15 et 16 juin prochains, le Musée de la Bataille de Fromelles se propose de montrer aux visiteurs le caractère exceptionnel des découvertes archéologiques faites à Fromelles, ainsi que l’importance de l’archéologie pour mieux comprendre les périodes contemporaines.\\n\\nLe droit d’entrée au musée est de 4 € pour tous pendant ces 2 jours.\\n\\nDes animations vous sont également proposées :\\n\\nVendredi 14 juin 2019 à 15h - Visite animée \\\"Sur les traces d’Oliver\\\"\\n\\nVous vous transformerez en archéologues d’un jour et utiliserez les méthodes de raisonnement scientifique pour découvrir l’identité d’un soldat fictif. Avec le médiateur, vous ferez parler les objets de l’exposition pour découvrir sa nationalité, son rôle sur le champ de bataille, etc...\\n\\nTarif : 4 € (entrée du Musée incluse)\\n\\nSamedi 15 juin 2019 à 15h - Visite animée \\\"Sur les traces d’Oliver\\\"\\n\\nVous vous transformerez en archéologues d’un jour et utiliserez les méthodes de raisonnement scientifique pour découvrir l’identité d’un soldat fictif. Avec le médiateur, vous ferez parler les objets de l’exposition pour découvrir sa nationalité, son rôle sur le champ de bataille, etc...\\n\\nTarif : 4 € (entrée du Musée incluse)\\n\\nDimanche 16 juin 2019 à 15h - Atelier \\\"Objets trouvés\\\"\\n\\nAu cours de cette animation, vous devrez identifier des objets archéologiques sur différents types de photographies. Vous apprendrez ensuite quels indices cela révèle sur l’identité du soldat retrouvé avec l’objet.\\n\\nTarif : gratuit (entrée du Musée non incluse)\\n\\nPour en savoir plus, rendez-vous sur le site du [musée de la bataille de Fromelles](https://www.musee-bataille-fromelles.fr/)\"}', '{}', '{\"fr\":\"Nombre de places limité pour les animations - Réservation conseillée\"}', '{\"filename\":\"55094384038744cd9c2842b43f0f3426.base.image.jpg\",\"size\":{\"width\":700,\"height\":204},\"variants\":[{\"filename\":\"55094384038744cd9c2842b43f0f3426.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":860,\"height\":250}},{\"filename\":\"55094384038744cd9c2842b43f0f3426.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-14T13:00:00.000Z\",\"end\":\"2019-06-14T17:00:00.000Z\"},{\"begin\":\"2019-06-15T13:00:00.000Z\",\"end\":\"2019-06-15T17:00:00.000Z\"},{\"begin\":\"2019-06-16T13:00:00.000Z\",\"end\":\"2019-06-16T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.musee-bataille-fromelles.fr/\",\"03.59.61.15.14\",\"contact@musee-bataille-fromelles.fr\"]', '2019-06-13 13:56:43', '2019-06-13 13:56:43', NULL, NULL, '[]', '[]'),
(586532, 93380716, 10265018, 10265018, 89904399, 13442713, 'halterophilie-finale-de-la-coupe-de-france-des-clubs-seniors-mixtes', '{\"fr\":\"Haltérophilie : Finale de la coupe de France des clubs seniors mixtes\"}', '{\"fr\":\"Compétition réunissant les 8 meilleurs clubs français, qualifiés après un 1er tour qui a eu lieu en mars dernier.\"}', '{\"fr\":\"Organisée par le Club Haltérophile Cominois Decottignies,\\n\\nCompétition réunissant les 8 meilleurs clubs français, qualifiés après un 1er tour qui a eu lieu en mars dernier.\\n\\nSalles Jean Debuf et Raymond Herbaux - Comines.\\n\\nPour en savoir plus, rendez-vous sur le site de la [Fédération Française d’Haltérophilie - Musculation](http://www.ffhaltero.fr/Halterophilie/Actualites/Finale-de-la-coupe-de-France-des-clubs-seniors-mixtes)\"}', '{}', '{}', '{\"filename\":\"165b702c9dfa4453bc7999573ced3ecf.base.image.jpg\",\"size\":{\"width\":700,\"height\":1067},\"variants\":[{\"filename\":\"165b702c9dfa4453bc7999573ced3ecf.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":603,\"height\":919}},{\"filename\":\"165b702c9dfa4453bc7999573ced3ecf.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-15T09:00:00.000Z\",\"end\":\"2019-06-15T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.ffhaltero.fr/Halterophilie/Actualites/Finale-de-la-coupe-de-France-des-clubs-seniors-mixtes\"]', '2019-06-13 13:52:24', '2019-06-13 13:52:24', NULL, NULL, '[]', '[]'),
(585924, 55347888, 44809506, 44809506, 89904399, 7727619, 'jules-adler-peindre-sous-la-iii-eme-republique', '{\"fr\":\"Jules Adler : Peindre sous la III ème République\"}', '{\"fr\":\"Une centaine d\'oeuvres se situant entre modernité et académisme\"}', '{\"fr\":\"Cet été au musée de la Piscine, découvrez l\'exposition consacré au peintre naturaliste du XX ème siècle : **Jules Adler**.\\n\\nCe peintre a consacré une partie de son oeuvre à représenter la misère sociale en peignant des pauvres parisiens ou encore des professions peu élevées.\\n\\nSa palette de couleurs principale contient des tons sombres avec quelques touches de couleurs vives pour impacter son tableau et amener les visiteurs à s\'inetrroger sur les conditions sociétales de la **III ème République.**\\n\\nCertaines toiles représentent le travail à la mine, ce qui fait tout particulièrement écho à la culture des Flandres.\\n\\n**Découvrez le parcours de visite :**\\n\\n*   devenir peintre\\n*   figures populaires\\n*   rues de Paris\\n*   au pays de la mine\\n*   peinture d\'histoire ?\\n*   chemineaux et pêcheurs\\n*   voyager\\n*   la Grande Guerre (1914-1918)\"}', '{\"fr\":[\"exposition\",\"peinture\",\"peintre\",\"ADLER\",\"LaPiscine\",\"Roubaix\",\"Juin\",\"Juillet\",\"Aout\",\"Septembre\",\"2019\"]}', '{\"fr\":\"11 € Tarif plein / 9 € Tarif réduit\"}', '{\"filename\":\"c5a4d52197ba4821b307be148f623885.base.image.jpg\",\"credits\":\"J.C. PoumeyroL\",\"size\":{\"height\":865,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"c5a4d52197ba4821b307be148f623885.full.image.jpg\",\"size\":{\"height\":895,\"width\":725}},{\"type\":\"thumbnail\",\"filename\":\"c5a4d52197ba4821b307be148f623885.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-29T08:00:00.000Z\",\"end\":\"2019-06-29T17:00:00.000Z\"},{\"begin\":\"2019-06-30T08:00:00.000Z\",\"end\":\"2019-06-30T17:00:00.000Z\"},{\"begin\":\"2019-07-01T08:00:00.000Z\",\"end\":\"2019-07-01T17