(584062, 57622506, 44809506, 44809506, 89904399, 82440443, 'braderie-de-larchitecture', '{\"fr\":\"Braderie de l\'architecture\"}', '{\"fr\":\"7 ème édition de cette braderie inédite sur le thème de La Frugalité heureuse !\"}', '{\"fr\":\"Cet événement promet de rassembler professionnels, étudiants ou encore particuliers pour une vente exclusive d\'objets en tout genre relevant du domaine d el\'architecture, de l\'urbanisme ou du paysage.\\n\\nQue vous souhaitiez vendre ou acheter des maquettes, des ouvrages, du matériel, une maison de poupées, des jeux de construction ou des dessins, il y en aura pour tous.\\n\\nDurant cette journée, il vous sera également proposé :\\n\\n*   des stands d\'informations sur les projets urbains métropolitains mais aussi pour vous conseiller sur l\'architecture et l\'habitat.\\n*   des ateliers et des visites du quartier\\n*   différents espaces de restauration\\n\\n*   des animations musicales\\n\\nCette année, Philippe Madec incarne le parrain de cette édition et portera sur le réemploi et les matériaux biosourcés.\"}', '{\"fr\":[\"braderie\",\"architecture\",\"fives\",\"juin\",\"2019\",\"brocante\",\"maquette\",\"art\"]}', '{\"fr\":\"Entrée libre pour les visiteurs, donation de 5€ pour les exposants\"}', '{\"filename\":\"1b5b24d60be648eea52dbe3a0bedae72.base.image.jpg\",\"size\":{\"width\":700,\"height\":323},\"variants\":[{\"filename\":\"1b5b24d60be648eea52dbe3a0bedae72.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":744,\"height\":343}},{\"filename\":\"1b5b24d60be648eea52dbe3a0bedae72.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"WAAO - Centre d\'architecture et d\'urbanisme\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-15T08:00:00.000Z\",\"end\":\"2019-06-15T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":1,\"max\":99}', '[\"http://waao.fr/publication/braderie-de-larchitecture-2019/\",\"http://waao.fr/wp-content/uploads/2019/03/BULLETIN-DINSCRIPTION-BRADERIE-2019.pdf\",\"hello@waao.fr\",\"0374090040\"]', '2019-06-11 10:59:47', '2019-06-11 10:59:47', NULL, NULL, '[]', '[]');
INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `creator_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at`, `file_key`, `references`, `links`) VALUES
(581763, 60714720, 44809506, 44809506, 89904399, 89717521, 'impact-investing-day', '{\"fr\":\"IMPACT INVESTING DAY\"}', '{\"fr\":\"Une occasion unique de réunir les investisseurs et les entrepreneurs sociaux pour enfin se donner les moyens d\'accélérer leur croissance\"}', '{\"fr\":\"**Impact Investing Tour** permet d\'accélérer le financement des entrepreneurs sociaux et des acteurs de l\'ESS. Il est co-organisé par le Mouves avec la Banque des Territoires - Caisse des Dépôts et Hauts-de-France Active, la Métropole Européenne de Lille ainsi que la CRESS Hauts-de-France.\\n\\nCet événement a pour de but de former les entrepreneurs sociaux, rapprocher les financeurs, les investisseurs et les entrepreneurs sociaux mais aussi dans le but de valoriser et accompagner les initiatives à fort impact social.\\n\\nDécouvrez le programme complet de cette matinée :\\n\\n*   9h Accueil\\n*   9h30 Mot de bienvenue\\n*   9h45 Ateliers experts\\n*   10h45 Remise du prix Territoire\\n*   11h15 Pitch des financeurs\\n*   11h30 Ateliers financeurs\\n*   12h30 Apéro Networking\\n\\nVous êtes une association, une coopérative ou encore une entreprise d\'utilité sociale, vous mettez l\'impact sociétal et la résolution d\'un de ces grands défis au coeur de votre projet, Impact Investing Day est l\'événement incontournable.\"}', '{\"fr\":[\"investisseurs\",\"impact\",\"day\",\"juillet\",\"2019\"]}', '{\"fr\":\"Gratuit sur réservation\"}', '{\"filename\":\"dfcad0cb69d84e6bb6515dd44686e6ba.base.image.jpg\",\"credits\":\"MOUVES\",\"size\":{\"height\":922,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"dfcad0cb69d84e6bb6515dd44686e6ba.full.image.jpg\",\"size\":{\"height\":770,\"width\":585}},{\"type\":\"thumbnail\",\"filename\":\"dfcad0cb69d84e6bb6515dd44686e6ba.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-07-02T07:00:00.000Z\",\"end\":\"2019-07-02T11:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":18,\"max\":99}', '[\"http://mouves.org/Mouves2015/wp-content/uploads/2017/02/programme-iid-lille.pdf\",\"animation@mouves.org\",\"https://www.helloasso.com/associations/mouvement-des-entrepreneurs-sociaux/evenements/impact-investing-day-lille\"]', '2019-06-06 14:33:08', '2019-06-07 15:08:44', NULL, NULL, '[]', '[]'),
(577867, 65006917, 60654151, 60654151, 89904399, 69078313, 'cafe-citoyen-sur-le-climat', '{\"fr\":\"Café citoyen sur le climat\"}', '{\"fr\":\"La MEL s\'engage pour le climat. Elle invite les habitants du territoire à des cafés citoyens.\"}', '{\"fr\":\"La Métropole Européenne de Lille invite les habitants à des cafés citoyens pour réfléchir à un nouveau projet de société. L\'idée est de partager en toute convivialité des points de vue, des idées, des propositions sur la transition énergétique et climatique pour enrichir le Plan Climat Air Energie Territorial de la MEL.\\n\\n**Café citoyen : un sujet, un intervenant, un café !**\\n\\nUne dizaine de cafés citoyens sont organisés entre mars et juillet 2019. Poursuite en juin de ces rendez-vous convivaux ouverts à tous.\\n\\n**Café climat**\\n\\n**\\\" Les enjeux climatiques : pour qui, pour quoi, pour quand ? \\\"**\\n\\n**24 juin à 17h30**\\n\\n**au bar \\\"La luck\\\" à Lille**\\n\\nAvec les interventions de Bastien Alex, responsable du pôle « Climat,\\n\\nénergie et sécurité » à l’IRIS et Alice Baillat, chercheure à l’IRIS et docteure associée au CERI à Sciences Po Paris. Ils s’intéressent aux conséquences migratoires et sécuritaires des changements climatiques.\"}', '{}', '{\"fr\":\"Gratuit. Entrée libre.\"}', '{\"filename\":\"28270f9ed7704c84ba43b6e45a9ef8c4.base.image.jpg\",\"size\":{\"width\":700,\"height\":555},\"variants\":[{\"filename\":\"28270f9ed7704c84ba43b6e45a9ef8c4.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":523,\"height\":414}},{\"filename\":\"28270f9ed7704c84ba43b6e45a9ef8c4.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"MEL\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-24T15:30:00.000Z\",\"end\":\"2019-06-24T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"0359006474\"]', '2019-06-03 08:25:34', '2019-06-13 15:53:46', NULL, NULL, '[]', '[]'),
(577847, 76845055, 60654151, 60654151, 89904399, 79759308, 'cafe-citoyen-sur-la-sante-environnementale', '{\"fr\":\"Café citoyen sur la santé environnementale\"}', '{\"fr\":\"La MEL s\'engage pour le climat. Elle invite les habitants du territoire à des cafés citoyens.\"}', '{\"fr\":\"La Métropole Européenne de Lille invite les habitants à des cafés citoyens pour réfléchir à un nouveau projet de société. L\'idée est de partager en toute convivialité des points de vue, des idées, des propositions sur la transition énergétique et climatique pour enrichir le Plan Climat Air Energie Territorial de la MEL.\\n\\n**Café citoyen : un sujet, un intervenant, un café !**\\n\\nUne dizaine de cafés citoyens sont organisés entre mars et juillet 2019. Poursuite en juin de ces rendez-vous convivaux ouverts à tous.\\n\\n**Café sur la santé environnementale**\\n\\n**\\\" Quels liens entre les pollutions atmosphériques et la santé? \\\"**\\n\\n**17 juin à 18h30**\\n\\n**au Forum des Sciences à Villeneuve d\'Ascq**\\n\\nAvec les interventions de Damien Cuny et Florent Occelli, chercheurs\\n\\nà l’Université de Lille et membres de l’équipe porteuse du programme SIGLES. Ce programme cherche à déterminer si les populations présentant\\n\\nun état de santé amoindri vivent dans un environnement dégradé (air, eau, sol).\\n\\nL\'espace d\'expression proposera notamment de défaire collectivement les idées reçues sur la pollution de l’air, les polluants et leurs origines, les impacts de la pollution de l’air sur la santé.\"}', '{}', '{\"fr\":\"Gratuit. Entrée libre.\"}', '{\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":400,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.full.image.jpg\",\"size\":{\"height\":3417,\"width\":5126}},{\"type\":\"thumbnail\",\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-17T16:30:00.000Z\",\"end\":\"2019-06-17T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"0359006474\"]', '2019-06-03 08:08:22', '2019-06-03 08:18:47', '2019-06-13 09:42:21', NULL, '[]', '[]'),
(575776, 34883904, 10265018, 10265018, 89904399, 86180740, 'forum-au-feminum', '{\"fr\":\"Forum [Au FémiNum\']\"}', '{\"fr\":\"Venez découvrir les métiers du numérique, trouver une formation, rencontrer des entreprises pour un métier d\'aujourd\'hui et de demain !\"}', '{\"fr\":\"À propos de cet événement\\n\\nForum destiné 100% aux femmes, demandeuses d\'emploi ou en reconversion, désirant découvrir des métiers du numérique et de l\'informatique.\\n\\nAu programme :\\n\\n\\\\- témoignages de femmes travaillant dans le numérique\\n\\n\\\\- stands écoles et organismes de formation : présentation des formations démarrant dans les 6 mois avec les modalités de financement: découverte, initiation, formation qualifiante et diplômante ...\\n\\n\\\\- stands entreprises : témoignages, propositions de stages, marrainages, alternances...\\n\\nOrganisé par : l\'Etat-Préfecture avec la DRDFE (Direction Régionale aux Droits des Femmes et à l\'Egalité des chances), la Région Hauts-de-France, AXA et le CORIF (Conseil Orientation Recherche, Ingénierie et Formation pour l\'égalité hommes femmes)\\n\\nEn partenariat avec : Pôle Emploi\\n\\nEntreprises présentes : EuraTechnologies, IBM, Promod, Inzerty, Leansys...\\n\\nEcoles et organismes de formation: GRETA, AFPA, Popschool, Simplon, Wild code school, AFP2I, IFOCOP, FAFIEC, Université de Lille, EPSI, M2I Formation...\\n\\nAdresse\\n\\nSiège de Région Hauts-de-France\\n\\n151 Avenue du Président Hoover\\n\\nMetro ligne 2: station Lille Grand Palais\\n\\n59000 Lille\"}', '{}', '{\"fr\":\"Inscrivez-vous gratuitement : https://www.eventbrite.fr/e/billets-forum-aufeminum-femmes-numerique-62203184399\"}', '{\"filename\":\"8bebdc522e9447faa82b2ddbb2e71f9d.base.image.jpg\",\"size\":{\"width\":700,\"height\":341},\"variants\":[{\"filename\":\"8bebdc522e9447faa82b2ddbb2e71f9d.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":717,\"height\":349}},{\"filename\":\"8bebdc522e9447faa82b2ddbb2e71f9d.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-28T07:00:00.000Z\",\"end\":\"2019-06-28T14:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.eventbrite.fr/e/billets-forum-aufeminum-femmes-numerique-62203184399\"]', '2019-05-29 09:37:17', '2019-05-29 09:37:17', NULL, NULL, '[]', '[]'),
(574053, 86003192, 10265018, 10265018, 89904399, 73920393, 'semi-marathon-de-lille', '{\"fr\":\"Semi-marathon de Lille\"}', '{\"fr\":\"Le semi-marathon de Lille s\'élancera rue du Ballon le 31 août.\"}', '{\"fr\":\"**SEMI MARATHON**\\n\\n**HORAIRE**\\n\\n9h00 : Semi-marathon à label international (2001 et avant)\\n\\n**DÉPART**\\n\\nLe semi-marathon s’élancera Rue du Ballon à Lille\\n\\n**ARRIVÉE**\\n\\nL\'arrivée des courses se fera Boulevard Carnot à Lille\\n\\n**LIMITE D’INSCRIPTION**\\n\\nLes inscriptions sur internet seront fermées le lundi 25 août à minuit\\n\\nInscriptions sur les lieux de retrait des dossards les 28, 29 et 30 août\\n\\n**TARIFS**\\n\\n16€ jusqu’au 30 juin et 20€ à partir du 1er juillet\\n\\n**RETRAIT DES DOSSARDS**\\n\\nRetrait des dossards en magasin DECATHLON Campus le mercredi 28 août 2019 de 11h à 19h, le jeudi 29 août 2019 de 10h à 19h et le vendredi 30 août 2019 de 10h à 19h.\\n\\nRetrait des dossards le jour de la course au siège de la MEL (Métropole Européenne de Lille) rue du ballon à Lille de 7h à 8h45.\\n\\n**CONSIGNES**\\n\\nAu siège de la MEL\\n\\n**10KM**\\n\\n**HORAIRE**\\n\\n11h00 : 10 km à Label régional (2001 et avant)\\n\\n**DÉPART**\\n\\nLe 10km s’élancera Rue du Ballon à Lille\\n\\n**ARRIVÉE**\\n\\nL\'arrivée de la course se fera Boulevard Carnot à Lille\\n\\n**LIMITE D’INSCRIPTION**\\n\\nLes inscriptions sur internet seront fermées le lundi 25 août à minuit\\n\\nInscriptions sur les lieux de retrait des dossards les 28, 29 et 30 août\\n\\n**TARIFS**\\n\\n10€ jusqu’au 30 juin et 13€ à partir 1er juillet\\n\\n**RETRAIT DES DOSSARDS**\\n\\nRetrait des dossards en magasin DECATHLON Campus le mercredi 28 août 2019 de 11h à 19h, le jeudi 29 août 2019 de 10h à 19h et le vendredi 30 août 2019 de 10h à 19h.\\n\\nRetrait des dossards le jour de la course au siège de la MEL (Métropole Européenne de Lille) rue du ballon à Lille de 7h à 8h45.\\n\\n**CONSIGNES**\\n\\nAu siège de la MEL\"}', '{}', '{\"fr\":\"16€ jusqu’au 30 juin et 20€ à partir du 1er juillet\"}', '{\"filename\":\"e70a72c22f2443caae079425b3cc0626.base.image.jpg\",\"size\":{\"width\":700,\"height\":467},\"variants\":[{\"filename\":\"e70a72c22f2443caae079425b3cc0626.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":4000,\"height\":2667}},{\"filename\":\"e70a72c22f2443caae079425b3cc0626.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-08-31T07:00:00.000Z\",\"end\":\"2019-08-31T08:00:00.000Z\"},{\"begin\":\"2019-08-31T09:00:00.000Z\",\"end\":\"2019-08-31T10:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.njuko.net/lescoursesdelabradery2019/select_competition\"]', '2019-05-27 14:02:38', '2019-05-27 14:02:38', NULL, NULL, '[]', '[]'),
(569259, 93894863, 10265018, 10265018, 89904399, 30308718, 'carmen-de-bizet-a-lorchestre-national-de-lille', '{\"fr\":\"Carmen de Bizet à l\'Orchestre National de Lille\"}', '{\"fr\":\"Venez (re)découvrir l\'opéra Carmen de Bizet en juillet, joué par l\'Orchestre National de Lille.\"}', '{\"fr\":\"Opéra le plus joué au monde, **_Carmen_** ne cesse de conquérir un public toujours plus large. Sans doute la thématique intemporelle de la passion amoureuse mêlée de transgression n’est-elle pas étrangère à ce succès planétaire ? La bohémienne séductrice va se jouer du beau militaire Don José, le rendre fou de jalousie et le pousser au drame. La version semi-scénique qui sera donnée place l’orchestre symphonique au centre de la scène et lui redonne toute l’importance qu’il revêt dans cet opéra. Georges Bizet y fait montre de génie dans ses mélodies entêtantes ainsi que dans ses orchestrations raffinées, sans cesse renouvelées au gré de la large palette d’émotions imaginée par Mérimée : de la lumière radieuse et insouciante de l’été andalou à la noirceur du destin tragique de la femme fatale. L’osmose entre orchestre et chanteurs sera totale sous la direction d’Alexandre Bloch qui, après l’énorme succès des Pêcheurs de Perles en 2017, défendra avec fougue et clairvoyance le grand chef-d’œuvre de Bizet.\"}', '{}', '{}', '{\"filename\":\"1baf7daa7dad4282963a1e3ebc86e71f.base.image.jpg\",\"size\":{\"width\":700,\"height\":525},\"variants\":[{\"filename\":\"1baf7daa7dad4282963a1e3ebc86e71f.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":1024,\"height\":767}},{\"filename\":\"1baf7daa7dad4282963a1e3ebc86e71f.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"Instagram @onlille\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-07-09T18:00:00.000Z\",\"end\":\"2019-07-09T20:30:00.000Z\"},{\"begin\":\"2019-07-11T18:00:00.000Z\",\"end\":\"2019-07-11T20:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-20 08:46:43', '2019-05-20 08:46:43', NULL, NULL, '[]', '[]'),
(568663, 80311991, 82253124, 82253124, 89904399, 83889988, 'kopek-exposition-ephemere', '{\"fr\":\"KOPEK, exposition éphémère\"}', '{\"fr\":\"Exposition de l\'artiste KOPEK, concert du groupe Collector.\"}', '{\"fr\":\"KOPEK expose ses œuvres à LA FERME ! Le 15 juin 2019 de 11h à 20h. Il a travaillé autour de deux thèmes :\\n\\n*   binaire, position dans le noir\\n\\n*   nature, travail de la matière\\n\\nÀ 18h, autour d\'un verre, vous pourrez échanger avec lui et écouter le concert du groupe Collector, reprises jazz, funk, soul, disco, blues...\"}', '{}', '{}', '{\"filename\":\"2cdecbea487d4be58e7eddbfa147e64c.base.image.jpg\",\"credits\":null,\"size\":{\"height\":1069,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"2cdecbea487d4be58e7eddbfa147e64c.full.image.jpg\",\"size\":{\"height\":3424,\"width\":2243}},{\"type\":\"thumbnail\",\"filename\":\"2cdecbea487d4be58e7eddbfa147e64c.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-15T09:00:00.000Z\",\"end\":\"2019-06-15T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-17 14:33:00', '2019-05-17 15:27:09', NULL, NULL, '[]', '[]'),
(568657, 59847993, 10265018, 10265018, 89904399, 10175029, 'happy-day', '{\"fr\":\"Happy Day\"}', '{\"fr\":\"Le 2 juin prochain, à l’Opéra de Lille, tous les enfants Finoreille se réuniront pour une grande journée festive… en musique !\"}', '{\"fr\":\"Au programme de cette grande journée musicale :\\n\\nLes petits concerts par ateliers :\\n\\nNous aurons la chance ce jour-là de pouvoir entendre 7 concerts d’un quart d’heure réalisés par différents ateliers Finoreille :\\n\\n11h45 – atelier de Solesmes au Studio\\n\\n12h – atelier de Vauban au Grand Foyer\\n\\n13h15 – atelier de Beuvry au Studio\\n\\n13h30 – ateliers de Nort-Leulinghem et de Dunkerque à la Rotonde\\n\\n13h45 – atelier de Marcq-en-Baroeul au Grand Foyer\\n\\n14h15 – atelier de Villeneuve d’Ascq au Studio\\n\\n14h30 – atelier de Bois-Blancs à la Rotond\"}', '{}', '{}', '{\"filename\":\"5116b32bee674f4b988785afd2c99a5e.base.image.jpg\",\"size\":{\"width\":700,\"height\":409},\"variants\":[{\"filename\":\"5116b32bee674f4b988785afd2c99a5e.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":1200,\"height\":700}},{\"filename\":\"5116b32bee674f4b988785afd2c99a5e.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"Opéra de Lille\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-02T09:45:00.000Z\",\"end\":\"2019-06-02T13:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-17 14:29:02', '2019-05-17 14:29:02', NULL, NULL, '[]', '[]'),
(567801, 14777605, 10265018, 10265018, 89904399, 46540342, 'le-labo-mobile-sen-mel-atelier-decriture-a-la-bibliotheque-de-beaucamps-ligny', '{\"fr\":\"Le Labo Mobile s\'en MEL - Atelier d\'écriture à la bibliothèque de Beaucamps-Ligny\"}', '{\"fr\":\"Le Labo Mobile organise un atelier d\'écriture à la bibliothèque de Beaucamps-Ligny.\"}', '{\"fr\":\"Le Labomobile part en tournée dans les Hauts-de-France et fera escale dans plusieurs territoires ruraux de la MEL afin de proposer des ateliers d’écriture ludiques et gratuits aux plus jeunes. Écriture de chansons, de poésies ou de slam, le Labomobile propose une nouvelle manière d’aborder l’écriture en allant directement à la rencontre des jeunes. Les intervenants proposeront aux participants des ateliers de prendre part à un projet collectif construit au fur et à mesure de la tournée. Ce dernier sera rendu public une fois la tournée terminée.\"}', '{}', '{}', '{\"filename\":\"57d3ca66880d487abd1eec946cf2b300.base.image.jpg\",\"size\":{\"width\":700,\"height\":981},\"variants\":[{\"filename\":\"57d3ca66880d487abd1eec946cf2b300.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":567,\"height\":794}},{\"filename\":\"57d3ca66880d487abd1eec946cf2b300.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-09-28T12:00:00.000Z\",\"end\":\"2019-09-28T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-16 13:59:29', '2019-05-16 13:59:29', NULL, NULL, '[]', '[]'),
(567797, 86387909, 10265018, 10265018, 89904399, 50685988, 'le-labo-mobile-sen-mel-atelier-decriture-a-la-bibliotheque-de-sequedin', '{\"fr\":\"Le Labo Mobile s\'en MEL - Atelier d\'écriture à la bibliothèque de Sequedin\"}', '{\"fr\":\"Le Labo Mobile s\'en MEL organise un atelier d\'écriture à la bibliothèque de Sequedin\"}', '{\"fr\":\"Slam ton voyage. Au programme : introduction à l\'art du slam, réflexions poétiques autour des pays et voyages imaginaires, entraînement à la déclamation ; avec le slameur ZenMasta.\\n\\nLe Labomobile part en tournée dans les Hauts-de-France et fera escale dans plusieurs territoires ruraux de la MEL afin de proposer des ateliers d’écriture ludiques et gratuits aux plus jeunes. Écriture de chansons, de poésies ou de slam, le Labomobile propose une nouvelle manière d’aborder l’écriture en allant directement à la rencontre des jeunes. Les intervenants proposeront aux participants des ateliers de prendre part à un projet collectif construit au fur et à mesure de la tournée. Ce dernier sera rendu public une fois la tournée terminée.\"}', '{}', '{}', '{\"filename\":\"eed7cbf95562403786cbfb6b1d19918f.base.image.jpg\",\"size\":{\"width\":700,\"height\":981},\"variants\":[{\"filename\":\"eed7cbf95562403786cbfb6b1d19918f.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":567,\"height\":794}},{\"filename\":\"eed7cbf95562403786cbfb6b1d19918f.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-07-09T12:30:00.000Z\",\"end\":\"2019-07-09T14:00:00.000Z\"},{\"begin\":\"2019-07-11T12:30:00.000Z\",\"end\":\"2019-07-11T14:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-16 13:57:25', '2019-05-16 13:57:25', NULL, NULL, '[]', '[]'),
(567791, 38180687, 10265018, 10265018, 89904399, 2800780, 'le-labo-mobile-sen-mel-atelier-decriture-a-la-bibliotheque-dhaubourdin', '{\"fr\":\"Le Labo Mobile s\'en MEL - Atelier d\'écriture à la bibliothèque d\'Haubourdin\"}', '{\"fr\":\"Le Labo Mobile propose un atelier d\'écriture à la bibliothèque d\'Haubourdin.\"}', '{\"fr\":\"Venez participer à un atelier illustrations et écriture avec confection de masques mexicains et écriture ludique et poétique autour des pays et voyages imaginaires. Avec l\'illustratrice Anaïs Ruch.\\n\\nLe Labomobile part en tournée dans les Hauts-de-France et fera escale dans plusieurs territoires ruraux de la MEL afin de proposer des ateliers d’écriture ludiques et gratuits aux plus jeunes. Écriture de chansons, de poésies ou de slam, le Labomobile propose une nouvelle manière d’aborder l’écriture en allant directement à la rencontre des jeunes. Les intervenants proposeront aux participants des ateliers de prendre part à un projet collectif construit au fur et à mesure de la tournée. Ce dernier sera rendu public une fois la tournée terminée.\"}', '{}', '{}', '{\"filename\":\"b016cc57f6ec45968004ad73f8c32782.base.image.jpg\",\"size\":{\"width\":700,\"height\":981},\"variants\":[{\"filename\":\"b016cc57f6ec45968004ad73f8c32782.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":567,\"height\":794}},{\"filename\":\"b016cc57f6ec45968004ad73f8c32782.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-07-06T07:00:00.000Z\",\"end\":\"2019-07-06T10:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-16 13:54:01', '2019-05-16 13:54:01', NULL, NULL, '[]', '[]'),
(567772, 75046252, 10265018, 10265018, 89904399, 84892159, 'le-labo-mobile-sen-mel-atelier-a-la-bibliotheque-dennetieres-en-weppes', '{\"fr\":\"Le Labo Mobile s\'en MEL - Atelier à la bibliothèque d\'Ennetières-en-Weppes\"}', '{\"fr\":\"Le Labo Mobile propose un atelier d\'écriture sur le thème des montgolfières à la bibliothèque d\'Ennetières-en-Weppes\"}', '{\"fr\":\"Voyages en montgolfières. Au programme : confection de montgolfières et écriture de récits ou d\'envies de voyages imaginaires ; avec l\'auteure Nancy Guilbert.\\n\\nLe Labomobile part en tournée dans les Hauts-de-France et fera escale dans plusieurs territoires ruraux de la MEL afin de proposer des ateliers d’écriture ludiques et gratuits aux plus jeunes. Écriture de chansons, de poésies ou de slam, le Labomobile propose une nouvelle manière d’aborder l’écriture en allant directement à la rencontre des jeunes. Les intervenants proposeront aux participants des ateliers de prendre part à un projet collectif construit au fur et à mesure de la tournée. Ce dernier sera rendu public une fois la tournée terminée.\"}', '{}', '{}', '{\"filename\":\"8910c24a18894ccd9b7e7b98aa982139.base.image.jpg\",\"size\":{\"width\":700,\"height\":981},\"variants\":[{\"filename\":\"8910c24a18894ccd9b7e7b98aa982139.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":567,\"height\":794}},{\"filename\":\"8910c24a18894ccd9b7e7b98aa982139.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-14T07:00:00.000Z\",\"end\":\"2019-06-14T10:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-16 13:44:16', '2019-05-16 13:44:16', NULL, NULL, '[]', '[]'),
(567767, 90584329, 10265018, 10265018, 89904399, 20529368, 'le-labo-mobile-sen-mel-atelier-decriture-a-la-bibliotheque-de-fretin', '{\"fr\":\"Le Labo Mobile s\'en MEL - Atelier d\'écriture à la bibliothèque de Fretin\"}', '{\"fr\":\"Le Labo Mobile propose un atelier d\'écriture à la bibliothèques de Fretin\"}', '{\"fr\":\"À la découverte du pays imaginaire ! Au programme : Invention d\'un pays imaginaire (habitants, coutumes, style, alimentation, langage) et reproduction de sa carte géographique sur des parchemins faits \\\"maison\\\" ; avec la conteuse Chloé Penet.\\n\\nLe Labomobile part en tournée dans les Hauts-de-France et fera escale dans plusieurs territoires ruraux de la MEL afin de proposer des ateliers d’écriture ludiques et gratuits aux plus jeunes. Écriture de chansons, de poésies ou de slam, le Labomobile propose une nouvelle manière d’aborder l’écriture en allant directement à la rencontre des jeunes. Les intervenants proposeront aux participants des ateliers de prendre part à un projet collectif construit au fur et à mesure de la tournée. Ce dernier sera rendu public une fois la tournée terminée.\"}', '{}', '{}', '{\"filename\":\"d9b066f9f969452bb7f59cef5a9e1f8c.base.image.jpg\",\"size\":{\"width\":700,\"height\":981},\"variants\":[{\"filename\":\"d9b066f9f969452bb7f59cef5a9e1f8c.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":567,\"height\":794}},{\"filename\":\"d9b066f9f969452bb7f59cef5a9e1f8c.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-12T12:00:00.000Z\",\"end\":\"2019-06-12T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-16 13:41:41', '2019-05-16 13:41:41', NULL, NULL, '[]', '[]'),
(567764, 41060381, 10265018, 10265018, 89904399, 35764240, 'le-labo-mobile-sen-mel-atelier-a-la-bibliotheque-de-fromelles', '{\"fr\":\"Le Labo Mobile s\'en MEL - Atelier à la bibliothèque de Fromelles\"}', '{\"fr\":\"Le Labo Mobile propose un atelier d\'écriture à Fromelles.\"}', '{\"fr\":\"Petits jeux d\'écriture sur la place du marché, pour un dépaysement parfait.\\n\\nLe Labomobile part en tournée dans les Hauts-de-France et fera escale dans plusieurs territoires ruraux de la MEL afin de proposer des ateliers d’écriture ludiques et gratuits aux plus jeunes. Écriture de chansons, de poésies ou de slam, le Labomobile propose une nouvelle manière d’aborder l’écriture en allant directement à la rencontre des jeunes. Les intervenants proposeront aux participants des ateliers de prendre part à un projet collectif construit au fur et à mesure de la tournée. Ce dernier sera rendu public une fois la tournée terminée.\"}', '{}', '{}', '{\"filename\":\"15e41593bccb4705bc3d843407e3f788.base.image.jpg\",\"size\":{\"width\":700,\"height\":981},\"variants\":[{\"filename\":\"15e41593bccb4705bc3d843407e3f788.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":567,\"height\":794}},{\"filename\":\"15e41593bccb4705bc3d843407e3f788.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-07T14:00:00.000Z\",\"end\":\"2019-06-07T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-16 13:39:06', '2019-05-16 13:39:06', NULL, NULL, '[]', '[]'),
(567755, 6311424, 10265018, 10265018, 89904399, 86660666, 'le-labo-mobile-sen-mel-atelier', '{\"fr\":\"Le Labo Mobile s\'en MEL - Atelier\"}', '{\"fr\":\"Le Labo Mobile propose un atelier d\'écriture de chansons à la bibliothèque d\'Houplin-Ancoisne.\"}', '{\"fr\":\"À chaque pays son hymne ! Au programme : invention de chansons (paroles, style, mélodie), à la voix et au son (percussions corporelles, utilisations de petits instruments ou d\'ustensiles du quotidien...) ; avec la conteuse Chloé Penet\\n\\nLe Labomobile part en tournée dans les Hauts-de-France et fera escale dans plusieurs territoires ruraux de la MEL afin de proposer des ateliers d’écriture ludiques et gratuits aux plus jeunes. Écriture de chansons, de poésies ou de slam, le Labomobile propose une nouvelle manière d’aborder l’écriture en allant directement à la rencontre des jeunes. Les intervenants proposeront aux participants des ateliers de prendre part à un projet collectif construit au fur et à mesure de la tournée. Ce dernier sera rendu public une fois la tournée terminée.\"}', '{}', '{}', '{\"filename\":\"e793afa7a1004474a5d6acf2e875a71f.base.image.jpg\",\"size\":{\"width\":700,\"height\":981},\"variants\":[{\"filename\":\"e793afa7a1004474a5d6acf2e875a71f.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":567,\"height\":794}},{\"filename\":\"e793afa7a1004474a5d6acf2e875a71f.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-05T12:00:00.000Z\",\"end\":\"2019-06-05T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-16 13:34:27', '2019-05-16 13:34:27', NULL, NULL, '[]', '[]'),
(563141, 55646917, 10265018, 10265018, 89904399, 5788293, 'la-mel-participe-a-la-fete-internationale-des-marches-saison-5_736814', '{\"fr\":\"La MEL participe à la Fête Internationale des Marchés saison 5 !\"}', '{\"fr\":\"La Fête Internationale des Marchés revient du 10 au 26 mai dans la MEL.\"}', '{\"fr\":\"Pour sa 5e édition, la Fête internationale des marchés, parrainée par Jean-Luc Petitrenaud, Luana Belmondo et Christian Constant, revient du 10 au 26 mai 2019, en France et dans une quinzaine de pays du monde.\\n\\nL’occasion de faire redécouvrir aux consommateurs leurs marchés de détail, les produits de leurs terroirs et… leurs commerçants locaux !\\n\\nLa Fête Internationale des Marchés sera présente dans votre département, le Nord, aux dates et lieux suivants :\\n\\n**Wervicq-Sud :**\\n\\nPlace de l\'Europe :\\n\\nLes dimanches matin 12, 19 et 26 mai.\\n\\nDimanche 26 mai : le marché fête les mamans, distribution de roses !\"}', '{}', '{}', '{\"filename\":\"415b5f2e3ecb4d51b1dd8ec0efbb3150.base.image.jpg\",\"size\":{\"width\":700,\"height\":1050},\"variants\":[{\"filename\":\"415b5f2e3ecb4d51b1dd8ec0efbb3150.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":728,\"height\":1092}},{\"filename\":\"415b5f2e3ecb4d51b1dd8ec0efbb3150.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":201,\"height\":201}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-12T06:00:00.000Z\",\"end\":\"2019-05-12T11:00:00.000Z\"},{\"begin\":\"2019-05-19T06:00:00.000Z\",\"end\":\"2019-05-19T12:30:00.000Z\"},{\"begin\":\"2019-05-26T06:30:00.000Z\",\"end\":\"2019-05-26T13:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-10 08:44:38', '2019-05-10 08:44:38', NULL, NULL, '[]', '[]'),
(563137, 80165119, 10265018, 10265018, 89904399, 62898885, 'la-mel-participe-a-la-fete-internationale-des-marches-saison-5_524238', '{\"fr\":\"La MEL participe à la Fête Internationale des Marchés saison 5 !\"}', '{\"fr\":\"La Fête Internationale des Marchés revient du 10 au 26 mai dans la MEL.\"}', '{\"fr\":\"Pour sa 5e édition, la Fête internationale des marchés, parrainée par Jean-Luc Petitrenaud, Luana Belmondo et Christian Constant, revient du 10 au 26 mai 2019, en France et dans une quinzaine de pays du monde.\\n\\nL’occasion de faire redécouvrir aux consommateurs leurs marchés de détail, les produits de leurs terroirs et… leurs commerçants locaux !\\n\\nLa Fête Internationale des Marchés sera présente dans votre département, le Nord, aux dates et lieux suivants :\\n\\n**Tourcoing :**\\n\\nMarché du Centre (Grand\'Place) :\\n\\nLes lundis matin 13 et 20 mai, jeudis matin 16, 23 et 30 mai & samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\nCroix Rouge (Place Saint-Joseph) :\\n\\nLes mardis apès-midi 14 et 21 mai: promotions, dégustations et mises en avant de produits !\\n\\nPhalempins (Place des Phalempins) :\\n\\nLes mercredis matin 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nClinquet (Place Bocktaels) :\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\nBrun-Pain (Place Sainte-Anne):\\n\\nLes mercredis après-midi 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nPlace de la Bourgogne:\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Wervicq-Sud :**\\n\\nPlace de l\'Europe :\\n\\nLes dimanches matin 12, 19 et 26 mai.\\n\\nDimanche 26 mai : le marché fête les mamans, distribution de roses !\"}', '{}', '{}', '{\"filename\":\"ec0f002183884a6ea11ff68d63c4e275.base.image.jpg\",\"size\":{\"width\":700,\"height\":1050},\"variants\":[{\"filename\":\"ec0f002183884a6ea11ff68d63c4e275.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":728,\"height\":1092}},{\"filename\":\"ec0f002183884a6ea11ff68d63c4e275.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":201,\"height\":201}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-10T11:00:00.000Z\",\"end\":\"2019-05-10T15:30:00.000Z\"},{\"begin\":\"2019-05-11T06:00:00.000Z\",\"end\":\"2019-05-11T11:00:00.000Z\"},{\"begin\":\"2019-05-13T06:00:00.000Z\",\"end\":\"2019-05-13T11:00:00.000Z\"},{\"begin\":\"2019-05-14T11:00:00.000Z\",\"end\":\"2019-05-14T15:30:00.000Z\"},{\"begin\":\"2019-05-15T06:00:00.000Z\",\"end\":\"2019-05-15T11:00:00.000Z\"},{\"begin\":\"2019-05-15T11:00:00.000Z\",\"end\":\"2019-05-15T15:30:00.000Z\"},{\"begin\":\"2019-05-16T06:00:00.000Z\",\"end\":\"2019-05-16T11:00:00.000Z\"},{\"begin\":\"2019-05-17T11:00:00.000Z\",\"end\":\"2019-05-17T15:00:00.000Z\"},{\"begin\":\"2019-05-18T06:00:00.000Z\",\"end\":\"2019-05-18T11:00:00.000Z\"},{\"begin\":\"2019-05-20T06:00:00.000Z\",\"end\":\"2019-05-20T11:00:00.000Z\"},{\"begin\":\"2019-05-21T11:00:00.000Z\",\"end\":\"2019-05-21T15:00:00.000Z\"},{\"begin\":\"2019-05-22T06:00:00.000Z\",\"end\":\"2019-05-22T11:00:00.000Z\"},{\"begin\":\"2019-05-22T11:00:00.000Z\",\"end\":\"2019-05-22T15:30:00.000Z\"},{\"begin\":\"2019-05-23T06:00:00.000Z\",\"end\":\"2019-05-23T11:00:00.000Z\"},{\"begin\":\"2019-05-24T11:00:00.000Z\",\"end\":\"2019-05-24T15:30:00.000Z\"},{\"begin\":\"2019-05-25T06:00:00.000Z\",\"end\":\"2019-05-25T11:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-10 08:43:06', '2019-05-10 08:43:06', NULL, NULL, '[]', '[]'),
(563127, 76833986, 10265018, 10265018, 89904399, 35870359, 'la-mel-participe-a-la-fete-internationale-des-marches-saison-5_402000', '{\"fr\":\"La MEL participe à la Fête Internationale des Marchés saison 5 !\"}', '{\"fr\":\"La Fête Internationale des Marchés revient du 10 au 26 mai dans la MEL.\"}', '{\"fr\":\"Pour sa 5e édition, la Fête internationale des marchés, parrainée par Jean-Luc Petitrenaud, Luana Belmondo et Christian Constant, revient du 10 au 26 mai 2019, en France et dans une quinzaine de pays du monde.\\n\\nL’occasion de faire redécouvrir aux consommateurs leurs marchés de détail, les produits de leurs terroirs et… leurs commerçants locaux !\\n\\nLa Fête Internationale des Marchés sera présente dans votre département, le Nord, aux dates et lieux suivants :\\n\\n**Toufflers :**\\n\\nMarché du parking des écoles :\\n\\nLes samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Tourcoing :**\\n\\nMarché du Centre (Grand\'Place) :\\n\\nLes lundis matin 13 et 20 mai, jeudis matin 16, 23 et 30 mai & samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\nCroix Rouge (Place Saint-Joseph) :\\n\\nLes mardis apès-midi 14 et 21 mai: promotions, dégustations et mises en avant de produits !\\n\\nPhalempins (Place des Phalempins) :\\n\\nLes mercredis matin 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nClinquet (Place Bocktaels) :\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\nBrun-Pain (Place Sainte-Anne):\\n\\nLes mercredis après-midi 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nPlace de la Bourgogne:\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Wervicq-Sud :**\\n\\nPlace de l\'Europe :\\n\\nLes dimanches matin 12, 19 et 26 mai.\\n\\nDimanche 26 mai : le marché fête les mamans, distribution de roses !\"}', '{}', '{}', '{\"filename\":\"d49240a9ba124e1fa43d1f5ecca964c5.base.image.jpg\",\"size\":{\"width\":700,\"height\":1050},\"variants\":[{\"filename\":\"d49240a9ba124e1fa43d1f5ecca964c5.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":728,\"height\":1092}},{\"filename\":\"d49240a9ba124e1fa43d1f5ecca964c5.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":201,\"height\":201}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-11T06:00:00.000Z\",\"end\":\"2019-05-11T11:00:00.000Z\"},{\"begin\":\"2019-05-18T06:00:00.000Z\",\"end\":\"2019-05-18T11:00:00.000Z\"},{\"begin\":\"2019-05-25T06:00:00.000Z\",\"end\":\"2019-05-25T11:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-10 08:38:49', '2019-05-10 08:38:49', NULL, NULL, '[]', '[]'),
(563121, 8295807, 10265018, 10265018, 89904399, 15105033, 'la-mel-participe-a-la-fete-internationale-des-marches-saison-5_975317', '{\"fr\":\"La MEL participe à la Fête Internationale des Marchés saison 5 !\"}', '{\"fr\":\"La Fête Internationale des Marchés revient du 10 au 26 mai dans la MEL.\"}', '{\"fr\":\"Pour sa 5e édition, la Fête internationale des marchés, parrainée par Jean-Luc Petitrenaud, Luana Belmondo et Christian Constant, revient du 10 au 26 mai 2019, en France et dans une quinzaine de pays du monde.\\n\\nL’occasion de faire redécouvrir aux consommateurs leurs marchés de détail, les produits de leurs terroirs et… leurs commerçants locaux !\\n\\nLa Fête Internationale des Marchés sera présente dans votre département, le Nord, aux dates et lieux suivants :\\n\\n**Marcq-en-Baroeul :**\\n\\nMarché du Bourg (place du Général de Gaulle) :\\n\\nLes vendredis matin 10, 17 et 24 mai: promotions, dégustations et mises en avant de produits !\\n\\nMarché Rouges-Barres :\\n\\nPlace du Général Leclerc :\\n\\nLes mardis matin 14 et 21 mai : promotions, dégustations et mises en avant de produits !\\n\\nRue Marcel Dassault :\\n\\nles samedis matin 11, 18 et 25 mai: promotions, dégustations et mises en avant de produits !\\n\\nMarché Monplaisir (Place Paul Doumer) :\\n\\nLes samedis matin 11, 18 et 25 mai: promotions, dégustations et mises en avant de produits\\n\\n**Toufflers :**\\n\\nMarché du parking des écoles :\\n\\nLes samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Tourcoing :**\\n\\nMarché du Centre (Grand\'Place) :\\n\\nLes lundis matin 13 et 20 mai, jeudis matin 16, 23 et 30 mai & samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\nCroix Rouge (Place Saint-Joseph) :\\n\\nLes mardis apès-midi 14 et 21 mai: promotions, dégustations et mises en avant de produits !\\n\\nPhalempins (Place des Phalempins) :\\n\\nLes mercredis matin 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nClinquet (Place Bocktaels) :\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\nBrun-Pain (Place Sainte-Anne):\\n\\nLes mercredis après-midi 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nPlace de la Bourgogne:\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Wervicq-Sud :**\\n\\nPlace de l\'Europe :\\n\\nLes dimanches matin 12, 19 et 26 mai.\\n\\nDimanche 26 mai : le marché fête les mamans, distribution de roses !\"}', '{}', '{}', '{\"filename\":\"6b43c6edbb314cadbebb73d21bc21871.base.image.jpg\",\"size\":{\"width\":700,\"height\":1050},\"variants\":[{\"filename\":\"6b43c6edbb314cadbebb73d21bc21871.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":728,\"height\":1092}},{\"filename\":\"6b43c6edbb314cadbebb73d21bc21871.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":201,\"height\":201}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-10T06:00:00.000Z\",\"end\":\"2019-05-10T11:00:00.000Z\"},{\"begin\":\"2019-05-11T06:00:00.000Z\",\"end\":\"2019-05-11T11:00:00.000Z\"},{\"begin\":\"2019-05-14T06:00:00.000Z\",\"end\":\"2019-05-14T11:00:00.000Z\"},{\"begin\":\"2019-05-17T06:00:00.000Z\",\"end\":\"2019-05-17T11:00:00.000Z\"},{\"begin\":\"2019-05-18T06:00:00.000Z\",\"end\":\"2019-05-18T11:00:00.000Z\"},{\"begin\":\"2019-05-24T06:00:00.000Z\",\"end\":\"2019-05-24T11:00:00.000Z\"},{\"begin\":\"2019-05-25T06:00:00.000Z\",\"end\":\"2019-05-25T11:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-10 08:36:23', '2019-05-10 08:36:23', NULL, NULL, '[]', '[]'),
