(563098, 53290263, 10265018, 10265018, 89904399, 24627771, 'la-mel-participe-a-la-fete-internationale-des-marches-saison-5', '{\"fr\":\"La MEL participe à la Fête Internationale des Marchés saison 5 !\"}', '{\"fr\":\"La Fête Internationale des Marchés revient du 10 au 26 mai dans la MEL.\"}', '{\"fr\":\"Pour sa 5e édition, la Fête internationale des marchés, parrainée par Jean-Luc Petitrenaud, Luana Belmondo et Christian Constant, revient du 10 au 26 mai 2019, en France et dans une quinzaine de pays du monde.\\n\\nL’occasion de faire redécouvrir aux consommateurs leurs marchés de détail, les produits de leurs terroirs et… leurs commerçants locaux !\\n\\nLa Fête Internationale des Marchés sera présente dans votre département, le Nord, aux dates et lieux suivants :\\n\\n**Croix :**\\n\\nMarché du centre (place des martyrs) :\\n\\nLes mercredis matin 15 et 22 mai & les samedis matin 11, 18 et 25 mai.\\n\\nSamedi 25 mai : De nombreux cabas offerts par vos commerçants !\\n\\nMarché Saint-Pierre (place de la Liberté) :\\n\\nLes mardis matin 14 et 21 mai, les vendredis matin 10, 17 et 24 mai & les dimanches matin 12, 19 et 26 mai.\\n\\nDimanche 26 mai : De nombreux cabas offerts par vos commerçants !\\n\\n**Halluin :**\\n\\nHalle N\'Kong Zem (rue Gabriel Péri) :\\n\\nLes mercredis matin 15 et 22 mai.\\n\\nMercredi 15 mai : De nombreux bons d\'achat à gagner !\\n\\nMarché du Centre (place du Général de Gaulle):\\n\\nLes samedis matin 11, 18 et 25 mai.\\n\\nSamedi 11 mai : De nombreux bons d\'achat à gagner !\\n\\n**Hem :**\\n\\nGrand\' Place :\\n\\nLes dimanches matin 12, 19 et 26 mai.\\n\\nDimanches 12 mai : de nombreux bons d\'achat offerts !\\n\\n**Lys-lez-Lannoy :**\\n\\nPlace Dinah Derycke :\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Marcq-en-Baroeul :**\\n\\nMarché du Bourg (place du Général de Gaulle) :\\n\\nLes vendredis matin 10, 17 et 24 mai: promotions, dégustations et mises en avant de produits !\\n\\nMarché Rouges-Barres :\\n\\nPlace du Général Leclerc :\\n\\nLes mardis matin 14 et 21 mai : promotions, dégustations et mises en avant de produits !\\n\\nRue Marcel Dassault :\\n\\nles samedis matin 11, 18 et 25 mai: promotions, dégustations et mises en avant de produits !\\n\\nMarché Monplaisir (Place Paul Doumer) :\\n\\nLes samedis matin 11, 18 et 25 mai: promotions, dégustations et mises en avant de produits\\n\\n**Toufflers :**\\n\\nMarché du parking des écoles :\\n\\nLes samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Tourcoing :**\\n\\nMarché du Centre (Grand\'Place) :\\n\\nLes lundis matin 13 et 20 mai, jeudis matin 16, 23 et 30 mai & samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\nCroix Rouge (Place Saint-Joseph) :\\n\\nLes mardis apès-midi 14 et 21 mai: promotions, dégustations et mises en avant de produits !\\n\\nPhalempins (Place des Phalempins) :\\n\\nLes mercredis matin 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nClinquet (Place Bocktaels) :\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\nBrun-Pain (Place Sainte-Anne):\\n\\nLes mercredis après-midi 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nPlace de la Bourgogne:\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Wervicq-Sud :**\\n\\nPlace de l\'Europe :\\n\\nLes dimanches matin 12, 19 et 26 mai.\\n\\nDimanche 26 mai : le marché fête les mamans, distribution de roses !\"}', '{}', '{}', '{\"filename\":\"3bf9889be93d48598fea4e9c8f8f5491.base.image.jpg\",\"size\":{\"width\":700,\"height\":1050},\"variants\":[{\"filename\":\"3bf9889be93d48598fea4e9c8f8f5491.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":728,\"height\":1092}},{\"filename\":\"3bf9889be93d48598fea4e9c8f8f5491.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":201,\"height\":201}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-10T06:00:00.000Z\",\"end\":\"2019-05-10T10:00:00.000Z\"},{\"begin\":\"2019-05-11T06:00:00.000Z\",\"end\":\"2019-05-11T10:00:00.000Z\"},{\"begin\":\"2019-05-12T06:00:00.000Z\",\"end\":\"2019-05-12T10:00:00.000Z\"},{\"begin\":\"2019-05-15T06:00:00.000Z\",\"end\":\"2019-05-15T10:00:00.000Z\"},{\"begin\":\"2019-05-17T06:00:00.000Z\",\"end\":\"2019-05-17T10:00:00.000Z\"},{\"begin\":\"2019-05-18T06:00:00.000Z\",\"end\":\"2019-05-18T10:00:00.000Z\"},{\"begin\":\"2019-05-19T06:00:00.000Z\",\"end\":\"2019-05-19T10:00:00.000Z\"},{\"begin\":\"2019-05-21T06:00:00.000Z\",\"end\":\"2019-05-21T10:00:00.000Z\"},{\"begin\":\"2019-05-22T06:00:00.000Z\",\"end\":\"2019-05-22T10:00:00.000Z\"},{\"begin\":\"2019-05-24T06:00:00.000Z\",\"end\":\"2019-05-24T10:00:00.000Z\"},{\"begin\":\"2019-05-25T06:00:00.000Z\",\"end\":\"2019-05-25T10:00:00.000Z\"},{\"begin\":\"2019-05-26T06:00:00.000Z\",\"end\":\"2019-05-26T10:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-10 08:23:51', '2019-05-10 08:23:51', NULL, NULL, '[]', '[]'),
(563040, 29601647, 10265018, 10265018, 89904399, 11186551, 'le-nord-participe-a-la-fete-internationale-des-marches-saison-5', '{\"fr\":\"La MEL participe à la Fête Internationale des Marchés saison 5 !\"}', '{\"fr\":\"La Fête Internationale des Marchés revient du 10 au 26 mai dans la MEL.\"}', '{\"fr\":\"Pour sa 5e édition, la Fête internationale des marchés, parrainée par Jean-Luc Petitrenaud, Luana Belmondo et Christian Constant, revient du 10 au 26 mai 2019, en France et dans une quinzaine de pays du monde.\\n\\nL’occasion de faire redécouvrir aux consommateurs leurs marchés de détail, les produits de leurs terroirs et… leurs commerçants locaux !\\n\\nLa Fête Internationale des Marchés sera présente dans votre département, le Nord, aux dates et lieux suivants :\\n\\n**Comines :**\\n\\nGrand\' Place :\\n\\nLes lundis matin 13 et 20 mai & les samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Croix :**\\n\\nMarché du centre (place des martyrs) :\\n\\nLes mercredis matin 15 et 22 mai & les samedis matin 11, 18 et 25 mai.\\n\\nSamedi 25 mai : De nombreux cabas offerts par vos commerçants !\\n\\nMarché Saint-Pierre (place de la Liberté) :\\n\\nLes mardis matin 14 et 21 mai, les vendredis matin 10, 17 et 24 mai & les dimanches matin 12, 19 et 26 mai.\\n\\nDimanche 26 mai : De nombreux cabas offerts par vos commerçants !\\n\\n**Halluin :**\\n\\nHalle N\'Kong Zem (rue Gabriel Péri) :\\n\\nLes mercredis matin 15 et 22 mai.\\n\\nMercredi 15 mai : De nombreux bons d\'achat à gagner !\\n\\nMarché du Centre (place du Général de Gaulle):\\n\\nLes samedis matin 11, 18 et 25 mai.\\n\\nSamedi 11 mai : De nombreux bons d\'achat à gagner !\\n\\n**Hem :**\\n\\nGrand\' Place :\\n\\nLes dimanches matin 12, 19 et 26 mai.\\n\\nDimanches 12 mai : de nombreux bons d\'achat offerts !\\n\\n**Lys-lez-Lannoy :**\\n\\nPlace Dinah Derycke :\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Marcq-en-Baroeul :**\\n\\nMarché du Bourg (place du Général de Gaulle) :\\n\\nLes vendredis matin 10, 17 et 24 mai: promotions, dégustations et mises en avant de produits !\\n\\nMarché Rouges-Barres :\\n\\nPlace du Général Leclerc :\\n\\nLes mardis matin 14 et 21 mai : promotions, dégustations et mises en avant de produits !\\n\\nRue Marcel Dassault :\\n\\nles samedis matin 11, 18 et 25 mai: promotions, dégustations et mises en avant de produits !\\n\\nMarché Monplaisir (Place Paul Doumer) :\\n\\nLes samedis matin 11, 18 et 25 mai: promotions, dégustations et mises en avant de produits\\n\\n**Toufflers :**\\n\\nMarché du parking des écoles :\\n\\nLes samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Tourcoing :**\\n\\nMarché du Centre (Grand\'Place) :\\n\\nLes lundis matin 13 et 20 mai, jeudis matin 16, 23 et 30 mai & samedis matin 11, 18 et 25 mai : promotions, dégustations et mises en avant de produits !\\n\\nCroix Rouge (Place Saint-Joseph) :\\n\\nLes mardis apès-midi 14 et 21 mai: promotions, dégustations et mises en avant de produits !\\n\\nPhalempins (Place des Phalempins) :\\n\\nLes mercredis matin 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nClinquet (Place Bocktaels) :\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\nBrun-Pain (Place Sainte-Anne):\\n\\nLes mercredis après-midi 15 et 22 mai: promotions, dégustations et mises en avant de produits !\\n\\nPlace de la Bourgogne:\\n\\nLes vendredis après-midi 10, 17 et 24 mai : promotions, dégustations et mises en avant de produits !\\n\\n**Wervicq-Sud :**\\n\\nPlace de l\'Europe :\\n\\nLes dimanches matin 12, 19 et 26 mai.\\n\\nDimanche 26 mai : le marché fête les mamans, distribution de roses !\"}', '{}', '{}', '{\"filename\":\"7e808f0d5a7a472fb72c3c2d2126df7d.base.image.jpg\",\"credits\":null,\"size\":{\"height\":1050,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"7e808f0d5a7a472fb72c3c2d2126df7d.full.image.jpg\",\"size\":{\"height\":1092,\"width\":728}},{\"type\":\"thumbnail\",\"filename\":\"7e808f0d5a7a472fb72c3c2d2126df7d.thumb.image.jpg\",\"size\":{\"height\":201,\"width\":201}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-11T06:00:00.000Z\",\"end\":\"2019-05-11T11:00:00.000Z\"},{\"begin\":\"2019-05-13T06:00:00.000Z\",\"end\":\"2019-05-13T11:00:00.000Z\"},{\"begin\":\"2019-05-18T06:00:00.000Z\",\"end\":\"2019-05-18T11:00:00.000Z\"},{\"begin\":\"2019-05-20T06:00:00.000Z\",\"end\":\"2019-05-20T11:00:00.000Z\"},{\"begin\":\"2019-05-25T06:00:00.000Z\",\"end\":\"2019-05-25T11:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-10 07:26:01', '2019-05-10 08:17:38', NULL, NULL, '[]', '[]'),
(562447, 25864706, 64095289, 64095289, 89904399, 90032363, 'fete-de-lenvironnement-et-des-solidarites', '{\"fr\":\"Fête de l’environnement et des solidarités\"}', '{\"fr\":\"La fête de l\'environnement revient à la gare saint sauveur !\"}', '{\"fr\":\"La Maison Régionale de l’Environnement et des Solidarités, accompagnée de son réseau d’associations et des Lille-Makers viennent occuper la Gare Saint Sauveur pour partager leurs connaissances et leur savoir-faire le temps d’un week-end festif.\\n\\n**Au programme** :\\n\\n*   La soirée du vendredi dédiée à « Décamper » : ateliers, temps d’échanges, projections autour des thèmes de l’exil et des politiques migratoires récentes.\\n*   L’Open Bidouille Camp lillois #5, Plus de 20 ateliers gratuits et accessibles à un public non initié. Venez bidouiller, inventer, échanger, découvrir et expérimenter ensemble l’art du « fait maison » sous toutes ses formes.\\n*   Des projections : Films et court-métrages qui questionnent notre rapport à l’écologie et à la solidarité.\\n*   Un espace mini-conf’ – débat autour des thématiques solidaires et responsables : agriculture urbaine, solidarités entre les populations, sobriété énergétique …\\n*   Des expositions.\\n*   Des animations tout au long du week-end : concerts, jeux, happening …\\n*   Du partage, de la bonne humeur, la découverte d’alternatives économiques et écologiques au quotidien !\"}', '{\"fr\":[\"semaine\",\"solidarité\",\"envrionnement\",\"lille\",\"metropolelilloise\",\"saintsauveur\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"d5a01904875c4a0aa9aa716d2c7bc441.base.image.jpg\",\"credits\":\"Vincent Lecigne\",\"size\":{\"height\":467,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"d5a01904875c4a0aa9aa716d2c7bc441.full.image.jpg\",\"size\":{\"height\":200,\"width\":300}},{\"type\":\"thumbnail\",\"filename\":\"d5a01904875c4a0aa9aa716d2c7bc441.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-17T16:30:00.000Z\",\"end\":\"2019-05-17T22:00:00.000Z\"},{\"begin\":\"2019-05-18T12:00:00.000Z\",\"end\":\"2019-05-18T22:00:00.000Z\"},{\"begin\":\"2019-05-19T12:00:00.000Z\",\"end\":\"2019-05-19T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03.20.52.12.02\",\"mres@mres-asso.org\",\"http://www.mres-asso.org\"]', '2019-05-09 12:10:04', '2019-05-09 12:12:06', NULL, NULL, '[]', '[]'),
(561199, 20596006, 64095289, 64095289, 89904399, 86888201, '333933', '{\"fr\":\"CARNAVAL > CAP SUR L\'ELDORADO !\"}', '{\"fr\":\"Venez decouvrir l\'ediditon 2019 de cette parade carnavalesque\"}', '{\"fr\":\"La Ville de Lomme s’apprête à faire la fête sur la thématique colorée d’Eldorado de Lille 3000 !\\n\\nAu programme : un spectacle pyrosymphonique, une parade et des animations, sans oublier le concert gratuit en plein air pour danser jusqu’au bout de la nuit !\\n\\nSamedi 8/06\\n-----------\\n\\n**21h : Concert d’Hélène SEGARA** avec en **première partie Jérémy Charvet**\\n\\n_Place du Marché Foire_\\n\\n**23h : Spectacle pyrosymphonique**\\n\\n_Espaces verts à côté de l’Hôtel de Ville_\\n\\nDimanche 9/06\\n-------------\\n\\n11h : **Baptême des chars « Fête des morts », « Cité d’or », « coco » et « Mexique »** avec la participation de Magic Parade\\n\\n_Place Charles Gide_\\n\\n**14h à 18h : Animations**\\n\\n_Espaces verts face à la Place Denis Cordonnier_\\n\\n\\\\> **Camp médiéval** par « Les seigneurs de l’aube »\\n\\n> **Les cabanes dans les nuages** par « la Cie L’éléphant dans le boa »\\n\\n\\\\> **Jeux anciens** du « Secours Populaire »\\n\\n> **Ateliers multi activités autours des différentes pratiques de cirque** par le « Centre Régional des Arts du Cirque »\\n\\n\\\\> **Spectacles et animations de théâtre de rue** (jusque 17h) avec les Bosquets\\n\\n> **Premiers secours**, cie Odile Pinson\\n\\n> **Concours de déguisements** au stand photo qui accueillera les enfants déguisés sur la t**hématique de l’Eldorado**\\n\\n> **Animation des tribunes** par l’association OSML G.V. (Zumba)\\n\\n**15h30 à 18h30 : Parade carnavalesque**\\n\\n_Depuis l’angle de la rue du Maire Becquart et l’avenue de Dunkerque_\\n\\nLes chars et les associations prendront la direction de la Place Denis Cordonnier jusqu’aux tribunes*.\\n\\n**18h30 : Apéritif festi**f animé par l’association Music Act\\n\\nDevant l’Hôtel de Ville\"}', '{\"fr\":[\"carnaval\",\"eldorado\",\"metropolelilloise\",\"parade\",\"lomme\",\"lille3000\",\"concert\",\"spectacle\"]}', '{\"fr\":\"invitations à retirer auprès du Service Animation Vie Associative à partir du 28/05\"}', '{\"filename\":\"1e1e3ed8ee7d476db9087dc240c2bb87.base.image.jpg\",\"size\":{\"width\":700,\"height\":467},\"variants\":[{\"filename\":\"1e1e3ed8ee7d476db9087dc240c2bb87.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":300,\"height\":200}},{\"filename\":\"1e1e3ed8ee7d476db9087dc240c2bb87.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"Alexandre Traisnel\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-08T19:00:00.000Z\",\"end\":\"2019-06-08T21:00:00.000Z\"},{\"begin\":\"2019-06-09T09:00:00.000Z\",\"end\":\"2019-06-09T16:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 48 44 16\"]', '2019-05-07 09:14:53', '2019-05-07 15:43:28', NULL, NULL, '[]', '[]'),
(560879, 24218253, 64095289, 64095289, 89904399, 4128039, 'la-fete-mondial-du-jeu', '{\"fr\":\"LA FETE MONDIAL DU JEU\"}', '{\"fr\":\"Venez jouer seul ou en famille à la Médiathèque\"}', '{\"fr\":\"Rendez-vous le samedi 25 mai dès 11h30 pour participer à la fête mondiale du jeu !\\n\\nProgrammation :\\n\\n*   APÉRO QUIZ, de 11h30 à 12h30\\n\\n*   TOURNOI MARIO TENNIS ACES SUR SWITCH de 14h30 à 16h\\n*   JEUX DE SOCIÉTÉ de 14h30 à 17h30\\n*   RÉTRO GAMING de 14h30 à 17h30\\n*   BORNES D’ARCADE de 14h30 à 17h30\\n\\n*   DÉCOUVERTE D’UNE NOUVEAUTÉ SWITCH de 16h30 à 17h30\\n\\nEt dans le jardin, si le temps le permet, jouez au mikado géant et au mölkky !\"}', '{\"fr\":[\"jeu\",\"la madeleine\",\"fête\",\"mediathéque\"]}', '{\"fr\":\"Accès libre et gratuit\"}', '{\"filename\":\"65030669cc5242739257e4f1c7bdb7cd.base.image.jpg\",\"credits\":\"Pascaline Chombart\",\"size\":{\"height\":465,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"65030669cc5242739257e4f1c7bdb7cd.full.image.jpg\",\"size\":{\"height\":398,\"width\":600}},{\"type\":\"thumbnail\",\"filename\":\"65030669cc5242739257e4f1c7bdb7cd.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-25T09:30:00.000Z\",\"end\":\"2019-05-25T15:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"mediatheque@ville-lamadeleine.fr\",\"03 59 09 59 09\"]', '2019-05-06 14:27:16', '2019-05-07 09:15:21', NULL, NULL, '[]', '[]'),
(560820, 13059734, 64095289, 64095289, 89904399, NULL, '551732', '{\"fr\":\"24ème Festival l\'Enfance de l\'Art\"}', '{\"fr\":\"Spéctacle jeune public\"}', '{\"fr\":\"Le Festival L\'Enfance de l\'Art de Wattrelos organise sa 24e édition cette année ! Une belle occasion d\'assister à une ribambelle de spectacles en famille, du 11 mai au 2juin 2019.\\n\\nL\'Enfance de l\'Art, c\'est un rendez-vous jeune public qui rassemble une dizaine de compagnies du spectacle vivant. Au programme : arts du cirque, concerts, danse, théâtre, contes, marionnettes...\"}', '{\"fr\":[\"festival\",\"art\",\"wattrelos\",\"spectacle\",\"danse\",\"thêatre\"]}', '{\"fr\":\"Tarif 2 € - gratuit pour les moins de 18 ans\"}', '{\"filename\":\"32fd6d836e5246bf81145a181aa52327.base.image.jpg\",\"size\":{\"width\":700,\"height\":447},\"variants\":[{\"filename\":\"32fd6d836e5246bf81145a181aa52327.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":600,\"height\":383}},{\"filename\":\"32fd6d836e5246bf81145a181aa52327.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":201,\"height\":201}}],\"credits\":\"Pascaline Chombart\"}', 1, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-10T15:00:00.000Z\",\"end\":\"2019-05-10T18:00:00.000Z\"},{\"begin\":\"2019-05-11T15:00:00.000Z\",\"end\":\"2019-05-11T18:00:00.000Z\"},{\"begin\":\"2019-05-12T07:30:00.000Z\",\"end\":\"2019-05-12T17:00:00.000Z\"},{\"begin\":\"2019-05-14T08:30:00.000Z\",\"end\":\"2019-05-14T11:00:00.000Z\"},{\"begin\":\"2019-05-14T16:30:00.000Z\",\"end\":\"2019-05-14T18:00:00.000Z\"},{\"begin\":\"2019-05-15T13:00:00.000Z\",\"end\":\"2019-05-15T18:00:00.000Z\"},{\"begin\":\"2019-05-17T17:00:00.000Z\",\"end\":\"2019-05-17T21:00:00.000Z\"},{\"begin\":\"2019-05-18T15:00:00.000Z\",\"end\":\"2019-05-18T18:00:00.000Z\"},{\"begin\":\"2019-05-22T12:30:00.000Z\",\"end\":\"2019-05-22T15:00:00.000Z\"},{\"begin\":\"2019-05-22T15:00:00.000Z\",\"end\":\"2019-05-22T19:00:00.000Z\"},{\"begin\":\"2019-05-25T15:00:00.000Z\",\"end\":\"2019-05-25T19:00:00.000Z\