(560814, 1913773, 64095289, 64095289, 89904399, 9057783, 'tournoi-de-petanque_987922', '{\"fr\":\"Tournoi de pétanque\"}', '{\"fr\":\"Compétition  gratuite organisée par la Pétanque Jean Zay et l\'EPHAD\"}', '{\"fr\":\"Le conseil de quartier Clinquet/Bois d\'Achelles et l\'EPHAD des Flandres avec la participation de l\'association \\\"Pétanque Jean Zay\\\" organisent un tournoi pétanque.\\n\\n\\\\- Doublette à la mêlée\\n\\n\\\\- Démonstration de danses country\\n\\n\\\\- Buvette et petite restauration sur place\"}', '{}', '{\"fr\":\"Inscriptions (gratuit):sur place de 9h à 9h45 ( places limitées)\"}', '{\"filename\":\"0e1a31852c9e4d80a278a0439e7ea48f.base.image.jpg\",\"credits\":\"Eric POLLET\",\"size\":{\"height\":457,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"0e1a31852c9e4d80a278a0439e7ea48f.full.image.jpg\",\"size\":{\"height\":391,\"width\":600}},{\"type\":\"thumbnail\",\"filename\":\"0e1a31852c9e4d80a278a0439e7ea48f.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-12T08:00:00.000Z\",\"end\":\"2019-05-12T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-06 13:45:04', '2019-05-07 09:44:37', NULL, NULL, '[]', '[]'),
(560763, 90359950, 64095289, 64095289, 89904399, 31692801, 'lutherie-sauvage', '{\"fr\":\"LUTHERIE SAUVAGE\"}', '{\"fr\":\"Ateliers de fabrication d\'instruments de musique\"}', '{\"fr\":\"La Ludo médiathèque Colette et le Conservatoire de Tourcoing proposent des ateliers de fabrication d\'instruments de musique à partir de matériaux de récupération permettant de découvrir les rudiments de la lutherie. Découvrez ces instruments uniques mis en action par leurs inventeurs lors de 3 événements festifs :\\n\\n\\\\- le 25 mai au jardin des cultures lors de la Fête du jeu.\\n\\n\\\\- le 19 juin au jardin botanique lors de la Fête de la musique des enfants.\\n\\n\\\\- le 12 juin à 15h30 à la Ludo médiathèque Colette pour une racontine tout en musique !\"}', '{\"fr\":[\"musique\",\"tourcoing\"]}', '{\"fr\":\"tout public\"}', '{\"filename\":\"b9853321817d4c89983315d912167380.base.image.jpg\",\"credits\":\"Pascaline Chombart\",\"size\":{\"height\":466,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"b9853321817d4c89983315d912167380.full.image.jpg\",\"size\":{\"height\":399,\"width\":600}},{\"type\":\"thumbnail\",\"filename\":\"b9853321817d4c89983315d912167380.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-25T15:00:00.000Z\",\"end\":\"2019-05-25T19:00:00.000Z\"},{\"begin\":\"2019-05-26T15:30:00.000Z\",\"end\":\"2019-05-26T16:30:00.000Z\"},{\"begin\":\"2019-05-27T15:00:00.000Z\",\"end\":\"2019-05-27T18:00:00.000Z\"},{\"begin\":\"2019-05-28T15:00:00.000Z\",\"end\":\"2019-05-28T18:00:00.000Z\"},{\"begin\":\"2019-05-29T15:00:00.000Z\",\"end\":\"2019-05-29T18:00:00.000Z\"},{\"begin\":\"2019-05-30T15:00:00.000Z\",\"end\":\"2019-05-30T18:00:00.000Z\"},{\"begin\":\"2019-05-31T15:00:00.000Z\",\"end\":\"2019-05-31T18:00:00.000Z\"},{\"begin\":\"2019-06-03T15:00:00.000Z\",\"end\":\"2019-06-03T18:00:00.000Z\"},{\"begin\":\"2019-06-04T15:00:00.000Z\",\"end\":\"2019-06-04T18:00:00.000Z\"},{\"begin\":\"2019-06-05T16:30