(560708, 98968086, 64095289, 64095289, 89904399, 8462637, 'avant-scene', '{\"fr\":\"AVANT-SCÈNE\"}', '{\"fr\":\"Concert des élèves du conservatoire de tourcoing\"}', '{\"fr\":\"L’ « avant-scène » est une belle opportunité pour les élèves des classes de clarinette, flûte et hautbois de s’entraîner et de se mettre en condition pour préparer les évaluations de fin de cycle.\"}', '{\"fr\":[\"concert\",\"tourcoing\",\"concervatoire\",\"avant scène\"]}', '{\"fr\":\"Entrée libre sur réservation\"}', '{\"filename\":\"f8a4bb66be454c2f992dae6c32abef8b.base.image.jpg\",\"credits\":\"Pascaline Chombart\",\"size\":{\"height\":466,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"f8a4bb66be454c2f992dae6c32abef8b.full.image.jpg\",\"size\":{\"height\":399,\"width\":600}},{\"type\":\"thumbnail\",\"filename\":\"f8a4bb66be454c2f992dae6c32abef8b.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-06T16:30:00.000Z\",\"end\":\"2019-05-06T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://culture-billetterie.tourcoing.fr\"]', '2019-05-06 12:34:53', '2019-05-07 09:16:55', NULL, NULL, '[]', '[]'),
(558993, 56780247, 10265018, 10265018, 89904399, 83500988, 'demonstration-para-hockey-et-match-gala', '{\"fr\":\"Démonstration para-hockey et match gala\"}', '{\"fr\":\"Le match de gala du samedi 18 mai sera précédé par une démonstration de para-hockey.\"}', '{\"fr\":\"Le match de gala du samedi 18 mai sera précédé par une démonstration de para-hockey.\\n\\nLa démonstration opposera une équipe composée de 6 joueurs et 1 gardien venant de Cherbourg ainsi qu\'une équipe composée de joueurs originaires de Rouen, de Belgique et de l\'équipe Loisirs des Lions.\\n\\nUne journée portes ouvertes avec essai de para-hockey est prévue le lendemain, dimanche 19 mai.\"}', '{}', '{}', '{\"filename\":\"d8ee3d213bfe487f83fc3d21083f8a9c.base.image.jpg\",\"size\":{\"width\":700,\"height\":258},\"variants\":[{\"filename\":\"d8ee3d213bfe487f83fc3d21083f8a9c.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":851,\"height\":313}},{\"filename\":\"d8ee3d213bfe487f83fc3d21083f8a9c.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-18T16:00:00.000Z\",\"end\":\"2019-05-18T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-05-02 10:20:31', '2019-05-02 10:20:31', NULL, NULL, '[]', '[]'),
(556599, 82468860, 60654151, 60654151, 89904399, 86888201, 'cafe-citoyen-sur-lavenir-de-notre-environnement', '{\"fr\":\"Café citoyen sur l\'avenir de notre environnement\"}', '{\"fr\":\"La MEL s\'engage pour le climat. Elle invite les habitants du territoire à des cafés citoyens.\"}', '{\"fr\":\"La Métropole Européenne de Lille invite les habitants à des cafés citoyens pour réfléchir à un nouveau projet de société. L\'idée est de partager en toute convivialité des points de vue, des idées, des propositions sur la transition énergétique et climatique pour enrichir le Plan Climat Air Energie Territorial de la MEL.\\n\\n**Café citoyen : un sujet, un intervenant, un café !**\\n\\nUne dizaine de cafés citoyens sont organisés entre mars et juillet 2019. Poursuite de ces rendez-vous convivaux ouverts à tous avec un café \\\"gesticulé\\\" sur le thème de l\'avenir de notre environnement.\\n\\n**Café gesticulé avec le collectif L\'Etincelle**\\n\\n**\\\" Qui peut sauver le climat ? \\\"**\\n\\n**12 juin à 18h30 en mairie de Lomme (salle Jean-Jaurès)**\\n\\n_L\'Etincelle_ est une coopérative d\'éducation populaire. Elle organise des ateliers sous forme d\'expression théâtralisée mélangeant humour et auto-dérision. L\'espace d\'expression proposé se construit collectivement à partir des vécus, colères, envies des participants, pour réfléchir ensemble sur l\'avenir de notre environnement.\"}', '{}', '{\"fr\":\"Gratuit. Entrée libre.\"}', '{\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":400,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.full.image.jpg\",\"size\":{\"height\":3417,\"width\":5126}},{\"type\":\"thumbnail\",\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-12T16:30:00.000Z\",\"end\":\"2019-06-12T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"0359006474\"]', '2019-04-26 13:09:15', '2019-04-26 13:14:40', NULL, NULL, '[]', '[]'),
(556569, 20070919, 60654151, 60654151, 89904399, 74375792, 'cafe-citoyen-sur-lavenir-du-climat', '{\"fr\":\"Café citoyen sur l\'avenir de notre environnement\"}', '{\"fr\":\"La MEL s\'engage pour le climat. Elle invite les habitants du territoire à des cafés citoyens.\"}', '{\"fr\":\"La Métropole Européenne de Lille invite les habitants à des cafés citoyens pour réfléchir à un nouveau projet de société. L\'idée est de partager en toute convivialité des points de vue, des idées, des propositions sur la transition énergétique et climatique pour enrichir le Plan Climat Air Energie Territorial de la MEL.\\n\\n**Café citoyen : un sujet, un intervenant, un café !**\\n\\nUne dizaine de cafés citoyens sont organisés entre mars et juillet 2019. Poursuite de ces rendez-vous convivaux ouverts à tous avec un café \\\"gesticulé\\\" sur le thème de l\'avenir de notre environnement.\\n\\n**Café gesticulé avec le collectif L\'Etincelle**\\n\\n**\\\" Qui peut sauver le climat ? \\\"**\\n\\n**13 mai à 18h30**\\n\\n**Espace La Chaufferie à Tourcoing**\\n\\n_L\'Etincelle_ est une coopérative d\'éducation populaire. Elle organise des ateliers sous forme d\'expression théâtralisée mélangeant humour et auto-dérision. L\'espace d\'expression proposé se construit collectivement à partir des vécus, colères, envies des participants, pour réfléchir ensemble sur l\'avenir de notre environnement.\"}', '{}', '{\"fr\":\"Gratuit. Entrée libre.\"}', '{\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":400,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.full.image.jpg\",\"size\":{\"height\":3417,\"width\":5126}},{\"type\":\"thumbnail\",\"filename\":\"b74604fb7b3c4083ba7181a5befe1471.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-13T16:30:00.000Z\",\"end\":\"2019-05-13T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"0359006474\"]', '2019-04-26 12:50:42', '2019-04-26 13:12:23', NULL, NULL, '[]', '[]'),
(556469, 48715916, 24129771, 24129771, 89904399, 51312374, 'finale-coupe-deurope-feminine-tennis-de-table', '{\"fr\":\"Finale Coupe d\'Europe féminine Tennis de Table\"}', '{\"fr\":\"La MEL sert en faveur de la Finale de la Coupe d\'Europe Féminine de Tennis de Table\"}', '{\"fr\":\"Le premier match aller, de la double confrontation en aller-retour, aura lieu dans le Nord. Il verra s’affronter le club pongiste de Lille Métropole et l’UCAM Cartagène TM, équipe espagnol.\\n\\nVenez les soutenir !\"}', '{\"fr\":[\"sport\",\"Finale\",\"Coupe d\'Europe\",\"Tennis de Table\",\"Ping Pong\"]}', '{\"fr\":\"Entrée : -12 ans gratuit / 5 euros autres\"}', '{\"filename\":\"4ec2c3b993654a7da39a8df3e6231209.base.image.jpg\",\"size\":{\"width\":700,\"height\":467},\"variants\":[{\"filename\":\"4ec2c3b993654a7da39a8df3e6231209.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":600,\"height\":400}},{\"filename\":\"4ec2c3b993654a7da39a8df3e6231209.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-03T17:00:00.000Z\",\"end\":\"2019-05-03T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"06.27.25.58.07\",\"lyssois.club-pongiste@orange.fr\"]', '2019-04-26 09:58:43', '2019-04-29 08:11:15', NULL, NULL, '[]', '[]'),
(556023, 42435658, 10265018, 10265018, 89904399, 83869956, 'les-parleuses-3_408495', '{\"fr\":\"Les parleuses #3\"}', '{\"fr\":\"Cette 3ème séance des Parleuses est consacrée à l\'autrice Carson McCullers.\"}', '{\"fr\":\"Au programme : ateliers de lecture par arpentage* d’une nouvelle de Carson McCullers menés par Aurélie Olivier, un atelier d’écriture mené par Chloé Delaume, Marraine 2019 des Parleuses, et une lecture – enregistrement de podcast imaginés par Fanny Chiarello !\\n\\nEntrée libre sur inscription, dans la limite des places disponibles.\\n\\n→ **Chez violette**, à Lille (Moulins), le 25 mai, de 14h à 18h\\n\\nAtelier d’arpentage, Atelier d’écriture, Lecture enregistrement de podcast & librairie éphémère (La librairie Meura).\\n\\nCarson McCullers (1917 – 1967) rencontre un succès fulgurant dès l’âge de 23 ans avec son premier roman Le coeur est un chasseur solitaire. Elle publie ensuite Reflets dans un œil d’or (1941), Frankie Addams (1946), La Ballade du café triste (1951), L’Horloge sans aiguilles (1961) et après sa mort, Le Cœur hypothéqué (1972). Pour en savoir + : RDV à la séance des parleuses !\\n\\nFanny Chiarello a publié L’éternité n’est pas si longue en 2010, Une faiblesse de Carlotta Delmont en 2013 (éd. de L’olivier), Dans son propre rôle en 2015 (éd. de L’olivier), Le tombeau de Pamela sauvage (éd. La Contre Allée) et Le Zeppelin (éd. de L’olivier) en 2016, La vie effaçant toutes choses en 2017, et A happy woman en 2019. Elle a également publié plusieurs recueils de poésie et livres pour enfants.\\n\\nChloé Delaume est née en 1973. elle pratique l’écriture sous de multiples formes et supports depuis bientôt deux décennies. Beaucoup de textes courts, près d’une trentaine de livres comme autant d’expériences. Romans, fragments poétiques, théâtre; autofictions. Son dernier ouvrage, Mes bien chères sœurs est paru au Seuil en 2019. Elle collabore régulièrement avec des artistes; vidéastes, designers, musiciens pour faire. Performances, pièces sonores, interventions, objets. Il lui arrive même d’être parolière. Elle est actuellement Artiste associée au Magasin des Horizons, le Centre National d’Art Contemporain de Grenoble, où elle développe jusqu’en 2021 un chantier autour des espaces oniriques et de leurs cartographies : Dream Operator. Elle dirige également la collection Extraction aux éditions Joca Seria, et anime à Paris des ateliers d’écriture au sein de l’école Les Mots.\\n\\n*On divise le livre, chacun.e des participant.e.s lit une partie isolément, puis chaque participant.e partage sa lecture personnelle jusqu’à ce que la discussion collective embrasse le texte dans son ensemble…\"}', '{}', '{\"fr\":\"Sur inscription : contact@litterature-etc.com\"}', '{\"filename\":\"53d60a7af33d4e36a51aecd03d222453.base.image.jpg\",\"size\":{\"width\":700,\"height\":370},\"variants\":[{\"filename\":\"53d60a7af33d4e36a51aecd03d222453.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":1024,\"height\":540}},{\"filename\":\"53d60a7af33d4e36a51aecd03d222453.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-25T12:00:00.000Z\",\"end\":\"2019-05-25T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-04-25 14:08:33', '2019-04-25 14:08:33', NULL, NULL, '[]', '[]'),
(556000, 96500031, 10265018, 10265018, 89904399, 56767719, 'les-parleuses-3_142108', '{\"fr\":\"Les parleuses #3\"}', '{\"fr\":\"Cette 3ème séance des Parleuses est consacrée à l\'autrice Carson McCullers.\"}', '{\"fr\":\"Au programme : ateliers de lecture par arpentage* d’une nouvelle de Carson McCullers menés par Aurélie Olivier, un atelier d’écriture mené par Chloé Delaume, Marraine 2019 des Parleuses, et une lecture – enregistrement de podcast imaginés par Fanny Chiarello !\\n\\n→ à la **Médiathèque de Villeneuve d’Ascq**, le 25 mai, de 10h à 12h\\n\\nAtelier d’arpentage.\\n\\n→ **Chez violette**, à Lille (Moulins), le 25 mai, de 14h à 18h\\n\\nAtelier d’arpentage, Atelier d’écriture, Lecture enregistrement de podcast & librairie éphémère (La librairie Meura). Sur inscription : contact@litterature-etc.com\\n\\nCarson McCullers (1917 – 1967) rencontre un succès fulgurant dès l’âge de 23 ans avec son premier roman Le coeur est un chasseur solitaire. Elle publie ensuite Reflets dans un œil d’or (1941), Frankie Addams (1946), La Ballade du café triste (1951), L’Horloge sans aiguilles (1961) et après sa mort, Le Cœur hypothéqué (1972). Pour en savoir + : RDV à la séance des parleuses !\\n\\nFanny Chiarello a publié L’éternité n’est pas si longue en 2010, Une faiblesse de Carlotta Delmont en 2013 (éd. de L’olivier), Dans son propre rôle en 2015 (éd. de L’olivier), Le tombeau de Pamela sauvage (éd. La Contre Allée) et Le Zeppelin (éd. de L’olivier) en 2016, La vie effaçant toutes choses en 2017, et A happy woman en 2019. Elle a également publié plusieurs recueils de poésie et livres pour enfants.\\n\\nChloé Delaume est née en 1973. elle pratique l’écriture sous de multiples formes et supports depuis bientôt deux décennies. Beaucoup de textes courts, près d’une trentaine de livres comme autant d’expériences. Romans, fragments poétiques, théâtre; autofictions. Son dernier ouvrage, Mes bien chères sœurs est paru au Seuil en 2019. Elle collabore régulièrement avec des artistes; vidéastes, designers, musiciens pour faire. Performances, pièces sonores, interventions, objets. Il lui arrive même d’être parolière. Elle est actuellement Artiste associée au Magasin des Horizons, le Centre National d’Art Contemporain de Grenoble, où elle développe jusqu’en 2021 un chantier autour des espaces oniriques et de leurs cartographies : Dream Operator. Elle dirige également la collection Extraction aux éditions Joca Seria, et anime à Paris des ateliers d’écriture au sein de l’école Les Mots.\\n\\n*On divise le livre, chacun.e des participant.e.s lit une partie isolément, puis chaque participant.e partage sa lecture personnelle jusqu’à ce que la discussion collective embrasse le texte dans son ensemble…\"}', '{}', '{\"fr\":\"Sur inscription : 03 20 61 73 00 ou bibli@villeneuvedascq.fr\"}', '{\"filename\":\"16888e1fedde44d28de695f597569121.base.image.jpg\",\"size\":{\"width\":700,\"height\":370},\"variants\":[{\"filename\":\"16888e1fedde44d28de695f597569121.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":1024,\"height\":540}},{\"filename\":\"16888e1fedde44d28de695f597569121.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-25T08:00:00.000Z\",\"end\":\"2019-05-25T10:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 61 73 00\",\"bibli@villeneuvedascq.fr\"]', '2019-04-25 14:05:53', '2019-04-25 14:05:53', NULL, NULL, '[]', '[]'),
(555991, 56902705, 10265018, 10265018, 89904399, 83748444, 'les-parleuses-3', '{\"fr\":\"Les parleuses #3\"}', '{\"fr\":\"Cette 3ème séance des Parleuses est consacrée à l\'autrice Carson McCullers.\"}', '{\"fr\":\"Au programme : ateliers de lecture par arpentage* d’une nouvelle de Carson McCullers menés par Aurélie Olivier, un atelier d’écriture mené par Chloé Delaume, Marraine 2019 des Parleuses, et une lecture – enregistrement de podcast imaginés par Fanny Chiarello !\\n\\n→ à la **médiathèque de Marcq-en-Barœul**, le 24 mai, de 18h à 20h /\\n\\nAtelier d’arpentage. Sur inscription auprès de la médiathèque.\\n\\n→ à la **Médiathèque de Villeneuve d’Ascq**, le 25 mai, de 10h à 12h /\\n\\nAtelier d’arpentage.\\n\\nSur inscription : 03 20 61 73 00 ou bibli@villeneuvedascq.fr\\n\\n→ **Chez** **violette**, à Lille (Moulins), le 25 mai, de 14h à 18h /\\n\\nAtelier d’arpentage, Atelier d’écriture, Lecture enregistrement de podcast & librairie éphémère (La librairie Meura). Sur inscription : contact@litterature-etc.com\\n\\nCarson McCullers (1917 – 1967) rencontre un succès fulgurant dès l’âge de 23 ans avec son premier roman Le coeur est un chasseur solitaire. Elle publie ensuite Reflets dans un œil d’or (1941), Frankie Addams (1946), La Ballade du café triste (1951), L’Horloge sans aiguilles (1961) et après sa mort, Le Cœur hypothéqué (1972). Pour en savoir + : RDV à la séance des parleuses !\\n\\nFanny Chiarello a publié L’éternité n’est pas si longue en 2010, Une faiblesse de Carlotta Delmont en 2013 (éd. de L’olivier), Dans son propre rôle en 2015 (éd. de L’olivier), Le tombeau de Pamela sauvage (éd. La Contre Allée) et Le Zeppelin (éd. de L’olivier) en 2016, La vie effaçant toutes choses en 2017, et A happy woman en 2019. Elle a également publié plusieurs recueils de poésie et livres pour enfants.\\n\\nChloé Delaume est née en 1973. elle pratique l’écriture sous de multiples formes et supports depuis bientôt deux décennies. Beaucoup de textes courts, près d’une trentaine de livres comme autant d’expériences. Romans, fragments poétiques, théâtre; autofictions. Son dernier ouvrage, Mes bien chères sœurs est paru au Seuil en 2019. Elle collabore régulièrement avec des artistes; vidéastes, designers, musiciens pour faire. Performances, pièces sonores, interventions, objets. Il lui arrive même d’être parolière. Elle est actuellement Artiste associée au Magasin des Horizons, le Centre National d’Art Contemporain de Grenoble, où elle développe jusqu’en 2021 un chantier autour des espaces oniriques et de leurs cartographies : Dream Operator. Elle dirige également la collection Extraction aux éditions Joca Seria, et anime à Paris des ateliers d’écriture au sein de l’école Les Mots.\\n\\n*On divise le livre, chacun.e des participant.e.s lit une partie isolément, puis chaque participant.e partage sa lecture personnelle jusqu’à ce que la discussion collective embrasse le texte dans son ensemble…\"}', '{}', '{\"fr\":\"Entrée libre sur inscription, dans la limite des places disponibles. / Sur inscription auprès de la médiathèque.\"}', '{\"filename\":\"e15cfaf0c755442c9dbf9cf3e85002e4.base.image.jpg\",\"size\":{\"width\":700,\"height\":370},\"variants\":[{\"filename\":\"e15cfaf0c755442c9dbf9cf3e85002e4.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":1024,\"height\":540}},{\"filename\":\"e15cfaf0c755442c9dbf9cf3e85002e4.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-24T16:00:00.000Z\",\"end\":\"2019-05-24T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-04-25 14:02:03', '2019-04-25 14:02:36', NULL, NULL, '[]', '[]');
INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `creator_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at`, `file_key`, `references`, `links`) VALUES
(555648, 31150303, 10265018, 10265018, 89904399, 27225159, 'les-beffrois-du-travail-banquet-des-cheminees', '{\"fr\":\"Les Beffrois du travail - Banquet des cheminées\"}', '{\"fr\":\"Le Non-Lieu organise la 13ème édition des Beffrois du travail qui valorise les cheminées d\'usines comme emblème du travail des hommes et des femmes.\"}', '{\"fr\":\"L\'association \\\"Le Non-Lieu\\\" travaille sur le lien entre le patrimoine industriel, les mémoires collectives et la création artistique contemporaine, notamment par la conception d\'évènements, la valorisation de sites à forte valeur identitaire et l\'édition d\'ouvrages. Le Non-Lieu gère également un lieu, La Forge de l\'Usine Cavrois-Mahieu, situé à Roubaix : lieu d\'expos, d\'ateliers d\'artistes.\\n\\nLe Non-Lieu organise la **13ème édition des Beffrois du travail** qui valorise les cheminées d\'usines comme emblème du travail des hommes et des femmes. Pour cette édition, sont mis à l’honneur les savoir-faire liés à la fabrication et à la restauration des cheminées en brique.\\n\\nPlusieurs temps forts seront organisés, dont le traditionnel **banquet des cheminées** le 1er mai et plusieurs manifestations patrimoniales, artistiques, festives et populaires.\\n\\nLe rendez-vous des amoureux de cheminées, pour s’émerveiller, chanter, manger ensemble dans l’usine et … grimper sur la cheminée !\\n\\n**Programme du Banquet des cheminées au NON-LIEU – 1er mai 2019**\\n\\n► 11H-13H\\n\\n\\\\- L’HOMME AUX 1000 CHEMINÉES > Film de Jérémy Moncheaux.\\n\\n\\\\- LE P’TIT MUSÉE DE LA CHEMINÉE > Présentation par Frank Coornaert.\\n\\n\\\\- CHEMINÉES À PAROLES > Exposition avec Anne Breton et Andy Kraft.\\n\\n\\\\- APÉRITIF¬CONCERT > avec le groupe TREMENDA TRIO.\\n\\n► 13H\\n\\n\\\\- BANQUET DES CHEMINÉES > Carbonade + chapeaux cheminées + karaoké concert\\n\\n(8€ / réservation contact@non-lieu.fr )\\n\\n► 14H-18H\\n\\n\\\\- HISSE¬ÉMOI > Grimpe sur la cheminée avec la Cie de danse Retouramont !\\n\\n\\\\- VUE D’EN HAUT, VUE D’EN BAS > Atelier avec Marie Garde, plasticienne.\\n\\n\\\\- LE P’TIT MUSÉE DE LA CHEMINÉE + CHEMINÉES À PAROLES\\n\\n\\\\- DANSE SUR CHEMINÉE > Solo fi nal avec Isabelle Pinon.\"}', '{}', '{}', '{\"filename\":\"14d16be39dce46c9a88b89bf2e7009c9.base.image.jpg\",\"size\":{\"width\":700,\"height\":989},\"variants\":[{\"filename\":\"14d16be39dce46c9a88b89bf2e7009c9.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":602,\"height\":850}},{\"filename\":\"14d16be39dce46c9a88b89bf2e7009c9.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-01T09:00:00.000Z\",\"end\":\"2019-05-01T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"contact@non-lieu.fr\"]', '2019-04-25 08:19:19', '2019-04-25 08:19:19', NULL, NULL, '[]', '[]'),
(555114, 84599841, 82253124, 82253124, 89904399, 6870112, 'urban-climate-change-adaptation-eugreenweek', '{\"fr\":\"Urban Climate Change Adaptation #EUGreenWeek\"}', '{\"fr\":\"Alors que la MEL engage une procédure de refonte de son Plan Climat Air et Energie, cette conférence sera l’opportunité de mettre en avant les initiatives des villes, co-conçues avec leurs citoyens.\"}', '{\"fr\":\"Le contexte urbain européen est confronté à de nouvelles problématiques liées au changement climatique telles que les vagues de chaleur, pics de pollution, érosion des ressources naturelles, etc. Bon nombre de solutions pour lutter contre le changement climatique et l\'atténuer dans les meilleures conditions sont pensées localement, au niveau municipal. Les enjeux et la présentation de solutions locales sont le sujet de cette conférence. De l’intégration de solutions basées sur la nature aux initiatives d’autosuffisance alimentaire, des stratégies pour l’eau, l’air et les sols à l’environnement aux politiques de santé… Quels sont les projets concrets pour rendre les villes et les zones urbaines plus résilientes? Comment assurer la stabilisation du climat de demain sur le terrain? Quels sont les leviers à l\'échelle métropolitaine? Comment l’Europe aide-t-elle les villes à faire face à ces grandes questions dans les meilleures conditions?\\n\\nAlors que la Métropole Européenne de Lille engage une procédure de refonte de son Plan Climat Air et Energie et s’apprête à devenir Capitale Mondiale du Design en 2020, cette conférence sera l’opportunité de mettre en avant les initiatives concrètes des villes, co-conçues avec leurs citoyens.\"}', '{}', '{}', '{\"filename\":null,\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[]}', 0, 0, 'Europe/Brussels', '[{\"begin\":\"2019-04-25T13:30:00.000Z\",\"end\":\"2019-04-25T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.eventbrite.fr/e/billets-urban-adaptation-to-climate-change-56195031853\"]', '2019-04-24 13:07:26', '2019-04-24 13:07:26', NULL, NULL, '[]', '[]'),
(554444, 49207301, 10265018, 10265018, 89904399, 50651588, 'geek-days-2019', '{\"fr\":\"Geek Days 2019\"}', '{\"fr\":\"La quatrième édition des Geek Days aura lieu les 18 et 19 mai à Lille Grand Palais.\"}', '{\"fr\":\"Les **Geeks Days** reviennent à Lille pour la quatrième année consécutive. Jeux vidéos, comics, manga, cosplay et science-fiction seront au rendez-vous de cet événement dédié à la pop culture.\\n\\nDe nombreuses animations seront proposées au public au cours de ce week-end festif : cours de japonais, ateliers, rencontres avec des Youtubeurs, concours de cosplay...\\n\\nPour la première fois cette année, le festival lillois accueille deux acteurs de séries télévisées : Frankie Muniz, héros de la série _Malcolm_ et Nicholas Brendon, interprète d\'Alex dans _Buffy contre les vampires_. Tous deux se prêteront au jeu des dédicaces et des questions-réponses avec le public lillois.\"}', '{}', '{\"fr\":\"Pass 1 jour - 11€ / Pass 2 jours 20€ / Billetterie : https://yurplan.com/event/GEEK-DAYS-LILLE/32713#/\"}', '{\"filename\":\"5cd316009aee408e8800e46351036086.base.image.jpg\",\"credits\":\"Geek Days\",\"size\":{\"height\":700,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"5cd316009aee408e8800e46351036086.full.image.jpg\",\"size\":{\"height\":1200,\"width\":1200}},{\"type\":\"thumbnail\",\"filename\":\"5cd316009aee408e8800e46351036086.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-18T08:00:00.000Z\",\"end\":\"2019-05-18T17:00:00.000Z\"},{\"begin\":\"2019-05-19T08:00:00.000Z\",\"end\":\"2019-05-19T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-04-23 13:57:18', '2019-04-23 13:59:22', NULL, NULL, '[]', '[]'),
(554271, 90850745, 60654151, 60654151, 89904399, 77607806, 'fresque-murale-de-lady-alezia-biennale-internationale-dart-mural-4', '{\"fr\":\"Fresque murale de Lady Alézia - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de Lady Alézia (France)**\\n\\n**du 03 au 07 juin à Lille**\\n\\n_Graffeuse et calligraphe de la région lilloise, Lady Alézia apporte un regard empreint de douceur et de richesse de couleur, tout en mouvement. Sensible aux écritures urbaines, calligraphiques et typographiques, à la recherche d\'un alphabet esthétisé à travers tags, lettres gothiques, représentations figuratives, éléments urbains, floraux, végétaux, elle aborde principalement la thématique du temps._\\n\\n*   Instagram : [https://www.instagram.com/lady.alezia/](https://www.instagram.com/lady.alezia/)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-03T07:00:00.000Z\",\"end\":\"2019-06-03T19:00:00.000Z\"},{\"begin\":\"2019-06-04T07:00:00.000Z\",\"end\":\"2019-06-04T19:00:00.000Z\"},{\"begin\":\"2019-06-05T07:00:00.000Z\",\"end\":\"2019-06-05T19:00:00.000Z\"},{\"begin\":\"2019-06-06T07:00:00.000Z\",\"end\":\"2019-06-06T19:00:00.000Z\"},{\"begin\":\"2019-06-07T07:00:00.000Z\",\"end\":\"2019-06-07T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-23 11:33:57', '2019-04-23 11:33:57', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/lady.alezia/\",\"data\":{\"url\":\"https://www.instagram.com/lady.alezia/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"~ Lady Alézia ~ (@lady.alezia) • Instagram photos and videos\",\"description\":\"234 Followers, 72 Following, 8 Posts - See Instagram photos and videos from ~ Lady Alézia ~ (@lady.alezia)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/4ec9360ab5dfc174bf13a478b95c2a06/5D57CAC4/t51.2885-19/s150x150/36928544_1968776833414449_4230633796917002240_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/lady.alezia/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Flady.alezia%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(554270, 12502890, 60654151, 60654151, 89904399, NULL, 'fresque-murale-de-danyboy-biennale-internationale-dart-mural-4', '{\"fr\":\"Fresque murale de DANYBOY - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de DANYBOY (France)**\\n\\n**du 27 au 31 mai à Villeneuve d\'Ascq**\\n\\n_En arrivant sur Roubaix, Danyboy apprend dès le début des années 90, le tag, le lettrage et les bboys. Ce qu\'il aime par dessus tout, c\'est la création de ses \\\"gueules\\\", sortes de têtes grimaçantes. Ce sont des têtes mais aussi un travail de lettrage, presque de calligraphie. Bien sûr, on ne peut pas parler de son style sans évoquer les dinosaures qu\'il aime dessiner car leurs gueules s\'apparentes aux têtes qu\'il crée._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/danyboylille/)\\n    \\n*   Instagram : https://www.instagram.com/danyboylille/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 1, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-27T07:00:00.000Z\",\"end\":\"2019-05-27T19:00:00.000Z\"},{\"begin\":\"2019-05-28T07:00:00.000Z\",\"end\":\"2019-05-28T19:00:00.000Z\"},{\"begin\":\"2019-05-29T07:00:00.000Z\",\"end\":\"2019-05-29T19:00:00.000Z\"},{\"begin\":\"2019-05-30T07:00:00.000Z\",\"end\":\"2019-05-30T19:00:00.000Z\"},{\"begin\":\"2019-05-31T07:00:00.000Z\",\"end\":\"2019-05-31T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-23 11:28:15', '2019-04-23 11:28:15', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/danyboylille/\",\"data\":{\"url\":\"https://www.instagram.com/danyboylille/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Danyboy Lille (@danyboylille) • Instagram photos and videos\",\"description\":\"167 Followers, 71 Following, 8 Posts - See Instagram photos and videos from Danyboy Lille (@danyboylille)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/3306895bfb8a4be2b77a8067f4137bf0/5D38838D/t51.2885-19/s150x150/45595728_382566989149826_2930149001409855488_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/danyboylille/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fdanyboylille%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(554267, 27995042, 60654151, 60654151, 89904399, 29538202, 'fresque-murale-dalegria-del-prado-biennale-internationale-dart-mural-4_106224', '{\"fr\":\"Fresque murale d\'ALEGRIA DEL PRADO - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale d\'ALEGRIA DEL PRADO (Espagne - Mexique) du 27 au 31 mai à Hellemmes**\\n\\n_Le travail d\'Octavio Alegria (Mexique) et d’Ester del Prado (Espagne) mêle deux visions et couleurs nées sur différents continents, inspirées principalement par des animaux, des éléments organiques et ethniques à la nuance surréaliste. Ils mêlent des animaux mythologiques, qui cachent une force, un talent ou une vertu que l’homme peut apprendre, à des éléments organiques, et des symboles personnels dans une atmosphère onirique._\\n\\n*   [Facebook du duo](https://www.facebook.com/alegriadelpradoarte/)\\n    \\n*   Instagram : [https://www.instagram.com/alegriadelprado/](https://www.instagram.com/alegriadelprado/)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-27T07:30:00.000Z\",\"end\":\"2019-05-27T19:00:00.000Z\"},{\"begin\":\"2019-05-28T07:30:00.000Z\",\"end\":\"2019-05-28T19:00:00.000Z\"},{\"begin\":\"2019-05-29T07:30:00.000Z\",\"end\":\"2019-05-29T19:00:00.000Z\"},{\"begin\":\"2019-05-30T07:30:00.000Z\",\"end\":\"2019-05-30T19:00:00.000Z\"},{\"begin\":\"2019-05-31T07:30:00.000Z\",\"end\":\"2019-05-31T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-23 11:17:31', '2019-04-23 11:17:31', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/alegriadelprado/\",\"data\":{\"url\":\"https://www.instagram.com/alegriadelprado/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Alegria del Prado (@alegriadelprado) • Instagram photos and videos\",\"description\":\"14.4k Followers, 1,186 Following, 402 Posts - See Instagram photos and videos from Alegria del Prado (@alegriadelprado)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/82ee75162db3f3b2a98c949497a2f986/5D36D8CA/t51.2885-19/1962893_1125103510851246_42730519_a.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/alegriadelprado/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Falegriadelprado%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(554266, 74729257, 60654151, 60654151, 89904399, 43132037, 'fresque-murale-de-btoy-biennale-internationale-dart-mural-4', '{\"fr\":\"Fresque murale de BTOY - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de BTOY (Espagne)**\\n\\n**du 27 au 31 mai à Lille**\\n\\n_L’artiste catalane Michaelsson aka BTOY travaille au pochoir sur les portraits, à l’expression mélancolique, de ses modèles fétiches, vedettes de l’âge d’or du cinéma muet, telles que Louise Brooks et Clara Bow. Mélange d’aquarelle, d’encre et de peinture à la bombe, les œuvres de BTOY, inspirées par d’anciennes photographies en noir et blanc sont caractérisées_\\n\\n_par une palette de couleurs vives et d\'un coup de pinceau énergique._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/BTOY-131023090241290/)\\n    \\n*   Instagram : https://www.instagram.com/btoyandrea/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-27T07:00:00.000Z\",\"end\":\"2019-05-27T19:00:00.000Z\"},{\"begin\":\"2019-05-28T07:00:00.000Z\",\"end\":\"2019-05-28T19:00:00.000Z\"},{\"begin\":\"2019-05-29T07:00:00.000Z\",\"end\":\"2019-05-29T19:00:00.000Z\"},{\"begin\":\"2019-05-30T07:00:00.000Z\",\"end\":\"2019-05-30T19:00:00.000Z\"},{\"begin\":\"2019-05-31T07:00:00.000Z\",\"end\":\"2019-05-31T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-23 11:13:27', '2019-04-23 11:13:27', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/btoyandrea/\",\"data\":{\"url\":\"https://www.instagram.com/btoyandrea/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"BTOY (@btoyandrea) • Instagram photos and videos\",\"description\":\"4,381 Followers, 692 Following, 234 Posts - See Instagram photos and videos from BTOY (@btoyandrea)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/7086f7c597854e580ef7b5d0432f0c66/5D76EDA0/t51.2885-19/s150x150/31136704_486705345066181_6229665035656888320_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/btoyandrea/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fbtoyandrea%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(554262, 88282619, 60654151, 60654151, 89904399, 33005553, 'fresque-murale-dalegria-del-prado-biennale-internationale-dart-mural-4', '{\"fr\":\"Fresque murale d\'ALEGRIA DEL PRADO - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale d\'ALEGRIA DEL PRADO (Espagne - Mexique) du 20 au 24 mai à Lomme**\\n\\n_Le travail d\'Octavio Alegria (Mexique) et d’Ester del Prado (Espagne) mêle deux visions et couleurs nées sur différents continents, inspirées principalement par des animaux, des éléments organiques et ethniques à la nuance surréaliste. Ils mêlent des animaux mythologiques, qui cachent une force, un talent ou une vertu que l’homme peut apprendre, à des éléments organiques, et des symboles personnels dans une atmosphère onirique._\\n\\n*   [Facebook du duo](https://www.facebook.com/alegriadelpradoarte/)\\n    \\n*   Instagram : https://www.instagram.com/alegriadelprado/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-20T07:00:00.000Z\",\"end\":\"2019-05-20T19:00:00.000Z\"},{\"begin\":\"2019-05-21T07:00:00.000Z\",\"end\":\"2019-05-21T19:00:00.000Z\"},{\"begin\":\"2019-05-22T07:00:00.000Z\",\"end\":\"2019-05-22T19:00:00.000Z\"},{\"begin\":\"2019-05-23T07:00:00.000Z\",\"end\":\"2019-05-23T19:00:00.000Z\"},{\"begin\":\"2019-05-24T07:00:00.000Z\",\"end\":\"2019-05-24T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-23 11:06:03', '2019-04-23 11:06:03', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/alegriadelprado/\",\"data\":{\"url\":\"https://www.instagram.com/alegriadelprado/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Alegria del Prado (@alegriadelprado) • Instagram photos and videos\",\"description\":\"14.4k Followers, 1,186 Following, 402 Posts - See Instagram photos and videos from Alegria del Prado (@alegriadelprado)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/82ee75162db3f3b2a98c949497a2f986/5D36D8CA/t51.2885-19/1962893_1125103510851246_42730519_a.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/alegriadelprado/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Falegriadelprado%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(554254, 68058280, 60654151, 60654151, 89904399, 47789417, 'fresque-murale-de-jace-biennale-internationale-dart-mural-4', '{\"fr\":\"Fresque murale de JACE - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de JACE (France)**\\n\\n**du 20 au 24 mai à Saint-André-lez-Lille**\\n\\n_Universel, humoristique et original, \\\"Gouzou\\\", le personnage emblématique et facétieux de Jace fait son apparition sur les murs de Saint-André à l\'occasion de la BIAM#4. Créés en 1992, les Gouzous sont désormais mondialement connus pour avoir voyagé dans plus d\'une quarantaine de pays et territoires. Avec sa mascotte au graphisme épuré, leur créateur fait passer des messages simples et efficaces, qu\'ils soient sociétaux, politiques ou environnementaux._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/JACE-81319567629/)\\n    \\n*   Instagram : https://www.instagram.com/jaceticot/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-20T07:00:00.000Z\",\"end\":\"2019-05-20T19:00:00.000Z\"},{\"begin\":\"2019-05-21T07:00:00.000Z\",\"end\":\"2019-05-21T19:00:00.000Z\"},{\"begin\":\"2019-05-22T07:00:00.000Z\",\"end\":\"2019-05-22T19:00:00.000Z\"},{\"begin\":\"2019-05-23T07:00:00.000Z\",\"end\":\"2019-05-23T19:00:00.000Z\"},{\"begin\":\"2019-05-24T07:00:00.000Z\",\"end\":\"2019-05-24T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-23 10:57:14', '2019-04-23 10:57:14', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/jaceticot/\",\"data\":{\"url\":\"https://www.instagram.com/jaceticot/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Jace Gouzou (@jaceticot) • Instagram photos and videos\",\"description\":\"41.1k Followers, 1,204 Following, 2,304 Posts - See Instagram photos and videos from Jace Gouzou (@jaceticot)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/5601f5265c0e02e36c6050848e5ba36a/5D6ED786/t51.2885-19/s150x150/31338677_450777305371536_215841872063496192_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/jaceticot/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fjaceticot%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(554251, 43877368, 60654151, 60654151, 89904399, 14873717, 'fresque-murale-de-da-cruz-biennale-internationale-dart-mural-4', '{\"fr\":\"Fresque murale de DA CRUZ - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de l\'artiste DA CRUZ (France)**\\n\\n**du 20 au 24 mai à Lille**\\n\\n_Dès le début des années 80, l’artiste français Da Cruz investit les murs du 19ème arrondissement de Paris avant de plonger dans les cultures de l’Amérique du Sud, de l’Afrique et de la Palestine qui sont désormais une source de créativité perpétuelle pour lui. La confrontation avec ces cultures ancestrales (les masques des cultures précolombiennes l’ont tout particulièrement marqué) a forgé chez lui un style primitif, coloré et urbain. Ses œuvres et sa pratique sont aussi un écho permanent aux problèmes politiques et sociaux actuels._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/dacruzgraffiti/)\\n    \\n*   Instagram : [https://www.instagram.com/dacruzgraffiti/](https://www.instagram.com/dacruzgraffiti/)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-20T07:00:00.000Z\",\"end\":\"2019-05-20T19:00:00.000Z\"},{\"begin\":\"2019-05-21T07:00:00.000Z\",\"end\":\"2019-05-21T19:00:00.000Z\"},{\"begin\":\"2019-05-22T07:00:00.000Z\",\"end\":\"2019-05-22T19:00:00.000Z\"},{\"begin\":\"2019-05-23T07:00:00.000Z\",\"end\":\"2019-05-23T19:00:00.000Z\"},{\"begin\":\"2019-05-24T07:00:00.000Z\",\"end\":\"2019-05-24T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-23 10:46:22', '2019-04-23 10:47:16', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/dacruzgraffiti/\",\"data\":{\"url\":\"https://www.instagram.com/dacruzgraffiti/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"@dacruzgraffiti • Instagram photos and videos\",\"description\":\"8,033 Followers, 1,786 Following, 331 Posts - See Instagram photos and videos from @dacruzgraffiti\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/1b3bba9661a4aa909550bfd4950a93b0/5D7745DB/t51.2885-19/s150x150/51050484_350191655822828_1277318476351930368_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/dacruzgraffiti/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fdacruzgraffiti%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(554245, 12107580, 60654151, 60654151, 89904399, 14834970, 'fresque-murale-de-the-dude-company-biennale-internationale-dart-mural-4', '{\"fr\":\"Fresque murale de THE DUDE COMPANY - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de THE DUDE COMPANY (France)**\\n\\n**du 20 au 24 mai à Lille**\\n\\n_Artiste plasticien spécialisé dans la technique du pochoir, The Dude Company développe depuis 2008 sa propre technique : il réalise, à partir de photographies découpées entièrement à la main, des pochoirs minutieux et détaillés. Passionné de l\'image, des lignes, des courbes et des assemblages géométriques, il recouvre les murs de Lille de ses œuvres à l’aide de ses bombes de peinture et de ses pistolets aérographes._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/thedudecompanyart/)\\n    \\n*   Instagram : https://www.instagram.com/thedudecompany/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-20T07:00:00.000Z\",\"end\":\"2019-05-20T19:00:00.000Z\"},{\"begin\":\"2019-05-21T07:00:00.000Z\",\"end\":\"2019-05-21T19:00:00.000Z\"},{\"begin\":\"2019-05-22T07:00:00.000Z\",\"end\":\"2019-05-22T19:00:00.000Z\"},{\"begin\":\"2019-05-23T07:00:00.000Z\",\"end\":\"2019-05-23T19:00:00.000Z\"},{\"begin\":\"2019-05-24T07:00:00.000Z\",\"end\":\"2019-05-24T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-23 10:40:16', '2019-04-23 10:40:16', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/thedudecompany/\",\"data\":{\"url\":\"https://www.instagram.com/thedudecompany/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Etienne BERGOT (@thedudecompany) • Instagram photos and videos\",\"description\":\"510 Followers, 245 Following, 462 Posts - See Instagram photos and videos from Etienne BERGOT (@thedudecompany)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/3cfc9046fbf56d198734e916a6149c52/5D58E730/t51.2885-19/s150x150/27576828_150656265613879_3199627760800628736_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/thedudecompany/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fthedudecompany%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(554239, 83368060, 60654151, 60654151, 89904399, 2286011, 'fresque-murale-de-meda-biennale-internationale-dart-mural-4', '{\"fr\":\"Fresque murale de MEDA - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de l\'artiste MEDA (France)**\\n\\n**du 20 au 24 mai à Lomme**\\n\\n_Graphiste de formation, Meda travaille sur les abstractions de couleurs. Peintre mais également jardinier professionnel, il réalisera des créations colorées en lien avec la sculpture paysagère._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/Nicolameda-654514401281074/)\\n    \\n*   Instagram : https://www.instagram.com/hellomeda/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-20T07:00:00.000Z\",\"end\":\"2019-05-20T19:00:00.000Z\"},{\"begin\":\"2019-05-21T07:00:00.000Z\",\"end\":\"2019-05-21T19:00:00.000Z\"},{\"begin\":\"2019-05-22T07:00:00.000Z\",\"end\":\"2019-05-22T19:00:00.000Z\"},{\"begin\":\"2019-05-23T07:00:00.000Z\",\"end\":\"2019-05-23T19:00:00.000Z\"},{\"begin\":\"2019-05-24T07:00:00.000Z\",\"end\":\"2019-05-24T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-23 10:30:47', '2019-04-23 10:31:52', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/hellomeda/\",\"data\":{\"url\":\"https://www.instagram.com/hellomeda/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"NicolaMeda (@hellomeda) • Instagram photos and videos\",\"description\":\"716 Followers, 2,201 Following, 311 Posts - See Instagram photos and videos from NicolaMeda (@hellomeda)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/851d33b5081da5ded6d2f0a399ea1d01/5D40AB04/t51.2885-19/s150x150/36136449_238988783584959_3257310335522045952_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/hellomeda/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fhellomeda%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(552552, 24312897, 10265018, 10265018, 89904399, 99127135, 'collectes-des-dechets-chimiques-des-particuliers-dans-les-grandes-surfaces-de-bricolage_846765', '{\"fr\":\"Collectes des déchets chimiques des particuliers dans les grandes surfaces de bricolage\"}', '{\"fr\":\"Afin de sensibiliser les métropolitains au tri des déchets, EcoDDS organise une grande collecte de déchets chimiques dans plusieurs communes de la Métropole.\"}', '{\"fr\":\"EcoDDS a décidé de renouveler ses journées de collectes exceptionnelles sur les parkings des Grandes Surface de Bricolage partenaires. Rendez-vous le samedi 22 juin de 10h à 17h dans les magasins Castorama de **Lille Hellemmes**, **Englos** et **Haubourdin**.\\n\\nPourquoi apporter vos déchets chimiques en point de collecte ?\\n\\nLes produits chimiques usagés peuvent être des déchets dangereux pour votre environnement et votre santé. Qu’ils soient vides, souillés ou avec un reste de contenu, ils doivent être apportés en déchetterie ou en point de collecte temporaire afin de bénéficier d’une prise en charge et d’un traitement sécurisés. Il est donc important de ne plus les jeter dans la poubelle (ordures ménagères, tri sélectif) ou dans les canalisations (WC, évier) mais de les apporter en point de collecte, si possible dans leur emballage d’origine.\"}', '{}', '{}', '{\"filename\":\"19d913aa965f4c9e9c586e597d066dd1.base.image.jpg\",\"size\":{\"width\":700,\"height\":986},\"variants\":[{\"filename\":\"19d913aa965f4c9e9c586e597d066dd1.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":621,\"height\":874}},{\"filename\":\"19d913aa965f4c9e9c586e597d066dd1.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-22T08:00:00.000Z\",\"end\":\"2019-06-22T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-04-18 08:28:40', '2019-04-18 08:28:40', NULL, NULL, '[]', '[]'),
(552549, 91588903, 10265018, 10265018, 89904399, NULL, 'collectes-des-dechets-chimiques-des-particuliers-dans-les-grandes-surfaces-de-bricolage_292219', '{\"fr\":\"Collectes des déchets chimiques des particuliers dans les grandes surfaces de bricolage\"}', '{\"fr\":\"Afin de sensibiliser les métropolitains au tri des déchets, EcoDDS organise une grande collecte de déchets chimiques dans plusieurs communes de la Métropole.\"}', '{\"fr\":\"EcoDDS a décidé de renouveler ses journées de collectes exceptionnelles sur les parkings des Grandes Surface de Bricolage partenaires. Rendez-vous le samedi 22 juin de 10h à 17h dans les magasins Castorama de **Lille Hellemmes**, **Englos** et **Haubourdin**.\\n\\nPourquoi apporter vos déchets chimiques en point de collecte ?\\n\\nLes produits chimiques usagés peuvent être des déchets dangereux pour votre environnement et votre santé. Qu’ils soient vides, souillés ou avec un reste de contenu, ils doivent être apportés en déchetterie ou en point de collecte temporaire afin de bénéficier d’une prise en charge et d’un traitement sécurisés. Il est donc important de ne plus les jeter dans la poubelle (ordures ménagères, tri sélectif) ou dans les canalisations (WC, évier) mais de les apporter en point de collecte, si possible dans leur emballage d’origine.\"}', '{}', '{}', '{\"filename\":\"0a5cff14e2354c9b86589261ab4329d6.base.image.jpg\",\"size\":{\"width\":700,\"height\":986},\"variants\":[{\"filename\":\"0a5cff14e2354c9b86589261ab4329d6.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":621,\"height\":874}},{\"filename\":\"0a5cff14e2354c9b86589261ab4329d6.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 1, 0, 'Europe/Paris', '[]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-04-18 08:25:34', '2019-04-18 08:25:34', NULL, NULL, '[]', '[]');
INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `creator_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at`, `file_key`, `references`, `links`) VALUES
(552540, 61659808, 10265018, 10265018, 89904399, 38279310, 'collectes-des-dechets-chimiques-des-particuliers-dans-les-grandes-surfaces-de-bricolage', '{\"fr\":\"Collectes des déchets chimiques des particuliers dans les grandes surfaces de bricolage\"}', '{\"fr\":\"Afin de sensibiliser les métropolitains au tri des déchets, EcoDDS organise une grande collecte de déchets chimiques dans plusieurs communes de la Métropole.\"}', '{\"fr\":\"EcoDDS a décidé de renouveler ses journées de collectes exceptionnelles sur les parkings des Grandes Surface de Bricolage partenaires. Rendez-vous le samedi 22 juin de 10h à 17h dans les magasins Castorama de **Lille Hellemmes**, **Englos** et **Haubourdin**.\\n\\nPourquoi apporter vos déchets chimiques en point de collecte ?\\n\\nLes produits chimiques usagés peuvent être des déchets dangereux pour votre environnement et votre santé. Qu’ils soient vides, souillés ou avec un reste de contenu, ils doivent être apportés en déchetterie ou en point de collecte temporaire afin de bénéficier d’une prise en charge et d’un traitement sécurisés. Il est donc important de ne plus les jeter dans la poubelle (ordures ménagères, tri sélectif) ou dans les canalisations (WC, évier) mais de les apporter en point de collecte, si possible dans leur emballage d’origine.\"}', '{}', '{}', '{\"filename\":\"c430a80ae9fb4b9f896ab818350c2413.base.image.jpg\",\"credits\":null,\"size\":{\"height\":986,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"c430a80ae9fb4b9f896ab818350c2413.full.image.jpg\",\"size\":{\"height\":874,\"width\":621}},{\"type\":\"thumbnail\",\"filename\":\"c430a80ae9fb4b9f896ab818350c2413.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-22T08:00:00.000Z\",\"end\":\"2019-06-22T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-04-18 08:17:26', '2019-04-18 08:23:25', NULL, NULL, '[]', '[]'),
(552517, 96827486, 10265018, 10265018, 89904399, 22687618, 'alberto-giacometti-a-lhonneur-de-la-15e-nuit-des-musees-au-lam', '{\"fr\":\"Alberto Giacometti à l\'honneur de la 15e Nuit des musées au LaM\"}', '{\"fr\":\"Découvrez les sculptures du parc et les œuvres d\'Alberto Giacometti comme vous ne les avez jamais vues...  à la lumière de vos lampes de poche !\"}', '{\"fr\":\"À l\'occasion de la 15è édition de la Nuit européenne, le LaM ouvre ses portes gratuitement au public de 18h à minuit ! Ce rendez-vous annuel est l\'occasion de (re)découvrir le musée, sa collection permanente et son exposition-événement, **_Alberto Giacometti, une aventure moderne_**, sous un angle original et festif. Au programme, des visites et des ateliers visant à faire découvrir le musée autrement !\\n\\nAu programme :\\n\\n**18h30 > 23h : Visites guidées de l\'exposition** **_Alberto Giacometti, une aventure moderne_**\\n\\nUn mois avant la fermeture des portes de l\'exposition-événement Alberto Giacometti, une aventure moderne, celle-ci ouvrira gratuitement au public à l\'occasion de la Nuit Européenne des Musées. Des visites guidées seront organisées tout au long de la soirée afin de découvrir le parcours sans équivalent de l\'un des artistes les plus mythiques du XXè siècle.\\n\\n**22h30 : Découverte des sculptures du parc et des oeuvres d\'Alberto Giacometti à la lumière de lampes-torches**\\n\\nOccasion rare d\'appréhender différemment les oeuvres d\'art, le musée proposera au public de déambuler dans les salles entièrement plongées dans l\'obscurité. À l\'aide d\'une lampe-torche, les visiteurs pourront contempler les sculptures d\'Alberto Giacometti, mais également celles du parc du musée, pour ne manquer aucun détail de ces oeuvres renfermant la patte de leurs créateurs.\\n\\n**Toute la soirée : Ateliers de sérigraphie et ateliers Main dans la main**\\n\\nPetits, grands, adolescents, jeunes actifs, les ateliers du musée ouvrent leurs portes à tous. Au programmen et pendant toute la soirée, des ateliers d\'initiation à la sérigraphie seront proposés ainsi que des ateliers parents-enfants. Une occasion rêvée de découvrir des pratiques d\'arts plastiques entre amis ou en famille !\"}', '{}', '{\"fr\":\"Entrée libre et gratuite de 18h à minuit (fermeture de l\'accès aux salles à partir de 23h30). Les activités proposées (visites guidées...) ont un nombre de places limité et nécessitent une réservation sur place le jour-même.\"}', '{\"filename\":\"40a6ca3c52ca40d4a89a9f9fb729e93d.base.image.jpg\",\"size\":{\"width\":700,\"height\":1051},\"variants\":[{\"filename\":\"40a6ca3c52ca40d4a89a9f9fb729e93d.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":733,\"height\":1100}},{\"filename\":\"40a6ca3c52ca40d4a89a9f9fb729e93d.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"Vue de l\'exposition Alberto Giacometti, une aventure moderne © Succession Alberto Giacometti (Fondation Alberto Giacometti, Paris + ADAGP, Paris) 2019\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-18T16:00:00.000Z\",\"end\":\"2019-05-18T22:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-04-18 07:41:14', '2019-04-18 08:22:06', NULL, NULL, '[]', '[]'),
(551661, 82914105, 10265018, 10265018, 89904399, 93922962, 'les-marocaines-du-regard-de-lautre-au-regard-sur-soi', '{\"fr\":\"Les Marocaines : du regard de l’autre au regard sur soi\"}', '{\"fr\":\"Une exposition inédite qui invite à porter un regard nouveau sur la représentation de la femme marocaine, par le prisme de la photographie.\"}', '{\"fr\":\"L\'exposition est une déambulation visuelle autour de la représentation de la femme marocaine à travers l’histoire de la photographie : de la carte postale coloniale, la photographie ethnographique et la photographie de mode aux années 1990, date à laquelle Yasmina Bouziane, première femme photographe marocaine, se joue des corps orientalisés par l’imaginaire colonial et en finit avec le « _regard de l’autre_ », masculin et étranger. C’est avec sa série « _Inhabited by Imaginings We Did Not Chose_ » qu’elle ouvre alors la route « _au regard sur soi_ ».\\n\\nL\'exposition dresse le portrait d\'une génération de femmes qui prennent leur destin en main. C\'est en images qu\'elle choisissent de parler de leurs corps, de celui de leurs mères et de leurs grands-mères, de leurs identités, leurs questionnements intérieurs, leurs désirs et leurs colères. Une quinzaine de photographes et vidéastes ont accepté de confier leurs travaux à la Maison de la photographie. Des œuvres à teneur tant sociale que politique, documentaire et intimiste.\"}', '{}', '{\"fr\":\"Normal 8€ / Réduit 5€ (Carte étudiant, seniors + 65ans , demandeurs d’emplois, détenteurs de carte famille nombreuse) / ratuit ( Enfants de - 8 ans, bénéficiaires du RSA, personnes à mobilité réduite + 1 accompagnant et lors du vernissage de l’exposition)\"}', '{\"filename\":\"11efc70f8b8e48489a6b334d3681336d.base.image.jpg\",\"credits\":\"© Yasmina Bouziane - Galerie 127\",\"size\":{\"height\":1047,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"11efc70f8b8e48489a6b334d3681336d.full.image.jpg\",\"size\":{\"height\":800,\"width\":535}},{\"type\":\"thumbnail\",\"filename\":\"11efc70f8b8e48489a6b334d3681336d.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-18T09:00:00.000Z\",\"end\":\"2019-04-18T16:00:00.000Z\"},{\"begin\":\"2019-04-19T09:00:00.000Z\",\"end\":\"2019-04-19T16:00:00.000Z\"},{\"begin\":\"2019-04-20T09:00:00.000Z\",\"end\":\"2019-04-20T16:00:00.000Z\"},{\"begin\":\"2019-04-21T09:00:00.000Z\",\"end\":\"2019-04-21T16:00:00.000Z\"},{\"begin\":\"2019-04-25T09:00:00.000Z\",\"end\":\"2019-04-25T16:00:00.000Z\"},{\"begin\":\"2019-04-26T09:00:00.000Z\",\"end\":\"2019-04-26T16:00:00.000Z\"},{\"begin\":\"2019-04-27T09:00:00.000Z\",\"end\":\"2019-04-27T16:00:00.000Z\"},{\"begin\":\"2019-04-28T09:00:00.000Z\",\"end\":\"2019-04-28T16:00:00.000Z\"},{\"begin\":\"2019-05-02T09:00:00.000Z\",\"end\":\"2019-05-02T16:00:00.000Z\"},{\"begin\":\"2019-05-03T09:00:00.000Z\",\"end\":\"2019-05-03T16:00:00.000Z\"},{\"begin\":\"2019-05-04T09:00:00.000Z\",\"end\":\"2019-05-04T16:00:00.000Z\"},{\"begin\":\"2019-05-05T09:00:00.000Z\",\"end\":\"2019-05-05T16:00:00.000Z\"},{\"begin\":\"2019-05-09T09:00:00.000Z\",\"end\":\"2019-05-09T16:00:00.000Z\"},{\"begin\":\"2019-05-10T09:00:00.000Z\",\"end\":\"2019-05-10T16:00:00.000Z\"},{\"begin\":\"2019-05-11T09:00:00.000Z\",\"end\":\"2019-05-11T16:00:00.000Z\"},{\"begin\":\"2019-05-12T09:00:00.000Z\",\"end\":\"2019-05-12T16:00:00.000Z\"},{\"begin\":\"2019-05-16T09:00:00.000Z\",\"end\":\"2019-05-16T16:00:00.000Z\"},{\"begin\":\"2019-05-17T09:00:00.000Z\",\"end\":\"2019-05-17T16:00:00.000Z\"},{\"begin\":\"2019-05-18T09:00:00.000Z\",\"end\":\"2019-05-18T16:00:00.000Z\"},{\"begin\":\"2019-05-19T09:00:00.000Z\",\"end\":\"2019-05-19T16:00:00.000Z\"},{\"begin\":\"2019-05-23T09:00:00.000Z\",\"end\":\"2019-05-23T16:00:00.000Z\"},{\"begin\":\"2019-05-24T09:00:00.000Z\",\"end\":\"2019-05-24T16:00:00.000Z\"},{\"begin\":\"2019-05-25T09:00:00.000Z\",\"end\":\"2019-05-25T16:00:00.000Z\"},{\"begin\":\"2019-05-26T09:00:00.000Z\",\"end\":\"2019-05-26T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.maisonphoto.com/\"]', '2019-04-16 14:59:52', '2019-04-17 12:35:45', NULL, NULL, '[]', '[]'),
(551309, 55652259, 8140284, 8140284, 89904399, 90550256, 'yalla-weekend-famille', '{\"fr\":\"YALLA ! Weekend Famille\"}', '{\"fr\":\"A la découverte des traditions algériennes\"}', '{\"fr\":\"Après un voyage dans l’exposition Photographier l’Algérie, les participants découvrent les traditions algériennes à travers des ateliers et une séance de contes.\\n\\nContes berbères\\n---------------\\n\\n_Nora Aceval_\\n\\nLes contes que raconte Nora Aceval, elle les a entendus depuis sa plus petite enfance sur les hautes steppes algériennes où le conte était encore un acte social. Son répertoire lui vient donc exclusivement de l’oralité. Ponctué, ci et là, d’un savoureux parler arabe, les récits de Nora enchantent\\n\\nl’auditoire. Telle est l’originalité de cette conteuse qui se place dans la transmission de la belle tradition des voix nues.\\n\\nAteliers pâtisserie\\n-------------------\\n\\n_Miéline_\\n\\nTout en préparant une pâtisserie qu’ils pourront déguster chez eux, les participants découvrent le patrimoine culinaire algérien en compagnie d’une pâtissière professionnelle. Une dégustation sucrée vient clore l’atelier.\\n\\nTatouages au henné\\n------------------\\n\\n_Reshana Henné_\\n\\nAncestral rituel de beauté, rituel protecteur ou magique, le tatouage au henné est pratiqué depuis toujours par les femmes arabes ou berbères. Pour ce week-end consacré à l’Algérie, nous avons invité des tatoueuses professionnelles à décorer votre peau de motifs traditionnels.\"}', '{}', '{\"fr\":\"Billetterie en ligne et à l’accueil de l’IMA-Tourcoing\"}', '{\"filename\":\"c3ae3b2534504a93aa0e6e8c71a81fdb.base.image.jpg\",\"size\":{\"width\":700,\"height\":394},\"variants\":[{\"filename\":\"c3ae3b2534504a93aa0e6e8c71a81fdb.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":2048,\"height\":1152}},{\"filename\":\"c3ae3b2534504a93aa0e6e8c71a81fdb.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-20T08:00:00.000Z\",\"end\":\"2019-04-20T11:00:00.000Z\"},{\"begin\":\"2019-04-20T12:30:00.000Z\",\"end\":\"2019-04-20T15:30:00.000Z\"},{\"begin\":\"2019-04-21T08:00:00.000Z\",\"end\":\"2019-04-21T11:00:00.000Z\"},{\"begin\":\"2019-04-21T12:30:00.000Z\",\"end\":\"2019-04-21T15:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://ima-tourcoing.fr/institut-monde-arabe/week-end-famille-yalla/\"]', '2019-04-16 09:40:08', '2019-04-16 09:40:08', NULL, NULL, '[]', '[]'),
(550352, 91978743, 60654151, 60654151, 89904399, 76903492, 'fresque-murale-de-cix-et-duek-glez-biennale-internationale-dart-mural-4', '{\"fr\":\"Fresque murale de CIX et DUEK GLEZ -  Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez les fresques murales des artistes CIX et DUEK GLEZ (Mexique) du 13 au 17 mai à Lille**\\n\\n_Artiste urbain mexicain, CIX jongle entre culture mystique préhispanique, folklore mexicain moderne voire futuriste et culture populaire. A travers ses créations, il aborde les thématiques de la mort, les effets du temps et les cycles de la vie en jouant graphiquement sur la distorsion de ses personnages. Sa palette est essentiellement vive et fluorescente, ce qui lui_\\n\\n_confère un style que l’on peut qualifier de « pop psychédélique »._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/cixmexico/)\\n*   Instagram : [https://www.instagram.com/cixmugre/](https://www.instagram.com/cixmugre/)\\n\\n_Duek Glez est un artiste mexicain. Il réalise des fresques de très grands formats, symbolisant notre nature et le lien que nous avons avec elle. Il traite ce sujet à travers des images et des couleurs qui dénotent la culture hispanique et ses légendes, tels que les nahuales, des êtres mythologiques de nature double, à la fois humaine (ou divine) et animale._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/bryan.duek.pkr)\\n    \\n*   Instagram : [https://www.instagram.com/duek_glez/](https://www.instagram.com/duek_glez/)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-13T07:00:00.000Z\",\"end\":\"2019-05-13T19:00:00.000Z\"},{\"begin\":\"2019-05-14T07:00:00.000Z\",\"end\":\"2019-05-14T19:00:00.000Z\"},{\"begin\":\"2019-05-15T07:00:00.000Z\",\"end\":\"2019-05-15T19:00:00.000Z\"},{\"begin\":\"2019-05-16T07:00:00.000Z\",\"end\":\"2019-05-16T19:00:00.000Z\"},{\"begin\":\"2019-05-17T07:00:00.000Z\",\"end\":\"2019-05-17T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-12 17:53:29', '2019-04-12 17:53:29', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/cixmugre/\",\"data\":{\"url\":\"https://www.instagram.com/cixmugre/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Cix Mugre (@cixmugre) • Instagram photos and videos\",\"description\":\"26.9k Followers, 1,709 Following, 1,176 Posts - See Instagram photos and videos from Cix Mugre (@cixmugre)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/21dd9209afa070c6405015a3b01e0afa/5D3DFF95/t51.2885-19/s150x150/41467623_319101705504068_1288122973391159296_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/cixmugre/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fcixmugre%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"},{\"link\":\"https://www.instagram.com/duek_glez/\",\"data\":{\"url\":\"https://www.instagram.com/duek_glez/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Duek Glez (@duek_glez) • Instagram photos and videos\",\"description\":\"3,244 Followers, 391 Following, 179 Posts - See Instagram photos and videos from Duek Glez (@duek_glez)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/79d3087b8b60d5793b2d62c54f5512af/5D4DAF12/t51.2885-19/s150x150/36748213_287426658468769_2528191662241349632_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/duek_glez/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fduek_glez%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(550345, 48075820, 60654151, 60654151, 89904399, 6783389, 'fresque-murale-4e-edition-de-la-biennale-internationale-dart-mural_689252', '{\"fr\":\"Fresque murale de SPAÏK - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de l\'artiste SPAÏK (Mexique)**\\n\\n**du 06 au 10 mai et du 13 au 17 mai à Lompret**\\n\\n_Tout droit venu du Mexique, Spaïk s\'inspire du folklore et des traditions d\'Amérique latine pour réaliser ses œuvres à la fois colorées et rayonnantes. Artiste international, il colore les rues du monde entier de ses personnages et animaux tirés de contes et de la mythologie : des Etats-Unis à l\'Europe en passant par l\'Amérique du sud._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/spaik45/)\\n    \\n*   Instagram : [https://www.instagram.com/spaik45/](https://www.instagram.com/spaik45/)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-06T07:00:00.000Z\",\"end\":\"2019-05-06T19:00:00.000Z\"},{\"begin\":\"2019-05-07T07:00:00.000Z\",\"end\":\"2019-05-07T19:00:00.000Z\"},{\"begin\":\"2019-05-08T07:00:00.000Z\",\"end\":\"2019-05-08T19:00:00.000Z\"},{\"begin\":\"2019-05-09T07:00:00.000Z\",\"end\":\"2019-05-09T19:00:00.000Z\"},{\"begin\":\"2019-05-10T07:00:00.000Z\",\"end\":\"2019-05-10T19:00:00.000Z\"},{\"begin\":\"2019-05-13T07:00:00.000Z\",\"end\":\"2019-05-13T19:00:00.000Z\"},{\"begin\":\"2019-05-14T07:00:00.000Z\",\"end\":\"2019-05-14T19:00:00.000Z\"},{\"begin\":\"2019-05-15T07:00:00.000Z\",\"end\":\"2019-05-15T19:00:00.000Z\"},{\"begin\":\"2019-05-16T07:00:00.000Z\",\"end\":\"2019-05-16T19:00:00.000Z\"},{\"begin\":\"2019-05-17T07:00:00.000Z\",\"end\":\"2019-05-17T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-12 17:27:06', '2019-04-23 11:37:50', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/spaik45/\",\"data\":{\"url\":\"https://www.instagram.com/spaik45/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Spaik45 (@spaik45) • Instagram photos and videos\",\"description\":\"10.3k Followers, 357 Following, 524 Posts - See Instagram photos and videos from Spaik45 (@spaik45)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/81c43f5e86180bb7a1c7fa8ea088b34d/5D57AD16/t51.2885-19/s150x150/49608307_359566251539022_8997943497138896896_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/spaik45/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fspaik45%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(550343, 83031408, 60654151, 60654151, 89904399, 93357848, 'fresque-murale-4e-edition-de-la-biennale-internationale-dart-mural_510943', '{\"fr\":\"Fresque murale du duo WANDERLUST SOCIAL CLUB - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez les fresques murales du duo d\'artiste**\\n\\n**WANDERLUST SOCIAL CLUB (France - Belgique)**\\n\\n**du 06 au 10 mai à Lille**\\n\\n_Passionnés par les arts naïfs et les différentes formes de peinture populaire, le duo d’artiste, Mary et Jiem, travaille de manière à la fois instinctive et spontanée. Toutes leurs œuvres gardent une grande fraicheur, affranchies des règles académiques et des standards de représentation. Ils abordent un large éventail de sujets tels que la ville et ses éléments graphiques, les cultures underground et leurs pratiques marginales, l\'amour et le romantisme..._\\n\\n*   [Facebook du duo](https://www.facebook.com/WanderlustSocialClub/)\\n*   Instagram :\\n\\nhttps://www.instagram.com/jiemwashere/\\n\\nhttps://www.instagram.com/marylimonade/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-06T07:00:00.000Z\",\"end\":\"2019-05-06T19:00:00.000Z\"},{\"begin\":\"2019-05-07T07:00:00.000Z\",\"end\":\"2019-05-07T19:00:00.000Z\"},{\"begin\":\"2019-05-08T07:00:00.000Z\",\"end\":\"2019-05-08T19:00:00.000Z\"},{\"begin\":\"2019-05-09T07:00:00.000Z\",\"end\":\"2019-05-09T19:00:00.000Z\"},{\"begin\":\"2019-05-10T07:00:00.000Z\",\"end\":\"2019-05-10T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-12 17:23:04', '2019-04-12 17:40:02', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/jiemwashere/\",\"data\":{\"url\":\"https://www.instagram.com/jiemwashere/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"JIEM (@jiemwashere) • Instagram photos and videos\",\"description\":\"1,813 Followers, 591 Following, 879 Posts - See Instagram photos and videos from JIEM (@jiemwashere)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/518c679a6c46133f8d34ffb2e37b0186/5D43519F/t51.2885-19/s150x150/52332925_602081503552316_2705271265479884800_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/jiemwashere/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fjiemwashere%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"},{\"link\":\"https://www.instagram.com/marylimonade/\",\"data\":{\"url\":\"https://www.instagram.com/marylimonade/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Mary Limonade (@marylimonade) • Instagram photos and videos\",\"description\":\"729 Followers, 527 Following, 304 Posts - See Instagram photos and videos from Mary Limonade (@marylimonade)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/f648c107c5b51f1ea7dac37f384e28ba/5D39CDE5/t51.2885-19/10808812_875850772438825_996187389_a.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/marylimonade/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fmarylimonade%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(550331, 20299999, 60654151, 60654151, 89904399, 11625437, 'fresque-murale-4e-edition-de-la-biennale-internationale-dart-mural_133317', '{\"fr\":\"Fresque murale de POES et JOBER - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez les fresques murales des artistes POES et JOBER (France) du 06 au 10 mai à Lille**\\n\\n_Graffeur français, Poes œuvre aux quatre coins de l’Europe dans une quête insatiable d’histoires, de rencontres et d’influences nouvelles. Toujours avec humour, il travaille sur la narration picturale. Il joue sur le contraste entre une peinture “naïve”, un langage graphique empreint des codes de la bande dessinée, et des thématiques plus graves, renvoyant très souvent aux mythologies antiques, urbaines ou contemporaines._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/monsieurpoes/)\\n*   Instagram : [https://www.instagram.com/monsieurpoes/](https://www.instagram.com/monsieurpoes/)\\n\\n_Passionné de dessin et de bande dessinée, JO BER commence par apposer son art sur les murs et trains de la ville de Paris au début des années 2000, et parcourt aujourd’hui le monde. Il traite avec ironie du quotidien, à travers des personnages aux visages ronds et souriants, des lignes claires et des couleurs vives. Ses inspirations oscillent entre la bande dessinée, l’époque des Néo Sumeriens, la Metropotamie, les mythologies urbaine et le ghetto_\\n\\n_antique._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/jober.artwork/)\\n    \\n*   Instagram : [https://www.instagram.com/jo__ber/](https://www.instagram.com/jo__ber/)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-06T07:00:00.000Z\",\"end\":\"2019-05-06T19:00:00.000Z\"},{\"begin\":\"2019-05-07T07:00:00.000Z\",\"end\":\"2019-05-07T19:00:00.000Z\"},{\"begin\":\"2019-05-08T07:00:00.000Z\",\"end\":\"2019-05-08T19:00:00.000Z\"},{\"begin\":\"2019-05-09T07:00:00.000Z\",\"end\":\"2019-05-09T19:00:00.000Z\"},{\"begin\":\"2019-05-10T07:00:00.000Z\",\"end\":\"2019-05-10T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-12 16:56:47', '2019-04-12 17:41:29', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/monsieurpoes/\",\"data\":{\"url\":\"https://www.instagram.com/monsieurpoes/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"poes (@monsieurpoes) • Instagram photos and videos\",\"description\":\"4,482 Followers, 1,602 Following, 550 Posts - See Instagram photos and videos from poes (@monsieurpoes)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/51669f4d88731d3306d761ad10960149/5D40A821/t51.2885-19/s150x150/17334062_187518368414558_3642632772431904768_a.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/monsieurpoes/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fmonsieurpoes%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"},{\"link\":\"https://www.instagram.com/jo__ber/\",\"data\":{\"url\":\"https://www.instagram.com/jo__ber/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"jo ber (@jo__ber) • Instagram photos and videos\",\"description\":\"4,393 Followers, 1,262 Following, 429 Posts - See Instagram photos and videos from jo ber (@jo__ber)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/e948e9cf152671dfce0e07376884069b/5D3275B5/t51.2885-19/11410390_437902283048233_940199059_a.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/jo__ber/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fjo__ber%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(550325, 61684329, 60654151, 60654151, 89904399, 77714462, 'fresque-murale-4e-edition-de-la-biennale-internationale-dart-mural_883872', '{\"fr\":\"Fresque murale de CIX et DUEK GLEZ -  Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez les fresques murales des artistes CIX et DUEK GLEZ (Mexique) du 06 au 10 mai à Lille**\\n\\n_Artiste urbain mexicain, CIX jongle entre culture mystique préhispanique, folklore mexicain moderne voire futuriste et culture populaire. A travers ses créations, il aborde les thématiques de la mort, les effets du temps et les cycles de la vie en jouant graphiquement sur la distorsion de ses personnages. Sa palette est essentiellement vive et fluorescente, ce qui lui_\\n\\n_confère un style que l’on peut qualifier de « pop psychédélique »._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/cixmexico/)\\n*   Instagram : [https://www.instagram.com/cixmugre/](https://www.instagram.com/cixmugre/)\\n\\n_Duek Glez est un artiste mexicain. Il réalise des fresques de très grands formats, symbolisant notre nature et le lien que nous avons avec elle. Il traite ce sujet à travers des images et des couleurs qui dénotent la culture hispanique et ses légendes, tels que les nahuales, des êtres mythologiques de nature double, à la fois humaine (ou divine) et animale._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/bryan.duek.pkr)\\n    \\n*   Instagram : [https://www.instagram.com/duek_glez/](https://www.instagram.com/duek_glez/)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-06T07:00:00.000Z\",\"end\":\"2019-05-06T19:00:00.000Z\"},{\"begin\":\"2019-05-07T07:00:00.000Z\",\"end\":\"2019-05-07T19:00:00.000Z\"},{\"begin\":\"2019-05-08T07:00:00.000Z\",\"end\":\"2019-05-08T19:00:00.000Z\"},{\"begin\":\"2019-05-09T07:00:00.000Z\",\"end\":\"2019-05-09T19:00:00.000Z\"},{\"begin\":\"2019-05-10T07:00:00.000Z\",\"end\":\"2019-05-10T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-12 16:50:46', '2019-04-12 17:43:06', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/cixmugre/\",\"data\":{\"url\":\"https://www.instagram.com/cixmugre/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Cix Mugre (@cixmugre) • Instagram photos and videos\",\"description\":\"26.9k Followers, 1,709 Following, 1,176 Posts - See Instagram photos and videos from Cix Mugre (@cixmugre)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/21dd9209afa070c6405015a3b01e0afa/5D3DFF95/t51.2885-19/s150x150/41467623_319101705504068_1288122973391159296_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/cixmugre/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fcixmugre%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"},{\"link\":\"https://www.instagram.com/duek_glez/\",\"data\":{\"url\":\"https://www.instagram.com/duek_glez/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Duek Glez (@duek_glez) • Instagram photos and videos\",\"description\":\"3,243 Followers, 391 Following, 179 Posts - See Instagram photos and videos from Duek Glez (@duek_glez)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/79d3087b8b60d5793b2d62c54f5512af/5D4DAF12/t51.2885-19/s150x150/36748213_287426658468769_2528191662241349632_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/duek_glez/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fduek_glez%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(550314, 58919270, 60654151, 60654151, 89904399, 43342849, 'fresque-murale-4e-edition-de-la-biennale-internationale-dart-mural_182056', '{\"fr\":\"Fresque murale de Jade Riviera - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de l\'artiste Jade Riviera (Pérou)**\\n\\n**du 22 au 26 avril à Lille**\\n\\n_Peintre muraliste péruvien, JADE réalise des peintures murales à grande échelle dans le monde entier. Son travail se concentre sur la représentation de situations de la vie quotidienne et culturelle à travers un imaginaire qui embrasse les émotions et la spiritualité de l\'être humain. Pour lui, la rue est un outil de communication qui permet de nous questionner sur notre quotidien à travers des réalisations délicates et colorées._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/RIVERAJADE/)\\n*   Instagram : https://www.instagram.com/jade1rivera/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-22T07:00:00.000Z\",\"end\":\"2019-04-22T19:00:00.000Z\"},{\"begin\":\"2019-04-23T07:00:00.000Z\",\"end\":\"2019-04-23T19:00:00.000Z\"},{\"begin\":\"2019-04-24T07:00:00.000Z\",\"end\":\"2019-04-24T19:00:00.000Z\"},{\"begin\":\"2019-04-25T07:00:00.000Z\",\"end\":\"2019-04-25T19:00:00.000Z\"},{\"begin\":\"2019-04-26T07:00:00.000Z\",\"end\":\"2019-04-26T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-12 16:34:35', '2019-04-12 17:44:01', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/jade1rivera/\",\"data\":{\"url\":\"https://www.instagram.com/jade1rivera/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Jade Rivera (@jade1rivera) • Instagram photos and videos\",\"description\":\"42.1k Followers, 1,320 Following, 1,044 Posts - See Instagram photos and videos from Jade Rivera (@jade1rivera)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/8afb46948253ac20aae607b7003b2a38/5D40CF11/t51.2885-19/11280241_1450384618605033_1644427243_a.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/jade1rivera/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fjade1rivera%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(550308, 97612082, 60654151, 60654151, 89904399, 33805772, 'fresque-murale-4e-edition-de-la-biennale-internationale-dart-mural_451186', '{\"fr\":\"Fresque murale de Maria Isabel Rueda - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de l\'artiste Maria Isabel Rueda (Colombie) du 22 au 26 avril à Lille**\\n\\n_Florales, féminines et lyriques, les œuvres de la plasticienne Maria Isabel Rueda nous apportent une part de Colombie pour cette 4ème édition de la BIAM. Maria Isabel Rueda recrée les scénarios de ses rêves, de ses souvenirs et de ses peurs dans ses créations, majoritairement réalisées en noir et blanc. Elle accorde une grande importance aux lignes, aux espaces et à la construction de ses dessins._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/mariaisabelrueda)\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-22T07:00:00.000Z\",\"end\":\"2019-04-22T19:00:00.000Z\"},{\"begin\":\"2019-04-23T07:00:00.000Z\",\"end\":\"2019-04-23T19:00:00.000Z\"},{\"begin\":\"2019-04-24T07:00:00.000Z\",\"end\":\"2019-04-24T19:00:00.000Z\"},{\"begin\":\"2019-04-25T07:00:00.000Z\",\"end\":\"2019-04-25T19:00:00.000Z\"},{\"begin\":\"2019-04-26T07:00:00.000Z\",\"end\":\"2019-04-26T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-12 16:21:30', '2019-04-12 17:45:02', NULL, NULL, '[]', '[]');
