(550303, 37648541, 60654151, 60654151, 89904399, 68342883, 'fresque-murale-4e-edition-de-la-biennale-internationale-dart-mural', '{\"fr\":\"Fresque murale de SPAÏK - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués, de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez la fresque murale de l\'artiste SPAÏK (Mexique)**\\n\\n**du 15 au 26 avril à Lille**\\n\\n_Tout droit venu du Mexique, Spaïk s\'inspire du folklore et des traditions d\'Amérique latine pour réaliser ses œuvres à la fois colorées et rayonnantes. Artiste international, il colore les rues du monde entier de ses personnages et animaux tirés de contes et de la mythologie : des Etats-Unis à l\'Europe en passant par l\'Amérique du sud._\\n\\n*   [Facebook de l\'artiste](https://www.facebook.com/spaik45/)\\n    \\n*   Instagram : https://www.instagram.com/spaik45/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-15T07:00:00.000Z\",\"end\":\"2019-04-15T19:00:00.000Z\"},{\"begin\":\"2019-04-16T07:00:00.000Z\",\"end\":\"2019-04-16T19:00:00.000Z\"},{\"begin\":\"2019-04-17T07:00:00.000Z\",\"end\":\"2019-04-17T19:00:00.000Z\"},{\"begin\":\"2019-04-18T07:00:00.000Z\",\"end\":\"2019-04-18T19:00:00.000Z\"},{\"begin\":\"2019-04-19T07:00:00.000Z\",\"end\":\"2019-04-19T19:00:00.000Z\"},{\"begin\":\"2019-04-20T07:00:00.000Z\",\"end\":\"2019-04-20T19:00:00.000Z\"},{\"begin\":\"2019-04-21T07:00:00.000Z\",\"end\":\"2019-04-21T19:00:00.000Z\"},{\"begin\":\"2019-04-22T07:00:00.000Z\",\"end\":\"2019-04-22T19:00:00.000Z\"},{\"begin\":\"2019-04-23T07:00:00.000Z\",\"end\":\"2019-04-23T19:00:00.000Z\"},{\"begin\":\"2019-04-24T07:00:00.000Z\",\"end\":\"2019-04-24T19:00:00.000Z\"},{\"begin\":\"2019-04-25T07:00:00.000Z\",\"end\":\"2019-04-25T19:00:00.000Z\"},{\"begin\":\"2019-04-26T07:00:00.000Z\",\"end\":\"2019-04-26T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-12 15:57:24', '2019-04-12 17:49:52', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/spaik45/\",\"data\":{\"url\":\"https://www.instagram.com/spaik45/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Spaik45 (@spaik45) • Instagram photos and videos\",\"description\":\"10.2k Followers, 353 Following, 524 Posts - See Instagram photos and videos from Spaik45 (@spaik45)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/83777035418eb05433ea14b187e39c26/5D302016/t51.2885-19/s150x150/49608307_359566251539022_8997943497138896896_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/spaik45/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Fspaik45%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(549807, 2608747, 60654151, 60654151, 89904399, 46245376, 'partcours-art-mural-a-velo', '{\"fr\":\"P[art]cours art mural à vélo\"}', '{\"fr\":\"Passionné d’art urbain, curieux, famille… cette visite pigmentée à vélo convient à tous !\"}', '{\"fr\":\"Le Collectif Renart vous embarque dans une visite insolite à vélo du quartier Moulins et Saint Sauveur dans le cadre de la 4ème édition de la Biennale Internationale d’Art Mural.\\n\\n**Gonflez vos pneus, sortez votre plus beau casque et venez découvrir une nouvelle facette haute en couleur de Lille, sous le prisme de l’art urbain.**\\n\\nLors de ces visites, vous découvrirez des œuvres réalisées dans le cadre des précédentes BIAM ainsi que des peintures en live par les artistes invités pour cette 4ème édition.\\n\\n**Pensez à réserver votre place par mail à :** biam.npdc@gmail.com\"}', '{}', '{\"fr\":\"Sur réservation; prix : 7€; Durée de la visite : 1h30-2h\"}', '{\"filename\":\"ebec3b68592846b491dd3ec691c3211c.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"ebec3b68592846b491dd3ec691c3211c.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"ebec3b68592846b491dd3ec691c3211c.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-30T16:00:00.000Z\",\"end\":\"2019-05-30T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":6,\"max\":99}', '[\"biam.npdc@gmail.com\",\"https://www.facebook.com/events/2003086329995060/\",\"https://www.facebook.com/collectif.renart/\",\"https://biam-npdc.blogspot.com/\"]', '2019-04-11 16:02:57', '2019-04-12 07:49:09', NULL, NULL, '[]', '[]'),
(549798, 50544915, 60654151, 60654151, 89904399, 46245376, 'partcours-art-mural-biennale-internationale-dart-mural', '{\"fr\":\"P[art]cours art mural – Biennale Internationale d\'Art Mural\"}', '{\"fr\":\"Passionné d’art urbain, curieux, famille… cette visite pigmentée convient à tous !\"}', '{\"fr\":\"Le Collectif Renart vous embarque dans une visite insolite du quartier Moulins et Saint Sauveur dans le cadre de la 4ème édition de la Biennale Internationale d’Art Mural.\\n\\n**Découvrez une nouvelle facette haute en couleur de la ville de Lille, sous le prisme de l’art urbain.**\\n\\nLors de ces visites, vous découvrirez des œuvres réalisées dans le cadre des précédentes BIAM ainsi que des peintures en live par les artistes invités pour cette 4ème édition.\\n\\n**Pensez à réserver votre place par mail à :** **biam.npdc@gmail.com**\"}', '{}', '{\"fr\":\"Sur réservation ; Prix : 7€ ; durée de la visite : 1h30/2h\"}', '{\"filename\":\"579dd1aa6e674d7fbebd59ea2a5ac4a6.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"579dd1aa6e674d7fbebd59ea2a5ac4a6.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"579dd1aa6e674d7fbebd59ea2a5ac4a6.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-25T16:00:00.000Z\",\"end\":\"2019-04-25T17:30:00.000Z\"},{\"begin\":\"2019-05-09T16:00:00.000Z\",\"end\":\"2019-05-09T17:30:00.000Z\"},{\"begin\":\"2019-05-16T16:00:00.000Z\",\"end\":\"2019-05-16T17:30:00.000Z\"},{\"begin\":\"2019-05-23T16:00:00.000Z\",\"end\":\"2019-05-23T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":6,\"max\":99}', '[\"biam.npdc@gmail.com\",\"https://www.facebook.com/events/1025764884280424/\",\"https://www.facebook.com/collectif.renart/\",\"https://biam-npdc.blogspot.com/\"]', '2019-04-11 15:56:59', '2019-04-12 07:48:11', NULL, NULL, '[]', '[]'),
(549790, 69942853, 60654151, 60654151, 89904399, 55660095, 'soiree-de-cloture-biennale-internationale-dart-mural', '{\"fr\":\"Soirée de clôture Biennale Internationale d\'Art Mural\"}', '{\"fr\":\"Pour fêter tous ensemble la fin de cette Biennale Internationale d\'Art Mural#4. Au menu : Soul, Hip-hop, Bass music ...\"}', '{\"fr\":\"Le Collectif Renart, en partenariat avec le Flow - Centre Eurorégional des Cultures Urbaines, vous donne rendez-vous pour\\n\\n**une soirée de clôture déchaînée**\\n\\n**vendredi 7 juin à partir de 20h**\\n\\n**à La Bulle Café - Maison Folie Moulins / Flow à Lille**\\n\\nSoirée en partenariat avec le Flow - Centre Eurorégional des Cultures Urbaines.\\n\\n**Au menu : Soul, Hip-hop et Bass music**\\n\\nDJ Sebti Baker\\n\\n► [https://www.mixcloud.com/sebti-baker/](https://www.mixcloud.com/sebti-baker/)\\n\\nDJ SAS\\n\\n► [https://soundcloud.com/djsasmusic](https://soundcloud.com/djsasmusic)\\n\\nDJ Sims & DJ May Din\\n\\n► [https://www.youtube.com/c/NOWFUTURRRR](https://www.youtube.com/c/NOWFUTURRRR)\\n\\n► [https://www.facebook.com/elfiloi](https://www.facebook.com/elfiloi)\\n\\nDj Keutch\\n\\n► [https://www.mixcloud.com/deejayKeutch/](https://www.mixcloud.com/deejayKeutch/)\\n\\n► [http://alouettestreet.fr/artist/dj-keutch-fr/](http://alouettestreet.fr/artist/dj-keutch-fr/)\"}', '{}', '{\"fr\":\"Entrée gratuire, buvette sur place\"}', '{\"filename\":\"c17f019ff3e5427cbf6c7f9612d47a6a.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"c17f019ff3e5427cbf6c7f9612d47a6a.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"c17f019ff3e5427cbf6c7f9612d47a6a.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-07T18:00:00.000Z\",\"end\":\"2019-06-07T23:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.facebook.com/labullecafe/\",\"https://www.facebook.com/collectif.renart/\",\"https://www.facebook.com/flowlille/\"]', '2019-04-11 15:38:53', '2019-04-12 07:50:56', NULL, NULL, '[]', '[{\"link\":\"https://soundcloud.com/djsasmusic\",\"data\":{\"url\":\"https://soundcloud.com/djsasmusic\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"DJ SAS Music\",\"author\":\"DJ SAS Music\",\"author_url\":\"http://soundcloud.com/djsasmusic\",\"provider_name\":\"SoundCloud\",\"description\":\"www.djsas.com\\r\\nEvent Bookings:\\r\\n(678)685-1056 \\r\\ndjsasmusic@gmail.com\\r\\n\",\"thumbnail_url\":\"//i1.sndcdn.com/avatars-000037580510-kfy4ft-t500x500.jpg\",\"thumbnail_width\":500,\"thumbnail_height\":500,\"height\":450,\"html\":\"<iframe src=\\\"https://w.soundcloud.com/player/?visual=true&amp;url=http%3A%2F%2Fapi.soundcloud.com%2Fusers%2F7796662&amp;show_artwork=true\\\" style=\\\"border: 0; width: 100%; height: 450px;\\\" allowfullscreen allow=\\\"autoplay; encrypted-media\\\"></iframe>\",\"cache_age\":86400},\"type\":\"oembed\"},{\"link\":\"https://www.youtube.com/c/NOWFUTURRRR\",\"data\":{\"url\":\"https://www.youtube.com/channel/UCfY6RHfEfD2Da-smuZsG5nA\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"NOW FUTUR\",\"provider_name\":\"YouTube\",\"description\":\"Diggin\' into the crates Samples, mixtapes and reworks specialists as seen on @Okayplayer @radionova\",\"thumbnail_url\":\"https://yt3.ggpht.com/a-/AAuE7mBn2EtK9RDpwCBi6x9q3xiU1WUTtnMiCtqPJQ=s900-mo-c-c0xffffffff-rj-k-no\",\"thumbnail_width\":900,\"thumbnail_height\":900,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.youtube.com/channel/UCfY6RHfEfD2Da-smuZsG5nA\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.youtube.com%2Fc%2FNOWFUTURRRR&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(549598, 7981912, 60654151, 60654151, 89904399, 21290586, '4e-edition-de-la-biennale-internationale-dart-mural-du-8-avril-au-8-juin', '{\"fr\":\"Fresques murales de Tlacolulokos et Lady Alézia - Biennale Internationale d’Art Mural #4\"}', '{\"fr\":\"Organisée par le Collectif Renart, la BIAM explore la richesse des techniques de l’art mural et fait rayonner la métropole en matière de street art. Au programme : ateliers, expos, visites guidées…\"}', '{\"fr\":\"La 4e édition de la Biennale Internationale d\'Art Mural est aux couleurs d\'Eldorado. Du 8 avril au 8 juin, de nombreux artistes mexicains sont invités et collaboreront avec des artistes locaux.\\n\\nCette nouvelle édition de la BIAM se déroule dans 6 villes métropolitaines : Hellemmes, Lille, Lomme, Lompret, Saint-André-Lez-Lille, Villeneuve d\'Ascq et 2 villes hors métropole : Denain et Wavrechain-Sous-Denain.\\n\\n**Partez à la rencontre d\'artistes multiculturels et multigénérationnels ouverts sur le monde**\\n\\nAu programme :\\n\\n*   Une trentaine d\'artistes impliqués de 6 nationalités différentes\\n*   Rencontres / débats, des projections, une exposition de sérigraphies…\\n*   Visites guidées street art\\n*   Ateliers d\'initiation prévus\\n*   24 installations murales\\n*   2 rétrospectives d\'ateliers\\n\\n**Découvrez les fresques murales des artistes Tlacolulokos et Lady Alézia (Mexique - France) du 22 au 26 avril à Lille**\\n\\n_Avec un style figuratif et une forte inspiration hispanique, les mexicains Dario Canul et Cosijoe- sa Cernas sont connus à travers le monde pour leurs fresques colossales. A eux deux, ils forment le duo « Tlacolulokos », nom emprunté à leur village d’origine. Au cœur de leur travail, la thématique de la famille, de l’identité et des traditions autochtones. Ils mélangent la calligraphie, l’ornementation et l’art du portrait pour proposer des œuvres originales et monumentales._\\n\\n*   [Facebook](https://www.facebook.com/Tlacolulokos/)\\n    \\n*   Instagram : https://www.instagram.com/tlacolulokos_activos/\\n    \\n\\n_Graffeuse & Calligraphe de la région Lilloise, Lady Alézia apporte un regard empreint de douceur et de richesse de couleur, tout en mouvement. Sensible aux écritures urbaines, calligraphiques et typographiques, à la recherche d\'un alphabet esthétisé à travers tags, lettres gothiques, représentations figuratives, éléments urbains, floraux, végétaux, elle aborde principalement la thématique du temps._\\n\\n*   Instagram : https://www.instagram.com/lady.alezia/\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.base.image.jpg\",\"credits\":\"Collectif Renart\",\"size\":{\"height\":260,\"width\":700},\"variants\":[{\"type\":\"full\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.full.image.jpg\",\"size\":{\"height\":315,\"width\":851}},{\"type\":\"thumbnail\",\"filename\":\"bdfd818892ed4f15aa8cf3ccd6451e12.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-22T07:00:00.000Z\",\"end\":\"2019-04-22T19:00:00.000Z\"},{\"begin\":\"2019-04-23T07:00:00.000Z\",\"end\":\"2019-04-23T19:00:00.000Z\"},{\"begin\":\"2019-04-24T07:00:00.000Z\",\"end\":\"2019-04-24T19:00:00.000Z\"},{\"begin\":\"2019-04-25T07:00:00.000Z\",\"end\":\"2019-04-25T19:00:00.000Z\"},{\"begin\":\"2019-04-26T07:00:00.000Z\",\"end\":\"2019-04-26T19:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://fr-fr.facebook.com/collectif.renart/\",\"https://www.instagram.com/collectif_renart/?hl=fr\",\"collectif.renart@gmail.com\"]', '2019-04-11 13:03:02', '2019-04-12 17:48:48', NULL, NULL, '[]', '[{\"link\":\"https://www.instagram.com/tlacolulokos_activos/\",\"data\":{\"url\":\"https://www.instagram.com/tlacolulokos_activos/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"Dario Cánul (@tlacolulokos_activos) • Instagram photos and videos\",\"description\":\"4,268 Followers, 1,129 Following, 334 Posts - See Instagram photos and videos from Dario Cánul (@tlacolulokos_activos)\",\"thumbnail_url\":\"https://scontent-iad3-1.cdninstagram.com/vp/97f88b253e6e48823f44dc400431d5ab/5D4FBFD9/t51.2885-19/s150x150/47583337_379451739475438_6289914261359558656_n.jpg?_nc_ht=scontent-iad3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/tlacolulokos_activos/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Ftlacolulokos_activos%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"},{\"link\":\"https://www.instagram.com/lady.alezia/\",\"data\":{\"url\":\"https://www.instagram.com/lady.alezia/\",\"type\":\"rich\",\"version\":\"1.0\",\"title\":\"~ Lady Alézia ~ (@lady.alezia) • Instagram photos and videos\",\"description\":\"226 Followers, 68 Following, 8 Posts - See Instagram photos and videos from ~ Lady Alézia ~ (@lady.alezia)\",\"thumbnail_url\":\"https://scontent-lga3-1.cdninstagram.com/vp/d3a2ad82b51b537232dadbd1532972d6/5D303DC4/t51.2885-19/s150x150/36928544_1968776833414449_4230633796917002240_n.jpg?_nc_ht=scontent-lga3-1.cdninstagram.com\",\"thumbnail_width\":150,\"thumbnail_height\":150,\"cache_age\":86400,\"html\":\"<div class=\\\"iframely-embed\\\"><div class=\\\"iframely-responsive\\\" style=\\\"height: 140px; padding-bottom: 0;\\\"><a href=\\\"https://www.instagram.com/lady.alezia/\\\" data-iframely-url=\\\"//cdn.iframe.ly/api/iframe?url=https%3A%2F%2Fwww.instagram.com%2Flady.alezia%2F&amp;key=7db9d78bdbb5e7d79acb1240cae64b0e\\\"></a></div></div><script async src=\\\"//cdn.iframe.ly/embed.js\\\" charset=\\\"utf-8\\\"></script>\"},\"type\":\"oembed\"}]'),
(548856, 16290539, 82253124, 82253124, 89904399, 44546590, 'diversidays', '{\"fr\":\"Diversidays\"}', '{\"fr\":\"Découvrez le parcours et les projets des huit talents accompagnés par Diversidays.\"}', '{\"fr\":\"L\'objectif de Diversidays ? Créer un collectif national de bénévoles et décideurs en faveur de l’émergence des talents de la diversité dans le secteur du numérique.\\n\\nUne grande cérémonie proposera aux décideurs des Hauts-de-France et au grand public de découvrir le parcours et les projets des 8 talents accompagnés par Diversidays.\"}', '{}', '{\"fr\":\"http://billetterie.diversidays.com\"}', '{\"filename\":\"2525c27c5908479c87cd88d00e743b0d.base.image.jpg\",\"credits\":\"Diversidays\",\"size\":{\"height\":368,\"width\":701},\"variants\":[{\"type\":\"full\",\"filename\":\"2525c27c5908479c87cd88d00e743b0d.full.image.jpg\",\"size\":{\"height\":2626,\"width\":5000}},{\"type\":\"thumbnail\",\"filename\":\"2525c27c5908479c87cd88d00e743b0d.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-25T17:30:00.000Z\",\"end\":\"2019-04-25T22:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.diversidays.com\"]', '2019-04-10 13:21:03', '2019-04-18 07:37:29', NULL, NULL, '[]', '[]'),
(545994, 74828576, 56673351, 56673351, 89904399, 1995915, 'tous-en-bottes-ferme-du-coeur-joyeux', '{\"fr\":\"Tous en bottes ! Ferme du cœur joyeux\"}', '{\"fr\":\"Partez à la découverte des fermes du réseau CIVAM ! À la ferme du cœur joyeux, découvrez la parcelle de maraîchage, la boulange, l\'activité apiculture, et participez à plusieurs ateliers.\"}', '{\"fr\":\"\\\"Venez visiter l\'exploitation d\'un maraîcher bio, producteur pour une AMAP, qui abrite également un apiculteur/boulanger et une productrice de plantes aromatiques.\\\" [CIVAM](http://www.civam-hautsdefrance.fr/)\\n\\n\\\\- **Atelier bombes de graines** : venez apprendre à réaliser vos \\\"bombes de graines\\\" et emmenez-les pur les jeter dans les lieux de friche où il manque de la verdure.\\n\\n\\\\- **Atelier semis** : venez réaliser des semis de légumes, fleurs ou plantes aromatiques et repartez avec vos réalisations.\\n\\n\\\\- **Dégustation à base de produits de la ferme**\"}', '{\"fr\":[\"ferme\",\"agriculture\",\"portes ouvertes\",\"CIVAM\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":null,\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[]}', 1, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-27T08:00:00.000Z\",\"end\":\"2019-04-27T15:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-04-04 15:16:43', '2019-04-04 15:16:43', NULL, NULL, '[]', '[]'),
(545769, 47542319, 56673351, 56673351, 89904399, 67780783, 'btwin-chti-bike-tour', '{\"fr\":\"Btwin Ch\'ti Bike Tour\"}', '{\"fr\":\"Les 24 et 25 août, participez au B\'Twin Ch\'ti Bike Tour : deux jours de vélo pour tous les âges. Différents parcours seront proposés dans toute la métropole.\"}', '{\"fr\":\"Btwin Ch\'ti Bike Tour\\n---------------------\\n\\n\\\"Deux jours de vélo pour tous\\\", telle est la devise du B\'Twin Ch\'ti Bike Tour qui aura lieu les 24 et 25 août. Du vélo pour tous les goûts, tous les niveaux et tous les âges.\\n\\nLes Prés du Hem à Armentières, le B\'Twin Village à Hellemmes et le parc d\'Olhain accueillent cet événement incontournable pour les amateurs de cycle.\\n\\nDifférents parcours sont proposés : un défi d\'environ 160km, du VTT en randonnée de nuit, une rando famille autour d\'Armentières et nouveauté, un Triban Ch\'ti Gravel, des randos sur chemin avec 2 distances au choix 40 et 60 km. Autre nouveauté, l\'Urban Rando Cyclo de la MEL avec la draisienne du B\'twin Village.\\n\\nPour découvrir la ville de Lille de façon originale grâce à des animations surprenantes, participez à l\'Urban Rando Cyclo au départ du B\'Twin Village en passant par le siège de la MEL. Nouveauté, la draisienne du B\'twin Village!\\n\\nChoisissez le parcours qui vous convient le mieux, inscrivez-vous et prenez la route à vélo seul, entre amis ou en famille.\\n\\nSamedi 24 Août\\n--------------\\n\\n### Armentières\\n\\n**\\\\- 8h00**\\n\\nDépart du Défi Route Crédit Mutuel 1ère étape\\n\\nEnviron 160 km - Entre Armentières et Olhain\\n\\n**\\\\- Entre 7h00 et 11h00**\\n\\nRoutes des Monts des Hauts de France\\n\\nRandos sur route 3 distances au choix : 50 km, 80 km, 110 km et 140km\\n\\nTriban Ch\'ti Gravel NOUVEAU !\\n\\nRandos sur chemins. Deux distances au choix : 40km et 60km\\n\\n**PARC D’OLHAIN**\\n\\n**\\\\- Entre 13h00 et 18h00** \\\\- Arrivée 1ère étape du Défi Route Crédit Mutuel\\n\\n**\\\\- 20h30** \\\\- Nocturne VTT du Pas de Calais\\n\\nDimanche 25 Août\\n----------------\\n\\n### Armentières -PRES DU HEM\\n\\n**\\\\- 10h30 -**\\n\\nRando Familles du Nord\\n\\n20 km à la visite originale d’Armentières et de ses environs\\n\\n**\\\\- A partir de 13h00 -**\\n\\nArrivée du Défi Route Crédit Mutuel\\n\\n**PARC D’OLHAIN**\\n\\n**\\\\- 7h30 -**\\n\\nDépart du Défi Route Crédit Mutuel 2ème étape\\n\\nEnviron 160 km entre Olhain et Armentières\\n\\n**\\\\- Entre 7h30 et 10h00**\\n\\nRandos VTT de l\'Agglo Béthune – BruayRandos 4 distances au choix : 20 km,40 km, 60 km, 90 km.\\n\\n### BTWIN VILLAGE\\n\\n**\\\\- A partir de 9h30 -**\\n\\nUrban Rando Cyclo de la MEL.\\n\\nBalade de 18 km à la découverte originale de Lille\\n\\nLa Draisienne du BTWIN Village NOUVEAU !\"}', '{\"fr\":[\"vélo\",\"chti\",\"bike\",\"tour\",\"parcours\",\"balade\",\"sport\"]}', '{\"fr\":\"Sur inscription\"}', '{\"filename\":\"dcfef64c2bb546069b02765fca1c7005.base.image.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":188,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"dcfef64c2bb546069b02765fca1c7005.full.image.jpg\",\"size\":{\"height\":625,\"width\":2000}},{\"type\":\"thumbnail\",\"filename\":\"dcfef64c2bb546069b02765fca1c7005.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-08-24T06:00:00.000Z\",\"end\":\"2019-08-24T18:00:00.000Z\"},{\"begin\":\"2019-08-25T06:00:00.000Z\",\"end\":\"2019-08-25T18:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false,\"ii\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.lechtibiketour.org\"]', '2019-04-04 11:36:13', '2020-05-28 08:32:01', '2020-05-28 08:32:37', NULL, '[]', '[]'),
(524126, 82306338, 8140284, 8140284, 89904399, 20270723, 'judo-tournoi-international-christophe-maquet-27', '{\"fr\":\"JUDO: TOURNOI INTERNATIONAL CHRISTOPHE MAQUET #27\"}', '{\"fr\":\"Le 27ème TCM, le samedi 6 avril à Sainghin en Mélantois, pourrait être un cru exceptionnel, avec la participation confirmée de 2 sélections de JUDO SCOTLAND, des Hollandais, des Belges et Italien\"}', '{\"fr\":\"Le 27ème TCM, le samedi 6 avril prochain à Sainghin en Mélantois, pourrait être un cru exceptionnel, avec la participation confirmée de 2 sélections de JUDO SCOTLAND, des Hollandais, des Belges et Italiens.\\n\\nPar ailleurs, certaines très grosses écuries françaises, comme FLAM91, Orléans, Chilly Mazarin ou encore Blanc Mesnil Sport Judo, pour ne citer qu’elles, promettent un plateau de niveau 1ère division et la présence, très certaine, de pointures de notre discipline, comme par exemple Kilian LE BLOUCH, tout récent vainqueur du Grand Slam d’Ekaterinbourg, qui pourrait accompagner son groupe de FLAM91.\\n\\nPlus d\'informations : [http://www.jcsainghin.com/27eme-tournoi-international-par-equipes-mixtes-juse-label-excellence-christophe-maquet-a-sainghin-en-melantois-060419-plateau-previsionnel/](http://www.jcsainghin.com/27eme-tournoi-international-par-equipes-mixtes-juse-label-excellence-christophe-maquet-a-sainghin-en-melantois-060419-plateau-previsionnel/)\"}', '{\"fr\":[\"judo\"]}', '{}', '{\"filename\":\"44b6752d88924d60b6283b898dfa39a4.base.image.jpg\",\"size\":{\"width\":600,\"height\":400},\"variants\":[{\"filename\":\"44b6752d88924d60b6283b898dfa39a4.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":600,\"height\":400}},{\"filename\":\"44b6752d88924d60b6283b898dfa39a4.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-06T11:30:00.000Z\",\"end\":\"2019-04-06T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.jcsainghin.com/27eme-tournoi-international-par-equipes-mixtes-juse-label-excellence-christophe-maquet-a-sainghin-en-melantois-060419-plateau-previsionnel/\"]', '2019-04-01 14:43:50', '2019-04-01 14:43:50', NULL, NULL, '[]', '[]'),
(522771, 27360568, 81996142, 81996142, 89904399, 66781882, 'moussin-lille', '{\"fr\":\"Mouss\'in Lille\"}', '{\"fr\":\"Concert Rollin Slippers\"}', '{\"fr\":\"Ça y est, la belle surprise que nous vous annoncions est arrivée !!!\\n\\nNous sommes heureux et fiers de vous annoncer une journée exceptionnelle au Novotel Lille Centre Gares : Mouss’in Lille !!!\\n\\nLors de l\'après-midi 20 Avril, les principales micro-brasseries de la métropole seront présentes afin de vous faire découvrir leurs produits dans le cadre d’une vente exclusive et éphémère.\\n\\nNous aurons le privilège d’accueillir 6 brasseurs et d’assister à la démonstration d’un brassage traditionnel dans le hall de l’hôtel !\\n\\nL\'Échappée Bière propose un atelier-dégustation de 16h à 18h. Vous découvrirez 4 bières d’exception avec des planches apéro en accompagnement.\\n\\nL’ensemble des brasseurs proposeront leurs bières tout au long de la journée au Gourmet Bar.\\n\\nEt pour terminer cet événement en beauté, les Rollin Slippers prendront d’assaut la scène du Novotel au rythme d’un blues/rock survolté, chaleureux et dansant !\\n\\nVenez nombreux pour cette fête conviviale, dont l\'entrée est gratuite, autour de l’un des plus chaleureux produits de la région Hauts-de-France.\\n\\nEn attendant cet événement, nous vous présenterons prochainement les brasseries partenaires au travers de nos prochains post.\"}', '{}', '{\"fr\":\"Entrée Libre Dégustation Sous Réservation\"}', '{\"filename\":\"bafc9e5d8e084ca8a9f8e941fafb8c62.base.image.jpg\",\"size\":{\"width\":600,\"height\":864},\"variants\":[{\"filename\":\"bafc9e5d8e084ca8a9f8e941fafb8c62.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":2392,\"height\":3441}},{\"filename\":\"bafc9e5d8e084ca8a9f8e941fafb8c62.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-20T12:00:00.000Z\",\"end\":\"2019-04-20T19:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://tourisme.echappee-biere.fr/produit/degustation-de-bieres-a-lille-samedi-20-avril/?fbclid=IwAR0ruB3awqfSqjjNsxVnBQ77Q5KRacnOB8Br7lG3n5zbnHPZAaRNCxnolio\"]', '2019-03-28 20:54:15', '2019-03-28 20:54:15', NULL, NULL, '[]', '[]'),
(522616, 94298442, 85191752, 85191752, 89904399, 32909231, 'soiree-de-degustation-de-la-nouvelle-biere-3-brasseurs-villeneuve-dascq', '{\"fr\":\"SOIRÉE DE DÉGUSTATION DE LA NOUVELLE BIÈRE \\\"3 BRASSEURS VILLENEUVE-D\'ASCQ\\\"\"}', '{\"fr\":\"Le restaurant 3 Brasseurs de Villeneuve-d\'Ascq vous propose de découvrir sa nouvelle bière, créée dans le cadre du concours Master Brasseur.\"}', '{\"fr\":\"Lucien Leuliette, Maitre Brasseur du restaurant 3 Brasseurs de Villeneuve-d\'Ascq, vous attend nombreux lors d\'une soirée de dégustation. A cette occasion, il dévoilera sa toute nouvelle création : une bière au Yuzu et poivre de Sichuan.\\n\\nUn bon moment de convivialité ponctué de nombreuses animations.\"}', '{}', '{\"fr\":\"Gratuit\"}', '{\"filename\":\"3eccd12253bc471b88076c783cea239a.base.image.jpg\",\"size\":{\"width\":600,\"height\":870},\"variants\":[{\"filename\":\"3eccd12253bc471b88076c783cea239a.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":245,\"height\":355}},{\"filename\":\"3eccd12253bc471b88076c783cea239a.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"3 Brasseurs\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-04T16:00:00.000Z\",\"end\":\"2019-04-04T22:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://restaurants.3brasseurs.com/fr/s/brasseurs/la-pilaterie/867\"]', '2019-03-28 16:05:38', '2019-03-28 16:05:38', NULL, NULL, '[]', '[]'),
(522611, 41913637, 85191752, 85191752, 89904399, 85237122, 'soiree-de-degustation-de-la-nouvelle-biere-3-brasseurs-englos', '{\"fr\":\"SOIRÉE DE DÉGUSTATION DE LA NOUVELLE BIÈRE \\\"3 BRASSEURS ENGLOS\\\"\"}', '{\"fr\":\"Le restaurant 3 Brasseurs d\'Englos vous propose de découvrir sa nouvelle bière, créée dans le cadre du concours Master Brasseur.\"}', '{\"fr\":\"Yann Bilongo, Maître Brasseur du restaurant 3 Brasseurs d\'Englos, vous attend nombreux lors d\'une soirée de dégustation. A cette occasion, il dévoilera sa toute nouvelle création : une bière blonde triple inspirée de la savane.\\n\\nUn bon moment de convivialité ponctué de nombreuses animations (concert et dégustation gratuite).\"}', '{}', '{\"fr\":\"Gratuit\"}', '{\"filename\":\"b89a96e90daf459e8f8b7e931051d413.base.image.jpg\",\"size\":{\"width\":600,\"height\":846},\"variants\":[{\"filename\":\"b89a96e90daf459e8f8b7e931051d413.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":369,\"height\":520}},{\"filename\":\"b89a96e90daf459e8f8b7e931051d413.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-04T16:00:00.000Z\",\"end\":\"2019-04-04T22:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://restaurants.3brasseurs.com/fr/s/brasseurs/englos/389\"]', '2019-03-28 16:03:14', '2019-03-28 16:03:14', NULL, NULL, '[]', '[]'),
(522606, 94903653, 85191752, 85191752, 89904399, 48197562, 'soiree-de-degustation-de-la-nouvelle-biere-3-brasseurs-lomme', '{\"fr\":\"SOIRÉE DE DÉGUSTATION DE LA NOUVELLE BIÈRE \\\"3 BRASSEURS LOMME\\\"\"}', '{\"fr\":\"Le restaurant 3 Brasseurs de Lomme vous propose de découvrir sa nouvelle bière, créée dans le cadre du concours Master Brasseur.\"}', '{\"fr\":\"Pierre Lesur, Maître Brasseur du restaurant 3 Brasseurs de Lomme, vous attend nombreux lors d\'une soirée de dégustation. A cette occasion, il dévoilera sa toute nouvelle création : une bière blonde au pamplemousse.\\n\\nUn bon moment de convivialité ponctué de nombreuses animations (concert gratuit et dégustation offerte).\"}', '{}', '{\"fr\":\"Gratuit\"}', '{\"filename\":\"a3fbaa03813643e4885d9174098ec599.base.image.jpg\",\"size\":{\"width\":600,\"height\":1067},\"variants\":[{\"filename\":\"a3fbaa03813643e4885d9174098ec599.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":720,\"height\":1280}},{\"filename\":\"a3fbaa03813643e4885d9174098ec599.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-04T16:00:00.000Z\",\"end\":\"2019-04-04T22:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://restaurants.3brasseurs.com/fr/s/brasseurs/lomme/445\"]', '2019-03-28 15:59:15', '2019-03-28 15:59:15', NULL, NULL, '[]', '[]'),
(522590, 93789671, 85191752, 85191752, 89904399, 88741454, 'soiree-de-degustation-de-la-nouvelle-biere-3-brasseurs-lille', '{\"fr\":\"SOIRÉE DE DÉGUSTATION DE LA NOUVELLE BIÈRE \\\"3 BRASSEURS LILLE\\\"\"}', '{\"fr\":\"Le restaurant 3 Brasseurs de Lille vous propose de découvrir sa nouvelle bière, créée dans le cadre du concours Master Brasseur.\"}', '{\"fr\":\"Nicolas Legrand et Nicolas Dejaegere, Maîtres Brasseurs du restaurant 3 Brasseurs de Lille, vous attendent nombreux lors d\'une soirée de dégustation. A cette occasion, ils dévoileront leur toute nouvelle création : une bière blonde, fruitée et épicée.\\n\\nUn bon moment de convivialité ponctué de nombreuses animations (concert gratuit et dégustation offerte).\"}', '{}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"21655c600e104849a4c602507656cf70.base.image.jpg\",\"size\":{\"width\":600,\"height\":450},\"variants\":[{\"filename\":\"21655c600e104849a4c602507656cf70.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":1032,\"height\":774}},{\"filename\":\"21655c600e104849a4c602507656cf70.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":\"3 Brasseurs\"}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-04T16:30:00.000Z\",\"end\":\"2019-04-04T22:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://restaurants.3brasseurs.com/fr/s/brasseurs/lille/455\"]', '2019-03-28 15:51:35', '2019-03-28 15:51:35', NULL, NULL, '[]', '[]'),
(519466, 8876098, 8140284, 8140284, 89904399, 91438416, 'route-du-louvre-14', '{\"fr\":\"ROUTE DU LOUVRE #14\"}', '{\"fr\":\"La 14ème édition de la Route du Louvre se déroulera le 12 mai 2019.\"}', '{\"fr\":\"L’édition 2018 a regroupé environ 16000 participants. La fête était au rendez-vous sur les lieux du départ, le long des parcours et sur le fabuleux site d’arrivée du musée du Louvre-Lens pour une grande première.\\n\\nRendez-vous le 12 mai pour la 14ème édition et de nouvelles aventures !\\n\\n*   Marathon :http://www.laroutedulouvre.fr/index.php/epreuves/marathon\\n*   Relais : http://www.laroutedulouvre.fr/index.php/epreuves/relais\\n*   10 km : http://www.laroutedulouvre.fr/index.php/epreuves/10km\\n*   Randonnées : http://www.laroutedulouvre.fr/index.php/epreuves/randonnees\\n\\nhttps://www.youtube.com/watch?v=ZwHFyg06B3I\"}', '{}', '{\"fr\":\"Sur inscription\"}', '{\"filename\":\"0c5b8e05431142509ea0480fd57741e7.base.image.jpg\",\"size\":{\"width\":600,\"height\":399},\"variants\":[{\"filename\":\"0c5b8e05431142509ea0480fd57741e7.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":600,\"height\":399}},{\"filename\":\"0c5b8e05431142509ea0480fd57741e7.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-05-12T07:00:00.000Z\",\"end\":\"2019-05-12T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.njuko.net/routedulouvre2019\"]', '2019-03-26 13:38:40', '2019-03-26 13:38:40', NULL, NULL, '[]', '[{\"link\":\"http://www.laroutedulouvre.fr/index.php/epreuves/marathon\",\"data\":{\"url\":\"http://www.laroutedulouvre.fr/index.php/epreuves/marathon\",\"type\":\"link\",\"version\":\"1.0\",\"title\":\"Marathon\",\"author\":\"Flo\",\"description\":\"Marathon de la Route du Louvre. 42,1 km entre Lens et le musée du Louvre\",\"cache_age\":86400},\"type\":\"oembed\"},{\"link\":\"http://www.laroutedulouvre.fr/index.php/epreuves/relais\",\"data\":{\"url\":\"http://www.laroutedulouvre.fr/index.php/epreuves/relais\",\"type\":\"link\",\"version\":\"1.0\",\"title\":\"Relais\",\"author\":\"Flo\",\"description\":\"marathon international entre Lille et Le Louvre Lens\",\"cache_age\":86400},\"type\":\"oembed\"},{\"link\":\"http://www.laroutedulouvre.fr/index.php/epreuves/10km\",\"data\":{\"url\":\"http://www.laroutedulouvre.fr/index.php/epreuves/10km\",\"type\":\"link\",\"version\":\"1.0\",\"title\":\"10km\",\"author\":\"Flo\",\"description\":\"marathon international entre Lille et Le Louvre Lens\",\"cache_age\":86400},\"type\":\"oembed\"},{\"link\":\"http://www.laroutedulouvre.fr/index.php/epreuves/randonnees\",\"data\":{\"url\":\"http://www.laroutedulouvre.fr/index.php/epreuves/randonnees\",\"type\":\"link\",\"version\":\"1.0\",\"title\":\"randonnées\",\"author\":\"Flo\",\"description\":\"marathon international entre Lille et Le Louvre Lens\",\"cache_age\":86400},\"type\":\"oembed\"},{\"link\":\"https://www.youtube.com/watch?v=ZwHFyg06B3I\",\"data\":{\"url\":\"https://www.youtube.com/watch?v=ZwHFyg06B3I\",\"type\":\"video\",\"version\":\"1.0\",\"title\":\"TEASER LA ROUTE DU LOUVRE 2018\",\"author\":\"LHDFA\",\"author_url\":\"https://www.youtube.com/channel/UCfCLgcBardpSZlElkp_pZsg\",\"provider_name\":\"YouTube\",\"thumbnail_url\":\"https://i.ytimg.com/vi/ZwHFyg06B3I/maxresdefault.jpg\",\"thumbnail_width\":1280,\"thumbnail_height\":720,\"html\":\"<div style=\\\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.2493%;\\\"><iframe src=\\\"https://www.youtube.com/embed/ZwHFyg06B3I?rel=0\\\" style=\\\"border: 0; top: 0; left: 0; width: 100%; height: 100%; position: absolute;\\\" allowfullscreen scrolling=\\\"no\\\" allow=\\\"autoplay; encrypted-media\\\"></iframe></div>\",\"cache_age\":86400},\"type\":\"oembed\"}]'),
(519033, 15477489, 60654151, 60654151, 89904399, 17470312, 'festival-du-jeu-ludinord_922287', '{\"fr\":\"Festival du jeu Ludinord\"}', '{\"fr\":\"Onzième festival du jeu et de la création les 30 et 31 mars\"}', '{\"fr\":\"### **11e édition du Festival du Jeu et de la Création, les 30 et 31 Mars 2019 à Mons-en-Barœul !**\\n\\nOrganisé par la Fédéjeux, LudiNord est le plus grand festival ludique au nord de Paris. Venez tester et découvrir toutes sortes de jeux ! Retrouvez de nombreux auteurs et illustrateurs mais aussi des surprises, des exclusivités, des tournois, une bourse aux jeux ...\\n\\nQuelques chiffres de l’édition 2018 :\\n\\n*   38h de festival non-stop\\n*   12 074 visiteurs\\n*   87 éditeurs\\n*   270 jeux présentés\\n*   410 bénévoles animant les jeux.\\n\\n[**Vidéo du festival**](https://youtu.be/T7x8mpBY-wA)\\n\\n**Un festival, quatre sites !**\\n\\nNouveauté cette année, le festival se déroule sur 4 sites très proches les uns des autres à Mons-en-Barœul : la salle du Fort de Mons, la salle Montaigne, la Maison des Associations et un nouveau lieu avec la salle Marie Curie.\\n\\nLa salle Marie Curie accueillera le pôle Jeux de cartes, avec des parties d\'initiation et des tournois.\\n\\n**Infos pratiques**\\n\\nLa salle Marie Curie se situe à 8 mn à pied du métro Fort de Mons. Elle sera également accessible avec la navette gratuite de Ludinord.\\n\\nLa session nocturne du festival démarre le samedi 30 mars à 22h et termine le lendemain aux aurores. Elle se déroule exclusivement au Fort de Mons. Le Festival ne ferme pas mais n\'accepte plus de nouvelles entrées après minuit.\"}', '{}', '{\"fr\":\"3€ par jour (nocturne comprise), 5€ pour le week-end (nocturne comprise), gratuit pour les enfants de moins de 10 ans accompagnés, restauration possible\"}', '{\"filename\":\"55512b1abae14ce6923bf39ce3f33638.base.image.jpg\",\"credits\":null,\"size\":{\"height\":849,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.full.image.jpg\",\"size\":{\"height\":2480,\"width\":1754}},{\"type\":\"thumbnail\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-30T09:00:00.000Z\",\"end\":\"2019-03-30T20:00:00.000Z\"},{\"begin\":\"2019-03-31T08:00:00.000Z\",\"end\":\"2019-03-31T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.LudiNord.fr\",\"http://www.facebook.com/ludinord\",\"http://twitter.com/LudiNord\",\"http://www.instagram.com/fedejeux\",\"contact@ludinord.fr\"]', '2019-03-25 15:46:05', '2019-03-25 15:55:29', NULL, NULL, '[]', '[{\"link\":\"https://youtu.be/T7x8mpBY-wA\",\"data\":{\"url\":\"https://www.youtube.com/watch?v=T7x8mpBY-wA\",\"type\":\"video\",\"version\":\"1.0\",\"title\":\"LudiNord 2017 - 9ème Festival du Jeu et de la Création\",\"author\":\"LudiNord\",\"author_url\":\"https://www.youtube.com/channel/UC-SK1YKneyKvT9tHrYNVvrw\",\"provider_name\":\"YouTube\",\"description\":\"Cette 9ème édition s\'est déroulée les 25 & 26 Mars 2017.\\n\\nPetit retour en vidéo sur cette édition où les sourires étaient au rendez-vous.\\n\\nNotez la date des 24 et 25 mars 2018 dans votre agenda pour la 10ème édition!\\n\\nImages de Ludovic SONRIER\\nRéalisation de Ludovic SONRIER\\nhttp://www.ludoandpictures.com/\",\"thumbnail_url\":\"https://i.ytimg.com/vi/T7x8mpBY-wA/maxresdefault.jpg\",\"thumbnail_width\":1280,\"thumbnail_height\":720,\"html\":\"<div style=\\\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.2493%;\\\"><iframe src=\\\"https://www.youtube.com/embed/T7x8mpBY-wA?rel=0\\\" style=\\\"border: 0; top: 0; left: 0; width: 100%; height: 100%; position: absolute;\\\" allowfullscreen scrolling=\\\"no\\\" allow=\\\"autoplay; encrypted-media\\\"></iframe></div>\",\"cache_age\":86400},\"type\":\"oembed\"}]'),
(519016, 93221072, 60654151, 60654151, 89904399, 49867100, 'festival-du-jeu-ludinord_500520', '{\"fr\":\"Festival du jeu Ludinord\"}', '{\"fr\":\"Onzième festival du jeu et de la création les 30 et 31 mars\"}', '{\"fr\":\"### **11e édition du Festival du Jeu et de la Création, les 30 et 31 Mars 2019 à Mons-en-Barœul !**\\n\\nOrganisé par la Fédéjeux, LudiNord est le plus grand festival ludique au nord de Paris. Venez tester et découvrir toutes sortes de jeux ! Retrouvez de nombreux auteurs et illustrateurs mais aussi des surprises, des exclusivités, des tournois, une bourse aux jeux ...\\n\\nQuelques chiffres de l’édition 2018 :\\n\\n*   38h de festival non-stop\\n*   12 074 visiteurs\\n*   87 éditeurs\\n*   270 jeux présentés\\n*   410 bénévoles animant les jeux.\\n\\n[**Vidéo du festival**](https://youtu.be/T7x8mpBY-wA)\\n\\n**Un festival, quatre sites !**\\n\\nNouveauté cette année, le festival se déroule sur 4 sites très proches les uns des autres à Mons-en-Barœul : la salle du Fort de Mons, la salle Montaigne, la Maison des Associations et un nouveau lieu avec la salle Marie Curie.\\n\\nLa Maison des Associations accueillera une partie du pôle Jeux de Rôle et des tournois. Elle permettra de faire jouer en toute tranquillité les parties longues des jeux de rôle.\\n\\n**Infos pratiques**\\n\\nLa Maison des Associations se situe à 4 mn à pied de la salle Fort de Mons.\\n\\nLa session nocturne du festival démarre le samedi 30 mars à 22h et termine le lendemain aux aurores. Elle se déroule exclusivement au Fort de Mons. Le Festival ne ferme pas mais n\'accepte plus de nouvelles entrées après minuit.\"}', '{}', '{\"fr\":\"3€ par jour (nocturne comprise), 5€ pour le week-end (nocturne comprise), gratuit pour les enfants de moins de 10 ans accompagnés, restauration possible\"}', '{\"filename\":\"55512b1abae14ce6923bf39ce3f33638.base.image.jpg\",\"credits\":null,\"size\":{\"height\":849,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.full.image.jpg\",\"size\":{\"height\":2480,\"width\":1754}},{\"type\":\"thumbnail\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-30T09:00:00.000Z\",\"end\":\"2019-03-30T20:00:00.000Z\"},{\"begin\":\"2019-03-31T08:00:00.000Z\",\"end\":\"2019-03-31T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.LudiNord.fr\",\"http://www.facebook.com/ludinord\",\"http://twitter.com/LudiNord\",\"http://www.instagram.com/fedejeux\",\"contact@ludinord.fr\"]', '2019-03-25 15:30:59', '2019-03-25 15:45:30', NULL, NULL, '[]', '[{\"link\":\"https://youtu.be/T7x8mpBY-wA\",\"data\":{\"url\":\"https://www.youtube.com/watch?v=T7x8mpBY-wA\",\"type\":\"video\",\"version\":\"1.0\",\"title\":\"LudiNord 2017 - 9ème Festival du Jeu et de la Création\",\"author\":\"LudiNord\",\"author_url\":\"https://www.youtube.com/channel/UC-SK1YKneyKvT9tHrYNVvrw\",\"provider_name\":\"YouTube\",\"description\":\"Cette 9ème édition s\'est déroulée les 25 & 26 Mars 2017.\\n\\nPetit retour en vidéo sur cette édition où les sourires étaient au rendez-vous.\\n\\nNotez la date des 24 et 25 mars 2018 dans votre agenda pour la 10ème édition!\\n\\nImages de Ludovic SONRIER\\nRéalisation de Ludovic SONRIER\\nhttp://www.ludoandpictures.com/\",\"thumbnail_url\":\"https://i.ytimg.com/vi/T7x8mpBY-wA/maxresdefault.jpg\",\"thumbnail_width\":1280,\"thumbnail_height\":720,\"html\":\"<div style=\\\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.2493%;\\\"><iframe src=\\\"https://www.youtube.com/embed/T7x8mpBY-wA?rel=0\\\" style=\\\"border: 0; top: 0; left: 0; width: 100%; height: 100%; position: absolute;\\\" allowfullscreen scrolling=\\\"no\\\" allow=\\\"autoplay; encrypted-media\\\"></iframe></div>\",\"cache_age\":86400},\"type\":\"oembed\"}]');
