(518992, 5338275, 60654151, 60654151, 89904399, 51747196, 'festival-du-jeu-ludinord_167060', '{\"fr\":\"Festival du jeu Ludinord\"}', '{\"fr\":\"Onzième festival du jeu et de la création les 30 et 31 mars\"}', '{\"fr\":\"### **11e édition du Festival du Jeu et de la Création, les 30 et 31 Mars 2019 à Mons-en-Barœul !**\\n\\nOrganisé par la Fédéjeux, LudiNord est le plus grand festival ludique au nord de Paris. Venez tester et découvrir toutes sortes de jeux ! Retrouvez de nombreux auteurs et illustrateurs mais aussi des surprises, des exclusivités, des tournois, une bourse aux jeux ...\\n\\nQuelques chiffres de l’édition 2018 :\\n\\n*   38h de festival non-stop\\n*   12 074 visiteurs\\n*   87 éditeurs\\n*   270 jeux présentés\\n*   410 bénévoles animant les jeux.\\n\\n[**Vidéo du festival**](https://youtu.be/T7x8mpBY-wA)\\n\\n**Un festival, quatre sites !**\\n\\nNouveauté cette année, le festival se déroule sur 4 sites très proches les uns des autres à Mons-en-Barœul : la salle du Fort de Mons, la salle Montaigne, la Maison des Associations et un nouveau lieu avec la salle Marie Curie.\\n\\n**Infos pratiques**\\n\\nUne navette est mise en place entre les sites Fort de Mons et Salle Montaigne. Le temps de marche entre les deux sites est de 8 mn.\\n\\nLa session nocturne du festival démarre le samedi 30 mars à 22h et termine le lendemain aux aurores. Elle se déroule exclusivement au Fort de Mons. Le Festival ne ferme pas mais n\'accepte plus de nouvelles entrées après minuit.\"}', '{}', '{\"fr\":\"3€ par jour (nocturne comprise), 5€ pour le week-end (nocturne comprise), gratuit pour les enfants de moins de 10 ans accompagnés, restauration possible\"}', '{\"filename\":\"55512b1abae14ce6923bf39ce3f33638.base.image.jpg\",\"credits\":null,\"size\":{\"height\":849,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.full.image.jpg\",\"size\":{\"height\":2480,\"width\":1754}},{\"type\":\"thumbnail\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-30T09:00:00.000Z\",\"end\":\"2019-03-30T20:00:00.000Z\"},{\"begin\":\"2019-03-31T08:00:00.000Z\",\"end\":\"2019-03-31T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.LudiNord.fr\",\"http://www.facebook.com/ludinord\",\"http://twitter.com/LudiNord\",\"http://www.instagram.com/fedejeux\",\"contact@ludinord.fr\"]', '2019-03-25 15:15:35', '2019-03-25 15:34:05', NULL, NULL, '[]', '[{\"link\":\"https://youtu.be/T7x8mpBY-wA\",\"data\":{\"url\":\"https://www.youtube.com/watch?v=T7x8mpBY-wA\",\"type\":\"video\",\"version\":\"1.0\",\"title\":\"LudiNord 2017 - 9ème Festival du Jeu et de la Création\",\"author\":\"LudiNord\",\"author_url\":\"https://www.youtube.com/channel/UC-SK1YKneyKvT9tHrYNVvrw\",\"provider_name\":\"YouTube\",\"description\":\"Cette 9ème édition s\'est déroulée les 25 & 26 Mars 2017.\\n\\nPetit retour en vidéo sur cette édition où les sourires étaient au rendez-vous.\\n\\nNotez la date des 24 et 25 mars 2018 dans votre agenda pour la 10ème édition!\\n\\nImages de Ludovic SONRIER\\nRéalisation de Ludovic SONRIER\\nhttp://www.ludoandpictures.com/\",\"thumbnail_url\":\"https://i.ytimg.com/vi/T7x8mpBY-wA/maxresdefault.jpg\",\"thumbnail_width\":1280,\"thumbnail_height\":720,\"html\":\"<div style=\\\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.2493%;\\\"><iframe src=\\\"https://www.youtube.com/embed/T7x8mpBY-wA?rel=0\\\" style=\\\"border: 0; top: 0; left: 0; width: 100%; height: 100%; position: absolute;\\\" allowfullscreen scrolling=\\\"no\\\" allow=\\\"autoplay; encrypted-media\\\"></iframe></div>\",\"cache_age\":86400},\"type\":\"oembed\"}]'),
(518966, 64641087, 60654151, 60654151, 89904399, 87673737, 'festival-du-jeu-ludinord_983558', '{\"fr\":\"Festival du jeu Ludinord\"}', '{\"fr\":\"Onzième festival du jeu et de la création les 30 et 31 mars\"}', '{\"fr\":\"### **11e édition du Festival du Jeu et de la Création, les 30 et 31 Mars 2019 à Mons-en-Barœul !**\\n\\nOrganisé par la Fédéjeux, LudiNord est le plus grand festival ludique au nord de Paris. Venez tester et découvrir toutes sortes de jeux ! Retrouvez de nombreux auteurs et illustrateurs mais aussi des surprises, des exclusivités, des tournois, une bourse aux jeux ...\\n\\nQuelques chiffres de l’édition 2018 :\\n\\n*   38h de festival non-stop\\n*   12 074 visiteurs\\n*   87 éditeurs\\n*   270 jeux présentés\\n*   410 bénévoles animant les jeux.\\n\\n[**Vidéo du festival**](https://youtu.be/T7x8mpBY-wA)\\n\\n**Un festival, quatre sites !**\\n\\nNouveauté cette année, le festival se déroule sur 4 sites très proches les uns des autres à Mons-en-Barœul : la salle du Fort de Mons, la salle Montaigne, la Maison des Associations et un nouveau lieu avec la salle Marie Curie.\\n\\n**Infos pratiques**\\n\\nUne navette est mise en place entre les sites Fort de Mons et Salle Montaigne. Le temps de marche entre les deux sites est de 8 mn.\\n\\nLa session nocturne du festival démarre le samedi 30 mars à 22h et termine le lendemain aux aurores. Elle se déroule exclusivement au Fort de Mons. Le Festival ne ferme pas mais n\'accepte plus de nouvelles entrées après minuit.\"}', '{}', '{\"fr\":\"3€ par jour (nocturne comprise), 5€ pour le week-end (nocturne comprise), gratuit pour les enfants de moins de 10 ans accompagnés, restauration possible\"}', '{\"filename\":\"55512b1abae14ce6923bf39ce3f33638.base.image.jpg\",\"credits\":null,\"size\":{\"height\":849,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.full.image.jpg\",\"size\":{\"height\":2480,\"width\":1754}},{\"type\":\"thumbnail\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-30T09:00:00.000Z\",\"end\":\"2019-03-30T20:00:00.000Z\"},{\"begin\":\"2019-03-30T20:00:00.000Z\",\"end\":\"2019-03-31T04:00:00.000Z\"},{\"begin\":\"2019-03-31T08:00:00.000Z\",\"end\":\"2019-03-31T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.LudiNord.fr\",\"http://www.facebook.com/ludinord\",\"http://twitter.com/LudiNord\",\"http://www.instagram.com/fedejeux\",\"contact@ludinord.fr\"]', '2019-03-25 14:54:44', '2019-03-25 15:05:51', NULL, NULL, '[]', '[{\"link\":\"https://youtu.be/T7x8mpBY-wA\",\"data\":{\"url\":\"https://www.youtube.com/watch?v=T7x8mpBY-wA\",\"type\":\"video\",\"version\":\"1.0\",\"title\":\"LudiNord 2017 - 9ème Festival du Jeu et de la Création\",\"author\":\"LudiNord\",\"author_url\":\"https://www.youtube.com/channel/UC-SK1YKneyKvT9tHrYNVvrw\",\"provider_name\":\"YouTube\",\"description\":\"Cette 9ème édition s\'est déroulée les 25 & 26 Mars 2017.\\n\\nPetit retour en vidéo sur cette édition où les sourires étaient au rendez-vous.\\n\\nNotez la date des 24 et 25 mars 2018 dans votre agenda pour la 10ème édition!\\n\\nImages de Ludovic SONRIER\\nRéalisation de Ludovic SONRIER\\nhttp://www.ludoandpictures.com/\",\"thumbnail_url\":\"https://i.ytimg.com/vi/T7x8mpBY-wA/maxresdefault.jpg\",\"thumbnail_width\":1280,\"thumbnail_height\":720,\"html\":\"<div style=\\\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.2493%;\\\"><iframe src=\\\"https://www.youtube.com/embed/T7x8mpBY-wA?rel=0\\\" style=\\\"border: 0; top: 0; left: 0; width: 100%; height: 100%; position: absolute;\\\" allowfullscreen scrolling=\\\"no\\\" allow=\\\"autoplay; encrypted-media\\\"></iframe></div>\",\"cache_age\":86400},\"type\":\"oembed\"}]'),
(518926, 12339464, 60654151, 60654151, 89904399, 87673737, 'festival-du-jeu-ludinord', '{\"fr\":\"Festival du jeu Ludinord\"}', '{\"fr\":\"Onzième festival du jeu et de la création les 30 et 31 mars\"}', '{\"fr\":\"### **11e édition du Festival du Jeu et de la Création, les 30 et 31 Mars 2019 à Mons-en-Barœul !**\\n\\nOrganisé par la Fédéjeux, LudiNord est le plus grand festival ludique au nord de Paris. Venez tester et découvrir toutes sortes de jeux ! Retrouvez de nombreux auteurs et illustrateurs mais aussi des surprises, des exclusivités, des tournois, une bourse aux jeux ...\\n\\nQuelques chiffres de l’édition 2018 :\\n\\n*   38h de festival non-stop\\n*   12 074 visiteurs\\n*   87 éditeurs\\n*   270 jeux présentés\\n*   410 bénévoles animant les jeux.\\n\\nRetrouvez de nombreux auteurs et illustrateurs mais aussi de nombreuses surprises, des exclusivités et des tournois ...\\n\\n[**Vidéo du festival**](https://youtu.be/T7x8mpBY-wA)\\n\\n**Un festival, quatre sites !**\\n\\nNouveauté cette année, le festival se déroule sur 4 sites très proches les uns des autres à Mons-en-Barœul : la salle du Fort de Mons, la salle Montaigne, la Maison des Associations et un nouveau lieu avec la salle Marie Curie.\\n\\n**Infos pratiques**\\n\\nUne navette est mise en place entre les sites Fort de Mons et Salle Montaigne. Le temps de marche entre les deux sites est de 8 mn.\\n\\nLa session nocturne du festival démarre le samedi 30 mars à 22h et termine le lendemain aux aurores. Elle se déroule exclusivement au Fort de Mons. Le Festival ne ferme pas mais n\'accepte plus de nouvelles entrées après minuit.\"}', '{}', '{\"fr\":\"3€ par jour (nocturne comprise), 5€ pour le week-end (nocturne comprise), gratuit pour les enfants de moins de 10 ans accompagnés, restauration possible sur place\"}', '{\"filename\":\"55512b1abae14ce6923bf39ce3f33638.base.image.jpg\",\"credits\":null,\"size\":{\"height\":849,\"width\":600},\"variants\":[{\"type\":\"full\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.full.image.jpg\",\"size\":{\"height\":2480,\"width\":1754}},{\"type\":\"thumbnail\",\"filename\":\"55512b1abae14ce6923bf39ce3f33638.thumb.image.jpg\",\"size\":{\"height\":200,\"width\":200}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-30T09:00:00.000Z\",\"end\":\"2019-03-30T20:00:00.000Z\"},{\"begin\":\"2019-03-30T20:00:00.000Z\",\"end\":\"2019-03-31T04:00:00.000Z\"},{\"begin\":\"2019-03-31T08:00:00.000Z\",\"end\":\"2019-03-31T17:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.LudiNord.fr\",\"http://www.facebook.com/ludinord\",\"http://twitter.com/LudiNord\",\"http://www.instagram.com/fedejeux\",\"contact@ludinord.fr\"]', '2019-03-25 14:20:23', '2019-03-25 15:00:24', '2019-03-25 15:01:49', NULL, '[]', '[{\"link\":\"https://youtu.be/T7x8mpBY-wA\",\"data\":{\"url\":\"https://www.youtube.com/watch?v=T7x8mpBY-wA\",\"type\":\"video\",\"version\":\"1.0\",\"title\":\"LudiNord 2017 - 9ème Festival du Jeu et de la Création\",\"author\":\"LudiNord\",\"author_url\":\"https://www.youtube.com/channel/UC-SK1YKneyKvT9tHrYNVvrw\",\"provider_name\":\"YouTube\",\"description\":\"Cette 9ème édition s\'est déroulée les 25 & 26 Mars 2017.\\n\\nPetit retour en vidéo sur cette édition où les sourires étaient au rendez-vous.\\n\\nNotez la date des 24 et 25 mars 2018 dans votre agenda pour la 10ème édition!\\n\\nImages de Ludovic SONRIER\\nRéalisation de Ludovic SONRIER\\nhttp://www.ludoandpictures.com/\",\"thumbnail_url\":\"https://i.ytimg.com/vi/T7x8mpBY-wA/maxresdefault.jpg\",\"thumbnail_width\":1280,\"thumbnail_height\":720,\"html\":\"<div style=\\\"left: 0; width: 100%; height: 0; position: relative; padding-bottom: 56.2493%;\\\"><iframe src=\\\"https://www.youtube.com/embed/T7x8mpBY-wA?rel=0\\\" style=\\\"border: 0; top: 0; left: 0; width: 100%; height: 100%; position: absolute;\\\" allowfullscreen scrolling=\\\"no\\\" allow=\\\"autoplay; encrypted-media\\\"></iframe></div>\",\"cache_age\":86400},\"type\":\"oembed\"}]'),
(518671, 72785344, 8140284, 8140284, 89904399, 78093466, 'creathon-food-and-well-being_193683', '{\"fr\":\"Créathon Food and well-being\"}', '{\"fr\":\"Dans le cadre d’une collaboration avec le Réseau Franco-Néerlandais, la MEL co-organise le Créathon \\\"Food & Well-Being\\\" qui se tiendra le 27, 28 et 29 mars 2019 à Lille.\"}', '{\"fr\":\"Vous êtes étudiant.e, doctorant.e ou jeune diplômé.e, vous faites vos études, travaillez ou bien envisagez de créer une start-up en France, en Belgique ou aux Pays-Bas et vous souhaitez imaginer des solutions alimentaires d’avenir. Posez votre candidature, avant le 7 février 2019, au Créathon ‘Food & Well-Being’ qui se tiendra les 27, 28 et 29 mars 2019 à Lille.\\n\\nLe public cible est constitué d’étudiants et de jeunes professionnels de 18 à 30 ans (10 de la Métropole Lilloise, 10 de Belgique et 10 des Pays-Bas) dont le domaine d’étude ou d’activité n’est pas forcément directement lié à l’(agro)alimentaire. D’autres disciplines pourront être privilégiées telles que la chimie verte, le design, la santé, l’ingénierie, l’histoire, la géographie, la psychologie, la sociologie, l’art, etc.\\n\\n**Mercredi 27 mars, 13h00 : Découverte du secteur alimentaire de Lille**\\n\\n*   13h Rendez-vous devant la MEL, 1 rue du Ballon à Lille\\n*   13h30 Départ en bus\\n*   14h00 Visite d’Euralimentaireet découverte des spécialités culinaires locales\\n*   16h30 Départ d’Euralimentaire\\n*   17h Visite de Fives-Cail, tiers-lieu et pôle alimentaire de Lille\\n*   18h Départ de Fives-Cail\\n*   18h30 Pause et installation à l’hôtel\\n*   20h Dîner des créathoniensaux 3 Brasseurs à Lille\\n\\n**Jeudi 28 mars, 08h30 : Sessions de créativité et de travail à PolytechLille**\\n\\nEvènement : [https://www.lillemetropole.fr/fr/evenement/creathon-food-and-well-being](https://www.lillemetropole.fr/fr/evenement/creathon-food-and-well-being)\\n\\n**Jeudi 28 mars, 19h00 : Soirée des partenaires – Networking**\\n\\n*   18h30 Accueil des participants\\n*   18h45 Discours d’ouverture\\n*   19h Table ronde composée des représentants français, belges et néerlandais de l’enseignement supérieuret de l’innovation alimentaire de grandes entreprises\\n*   19h30 Premiers pitchs des projets des créathoniens\\n*   20h Stands tenus par des entreprises de l’innovation alimentaire, et cocktail\\n*   21h30 Fin de la soirée\\n\\n**Vendredi 29 mars, 09h00 : Sessions de travail, pitchs et remise des prix**\\n\\n*   8h30 Accueil de la délégation économique des Pays-Bas et de la Belgique à Lille’s Agency, et présentation de l’agence\\n*   9h Session de travail pour les créathoniens\\n*   9h30 Départ de la délégation vers Eurasanté, et présentation du pôle Nutrition Santé Longevité et du centre Purifonction\\n*   12h30 Déjeuner de la délégation au Nouvel Atelier à La Madeleine\\n*   13h Déjeuner des créathoniens à la MEL\\n*   14h Timetopitch : les créathoniens présentent leurs projets devant un jury d’experts\\n*   15h15 Remise des prix\\n*   16h Pot de clôture\\n*   17h Fin de l’événement\"}', '{}', '{}', '{\"filename\":\"c1c1a2dcf8d348e6846f7885b06c74a3.base.image.jpg\",\"size\":{\"width\":600,\"height\":240},\"variants\":[{\"filename\":\"c1c1a2dcf8d348e6846f7885b06c74a3.full.image.jpg\",\"type\":\"full\",\"size\":{\"width\":1200,\"height\":480}},{\"filename\":\"c1c1a2dcf8d348e6846f7885b06c74a3.thumb.image.jpg\",\"type\":\"thumbnail\",\"size\":{\"width\":200,\"height\":200}}],\"credits\":null}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-27T12:00:00.000Z\",\"end\":\"2019-03-27T19:00:00.000Z\"},{\"begin\":\"2019-03-28T17:30:00.000Z\",\"end\":\"2019-03-28T20:30:00.000Z\"},{\"begin\":\"2019-03-29T08:00:00.000Z\",\"end\":\"2019-03-29T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"international@univ-lille.fr\"]', '2019-03-25 09:19:31', '2019-03-25 09:19:31', NULL, NULL, '[]', '[]'),
