(494748, 84271321, 56673351, 56673351, 89904399, 64532530, 'plu-communaux-le-maisnil', '{\"fr\":\"PLU communaux : Le Maisnil\"}', '{\"fr\":\"Le jeudi 07 février aura lieu au Maisnil une réunion publique dédiée à la révision du PLU dans les communes des Weppes.\"}', '{\"fr\":\"Le jeudi 07 février aura lieu au Maisnil une réunion publique dédiée à la révision du PLU dans les communes des Weppes.\\n\\nPlus d\'informations : [revisionplu5weppes@lillemetropole.fr](http://mailto:revisionplu5weppes@lillemetropole.fr)\"}', '{\"fr\":[\"PLU\",\"weppes\"]}', '{}', '{\"filename\":\"event_plu-communaux-le-maisnil_798360.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_plu-communaux-le-maisnil_798360.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_plu-communaux-le-maisnil_798360.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-07T17:30:00.000Z\",\"end\":\"2019-02-06T23:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"revisionplu5weppes@lillemetropole.fr\"]', '2019-01-29 14:53:05', '2019-01-29 14:53:06', NULL, '2ad14e0b0278401e81000eaa77a541cc', '[]', '[]'),
(494740, 41955413, 56673351, 56673351, 89904399, 73001111, 'plu-des-weppes-fromelles', '{\"fr\":\"PLU communaux : Fromelles\"}', '{\"fr\":\"Le vendredi 01 février aura lieu à Fromelles une réunion publique dédiée à la révision du PLU dans les communes des Weppes.\"}', '{\"fr\":\"Le vendredi 01 février aura lieu à Fromelles une réunion publique dédiée à la révision du PLU dans les communes des Weppes.\\n\\nPlus d\'informations : [revisionplu5weppes@lillemetropole.fr](http://mailto:revisionplu5weppes@lillemetropole.fr)\"}', '{\"fr\":[\"PLU\",\"Weppes\"]}', '{}', '{\"filename\":\"event_plu-des-weppes-fromelles_198306.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_plu-des-weppes-fromelles_198306.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_plu-des-weppes-fromelles_198306.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-01T17:30:00.000Z\",\"end\":\"2019-01-31T23:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"revisionplu5weppes@lillemetropole.fr\"]', '2019-01-29 14:44:46', '2019-01-29 14:54:09', NULL, '2ad14e0b0278401e81000eaa77a541cc', '[]', '[]'),
(494261, 92072515, 8140284, 8140284, 89904399, 6737485, 'finale-coupe-d-europe-par-equipes-15-16-ans-garcons', '{\"fr\":\"Finale coupe d\'Europe par équipes - 15/16 ans Garçons\"}', '{\"fr\":\"36 matchs pour une médaille d\'or\"}', '{\"fr\":\"**Les qualifications du 1 au 3 février 2019**\\n\\nZONE A : VARNIA (Bulgaria) : Bulgaria, Great Britain, Montenegro, Serbia, Slovakia, Spain and Turkey.\\n\\nZONE B : CHOLET (France) : Belgium, France, Malta, Netherlands, Norway, Poland, Portugal and Switzerland.\\n\\nZONE C : TBA (Hungary) : Croatia, Czech Republic, Germany, Hungary, Israel, Slovenia and Ukraine.\\n\\nZONE D : KAZAN (Russia) : Austria, Belarus, Estonia, Italy, Lithuania, Romania, Russia and Sweden.\\n\\n**Programme de la finale**\\n\\nJEUDI 14 FEVRIER (entraînement) à 18h30 réunion des capitaines et tirage au sort des rencontres à l’hôtel de ville de Ronchin.Venez nombreux à la Mairie découvrir les équipes.\\n\\nVENDREDI 15 FEVRIER (8 simples et 4 doubles) à partir de 13h30 1/4 de finale\\n\\nSAMEDI 16 FEVRIER (8 simples et 4 doubles) à partir de 10h30 rencontres de classement 5ème à 8ème places et 1/2 finalesvers 17h présentation des équipes\\n\\nDIMANCHE 17 FEVRIER (8 simples et 4 doubles)à partir de 9h30 rencontres de classement / à partir de 11h finalevers 17h cérémonie du palmarès.\"}', '{\"fr\":[]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_finale-coupe-d-europe-par-equipes-15-16-ans-garcons_403741.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_finale-coupe-d-europe-par-equipes-15-16-ans-garcons_403741.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_finale-coupe-d-europe-par-equipes-15-16-ans-garcons_403741.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-14T17:30:00.000Z\",\"end\":\"2019-02-14T21:00:00.000Z\"},{\"begin\":\"2019-02-15T12:30:00.000Z\",\"end\":\"2019-02-15T19:00:00.000Z\"},{\"begin\":\"2019-02-16T09:00:00.000Z\",\"end\":\"2019-02-16T16:00:00.000Z\"},{\"begin\":\"2019-02-17T08:30:00.000Z\",\"end\":\"2019-02-17T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-01-28 14:42:27', '2019-01-28 14:52:05', NULL, '35d9f94c31db4997942615183c77a605', '[]', '[]'),
(494251, 64513905, 8140284, 8140284, 89904399, 35024997, 'asloum-event-no-limit-episode-viii', '{\"fr\":\"ASLOUM Event - No Limit Episode VIII\"}', '{\"fr\":\"L\'ASLOUM EVENT NO LIMIT se tiendra à Lille Grand Palais le jeudi 28 mars prochain.\"}', '{\"fr\":\"C’est l’événement de boxe de cette fin d’année à Lille. \\n\\nRéservez vos places de sport pour : NO LIMIT EPISODE VIII - ZENITH ARENA LILLE\\n\\nLe prix des places est compris entre : 15.00 et 120.00 €\\n\\n[http://asloumevent.com/](http://asloumevent.com/)\"}', '{\"fr\":[]}', '{}', '{\"filename\":\"event_asloum-event-no-limit-episode-viii_298889.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_asloum-event-no-limit-episode-viii_298889.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_asloum-event-no-limit-episode-viii_298889.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-28T18:00:00.000Z\",\"end\":\"2019-03-27T23:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.ticketmaster.fr/fr/manifestation/no-limit-episode-viii-billet/idmanif/453621/idtier/43265\"]', '2019-01-28 14:20:15', '2019-01-28 14:20:16', NULL, '691e2126987a4510996d724d660afbae', '[]', '[]');
INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `creator_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at`, `file_key`, `references`, `links`) VALUES
(493991, 71035785, 8140284, 8140284, 89904399, 66965931, 'fab-mel-alimentation', '{\"fr\":\"FAB MEL -  Alimentation\"}', '{\"fr\":\"Présentation de la démarche PAT et des résultats de la concertation #AlimentationEnMétropole. Echanges sur les propositions citoyennes en faveur de l\'alimentation et construction du plan d\'actions.\"}', '{\"fr\":\"Ces derniers mois, une concertation citoyenne pour co-construire le **Projet Alimentaire Territorial du territoire de la MEL** s’est tenue avec plusieurs ateliers collaboratifs et des focus group. Venez découvrir le résultat très riche de ces travaux lors du point d’étape le jeudi 31 janvier.\\n\\nPour poursuivre et enraciner la démarche, nous vous convions à un prochain et important rendez-vous, cette FAB MEL Alimentation, qui sera l\'occasion de vous restituer les résultats des travaux engagés depuis 6 mois, d\'échanger avec vous sur les premières orientations stratégiques qui se dessinent et de travailler ensemble sur le programme d\'actions en faveur d\'une alimentation saine et durable accessible à tous :\\n\\n**Au programme** : Présentation de la démarche PAT et des résultats de la concertation #AlimentationEnMétropole Echanges sur les propositions citoyennes en faveur de l\'alimentation Coconstruction du programme d\'actions\\n\\nCette soirée se clôturera par un buffet convivial autour de produits locaux.\"}', '{\"fr\":[]}', '{\"fr\":\"Sur inscriptions\"}', '{\"filename\":\"event_fab-mel-alimentation_381402.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_fab-mel-alimentation_381402.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_fab-mel-alimentation_381402.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-31T17:00:00.000Z\",\"end\":\"2019-01-31T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"participationcitoyenne@lillemetropole.fr\"]', '2019-01-28 08:54:24', '2019-01-28 08:54:25', NULL, '439927032a5940f387f4147b5b2bc179', '[]', '[]'),
(492564, 43005110, 42070961, 42070961, 89904399, 50651588, 'lille-hardelot-2019', '{\"fr\":\"Lille Hardelot 2019\"}', '{\"fr\":\"Le rendez-vous incontournable des cyclistes et des randonneurs sera de retour le 2 juin 2019 !\"}', '{\"fr\":\"Lancée en 1981, Lille Hardelot a su réunir randonneurs et coureurs pour devenir un événement incontournable et international. Lille-Hardelot attire des belges, des suisses, des escouades hollandaises, des clubs anglais… et même des polonais !\\n\\nLa maîtrise acquise par l’URFA (Union des Randonneurs Flandres-Artois), la qualité d’une équipe animée par Edouard Pluta, la qualité de l’accueil sur le parcours - grâce aux clubs locaux -, la qualité du ravitaillement, la sécurité (SAMU et cibistes) ont fait la notoriété de la randonnée qui n’a cessé de croître. 7 300 inscrits en 2018, vous êtes prêts pour 2019 ?\\n\\n[La course démarrera entre 6h et 7h45 face à Lille Grand Palais.](https://lille-hardelot.com/parcours_detail_2019.php)\"}', '{\"fr\":[\"Course\",\"Randonnée\",\"Cyclisme\"]}', '{\"fr\":\"Tarifs : 21 € jusqu\'au 04 Mars 2019 - 24 € jusqu\'au 15 Avril 2019 - 26 € jusqu\'au 27 Mai 2019\"}', '{\"filename\":\"event_lille-hardelot-2019_245910.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_lille-hardelot-2019_245910.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_lille-hardelot-2019_245910.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-02T05:00:00.000Z\",\"end\":\"2019-06-02T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://lille-hardelot.com/inscription_2019.php\"]', '2019-01-24 14:21:21', '2019-01-24 14:21:22', NULL, 'eff71df2e11b48f5a485eeb36703ea93', '[]', '[]'),
(492558, 12821560, 42070961, 42070961, 89904399, 78593958, '2emes-assises-de-l-economie-sociale-et-solidaire', '{\"fr\":\"2èmes assises de l\'Économie Sociale et Solidaire\"}', '{\"fr\":\"Trouvez les réponses à toutes vos questions concernant l\'économie sociale et solidaire et quelles sont les actions mises en place dans la MEL !\"}', '{\"fr\":\"Comment la MEL s’investit durablement dans une économie plus solidaire ?\\n\\nComment les acteurs locaux peuvent investir les compétences de la MEL ?\\n\\nComment l’économie sociale et solidaire va devenir contributrice d’une Europe plus citoyenne et solidaire et accéder à ses financements ?\\n\\nLa Métropole Européenne de Lille investit durablement dans une économie plus solidaire et vous donne rendez-vous aux 2èmes assises L’Économie Sociale et Solidaire\\n\\nCONFERENCE-TABLES RONDES-ATELIERS : Animation de la matinée par Philippe Bertrand, journaliste à Radio France (Carnets de Campagne)\"}', '{\"fr\":[\"Economie sociale et solidaire\",\"Conférences\",\"Tables rondes\",\"Ateliers\"]}', '{\"fr\":\"Evénement gratuit sur inscription préalable obligatoire\"}', '{\"filename\":\"${schema}emes-assises-de-l-economie-sociale-et-solidaire_746205.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evf${schema}emes-assises-de-l-economie-sociale-et-solidaire_746205.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtb${schema}emes-assises-de-l-economie-sociale-et-solidaire_746205.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-07T07:30:00.000Z\",\"end\":\"2019-02-07T16:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://yurplan.com/event/2-EMES-ASSISES-DE-L-ECONOMIE-SOCIALE-ET-SOLIDAIRE/36992?fbclid=IwAR3ElEc2tacyRMOcz74KpVPX2Pgpkx5pgaCfzQNvQMvUH1JUAYzN7fhfSFU\"]', '2019-01-24 14:07:44', '2019-01-24 14:07:44', NULL, 'c67bceb0096f4b819516c0610b2ec0ba', '[]', '[]'),
(492518, 16577856, 42070961, 42070961, 89904399, 48070809, 'artiart-le-salon-des-artisans-d-art_693', '{\"fr\":\"ARTIART - Le Salon des Artisans d\'Art\"}', '{\"fr\":\"Les 27 et 28 avril 2019, ARTIART, le Salon des Artisans d’Art, que le Rotary Club Comines Wervicq Pays de La Lys organise régulièrement au profit d’une association caritative, fêtera sa 10ème édition.\"}', '{\"fr\":\"Sous l’égide de l’INMA (Institut National des Métiers d ‘Art), de la Chambre de Métiers et de l’Artisanat de Région et d’Ateliers d’Art de France, ce Salon rassemble, chaque année, une trentaine de professionnels talentueux et exigeants, soucieux de faire rimer transmission, création et perfection.\\n\\nDifférentes spécialités sont représentées et le travail de la pierre ou des pierres côtoie celui de la terre, du bois, du métal, du cuir, du tissu ou d’autres matériaux et matières devenant à chaque fois « oeuvre d’art ». \\n\\nSavoirs- faire traditionnels d’exception et procédés innovants se conjuguent pour donner libre cours à la créativité. **L’excellence est là.**\"}', '{\"fr\":[\"Artisanat\",\"Exposition\",\"Salon\"]}', '{}', '{\"filename\":\"event_artiart-le-salon-des-artisans-d-art_693_813335.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_artiart-le-salon-des-artisans-d-art_693_813335.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_artiart-le-salon-des-artisans-d-art_693_813335.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-27T08:00:00.000Z\",\"end\":\"2019-04-27T17:00:00.000Z\"},{\"begin\":\"2019-04-28T08:00:00.000Z\",\"end\":\"2019-04-28T17:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2019-01-24 12:03:29', '2019-01-24 12:03:29', NULL, '2414a308b07743079f476f71893293ae', '[]', '[]'),
(492513, 78046638, 42070961, 42070961, 89904399, 51971567, 'although-i-live-inside-my-hair-will-always-reach-toward-the-sun-vivat-la-danse', '{\"fr\":\"... although I live inside… my hair will always reach toward the sun… - Vivat la danse !\"}', '{\"fr\":\"Vous êtes prêts à plonger dans le délire loufoque de Robyn Orlin et Sophiatou Kossoko ? Ca se passe au Vivat !\"}', '{\"fr\":\"Apostrophant vertement la chorégraphe qui lui a demandé des choses impossibles, tout en dansant, mimant et trimbalant à sa suite une ribambelle de bouilloires et piscines en plastique, Sophiatou Kossoko entraîne le public dans un délire loufoque né d’une rencontre improbable et réussie entre une chorégraphe blanche vivant en Afrique et une danseuse noire vivant en Europe.\\n\\n**Et qui sait ? Nous danserons aussi sans doute pour cette dernière soirée...**\"}', '{\"fr\":[\"Danse\",\"Vivat la danse !\",\"Robyn Orlin\",\"Sophiatou Kossoko\"]}', '{\"fr\":\"Tarif : 8€\"}', '{\"filename\":\"event_although-i-live-inside-my-hair-will-always-reach-toward-the-sun-vivat-la-danse_851265.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_although-i-live-inside-my-hair-will-always-reach-toward-the-sun-vivat-la-danse_851265.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_although-i-live-inside-my-hair-will-always-reach-toward-the-sun-vivat-la-danse_851265.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-02T19:00:00.000Z\",\"end\":\"2019-02-02T19:45:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.levivat.net/reservez-vos-places/\",\"03 20 77 18 77\"]', '2019-01-24 11:50:00', '2019-01-24 11:50:01', NULL, '3005a64f245847ae88c31a88d7606472', '[]', '[]'),
(492512, 63167574, 42070961, 42070961, 89904399, 51971567, 'footbar-vivat-la-danse', '{\"fr\":\"Footbar - Vivat la danse !\"}', '{\"fr\":\"Un bar éphémère où le « plaisir » du pied sera prétexte à la convivialité !\"}', '{\"fr\":\"Un bar où l’on commande des bains de pieds.\\n\\nUn bar où l’on peut aussi y découvrir des histoires de pieds, des témoignages, des planches anatomiques, des danses, des contes, des mots croisés…\\n\\nUn bar éphémère où le « plaisir » du pied sera prétexte à la convivialité !\"}', '{\"fr\":[\"Vivat la danse !\",\"Bar éphémère\",\"Pied\"]}', '{\"fr\":\"Entrée gratuite\"}', '{\"filename\":\"event_footbar-vivat-la-danse_304086.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_footbar-vivat-la-danse_304086.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_footbar-vivat-la-danse_304086.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-02T17:30:00.000Z\",\"end\":\"2019-02-02T19:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 77 18 77\",\"http://www.levivat.net/reservez-vos-places/\"]', '2019-01-24 11:45:42', '2019-01-24 11:45:43', NULL, '732ddc6ddee64f7d878b43e53c0525cb', '[]', '[]'),
(492509, 1746913, 42070961, 42070961, 89904399, 51971567, 'k-sa-vivat-la-danse', '{\"fr\":\"K( )SA - Vivat la danse !\"}', '{\"fr\":\"Sheherazade Zambrano renverse les axes et expérimente des danses verticales, une invitation à explorer des nouveaux rapports à autrui et à notre milieu !\"}', '{\"fr\":\"En résidence au Vivat depuis septembre 2018, Scheherazade Zambrano y expérimente des danses verticales (et même parfois des danses sous l’eau). « _À l’envers_ », dirait Antonin Artaud.\\n\\n« _Depuis l’homo sapiens, nous passons la plupart de notre existence dans la position verticale. Notre rapport au milieu est déterminé par cette position. Ainsi, renverser les axes, comme proposition chorégraphique, est une invitation à explorer des nouveaux rapports à autrui et à notre milieu, une autre façon de concevoir le monde, de décoloniser l’être._» - Scheherazade Zambrano\"}', '{\"fr\":[\"Danse\",\"Vivat la danse\",\"Expérimentation\",\"Sheherazade Zambrano\"]}', '{\"fr\":\"Entrée gratuite\"}', '{\"filename\":\"event_k-sa-vivat-la-danse_219205.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_k-sa-vivat-la-danse_219205.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_k-sa-vivat-la-danse_219205.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-02T16:30:00.000Z\",\"end\":\"2019-02-02T17:30:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.levivat.net/reservez-vos-places/\",\"03 20 77 18 77\"]', '2019-01-24 11:39:14', '2019-01-24 11:39:15', NULL, '9a2f7185a36c4d75ac711289d02bdcd5', '[]', '[]'),
(492504, 42871767, 42070961, 42070961, 89904399, 11122402, 'l-oubli-vivat-la-danse', '{\"fr\":\"L\'oubli - Vivat la danse !\"}', '{\"fr\":\"Mélanger danseurs professionnels et amateurs pour parler de l\'oubli, et donc de mémoire : c\'est le projet de Sylvain Groud à découvrir dans le cadre de Vivat la danse !\"}', '{\"fr\":\"Inviter des amateurs dans un projet chorégraphique et les mettre en mouvement pour célébrer la danse. C’est la prise de position affirmée du nouveau directeur du Ballet du Nord qui offre ainsi un terrain de jeux aux aficionados du «_ Carnet de bord _» pour parler d’oubli, et donc de mémoire. Sur la musique d’Arvo Pärt, cette performance en trois temps interprétée par un duo de danseurs professionnels rejoint par ces amateurs, évoque en douceur ce temps de l’oubli où sont plongées les personnes atteintes de perte de mémoire. Dans l’écrin du salon d’honneur, ils offriront une danse expressive à la fois nostalgique, vive et subtile.\"}', '{\"fr\":[\"Danse\",\"Vivat la danse !\",\"Ballet de Nord\",\"Sylvain Groud\"]}', '{\"fr\":\"Gratuit, réservation conseillée\"}', '{\"filename\":\"event_l-oubli-vivat-la-danse_280086.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_l-oubli-vivat-la-danse_280086.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_l-oubli-vivat-la-danse_280086.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-02T15:00:00.000Z\",\"end\":\"2019-02-02T15:40:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 77 18 77\",\"http://www.levivat.net/reservez-vos-places/\"]', '2019-01-24 11:32:25', '2019-01-24 11:32:25', NULL, '60165939f62e4a87b4271cb37d8a7066', '[]', '[]'),
(492498, 53505078, 42070961, 42070961, 89904399, 51971567, 'confidence-publique-1', '{\"fr\":\"Confidence publique #1 - Vivat la danse !\"}', '{\"fr\":\"Samira El Ayachi se confie dans Confidence publique #1: \\\"toutes les choses que je n\'ai pas su faire\\\"\"}', '{\"fr\":\"Il y a tout ce que nous aimons faire, tout ce que nous aurions aimé faire, et tout ce que nous n’avons pas su faire. Une liste grosse sur le dos des hommes et des femmes modernes qui marchent dans la vie avec une sensation de ratage permanent. Samira El Ayachi explore une première confidence publique et politique sur le thème des déboires intimes.\\n\\n**Contribuez en envoyant la liste des choses que vous n’avez pas su faire à [confidencepublique@gmail.com](http://mailto:confidencepublique@gmail.com) !**\"}', '{\"fr\":[\"Vivat la danse !\",\"Samira El Ayachi\",\"Confidence\"]}', '{\"fr\":\"Gratuit sur réservation.\"}', '{\"filename\":\"event_confidence-publique-1_430415.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_confidence-publique-1_430415.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_confidence-publique-1_430415.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-02T13:30:00.000Z\",\"end\":\"2019-02-02T14:00:00.000Z\"},{\"begin\":\"2019-02-02T15:00:00.000Z\",\"end\":\"2019-02-02T15:30:00.000Z\"},{\"begin\":\"2019-02-02T17:00:00.000Z\",\"end\":\"2019-02-02T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.levivat.net/reservez-vos-places/\",\"03 20 77 18 77\"]', '2019-01-24 11:24:10', '2019-01-24 14:23:45', NULL, 'a3be825cdf7845809c75f2276f9e9f2f', '[]', '[]'),
(492486, 64161102, 42070961, 42070961, 89904399, 21988308, 'let-s-dance-vivat-la-danse', '{\"fr\":\"Let\'s dance - Vivat la danse !\"}', '{\"fr\":\"Et si un spectacle permettait à chacun de se transformer, de se lâcher, lâcher prise et ne rien lâcher ? L’espace d’une soirée, se sentir quelqu’un d’autre. Juste avec un bal. Let’s go !\"}', '{\"fr\":\"Elvis, Les Stones, en passant par La Femme, David Bowie. Rien de tel qu’un bon son rock pour lancer un appel à surgir sur le dancefloor. Lâchez prise, car dans ce spectacle interactif, explosif, vous serez les héros et les héroïnes. Dress-code : tenue, coiffure ou accessoires rock. Et si un spectacle permettait à chacun de se transformer, de se lâcher, lâcher prise et ne rien lâcher ? L’espace d’une soirée, se sentir quelqu’un d’autre. Juste avec un bal. Let’s go !\\n\\n**_Le bal rock let\'s dance_ recherche des complices pour ce spectacle : [cliquez ici pour en savoir plus](http://www.levivat.net/aveclespublics/rejoignez-les-complices-du-bal-rock-lets-dance)**\"}', '{\"fr\":[\"Vivat la danse\",\"Danse\",\"Bal\",\"Rock\"]}', '{\"fr\":\"Tarif : 8€\"}', '{\"filename\":\"event_let-s-dance-vivat-la-danse_481164.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_let-s-dance-vivat-la-danse_481164.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_let-s-dance-vivat-la-danse_481164.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-01T19:00:00.000Z\",\"end\":\"2019-02-01T20:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":8,\"max\":99}', '[\"03 20 77 18 77\",\"http://www.levivat.net/reservez-vos-places/\"]', '2019-01-24 11:10:39', '2019-01-24 11:10:40', NULL, '553dec24ff024658ae1871988d47c734', '[]', '[]'),
(492481, 11877463, 42070961, 42070961, 89904399, 51971567, 'self-portrait-camouflage-vivat-la-danse', '{\"fr\":\"Self portrait camouflage - Vivat la danse !\"}', '{\"fr\":\"Que reste-il de la France colonialiste ? Latifa Laâbissi nous pose la question et en impose le sujet à l’aide d’un humour grinçant.\"}', '{\"fr\":\"La France, de la première Exposition universelle de 1855 à la Coloniale de 1937, offre successivement à la Nation onze manifestations dont le retentissement exceptionnel lui permet vite d’exporter ce modèle hors de ses frontières. Autant d’occasions pour le public d’applaudir au riche spectacle des splendeurs de son Empire colonial. Des hommes, des femmes, des enfants y sont l’objet d’attractions curieuses… Que reste-il de cette France colonialiste ? Latifa Laâbissi nous pose la question et en impose le sujet à l’aide d’un humour grinçant. Mais le recours à la dérision, les accents drôles et décalés y sont autant de révélateurs au service d’un propos engagé.\"}', '{\"fr\":[\"Vivat la danse !\",\"Latifa Laâbissi\"]}', '{\"fr\":\"Tarif : 8€\"}', '{\"filename\":\"event_self-portrait-camouflage-vivat-la-danse_382550.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_self-portrait-camouflage-vivat-la-danse_382550.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_self-portrait-camouflage-vivat-la-danse_382550.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-31T20:30:00.000Z\",\"end\":\"2019-01-31T21:30:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"http://www.levivat.net/reservez-vos-places/\",\"03 20 77 18 77\"]', '2019-01-24 11:05:13', '2019-01-24 11:05:14', NULL, 'a444b4565f4b4958af87c6935f84bfb1', '[]', '[]'),
(492475, 44650085, 42070961, 42070961, 89904399, 51971567, 'grand-tetras-vivat-la-danse', '{\"fr\":\"Grand Tétras - Vivat la danse !\"}', '{\"fr\":\"Marion Sage rend hommage à l’engagement de Jean Weidt, personnage important, abandonné par l’histoire de la danse, en jouant avec les indices retrouvés de gestes passés.\"}', '{\"fr\":\"**Création : version 1**\\n\\nÇa commence par une balade, à la recherche d’un drôle d’oiseau. Des indices de présence de cet animal en voie d’extinction ont été collectés et triés. Ces traces sont des résidus de gestes mais ne laissent jamais apercevoir une danse, la dynamique des mouvements s’est perdue. Des amorces de pas, quelques élans immobilisés, des expressions de visages : ce sont des photographies et dessins représentant le jardinier et « _danseur rouge_ » Jean Weidt. Marion Sage rend hommage à l’engagement de ce personnage important, abandonné par l’histoire de la danse, en jouant avec les indices retrouvés de gestes passés.\"}', '{\"fr\":[\"Danse\",\"Vivat la danse !\",\"Jean Weidt\",\"Marion Sage\"]}', '{\"fr\":\"Tarif : 8€\"}', '{\"filename\":\"event_grand-tetras-vivat-la-danse_756568.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_grand-tetras-vivat-la-danse_756568.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_grand-tetras-vivat-la-danse_756568.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-31T19:00:00.000Z\",\"end\":\"2019-01-31T20:00:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 77 18 77\",\"http://www.levivat.net/reservez-vos-places/\"]', '2019-01-24 11:02:08', '2019-01-24 11:02:08', NULL, 'eb829cf891dc4eda9527b93e0a5f5990', '[]', '[]'),
(492462, 97731685, 42070961, 42070961, 89904399, 51971567, 'mon-solopera-noise-vivat-la-danse', '{\"fr\":\"Mon Solopéra noise - Vivat la danse !\"}', '{\"fr\":\"Le Solopéra noise de Patrick Guionnet met en résonance des monuments de la culture musicale avec l\'humble témoignage d\'un militaire sahraoui.\"}', '{\"fr\":\"Patrick Guionnet se jette vocalement et corporellement dans la mêlée pour aboutir à une forme étonnante et éminemment sonore, tout en évoquant une certaine idée de la solitude…\\n\\nSon Solopéra noise met en résonance des monuments de la culture musicale (comme _Petite fleur_ ou _Bohemian Rhapsody_) avec l’humble témoignage d’un militaire sahraoui (inspiré par le documentaire _Territoire perdu_ de Pierre-Yves Vandeweerd).\"}', '{\"fr\":[\"Danse\",\"Chant\",\"Vivat la danse\"]}', '{\"fr\":\"Entrée gratuite\"}', '{\"filename\":\"event_mon-solopera-noise-vivat-la-danse_770161.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_mon-solopera-noise-vivat-la-danse_770161.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_mon-solopera-noise-vivat-la-danse_770161.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-31T18:00:00.000Z\",\"end\":\"2019-01-31T18:30:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"http://www.levivat.net/reservez-vos-places/\",\"03 20 77 18 77\"]', '2019-01-24 10:53:05', '2019-01-24 10:53:05', NULL, '5fd49a4989674764b0e17e1d0451f54a', '[]', '[]'),
(492455, 30421570, 42070961, 42070961, 89904399, 51971567, 'red-haired-man-vivat-la-danse', '{\"fr\":\"Red haired man - Vivat la danse !\"}', '{\"fr\":\"Ici, Alexander Vantournhout s’attaque à la prose de Daniil Harms, en y intégrant des éléments de danse, cirque, contorsion, théâtre de marionnettes, magie et ventriloquie !\"}', '{\"fr\":\"« _Il était une fois un homme roux qui n’avait pas d’yeux et pas d’oreilles. Il n’avait pas de cheveux, ce n’est qu’arbitrairement qu’on le disait roux._ » - Daniil Harms\\n\\nIci, Alexander Vantournhout s’attaque à la prose de Daniil Harms, en y intégrant des éléments de danse, cirque, contorsion, théâtre de marionnettes, magie et ventriloquie ! Les personnages principaux disparaissent dans des moments d’illusion comique, faisant penser aux fêtes foraines. Des prothèses permettent aux corps de se contorsionner etÉde prendre des formes bizarres et nouvelles. Dans la lignée du spectacle ANECKXANDER, le circassien cherche à créer une œuvre d’art totale et surprenante.\\n\\n**Incroyable Navette : le Vivat met à votre disposition une navette qui vous mène jusqu\'au Prato. Départ 19h du Vivat, retour 22h !**\"}', '{\"fr\":[\"Danse\",\"Cirque\",\"Vivat la danse\",\"Contorsion\",\"Théâtre de marionnettes\",\"Magie\",\"Ventriloquie\"]}', '{\"fr\":\"Tarif : 8€\"}', '{\"filename\":\"event_red-haired-man-vivat-la-danse_204414.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_red-haired-man-vivat-la-danse_204414.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_red-haired-man-vivat-la-danse_204414.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-30T18:00:00.000Z\",\"end\":\"2019-01-30T21:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 77 18 77\",\"http://www.levivat.net/reservez-vos-places/\"]', '2019-01-24 10:44:12', '2019-01-24 10:44:13', NULL, 'e7b9003ff9e74a7faf6c543dcd364e75', '[]', '[]'),
(492443, 25081287, 42070961, 42070961, 89904399, 21988308, 'baleine-vivat-la-danse', '{\"fr\":\"Baleine - Vivat la danse !\"}', '{\"fr\":\"Baleine est un projet chorégraphique pour un corps tombé du ciel ou amené par le ressac sur la scène.\"}', '{\"fr\":\"« _Rien ne se perd, rien ne se crée, tout se transforme_ ». Inspirée par le principe de réaction en chaîne, cette danse météorologique tente de faire apparaître par le corps des paysages intérieurs à l’extérieur. Spectacle low-tech qui observe les échanges entre ici et là, entre le multiple et l’unique, tentant de mettre le monde au centre du corps et non l’inverse. Donner à lire tout et son contraire et peut-être même donner à entendre du cinéma muet. Baleine conduira le langage à une limite, au bord de la musique. - Jonas Chéreau \\n\\n« _Le monde infuse continûment_ » - Jean-Christophe Bailly, conférence donnée à la Manufacture des idées, 2016\"}', '{\"fr\":[\"Danse\",\"Jonas Chéreau\",\"Vivat la danse !\"]}', '{\"fr\":\"Tarif : 8€\"}', '{\"filename\":\"event_baleine-vivat-la-danse_551735.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_baleine-vivat-la-danse_551735.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_baleine-vivat-la-danse_551735.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-29T20:30:00.000Z\",\"end\":\"2019-01-29T21:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.levivat.net/reservez-vos-places/\",\"03 20 77 18 77\"]', '2019-01-24 10:30:51', '2019-01-24 10:30:51', NULL, '92f39600a90640ff9daa97ce91152998', '[]', '[]'),
(492440, 75688146, 42070961, 42070961, 89904399, 51971567, 'rapid-eye-movement-vivat-la-danse', '{\"fr\":\"Rapid eye movement - Vivat la danse !\"}', '{\"fr\":\"Un théâtre sans électricité, une jungle cultivée, un terrain toxique, un glacier carnivore : voici les décors que vous propose  de découvrir Estelle Gauthier.\"}', '{\"fr\":\"**Création : version 1**\\n\\nComment faire apparaître des morceaux de paysage sur la scène ?  Nous allons plonger dans un espace-temps obscur et mouvant : un théâtre sans électricité, une jungle cultivée, un terrain toxique, un glacier carnivore. Autant d’occasions de brouiller les pistes, de remonter le fil rouge d’une fiction à multiples facettes où les performeurs, le son, la lumière, la scénographie et l’imagination font corps. Ainsi la chorégraphie prend la forme d’une exploration de l’espace théâtral et de notre capacité à le construire sous vos yeux.\\n\\n_(Rapid Eye Movement fait référence à ce moment du sommeil paradoxal où les yeux bougent rapidement sous les paupières. Il semblerait que ces mouvements soient liés aux images des rêves.)_\"}', '{\"fr\":[\"Danse\",\"Performance\",\"Vivat la danse !\"]}', '{\"fr\":\"Tarif : 8€\"}', '{\"filename\":\"event_rapid-eye-movement-vivat-la-danse_321458.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_rapid-eye-movement-vivat-la-danse_321458.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_rapid-eye-movement-vivat-la-danse_321458.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-29T19:00:00.000Z\",\"end\":\"2019-01-29T19:45:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 77 18 77\",\"http://www.levivat.net/reservez-vos-places/\"]', '2019-01-24 10:26:19', '2019-01-24 10:26:20', NULL, 'c405c12f02ea4a5c8fc81170cdd43f3f', '[]', '[]'),
(492437, 78544452, 42070961, 42070961, 89904399, 51971567, 'on-se-les-pele-sur-la-pirogue-vivat-la-danse', '{\"fr\":\"On se les pèle sur la pirogue ! - Vivat la danse !\"}', '{\"fr\":\"Anne Lepère et Marion Sage vont vous ouvrir l\'appétit à bord de leur pirogue : ne loupez pas ce nouveau rendez-vous de Mythes et Recettes.\"}', '{\"fr\":\"« _À bord de notre pirogue, nous voguons le long des littoraux et amarrons dès qu’une odeur alléchante nous y invite. Pour ce nouveau rendez-vous de Mythes et Recettes, une saveur rustique nous a piégées : entre le pain de pommes de terre et les gyozas japonais, la consistance de ce plat est parfaite pour le mois de janvier ! Le récit tangue entre un mythe et une recette préparée devant vous. Nous remonterons le fil des deux histoires avec quelques élans sonores et gestes cuisinés. Dernier volet de cette performance : la dégustation._ » Anne Lepère & Marion Sage\"}', '{\"fr\":[\"Danse\",\"Vivat la danse\",\"Mythes et Recettes\"]}', '{\"fr\":\"Entrée gratuite\"}', '{\"filename\":\"event_on-se-les-pele-sur-la-pirogue-vivat-la-danse_105372.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_on-se-les-pele-sur-la-pirogue-vivat-la-danse_105372.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_on-se-les-pele-sur-la-pirogue-vivat-la-danse_105372.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-29T18:00:00.000Z\",\"end\":\"2019-01-29T18:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 77 18 77\",\"http://www.levivat.net/reservez-vos-places/\"]', '2019-01-24 10:19:15', '2019-01-24 10:19:16', NULL, 'b4dbec95def64adca4a425fafdf637c3', '[]', '[]'),
(492432, 19022477, 42070961, 42070961, 89904399, 21988308, 'incenses-vivat-la-danse', '{\"fr\":\"Incenses - Vivat la danse !\"}', '{\"fr\":\"Anne Collod vous fait découvrir une danse à la fois sensuelle et spirituelle nourrie par les apports des danses indiennes et asiatiques !\"}', '{\"fr\":\"Anne Collod se plonge dans l’œuvre luxuriante de Ruth Saint-Denis et de son partenaire Ted Shawn. Précurseurs au début du 20e siècle d’une danse à la fois sensuelle et spirituelle nourrie par les apports des danses indiennes et asiatiques, ils créent ensemble une œuvre prolifique traversée par la notion d’altérité et d’exotisme. À partir du travail de transmission des solos (notés en cinétographie Laban) et de leur interprétation, Anne Collod interrogera avec Shantala Shivalingappa, experte en Kuchipudi et formée au Baratha Natyam*, les emprunts, détournements et réécritures effectués par Ruth Saint-Denis. Elles s’intéressent également à la manière dont le Kuchipudi* joue avec les représentations du genre, pour les nourrir et les troubler.\\n\\n_*Le Kuchipudi et le Baratha Natyam sont deux des styles majeurs de la danse classique indienne._\"}', '{\"fr\":[]}', '{\"fr\":\"Tarif : 8€\"}', '{\"filename\":\"event_incenses-vivat-la-danse_693803.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_incenses-vivat-la-danse_693803.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_incenses-vivat-la-danse_693803.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-25T20:30:00.000Z\",\"end\":\"2019-01-25T21:15:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"03 20 77 18 77\",\"http://www.levivat.net/reservez-vos-places/\"]', '2019-01-24 10:11:50', '2019-01-24 10:11:50', NULL, '5912252b1003420581f1cd353d99eb16', '[]', '[]'),
(492428, 75883740, 42070961, 42070961, 89904399, 51971567, 'champ-constant-vivat-la-danse', '{\"fr\":\"Champ constant - Vivat la danse !\"}', '{\"fr\":\"Nourri de chansons et de paroles de paysans aux champs, d’appels de leurs bêtes, Champ constant se fait le témoin-transmetteur de ces rituels ancestraux, toujours actuels.\"}', '{\"fr\":\"Après avoir observé et interviewé de nombreux agriculteurs et après avoir étudié nombre de calendriers, encyclopédies, almanachs, guides et textes de Virgile à Pline l’Ancien, Céline Cartillier rend hommage à une paysannerie parfois un peu délaissée. La course du soleil, la déclinaison des jours, le rythme des saisons… Égrainés, parsemés et traçant leurs doux sillons, les gestes se font rituels entre ritournelles de danses et mouvements répétitifs du semeur ou du laboureur. Nourri de chansons et de paroles de paysans aux champs, d’appels de leurs bêtes, Champ constant se fait le témoin-transmetteur de ces rituels ancestraux, toujours actuels.\"}', '{\"fr\":[\"Danse\",\"Observation\",\"Agriculture\",\"Tradition\"]}', '{\"fr\":\"Tarif : 8€\"}', '{\"filename\":\"event_champ-constant-vivat-la-danse_920680.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_champ-constant-vivat-la-danse_920680.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_champ-constant-vivat-la-danse_920680.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-25T19:00:00.000Z\",\"end\":\"2019-01-25T20:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.levivat.net/\",\"03 20 77 18 77\"]', '2019-01-24 10:03:29', '2019-01-24 10:03:29', NULL, '4ac0aca2ba1b4322808bdbcccd953e4f', '[]', '[]'),
(492425, 46721833, 42070961, 42070961, 89904399, 51971567, 'seances-de-reiki-vivat-la-danse', '{\"fr\":\"Séances de Reiki - Vivat la danse !\"}', '{\"fr\":\"Besoin de relaxation ? Rendez vous au Vivat !\"}', '{\"fr\":\"La grand-mère de Lucien Fradin est pratiquante de Reiki. Avec Mathilde Bourgois et Clemmie Wonder, ils vous invitent à de courtes séances de cette technique de relaxation via l’apposition des mains, en lien avec Wulverdinghe.\"}', '{\"fr\":[\"Danse\",\"Relaxation\",\"Vivat la danse !\"]}', '{\"fr\":\"Entrée gratuite. Réservation conseillée.\"}', '{\"filename\":\"event_seances-de-reiki-vivat-la-danse_933246.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_seances-de-reiki-vivat-la-danse_933246.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_seances-de-reiki-vivat-la-danse_933246.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-25T15:00:00.000Z\",\"end\":\"2019-01-25T18:00:00.000Z\"},{\"begin\":\"2019-01-26T15:00:00.000Z\",\"end\":\"2019-01-26T18:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 77 18 77\",\"http://www.levivat.net\"]', '2019-01-24 09:58:53', '2019-01-24 09:58:53', NULL, '96faf99fabb8429aa28293caa8f4a226', '[]', '[]'),
(492419, 68359564, 42070961, 42070961, 89904399, 51971567, 'dans-l-ideal-vivat-la-danse', '{\"fr\":\"Dans l\'idéal - Vivat la danse !\"}', '{\"fr\":\"Que faire dans un monde idéal ? C\'est la question que se pose sur scène la Cie l\'Unanime !\"}', '{\"fr\":\"Dans l’idéal, c’est un projet qui se déroule dans des conditions idéales, et donc qui se pose la question de ce qui serait idéal de faire dans ces conditions.\\n\\n« _La nuit, parfois, je rêve de spectacles. Un des premiers spectacles que j’ai vu dans un rêve était incroyable, j’ai tout aimé dans ce spectacle, absolument tout, la lumière, le mouvement, le rythme, les images... c’était beau, simple, évident. (…) Je me dis qu’il faut absolument que je le fasse en vrai, dans la vie (…)._ » Laura Fouqueré — [Cie l’Unanime](http://lunanime.fr/spectacle/dans-lideal-de-facon-generale/).\"}', '{\"fr\":[\"Danse\",\"Vivat la danse\"]}', '{\"fr\":\"Entrée gratuite\"}', '{\"filename\":\"event_dans-l-ideal-vivat-la-danse_1415.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_dans-l-ideal-vivat-la-danse_1415.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_dans-l-ideal-vivat-la-danse_1415.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-01-25T18:00:00.000Z\",\"end\":\"2019-01-25T18:20:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 77 18 77\",\"http://www.levivat.net\"]', '2019-01-24 09:51:18', '2019-01-24 14:24:24', NULL, '250854ca3336496c98b613ef5e845a46', '[]', '[]'),
(487427, 60656335, 8140284, 8140284, 89904399, 85767602, 'artiart-le-salon-des-artisans-d-art', '{\"fr\":\"ARTIART, le Salon des Artisans d’Art\"}', '{\"fr\":\"Traditionnel salon des artisans d’art. L’occasion d’aller découvrir des savoir-faire traditionnels ou innovants.\"}', '{\"fr\":\"Les 27 et 28 avril 2019, ARTIART, le Salon des Artisans d’Art, que le Rotary Club Comines Wervicq Pays de La Lys organise régulièrement au profit d’une association caritative, fêtera sa 10ème édition.\\n\\nSous l’égide de l’INMA (Institut National des Métiers d ‘Art), de la Chambre de Métiers et de l’Artisanat de Région et d’Ateliers d’Art de France, ce Salon rassemble, chaque année, une trentaine de professionnels talentueux et exigeants, soucieux de faire rimer transmission, création et perfection.\\n\\nDifférentes spécialités sont représentées et le travail de la pierre ou des pierres côtoie celui de la terre, du bois, du métal, du cuir, du tissu ou d’autres matériaux et matières devenant à chaque fois « oeuvre d’art ». \\n\\nL’exposition se tient dans le bel écrin que représente le Complexe Lys-Aréna de Comines.\\n\\nSavoirs- faire traditionnels d’exception et procédés innovants se conjuguent pour donner libre cours à la créativité.\"}', '{\"fr\":[]}', '{}', '{\"filename\":\"event_artiart-le-salon-des-artisans-d-art_651313.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_artiart-le-salon-des-artisans-d-art_651313.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_artiart-le-salon-des-artisans-d-art_651313.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-27T08:00:00.000Z\",\"end\":\"2019-04-27T17:00:00.000Z\"},{\"begin\":\"2019-04-28T08:00:00.000Z\",\"end\":\"2019-04-28T17:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2019-01-21 15:44:05', '2019-01-21 15:44:06', NULL, '4263cfedb6184dedae23a713447adcdc', '[]', '[]'),
(487414, 57922226, 8140284, 8140284, 89904399, 50651588, 'art-up-12e-edition', '{\"fr\":\"Art Up! 12e édition\"}', '{\"fr\":\"Save the date, Art Up! est de retour du 28 février au 3 mars 2019 à Lille Grand Palais.\"}', '{\"fr\":\"Vous avez été 37 300 curieux à profiter de l’édition 2018 d’Art Up! La plus grosse foire d’art contemporain en région revient cette année avec pour thématique : La Photographie au cœur des créations artistiques d’aujourd’hui.\\n\\n### Pour un week-end d’art\\n\\nAteliers de gravure, de photographique, techniques du livre d’arts, lecture de portfolios… Art Up! propose aux visiteurs intéressés de découvrir l’art contemporain grâce à des ateliers accessibles à toute la famille !\\n\\n### Plus d’informations\\n\\nVous voulez exposer à Art Up! ? Trouvez toutes les informations nécessaires en suivant ce lien.\\n\\n[Réserver vos places en ligne ](https://ticket.anixy.com/FR/Tarif.awp?P1=ART_UP_LILLE_2019&P2=OE7n/y5Y&AWPID191FCA69=C917F33863860713C8C65BEDFA66E56EB34137F0)\"}', '{\"fr\":[]}', '{\"fr\":\"https://ticket.anixy.com/FR/Tarif.awp?P1=ART_UP_LILLE_2019&P2=OE7n/y5Y&AWPID191FCA69=C917F33863860713C8C65BEDFA66E56EB34137F0\"}', '{\"filename\":\"event_art-up-12e-edition_128863.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_art-up-12e-edition_128863.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_art-up-12e-edition_128863.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-02-28T10:00:00.000Z\",\"end\":\"2019-02-27T23:00:00.000Z\"},{\"begin\":\"2019-03-01T10:00:00.000Z\",\"end\":\"2019-03-01T20:00:00.000Z\"},{\"begin\":\"2019-03-02T09:00:00.000Z\",\"end\":\"2019-03-02T20:00:00.000Z\"},{\"begin\":\"2019-03-03T09:00:00.000Z\",\"end\":\"2019-03-03T20:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[]', '2019-01-21 15:15:52', '2019-01-21 15:15:54', NULL, '9549b971ce5a43ba8eb9df92b70e0671', '[]', '[]'),
(487398, 33275029, 8140284, 8140284, 89904399, 13817242, 'maker-faire-lille-faire-par-soi-meme', '{\"fr\":\"Maker Faire Lille : faire par soi-même !\"}', '{\"fr\":\"Vous êtes tenté par un voyage vers le futur ? Du 1 au 3 mars, au Tripostal, le Maker Faire Lille vous propose de découvrir l\'univers des Makers avec des ateliers, conférences et démonstrations !\"}', '{\"fr\":\"A Lille, pour sa troisième édition, le Maker Faire Lille voit les choses en grand ! Après le succès de l’édition 2018 partagée par près de 11 000 visiteurs et des centaines de makers, Le Tripostal accueille une nouvelle fois l\'événement du 1er au 3 mars 2019\\\\. La nouvelle édition prépare d’ores et déjà une programmation exceptionnelle : plus de 400 makers, le retour de l’atelier géant (encore plus grand), des démonstrations insolites…\\n\\n### Qu\'est ce que Maker Faire Lille ? \\n\\nMaker Faire Lille regroupera des ateliers, présentations et conférences autour des thèmes de la créativité, la fabrication et le mouvement Do it Yourself (\\\"Faites le vous même\\\"). C\'est un événement pour tous les adeptes de technologie, artisans, éducateurs, inventeurs, hobbyistes, ingénieurs, clubs de science, auteurs, artistes ou encore étudiants. Tous ces Makers se rassemblent pour présenter ce qu’ils font et partager ce qu’ils ont appris avec un public composé de familles, de professionnels et d’amateurs curieux de découvrir le mouvement des Makers. \\n\\n### Informations pratiques\\n\\nHoraires d’ouverture des 3 jours : de 10h à 19h\\n\\nAfin d’optimiser les flux de visiteurs, les billets sont vendus par créneaux d’arrivées.\\n\\nPour les créneaux du MATIN, la validation du billet d’entrée devra se faire entre 10h et 13h00.Pour les créneaux de l’APRES MIDI, la validation du billet d’entrée devra se faire entre 14h30 et 17h30.\\n\\n**Important :**\\n\\nLa durée de votre visite n’est pas limitée mais toute sortie sera définitive.Nous vous conseillons de privilégier une arrivée en début de session pour profiter pleinement de votre visite.\\n\\n**Il n\'y a pas de billetterie sur place, la vente des billets se fait uniquement en ligne. **\\n\\n*   Tarif Plein : 9€\\n*   Tarif réduit : 6€  (Jeunes de 6 à 18 ans, étudiants, demandeurs d’emplois sur présentation de justificatif à l’entrée)\\n*   Entrée gratuite pour les – de 6 ans\\n\\nAttention le nombre de places pour Maker Faire Lille est limité, n’attendez pas pour réserver [ici ](https://yurplan.com/event/MAKER-FAIRE-LILLE/34445?cat=non)!\\n\\nPour toutes questions ou informations vous pouvez nous contacter à l’adresse suivante : contact@makerfairefrance.com\"}', '{\"fr\":[]}', '{\"fr\":\"Payant, sur réservation\"}', '{\"filename\":\"event_maker-faire-lille-faire-par-soi-meme_98627.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_maker-faire-lille-faire-par-soi-meme_98627.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_maker-faire-lille-faire-par-soi-meme_98627.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-01T09:00:00.000Z\",\"end\":\"2019-03-01T18:00:00.000Z\"},{\"begin\":\"2019-03-02T09:00:00.000Z\",\"end\":\"2019-03-02T18:00:00.000Z\"},{\"begin\":\"2019-03-03T09:00:00.000Z\",\"end\":\"2019-03-03T18:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://yurplan.com/event/MAKER-FAIRE-LILLE/34445?cat=non\"]', '2019-01-21 14:48:38', '2019-01-21 14:48:39', NULL, '30a12ffd8c784e44a6b63d72eaff3aac', '[]', '[]'),
(487394, 93469090, 8140284, 8140284, 89904399, 47849833, '21e-salon-du-livre-de-bondues', '{\"fr\":\"21e Salon du Livre de Bondues\"}', '{\"fr\":\"Avis aux amoureux de littérature : le Salon du Livre de Bondues ouvre ses portes du samedi 23 mars 9h au dimanche 24 mars 18h30 !\"}', '{\"fr\":\"Le Salon du Livre de Bondues offre l’opportunité à des milliers de lecteurs de l’eurorégion de rencontrer des auteurs, des éditeurs et divers acteurs du monde littéraire et d’échanger de manière privilégiée avec les auteurs lors de forums et de séances de dédicaces.\\n\\n### Au programme\\n\\nPour cette nouvelle édition le Salon propose un programme dense et varié, pour tous les goûts et tous les âges : dédicaces, forums, concours, expositions, conférences, ateliers, contes et spectacles pour enfants, apéritifs et goûters littéraires. Yann Quéffelec, Prix Goncourt pour son roman \\\"Les noces barbares\\\" sera l\'invité d\'honneur de cet événement !\\n\\nEn nouveauté cette année, un espace livres de poche et des interventions pour la lutte contre l’illettrisme.\\n\\nLes visiteurs pourront également chercher \\\"Où est Charlie ?\\\" \\n\\n### Informations pratiques\\n\\nL\'entrée au Salon est gratuite. \\n\\nPour plus d\'informations vous pouvez contacter :\\n\\nTél : +33(0)3.20.25.99.31 \\n\\nMail : [salondulivre@mairie-bondues.fr ](mailto:salondulivre@mairie-bondues.fr)\\n\\nSur le salon : 06.16.65.17.20\"}', '{\"fr\":[]}', '{\"fr\":\"Gratuit\"}', '{\"filename\":\"${schema}1e-salon-du-livre-de-bondues_736580.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evf${schema}1e-salon-du-livre-de-bondues_736580.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtb${schema}1e-salon-du-livre-de-bondues_736580.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-23T08:00:00.000Z\",\"end\":\"2019-03-23T18:30:00.000Z\"},{\"begin\":\"2019-03-24T08:30:00.000Z\",\"end\":\"2019-03-24T17:30:00.000Z\"}]', '{\"mi\":false,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.ville-bondues.fr/salondulivre/\"]', '2019-01-21 14:40:06', '2019-02-18 13:10:17', NULL, 'a643eb359a4c4651ab0873d2d90236bf', '[]', '[]');
INSERT INTO `${schema}` (`id`, `uid`, `owner_uid`, `creator_uid`, `agenda_uid`, `location_uid`, `slug`, `title`, `description`, `long_description`, `keywords`, `conditions`, `image`, `draft`, `private`, `timezone`, `timings`, `accessibility`, `age`, `registration`, `created_at`, `updated_at`, `deleted_at`, `file_key`, `references`, `links`) VALUES
(487390, 19889810, 8140284, 8140284, 89904399, 4870090, 'game-all-over-4', '{\"fr\":\"Game All Over #4\"}', '{\"fr\":\"Game all Over, l\'événement 100% business dédié à la gamification revient pour sa 4e édition, le 13 juin 2019, à la Plaine Images : dernières tendances, solutions innovantes, mécaniques ludiques...\"}', '{\"fr\":\"Game all Over est l’événement pour les entreprises et les industries qui souhaitent connaître et appliquer les dernières tendances de la gamification.\\n\\n### Au programme\\n\\nRetours d’expérience, focus méthodologiques, présentations de solutions innovantes, échanges et rencontres au coeur d’un lieu où règne l’entertainment : Game all Over offre une journée unique pour repenser les métiers et les process sous le prisme du jeu.\\n\\nDécouvrez comment l’utilisation de mécaniques ludiques transforme chaque métier de l’entreprise, de la formation au marketing en passant par le management ou le recrutement. Apprenez de vos pairs; Découvrez les dernières tendances de la gamification et leurs usages pour l’entreprise et l’industrie; Rencontrer vos futurs partenaires; Immergez-vous dans un monde créatif; Repensez vos métiers et process !\\n\\n### Call for speakers\\n\\nDans le but d\'animer les sessions d\'échange lors de Game all Over, La Plaine Images lance un \\\"call for speakers\\\" ! Prenez part à des sessions inspirantes, engageantes et instructives. Tout speaker potentiel, de tout type d\'entreprise ou d\'organisation, peut répondre à ce call for speaker avant le 10 février minuit.\\n\\nUn comité de programme composé des partenaires de l\'événement se réunira durant le mois de février et vous serez recontacté à l\'issue de la sélection.\\n\\n**Voici les attentes :**\\n\\n*   Donner un éclairage concret sur les apports de la gamification au monde de l\'entreprise, appliqué à une problématique métier,\\n*   Raconter une histoire captivante, transparente et authentique\\n*   Etre capable de mettre en évidence des spécificité, usages, freins, coûts ou comment évaluer le ROI\\n\\n[Plus d\'informations sur votre inscription en tant que speaker.](https://docs.google.com/forms/d/e/1FAIpQLSc_qWAq9YktLR99L4fXmzTlimVBUyDeBQxhQK-RRXhz4TR2nA/viewform)\"}', '{\"fr\":[]}', '{\"fr\":\"Payant\"}', '{\"filename\":\"event_game-all-over-4_950600.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_game-all-over-4_950600.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_game-all-over-4_950600.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-06-13T06:30:00.000Z\",\"end\":\"2019-06-13T17:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"https://www.eventbrite.fr/e/billets-game-all-over-4-54520060970\"]', '2019-01-21 14:32:59', '2019-01-21 14:33:00', NULL, '2ae5b95320074f6eaa339b09b96a8044', '[]', '[]'),
(477368, 39668740, 8140284, 8140284, 89904399, 50651588, 'salon-des-blogueurs-de-voyage-wat-2019', '{\"fr\":\"Salon des Blogueurs de Voyage : WAT 2019\"}', '{\"fr\":\"2 jours de conférences et networking du e-tourisme\"}', '{\"fr\":\"La blogosphère foisonne de sites de voyage. Ces influenceurs, de plus en plus professionnalisés, touchent des millions de touristes potentiels. Accueillir le Salon des blogueurs de voyage francophones est donc une occasion unique de faire connaître notre territoire comme destination touristique : plus de 300 blogueurs vont en effet la promouvoir en même temps. Vingt millions de vues avaient été recensées à Saint-Malo en 2017, nous en espérons encore plus !\\n\\n### Le salon We Are Travel 2019 - #WAT19\\n\\nDepuis 2014, l\'agence « We Are Travel » organise tous les ans (Cannes, Ajaccio, Bruxelles, St-Malo, l\'Aveyron) le Salon des Blogueurs Francophones de Voyage. Pendant 2 jours et demi, blogueurs et professionnels du tourisme se rencontrent durant des conférences et des ateliers sur le digital et les tendances. L\'occasion d\'inviter une sélection d\'entre eux à une journée de blog-trips dans la métropole et de leur faire découvrir une destination urbaine toujours en mouvement, chaleureuse et où il y a beaucoup à faire.\\n\\n### Une méthode de communication au cœur des tendances\\n\\nLa présence sur les nouveaux médias est l\'une des initiatives les plus efficaces pour faire connaître les destinations :\\n\\n87% des voyageurs utilisent désormais Internet pour préparer leur séjour,88% des internautes sont influencés dans le choix de la destination par les articles des blogueurs.\\n\\n### Une lisibilité numérique inédite et incomparable pour la destination\\n\\nLe salon donne l\'occasion de communiquer d\'une manière pérenne auprès de millions de lecteurs et d\'obtenir une visibilité incomparable 10 000 mentions 20 millions de vues pendant l\'évènement 2017 4 millions de visiteurs par mois d\'audience cumulé\\n\\n**Découvrez le teaser de l\'événement : **\\n\\nhttps://www.youtube.com/watch?v=SZzt9BTPC80\"}', '{\"fr\":[]}', '{}', '{\"filename\":\"event_salon-des-blogueurs-de-voyage-wat-2019_750823.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_salon-des-blogueurs-de-voyage-wat-2019_750823.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_salon-des-blogueurs-de-voyage-wat-2019_750823.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-11T06:00:00.000Z\",\"end\":\"2019-04-11T19:00:00.000Z\"},{\"begin\":\"2019-04-12T06:00:00.000Z\",\"end\":\"2019-04-12T19:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"https://www.salonblogueursvoyage.fr/\"]', '2019-01-09 14:20:53', '2019-01-09 14:20:54', NULL, 'dae8e00e28e1499881e5415101ab1873', '[]', '[]'),
(475733, 13836830, 42070961, 42070961, 89904399, 16369081, 'le-beffroi-d-armentieres', '{\"fr\":\"Le beffroi d\'Armentières\"}', '{\"fr\":\"Grimpez les 40 mètres du beffroi d\'Armentières et contemplez la Cité de la Toile !\"}', '{\"fr\":\"Classé au patrimoine mondial de l’UNESCO, le beffroi d’Armentières a fière allure. Comptez environ deux cents marches, que notre guide vous fera facilement oublier, et vous pourrez contemplez la Cité de la Toile à plus de 40 mètres de hauteur ! Vous profiterez d’une vue imprenable sur le territoire armentiérois, entre France et Belgique, aux portes des Flandres d’un côté et de Lille de l’autre.\"}', '{\"fr\":[\"Beffroi\",\"Visite\",\"Patrimoine mondial de l\'UNESCO\",\"Architecture\"]}', '{\"fr\":\"Entrée : 5€ adulte / 3€ enfant (de 6 à 12 ans)\"}', '{\"filename\":\"event_le-beffroi-d-armentieres_921607.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_le-beffroi-d-armentieres_921607.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_le-beffroi-d-armentieres_921607.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-04-06T12:30:00.000Z\",\"end\":\"2019-04-06T13:30:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"03 20 44 18 19\",\"ot.armentieres@wanadoo.fr\"]', '2019-01-04 15:58:14', '2019-01-04 15:58:15', NULL, 'a125023a40e94eb69b1e4ca82dc552ee', '[]', '[]'),
(475717, 41787985, 42070961, 42070961, 89904399, 91322533, 'autour-de-la-mairie-de-lambersart', '{\"fr\":\"Autour de la mairie de Lambersart\"}', '{\"fr\":\"Suivez un guide qui vous dévoilera l\'histoire et l\'évolution des lieux emblématiques et historiques de Lambersart.\"}', '{\"fr\":\"En 1950, le château du Pré Fleuri devient l’hôtel de ville de Lambersart. Il s’agit de la 8ème mairie depuis 1790\\\\. Le château de la Carnoy 1883, également appelé château Bonte, est baptisé en 1990 : Centre Charles de Gaulle. En parcourant ce circuit, le guide vous dévoilera l’histoire et l’évolution de ces lieux emblématiques de la ville.\"}', '{\"fr\":[\"Visite\",\"Architecture\",\"Patrimoine\",\"Mairie\"]}', '{\"fr\":\"Entrée : 2€ - Départ précisé lors de la réservation\"}', '{\"filename\":\"event_autour-de-la-mairie-de-lambersart_568309.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_autour-de-la-mairie-de-lambersart_568309.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_autour-de-la-mairie-de-lambersart_568309.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-17T14:00:00.000Z\",\"end\":\"2019-03-17T16:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"03 20 08 44 44\",\"03 20 00 60 06\",\"eparize@ville-lambersart.fr\"]', '2019-01-04 15:29:41', '2019-01-04 15:29:41', NULL, '1573ecaeccc64ae4a60aaa989dde020a', '[]', '[]'),
(475711, 94279187, 42070961, 42070961, 89904399, 87673737, 'le-fort-de-mons', '{\"fr\":\"Le Fort de Mons\"}', '{\"fr\":\"Que vous soyez amateur d’architecture militaire, des arts et des lettres, de verdure ou d’espace, venez découvrir le Fort de Mons !\"}', '{\"fr\":\"Le Fort de Mons en Baroeul, l’un des mieux conservé de la «place forte de Lille», comme on la désignait au moment de sa construction en 1880, est un trésor caché dans la ville. Épargné par les conflits, le fort a conservé, à l’exception de ses canons, ses attributs d’ouvrage militaire : son pont basculant, ses caponnières, ses magasins à poudre, son casernement. Ceux-ci ont été pacifiquement reconvertis en bibliothèque, salle de danse, de projection, école de musique, café-concert… Que vous soyez amateur d’architecture militaire, des arts et des lettres, de verdure ou d’espace, venez le découvrir !\\n\\n_En partenariat avec l’Association Historique de Mons en Baroeul._\"}', '{\"fr\":[\"Visite\",\"Architecture\",\"Patrimoine\"]}', '{\"fr\":\"Entrée : 2,5€\"}', '{\"filename\":\"event_le-fort-de-mons_955609.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_le-fort-de-mons_955609.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_le-fort-de-mons_955609.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2019-03-16T08:45:00.000Z\",\"end\":\"2019-03-16T11:15:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"03 20 43 55 75\",\"ot@villeneuvedascq-tourisme.eu\"]', '2019-01-04 15:20:00', '2019-01-04 15:20:01', NULL, 'def46d0244f94945a881ed2abcc563e4', '[]', '[]'),
(475703, 68863522, 42070961, 42070961, 89904399, 37241484, 'les-secrets-du-vieux-lille', '{\"fr\":\"Les secrets du Vieux-Lille\"}', '{\"fr\":\"Partez à la découverte du Vieux-Lille, de ses quartiers anciens, et appréciez son architecture.\"}', '{\"fr\":\"Partez à la découverte des quartiers anciens de la ville de Lille et appréciez les charmes d’une cité vivante et accueillante. D’une époque à l’autre, Lille a conservé de nombreux édifices témoins d’influences multiples, le Palais Rihour, la Vieille Bourse, le rang du Beauregard, la cathédrale Notre-Dame-de-la-Treille. Le parcours révèle la diversité architecturale de la cité et se termine près du musée de l’Hospice Comtesse, autre lieu de mémoire de Lille.\\n\\n**Réservation dans [tous les offices de tourisme de la métropole](http://fr/les-offices-de-tourisme-de-la-metropole). **\"}', '{\"fr\":[\"Vieux-Lille\",\"Visite\",\"Lille\",\"Quartiers anciens\"]}', '{\"fr\":\"Entrée : 9€ / 11€\"}', '{\"filename\":\"event_les-secrets-du-vieux-lille_338951.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_les-secrets-du-vieux-lille_338951.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_les-secrets-du-vieux-lille_338951.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-12-31T14:00:00.000Z\",\"end\":\"2018-12-31T16:00:00.000Z\"},{\"begin\":\"2019-01-01T14:00:00.000Z\",\"end\":\"2019-01-01T16:00:00.000Z\"},{\"begin\":\"2019-01-02T14:00:00.000Z\",\"end\":\"2019-01-02T16:00:00.000Z\"},{\"begin\":\"2019-01-03T14:00:00.000Z\",\"end\":\"2019-01-03T16:00:00.000Z\"},{\"begin\":\"2019-01-04T14:00:00.000Z\",\"end\":\"2019-01-04T16:00:00.000Z\"},{\"begin\":\"2019-01-05T14:00:00.000Z\",\"end\":\"2019-01-05T16:00:00.000Z\"},{\"begin\":\"2019-01-06T14:00:00.000Z\",\"end\":\"2019-01-06T16:00:00.000Z\"},{\"begin\":\"2019-01-07T14:00:00.000Z\",\"end\":\"2019-01-07T16:00:00.000Z\"}