(393888, 42076649, 69702957, 69702957, 89904399, 40338923, 'comprendre-et-reduire-ma-facture-d-energie_667', '{\"fr\":\"Comprendre et réduire ma facture d\'énergie\"}', '{\"fr\":\"Participez à cette animation pédagogique à Lille pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Il n\'est pas toujours évident de comprendre ce qui se cache derrière ses factures d\'énergie : consommations, tarification, abonnement, évolutions du fait de l\'ouverture du marché de l\'énergie...\\n\\nVotre conseiller info-énergie vous propose de détailler avec vous une facture et vous donne quelques astuces pour réduire votre consommation.\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\",\"loisirs\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_comprendre-et-reduire-ma-facture-d-energie_667_504718.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_comprendre-et-reduire-ma-facture-d-energie_667_504718.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_comprendre-et-reduire-ma-facture-d-energie_667_504718.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-07-06T12:00:00.000Z\",\"end\":\"2018-07-06T14:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-06-26 09:18:53', '2018-06-26 09:18:55', NULL, 'acbaaec7223341819190c11f47e01f1e', NULL, NULL),
