(386298, 24550787, 69702957, 69702957, 89904399, 40338923, 'fabriquer-mes-produits-menagers', '{\"fr\":\"Fabriquer mes produits ménagers\"}', '{\"fr\":\"Participez à cette animation pédagogique à Lille pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Pour prévenir les risques pour la santé, cette animation met en lumière les différentes sources de pollution dans le logement, rappelle la signification des pictogrammes dangereux et vous informe sur l\'intoxication au monoxyde de carbone.\\n\\nL\'animatrice vous invite ensuite à fabriquer un produit ménager sain, écologique et économique.\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\",\"Loisirs\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_fabriquer-mes-produits-menagers_588970.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_fabriquer-mes-produits-menagers_588970.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_fabriquer-mes-produits-menagers_588970.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-09-21T12:00:00.000Z\",\"end\":\"2018-09-21T14:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-06-15 13:38:44', '2018-06-15 13:38:45', NULL, '66bc4e7196cf46bd9bd369cef99390b5', NULL, NULL),
(386265, 12843431, 69702957, 69702957, 89904399, 54115636, 'poser-un-systeme-de-ventilation', '{\"fr\":\"Poser un système de ventilation\"}', '{\"fr\":\"Participez à cette animation pédagogique à Lille pou rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Avec l\'aide de professionnels qualifiés, découvrez les différents systèmes de ventilation existants et apprenez à installer une ventilation mécanique contrôlée (VMC)\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\",\"loisirs\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_poser-un-systeme-de-ventilation_548314.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_poser-un-systeme-de-ventilation_548314.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_poser-un-systeme-de-ventilation_548314.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-09-22T07:30:00.000Z\",\"end\":\"2018-09-22T10:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-06-15 13:31:49', '2018-06-15 13:31:50', NULL, 'c1c39ae8cf824cb7b17aca5026596046', NULL, NULL),
(386229, 13240277, 69702957, 69702957, 89904399, 40338923, 'repair-cafe-ne-jetez-rien-reparez-tout_590', '{\"fr\":\"Repair café : ne jetez rien, réparez tout !\"}', '{\"fr\":\"Participez à cette animation pédagogique à Lille pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Tous les 3èmes samedis du mois (sauf juillet-août), la Maison de l\'habitat durable accueille désormais son Repair café. Votre grille-pain ne fonctionne plus ? Le printemps arrive et votre tondeuse ne redémarre plus ? L\'association le Jardin des Bennes vous aide à réparer tous ces objets du quotidien qui peuvent encore vous servir.\\n\\n**Vous souhaitez devenir réparateur bénévole** **?**\\n\\nRejoignez le groupe des réparateurs du Repair Café de la Maison de l\'habitat durable et aidez, vous aussi, les visiteurs du Repair café à réparer leurs objets, tout en bénéficiant d\'une formation.\\n\\nPour toute information, rendez-vous sur le Facebook \\\"RepairCaféMaisonHabitatDurable\\\" ou contactez le 03 59 00 03 59 ou [maisonhabitatdurable@lillemetropole.fr](mailto:maisonhabitatdurable@lillemetropole.fr)\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\",\"Loisirs\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_repair-cafe-ne-jetez-rien-reparez-tout_590_942176.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_repair-cafe-ne-jetez-rien-reparez-tout_590_942176.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_repair-cafe-ne-jetez-rien-reparez-tout_590_942176.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-09-15T07:30:00.000Z\",\"end\":\"2018-09-15T10:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-06-15 13:21:00', '2018-06-15 13:21:02', NULL, 'b9ca7acf62de495f8