(367768, 18301730, 31745822, 31745822, 89904399, 64157139, 'vide-greniers-a-hallennes-lez-haubourdin', '{\"fr\":\"Vide-greniers à Hallennes-lez-Haubourdin\"}', '{\"fr\":\"Le Comité des fêtes organise le vide-grenier de la rue du Général de Gaulle, de 7h à 16h.\"}', '{\"fr\":\"Le Comité des fêtes organise le vide-grenier de la rue du Général de Gaulle, de 7h à 16h.\\n\\nEn partenariat avec la Ville, il est réservé aux particuliers.\\n\\nBuvette et restauration sur place. Pêche aux canards pour les enfants.\\n\\nLes véhicules auront l’interdiction absolue de stationner dans le périmètre du vide-grenier. Les riverains devront s\'organiser pour laisser leur véhicule en dehors du périmètre du vide-grenier s\'ils veulent se déplacer.\\n\\n350 exposants.\"}', '{\"fr\":[\"vide grenier\",\"braderie\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_vide-greniers-a-hallennes-lez-haubourdin_932680.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_vide-greniers-a-hallennes-lez-haubourdin_932680.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_vide-greniers-a-hallennes-lez-haubourdin_932680.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-09T05:00:00.000Z\",\"end\":\"2018-06-09T14:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-05-28 09:49:26', '2018-05-28 09:49:28', NULL, '532d422b6e7f48a6ac225341ee15d986', NULL, NULL),
