(367730, 56336437, 31745822, 31745822, 89904399, 87994224, 'braderie-de-l-architecture-a-lille', '{\"fr\":\"Braderie de l\'architecture à Lille\"}', '{\"fr\":\"La Braderie de l\'architecture revient pour sa 6ème édition.\"}', '{\"fr\":\"Vous pouvez venir vendre vos OBJETS et CRÉATIONS: maquettes, ouvrages, matériels, livres, dessins, jeux de constructions, maisons de poupées...\\n\\nUne vente exclusive d’objets en tout genre sur l’architecture, l’urbanisme, le paysage, le design… Bref, le cadre de vie en général...\\n\\nUne façon originale de rencontrer le grand public et de lui faire partager vos passions et vos métiers.\\n\\nOutre les stands de vente, des stands de promotion et de diffusion de l’architecture seront mis en place par les partenaires de l’opération: atelier et visites gratuites...\\n\\nUne buvette et une petite restauration seront proposées, avec un DJ Set toute la journée ass...uré par nos architectes musicos...\\n\\nA l’occasion de ce vide grenier ouvert à tous: particuliers, agences, structures de diffusion de l’architecture, une communication d’envergure est prévue afin de mettre en avant cet événement.\"}', '{\"fr\":[\"braderie\",\"architecture\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_braderie-de-l-architecture-a-lille_504297.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_braderie-de-l-architecture-a-lille_504297.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_braderie-de-l-architecture-a-lille_504297.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-09T08:00:00.000Z\",\"end\":\"2018-06-09T16:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-05-28 09:31:15', '2018-05-28 09:31:16', NULL, '84020ab4199b48a79f0357430e3976be', NULL, NULL),
