(364796, 74980446, 31745822, 31745822, 89904399, 93562200, 'vide-greniers-a-villeneuve-d-ascq', '{\"fr\":\"Vide greniers à Villeneuve d\'Ascq\"}', '{\"fr\":\"La ville de Villeneuve d’Ascq et les associations organisatrices vous accueillent pour chiner, découvrir l’objet recherché, faire de «bonnes affaires» ou tout simplement vous promener.\"}', '{\"fr\":\"La ville de Villeneuve d’Ascq et les associations organisatrices des braderies et vide greniers sont heureuses de vous accueillir pour chiner, découvrir l’objet recherché, en un mot faire de «bonnes affaires» ou tout simplement vous promener.\\n\\nPour rappel les vide greniers sont réservés uniquement aux particuliers alors que les braderies sont ouvertes aux particuliers et professionnels.\\n\\nQuartier de la Cousinerie, rue Contrscarpe\\n\\n200 exposants\"}', '{\"fr\":[\"braderie\",\"vide grenier\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_vide-greniers-a-villeneuve-d-ascq_950226.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_vide-greniers-a-villeneuve-d-ascq_950226.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_vide-greniers-a-villeneuve-d-ascq_950226.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-03T06:00:00.000Z\",\"end\":\"2018-06-03T13:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-05-23 08:48:33', '2018-05-23 08:48:34', NULL, '23bc754aa6e7452c95adc189828a8e84', NULL, NULL),
