(364743, 25635431, 69702957, 69702957, 89904399, 81838547, 'visite-d-un-logement-alimente-a-l-energie-solaire', '{\"fr\":\"Visite d\'un logement alimenté à l\'énergie solaire\"}', '{\"fr\":\"Participez à cette animation pédagogique à Baisieux pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Avec votre conseiller info-énergie, visitez la maison écologique et économique d\'un habitant de Baisieux qui a installé des panneaux photovoltaïques, un chauffe-eau solaire, qui a isolé ses combles perdus en ouate de cellulose...\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_visite-d-un-logement-alimente-a-l-energie-solaire_147721.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_visite-d-un-logement-alimente-a-l-energie-solaire_147721.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_visite-d-un-logement-alimente-a-l-energie-solaire_147721.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-29T16:30:00.000Z\",\"end\":\"2018-06-29T18:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-05-23 08:01:17', '2018-05-23 08:01:17', NULL, 'c0856be53c134104b486e05d00d76f6b', NULL, NULL),
(364734, 21188972, 31745822, 31745822, 89904399, 5823043, 'puces-couturieres-a-herlies', '{\"fr\":\"Puces couturières à Herlies\"}', '{\"fr\":\"Puces couturières et loisirs créatifs à Herlies\"}', '{\"fr\":\"Pour particuliers et professionnels.\\n\\nSalle Jean Monnet, place de l\'Europe.\\n\\nPuces couturières : Tissu, couture, broderie, patchwork, tricot, crochet, ...\\n\\nLoisirs créatifs : perles, cartonnage, scrapbooking, serviettes papier, ...\"}', '{\"fr\":[\"puces\",\"couture\",\"braderie\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_puces-couturieres-a-herlies_932798.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_puces-couturieres-a-herlies_932798.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_puces-couturieres-a-herlies_932798.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-03T08:00:00.000Z\",\"end\":\"2018-06-03T16:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-05-23 07:54:21', '2018-05-23 07:54:22', NULL, 'd15119b969cb4b0284b6365d784fd88a', NULL, NULL),
