(364722, 15339740, 31745822, 31745822, 89904399, 15459334, 'vide-greniers-a-don', '{\"fr\":\"Vide greniers à Don\"}', '{\"fr\":\"L’UNCSD organise avec le Pétanque Club Donois le traditionnel vide grenier du premier week-end de juin.\"}', '{\"fr\":\"L’UNCSD organise avec le Pétanque Club Donois le traditionnel vide grenier du premier week-end de juin.\\n\\nLa braderie s’étalera dans les rues Marcel SEMBAT, Franois LIENART et Jean LONGUET, au parc et sur le parking de la base nautique.\\n\\nBuvette et petite restauration sur place.\\n\\n200 exposants\"}', '{\"fr\":[\"braderie\",\"vide greniers\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_vide-greniers-a-don_411783.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_vide-greniers-a-don_411783.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_vide-greniers-a-don_411783.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-03T07:00:00.000Z\",\"end\":\"2018-06-03T13:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-05-23 07:44:09', '2018-05-23 07:44:10', NULL, 'e961acf4172546e7b70d621221e14692', NULL, NULL);
