(364719, 66936689, 69702957, 69702957, 89904399, 40338923, 'ameliorer-la-qualite-de-l-air-de-mon-interieur-et-fabriquer-mes-produits-menagers', '{\"fr\":\"Améliorer la qualité de l\'air de mon intérieur et fabriquer mes produits ménagers\"}', '{\"fr\":\"Participez à cette animation  pédagogique à Lille pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Pour prévenir les risques pour la santé, cette animation met en lumière les différentes sources de pollution dans le logement, rappelle la signification des pictogrammes dangereux et vous informe sur l\'intoxication au monoxyde de carbone.\\n\\nL\'animatrice vous invite ensuite à fabriquer un produit ménager sain, écologique et économique.\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_ameliorer-la-qualite-de-l-air-de-mon-interieur-et-fabriquer-mes-produits-menagers_948988.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_ameliorer-la-qualite-de-l-air-de-mon-interieur-et-fabriquer-mes-produits-menagers_948988.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_ameliorer-la-qualite-de-l-air-de-mon-interieur-et-fabriquer-mes-produits-menagers_948988.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-22T12:00:00.000Z\",\"end\":\"2018-06-22T14:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0350000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-05-23 07:42:24', '2018-05-23 07:42:25', NULL, 'b53a5d71ac1c4c02ace6327e49cabddd', NULL, NULL),
