(364716, 47853938, 31745822, 31745822, 89904399, 43671154, 'braderie-a-mons-en-baroeul', '{\"fr\":\"Braderie à Mons en Baroeul\"}', '{\"fr\":\"Braderie dans le centre de Mons en Baroeul\"}', '{\"fr\":\"Braderie de Mons en Baroeul\\n\\n250 exposants\"}', '{\"fr\":[\"braderie\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_braderie-a-mons-en-baroeul_47990.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_braderie-a-mons-en-baroeul_47990.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_braderie-a-mons-en-baroeul_47990.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-03T06:00:00.000Z\",\"end\":\"2018-06-03T12:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-05-23 07:35:27', '2018-05-23 07:35:27', NULL, 'fd0662f9cd284b96b7693a65d3698e03', NULL, NULL),
(364454, 55671576, 69702957, 69702957, 89904399, 80424942, 'visite-d-un-logement-renove-m-inspirer-d-une-renovation-reussie-et-receptionner-mes-travaux', '{\"fr\":\"Visite d\'un logement rénové : m\'inspirer d\'une rénovation réussie et réceptionner mes travaux\"}', '{\"fr\":\"Participez à cette animation pédagogique à Lomme pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Un particulier vous accueille chez lui pour visiter sa maison rénovée très basse consommation et vous fait partager son expérience de la rénovation.\\n\\nVotre conseiller info-énergie, expert en matière de rénovation énergétique, explique les aspects techniques de ce projet et répond à toutes vos questions. Puis, votre conseiller vous informe sur les points de vigilance à avoir au moment de la fin d\'un chantier.\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_visite-d-un-logement-renove-m-inspirer-d-une-renovation-reussie-et-receptionner-mes-travaux_928691.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_visite-d-un-logement-renove-m-inspirer-d-une-renovation-reussie-et-receptionner-mes-travaux_928691.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_visite-d-un-logement-renove-m-inspirer-d-une-renovation-reussie-et-receptionner-mes-travaux_928691.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-20T16:00:00.000Z\",\"end\":\"2018-06-20T18:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-05-22 14:52:39', '2018-05-22 14:52:40', NULL, '070927d66f4b4efa98d84de45bdcead7', NULL, NULL),
(364439, 63274597, 69702957, 69702957, 89904399, 40338923, 'les-prochains-sites-proposes-en-habitat-participatif-a-lille', '{\"fr\":\"Les prochains sites proposés en habitat participatif à Lille\"}', '{\"fr\":\"Des professionnels vous informent au cours de cette conférence à la Maison de l\'habitat durable\"}', '{\"fr\":\"Chaque trimestre, l\'association Eco Habitat groupé anime une conférence, en présence d\'habitants et de professionnels, pour mieux connaître ce type d\'habitat où des espaces communs complètent les logements individuels.\\n\\n**Organisateur** : Eco Habitat groupé\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_les-prochains-sites-proposes-en-habitat-participatif-a-lille_156230.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_les-prochains-sites-proposes-en-habitat-participatif-a-lille_156230.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_les-prochains-sites-proposes-en-habitat-participatif-a-lille_156230.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-16T07:30:00.000Z\",\"end\":\"2018-06-16T09:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-05-22 14:39:35', '2018-06-05 14:25:58', NULL, '6429c487bdff42f1885f96ed3608136a', NULL, NULL),
(364430, 42056796, 69702957, 69702957, 89904399, 40338923, 'repair-cafe-ne-jetez-rien-reparez-tout_156', '{\"fr\":\"Repair café : ne jetez rien, réparez tout !\"}', '{\"fr\":\"Participez à cette animation pédagogique à Lille pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Tous les 3èmes samedis du mois, la Maison de l\'habitat durable accueille désormais son Repair café. Votre grille-pain ne fonctionne plus ? Le printemps arrive et votre tondeuse ne redémarre plus ? L\'association le Jardin des Bennes vous aide à réparer tous ces objets du quotidien qui peuvent encore vous servir.\\n\\n**Pour devenir réparateur bénévole**.\\n\\nRejoignez le groupe des réparateurs du Repair Café de la Maison de l\'habitat durable et aidez, vous aussi, les visiteurs du Repair café à réparer leurs objets, tout en bénéficiant d\'une formation.\\n\\n**Information**\\n\\nFacebook \\\"RepairCaféMaisonHabitatDurable\\\" Tél : 03 59 00 03 59\\n\\nMail : [maisonhabitatdurable@lillemetropole.fr](mailto:maisonhabitatdurable@lillemetropole.fr)\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_repair-cafe-ne-jetez-rien-reparez-tout_156_319103.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_repair-cafe-ne-jetez-rien-reparez-tout_156_319103.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_repair-cafe-ne-jetez-rien-reparez-tout_156_319103.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-16T07:30:00.000Z\",\"end\":\"2018-06-16T10:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-05-22 14:33:04', '2018-05-22 14:33:04', NULL, 'ebfa64c685aa4185b19e70df978945d4', NULL, NULL),
(364417, 9549133, 69702957, 69702957, 89904399, 75391604, 'bricolage-poser-un-systeme-de-ventilation-pratique_197', '{\"fr\":\"Bricolage : Poser un système de ventilation (pratique)\"}', '{\"fr\":\"Participez à cette animation pédagogique à La Madeleine pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Avec l\'aide de professionnels qualifiés, découvrez les différents systèmes de ventilation existants et apprenez à installer une ventilation mécanique contrôlée (VMC).\\n\\nCette animation est proposée en deux sessions. Le suivi des deux parties est obligatoire.\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement durable\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_bricolage-poser-un-systeme-de-ventilation-pratique_197_751083.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_bricolage-poser-un-systeme-de-ventilation-pratique_197_751083.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_bricolage-poser-un-systeme-de-ventilation-pratique_197_751083.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-16T07:30:00.000Z\",\"end\":\"2018-06-16T10:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-05-22 14:20:46', '2018-05-22 14:20:46', NULL, 'f750bc1c347e48bba72e17164b6e4185', NULL, NULL),
