(364382, 18653972, 31745822, 31745822, 89904399, 55253754, 'vide-dressing-au-fort-de-mons', '{\"fr\":\"Vide dressing au Fort de Mons\"}', '{\"fr\":\"Échanger vos vêtements pour renouveler votre garde de robe à l\'occasion du vide dressing au Fort de Mons.\"}', '{\"fr\":\"Dans le but d\'aider à financer un voyage dans la ville de New-York pour un groupe de jeunes, l\'équipe événementielle du Centre Social Imagine de Mons-en-Baroeul organise son premier vide-dressing!\\n\\nVêtements, chaussures, accessoires, une journée consacrée à la vente des plus belles pièces qui malheureusement sont de trop dans vos placards.\\n\\nDurant cette journée, nous auront la chance d\'occuper la magnifique salle des fêtes du Fort de Mons. Un espace prestigieux pour un événement novateur à Mons-en-Baroeul. Un vide-dressing placé dans un univers Old School, Vintage et qui veut mettre en avant la sneaker.\\n\\nUn défilé mettra en lumière de jeunes créateurs locaux.\"}', '{\"fr\":[\"vide dressing\",\"braderie\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_vide-dressing-au-fort-de-mons_63814.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_vide-dressing-au-fort-de-mons_63814.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_vide-dressing-au-fort-de-mons_63814.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-02T08:00:00.000Z\",\"end\":\"2018-06-02T16:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-05-22 13:52:41', '2018-05-22 13:52:41', NULL, 'a6d8198eb430450c93d737784788511d', NULL, NULL),
(364369, 48443114, 69702957, 69702957, 89904399, 88103708, 'gestion-et-tri-des-dechets', '{\"fr\":\"Gestion et tri des déchets\"}', '{\"fr\":\"Participez à cette animation pédagogique à Neuville-en-Ferrain pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Pourquoi et comment trier ?\\n\\nAprès un échange autour des différentes pollutions occasionnées par les anciennes solutions de traitement des déchets, l\'animateur vous met au défi de retrouver les différents temps de recomposition des ordures et de placer les déchets dans les bons bacs.\"}', '{\"fr\":[\"Logement\",\"Habitat\",\"Développement Durable\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_gestion-et-tri-des-dechets_181776.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_gestion-et-tri-des-dechets_181776.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_gestion-et-tri-des-dechets_181776.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-09T08:00:00.000Z\",\"end\":\"2018-06-09T10:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-05-22 13:46:48', '2018-05-22 13:46:49', NULL, '9a400617dd8a41e597f7679e2e6a438c', NULL, NULL),
