(364344, 25430779, 69702957, 69702957, 89904399, 54115636, 'bricolage-isolation-des-combles-pratique-2', '{\"fr\":\"Bricolage : Isolation des combles (pratique 2)\"}', '{\"fr\":\"Participez à cette animation pédagogique à Lille pour rendre votre logement plus économe et confortable\"}', '{\"fr\":\"Avec l\'aide de professionnels qualifiés, faites les bons choix (techniques, matériaux...) et apprenez à réaliser votre isolation en vous exerçant sur un modèle de combles en taille réelle. Cette animation est proposée en trois parties. Le suivi des trois sessions est obligatoire.\"}', '{\"fr\":[\"Habitat\",\"Logement\",\"Habitat durable\"]}', '{\"fr\":\"Gratuit et sur inscription\"}', '{\"filename\":\"event_bricolage-isolation-des-combles-pratique-2_881738.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_bricolage-isolation-des-combles-pratique-2_881738.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_bricolage-isolation-des-combles-pratique-2_881738.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-09T07:30:00.000Z\",\"end\":\"2018-06-09T10:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":false}', '{\"min\":18,\"max\":99}', '[\"0359000359\",\"maisonhabitatdurable@lillemetropole.fr\"]', '2018-05-22 13:31:37', '2018-05-22 13:31:37', NULL, '3d351e5084bf487185632cf2d4bd942d', NULL, NULL),
