(354983, 54472222, 56673351, 56673351, 89904399, 9364949, 'fivestival-2018', '{\"fr\":\"Fivestival 2018\"}', '{\"fr\":\"Le Fivestival revient pour sa 11e édition dans le quartier Fives à Lille. Concerts, spectacles de rue, tournoi de mölkky, bal, village associatif viendront rythmer ces trois jours de fête.\"}', '{\"fr\":\"**Mercredi 30 mai**  \\n[Programmation](http://www.fivestival.org/mercredi-30-mai/) - 29 rue Eugène Jacquet 59800 Lille\\n\\n**Samedi 2 juin**  \\n[Programmation](http://www.fivestival.org/samedi-2-juin/) - 91 rue de Lannoy 59800 Lille\\n\\n**Dimanche 3 juin**  \\n[Programmation](http://www.fivestival.org/dimanche-3-juin/) - Square Lardemer, Rue de la Phalècque 59800 Lille\\n\\n[https://www.youtube.com/watch?v=wd0Lahv0Y5g](https://www.youtube.com/watch?v=wd0Lahv0Y5g)\"}', '{\"fr\":[\"fivestival\",\"fête\",\"festival\",\"fives\",\"concert\",\"spectacle\",\"tournoi\",\"mölkky\",\"bal\",\"rue\"]}', '{\"fr\":\"Gratuit / Bal à Fives : 5€ (tarif plein), 3€ (tarif réduit), gratuit (moins de 16 ans)\"}', '{\"filename\":\"event_fivestival-2018_618349.jpg\",\"credits\":\"NASDAC\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_fivestival-2018_618349.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_fivestival-2018_618349.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-30T12:30:00.000Z\",\"end\":\"2018-05-30T15:30:00.000Z\"},{\"begin\":\"2018-06-02T13:00:00.000Z\",\"end\":\"2018-06-01T22:00:00.000Z\"},{\"begin\":\"2018-06-03T12:00:00.000Z\",\"end\":\"2018-06-03T17:00:00.000Z\"}]', '{\"mi\":true,\"hi\":false,\"pi\":false,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"http://www.fivestival.org/\"]', '2018-05-04 09:35:45', '2018-05-04 16:49:01', NULL, '21e9981ebd8b4aeca37cc9b1677361f4', NULL, NULL),
(351508, 96607436, 31745822, 31745822, 89904399, 4597413, 'braderie-a-lille-quartier-wazemmes', '{\"fr\":\"Braderie à Lille - Quartier Wazemmes\"}', '{\"fr\":\"Cette année encore, la braderie de Wazemmes/Artois sera bien plus qu\'une braderie! Vous pourrez chiner, bien sûr, mais aussi vous y restaurer, y écouter de la musique, y voir du cirque, des concerts.\"}', '{\"fr\":\"Cette année encore, la braderie de Wazemmes/Artois sera bien plus qu\'une braderie! Vous pourrez chiner, bien sûr, mais aussi vous y restaurer, y écouter de la musique, y voir du cirque, des concerts.\\n\\nOrganisé par : Association des Habitants de la rue de Wazemmes et des Rues Voisines\\n\\nParticuliers et professionnels - de 200 à 300 exposants.\"}', '{\"fr\":[\"braderie\",\"fête\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_braderie-a-lille-quartier-wazemmes_164018.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_braderie-a-lille-quartier-wazemmes_164018.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_braderie-a-lille-quartier-wazemmes_164018.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-26T07:00:00.000Z\",\"end\":\"2018-05-26T14:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-27 09:28:30', '2018-04-27 09:28:31', NULL, 'd935657f80c8440dbd865f2026c790e0', NULL, NULL),
