(350871, 66850797, 31745822, 31745822, 89904399, 56264628, 'puces-de-printemps-a-roncq', '{\"fr\":\"Puces de printemps à Roncq\"}', '{\"fr\":\"Le dimanche 13 mai, de 7h à 14h, les Puces de printemps vont battre le pavé de la rue de Lille sur plusieurs kilomètres, de la rue du 8 mai 45 jusqu’à la rue de Tourcoing côté Blanc-Four !\"}', '{\"fr\":\"Le dimanche 13 mai, de 7h à 14h, les Puces de printemps vont battre le pavé de la rue de Lille sur plusieurs kilomètres, de la rue du 8 mai 45 jusqu’à la rue de Tourcoing côté Blanc-Four ! Deux associations se partagent le travail de l’organisation, soutenues par la Ville qui apporte la logistique, à savoir le « Comité des Allumoirs de Roncq Centre » pour le Centre-Bourg et « Association Solidarité Développement Cambodge (ASDC) » pour le Blanc-Four. En contrepartie, les bénéfices collectés par ces associations sont reversés au profit de leurs actions.\"}', '{\"fr\":[\"braderie\",\"brocante\",\"puces\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_puces-de-printemps-a-roncq_400442.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_puces-de-printemps-a-roncq_400442.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_puces-de-printemps-a-roncq_400442.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-13T05:00:00.000Z\",\"end\":\"2018-05-13T12:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-26 11:19:55', '2018-04-26 11:19:56', NULL, '04d133d8f50d4de6b6386edd4c93240e', NULL, NULL),
