(350389, 58550414, 31745822, 31745822, 89904399, 41721213, 'marche-aux-puces-et-braderie-a-tourcoing', '{\"fr\":\"Marché aux puces et braderie à Tourcoing - Quartier du Brun Pain\"}', '{\"fr\":\"Les braderies c’est LE bon plan pour aménager votre intérieur, vous habiller, lire ou dénicher l’antiquité de vos rêve à moindre coût. La tradition des braderies est vivace à Tourcoing aussi !\"}', '{\"fr\":\"Les braderies de quartier, c’est LE bon plan pour aménager votre intérieur, vous habiller, lire ou dénicher l’antiquité de vos rêves… à moindre coût. La tradition des braderies est vivace dans le Nord… A Tourcoing aussi !\"}', '{\"fr\":[\"braderie\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_marche-aux-puces-et-braderie-a-tourcoing_311174.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_marche-aux-puces-et-braderie-a-tourcoing_311174.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_marche-aux-puces-et-braderie-a-tourcoing_311174.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T06:00:00.000Z\",\"end\":\"2018-05-01T14:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-25 14:05:27', '2018-04-26 08:02:18', NULL, '3dc50ff90af94a6eb0e33bcea6600c0d', NULL, NULL),
(350388, 80144412, 56673351, 56673351, 89904399, 10479532, '50-ans-de-l-association-amitram', '{\"fr\":\"50 ans de l\'association AMITRAM\"}', '{\"fr\":\"Fêtez les 50 ans de l\'association AMITRAM à Wambrechies et Marquette-lez-Lille avec des parcours en tramway et autobus historiques de la métropole et de portes ouvertes exceptionnelles.\"}', '{\"fr\":\"Au programme des 50 ans de l\'association :\\n\\n*   Parcourez la ligne reliant Marquette-lez-Lille à Wambrechies à bord de tramways historiques de la métropole\\n\\n*   Empruntez les navettes relais en autobus anciens entre le dépôt de tramway de Marquette-lez-Lille et le dépôt Lavoisier\\n\\n*   Visitez le dépôt Lavoisier et son atelier de restauration pour des portes ouvertes exceptionnelles\\n\\n*   Découvrez une exposition de tramways et autobus en cours de restauration ainsi qu\'une exposition de modélisme ferroviaire\\n\\n*   Rencontrez les partenaires et associations amies d\'AMITRAM sur des stands prévus pour l\'occasion\"}', '{\"fr\":[\"tramway\",\"autobus\",\"historique\",\"anniversaire\",\"association\"]}', '{\"fr\":\"Balade en tramway + Navette + Visite du dépôt : 7€ / Visite du dépôt : 3€ / Balade en tramway : 5€\"}', '{\"filename\":\"event_50-ans-de-l-association-amitram_177266.jpg\",\"credits\":\"Pascaline Chombart/MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_50-ans-de-l-association-amitram_177266.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_50-ans-de-l-association-amitram_177266.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-12T12:00:00.000Z\",\"end\":\"2018-05-12T16:00:00.000Z\"},{\"begin\":\"2018-05-13T08:00:00.000Z\",\"end\":\"2018-05-13T10:00:00.000Z\"},{\"begin\":\"2018-05-13T12:00:00.000Z\",\"end\":\"2018-05-13T16:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"http://www.amitram.fr\"]', '2018-04-25 14:04:53', '2018-04-27 12:45:09', NULL, 'f2444bc1162e43328e9fb2d9910d3bbc', NULL, NULL),
(350378, 24977792, 31745822, 31745822, 89904399, 56536305, 'braderie-a-sainghin-en-weppes', '{\"fr\":\"Braderie à Sainghin-en-Weppes\"}', '{\"fr\":\"Braderie organisée par Brad\' en Weppes !\"}', '{\"fr\":\"Braderie organisée par Brad\' en Weppes dans les rues Edouard Vaillant et des Acacias.\"}', '{\"fr\":[\"braderi\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_braderie-a-sainghin-en-weppes_565062.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_braderie-a-sainghin-en-weppes_565062.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_braderie-a-sainghin-en-weppes_565062.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T05:00:00.000Z\",\"end\":\"2018-05-01T12:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-25 13:57:10', '2018-04-25 13:57:11', NULL, '80ffa4e4a0fc4625b2848b3dbcd1ee3f', NULL, NULL),
(350369, 61050948, 31745822, 31745822, 89904399, 41500403, 'braderie-a-roubaix', '{\"fr\":\"Braderie à Roubaix\"}', '{\"fr\":\"Braderie et brocante dans Roubaix\"}', '{\"fr\":\"Braderie et brocante dans Roubaix Rue de France (de la rue de l’Alma au boulevard des Bâtisseurs). Environ 200 exposants.\"}', '{\"fr\":[\"braderie\",\"brocante\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_braderie-a-roubaix_633125.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_braderie-a-roubaix_633125.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_braderie-a-roubaix_633125.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T06:00:00.000Z\",\"end\":\"2018-05-01T15:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-25 13:51:55', '2018-04-25 13:51:56', NULL, '0252caaf08864a7596aa385377d68791', NULL, NULL),
(350355, 95081867, 31745822, 31745822, 89904399, 36436676, 'marche-aux-puces-de-neuville-en-ferrain', '{\"fr\":\"Marché aux puces de Neuville-en-Ferrain\"}', '{\"fr\":\"Animations foraines et marché aux puces mardi 1er mai sur la place du Général de Gaulle\"}', '{\"fr\":\"Pour des raisons de sécurité, aucun véhicule ne pourra stationner sur le parcours entre 7h00 et 15h00 sauf les véhicules réservés à l’organisation et aux secours ainsi que ceux ayant reçu une autorisation de la part de l’organisateur (véhicules des personnes à mobilité réduite...).\\n\\nEnfin, les parkings de Carrefour Contact, du centre André Malraux, de l’école Saint-Joseph/Sacré Cœur et de la rue Edouard Branly seront fermés du 30 avril 18h (ou 21h selon le parking) au 1er mai 4h du matin pour des raisons de sécurité et éviter les réservations de stationnement.\\n\\nCes parkings seront donc tous bien ouverts au stationnement dès 4h du matin pour que les exposants puissent s\'y garer.\"}', '{\"fr\":[\"marché\",\"braderie\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_marche-aux-puces-de-neuville-en-ferrain_65903.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_marche-aux-puces-de-neuville-en-ferrain_65903.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_marche-aux-puces-de-neuville-en-ferrain_65903.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T05:00:00.000Z\",\"end\":\"2018-05-01T11:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-25 13:44:47', '2018-04-25 13:44:49', NULL, 'e17db817973e45cd9a61ec7462a7779b', NULL, NULL),
(350349, 56418774, 31745822, 31745822, 89904399, 5923282, 'grande-braderie-de-mouvaux-du-1er-mai', '{\"fr\":\"Grande Braderie de Mouvaux\"}', '{\"fr\":\"Chaque année, la Braderie de Mouvaux regroupe environ 500 exposants sur 1200 emplacements et plus de 10 000 visiteurs.\"}', '{\"fr\":\"La braderie de  Mouvaux  (près de Lille),  a lieu dans la rue  Franklin  Roosevelt, la rue des Ecoles, la rue Léo Lagrange, la rue Gallieni, la rue Kléber, la rue des Poilus et Poilus prolongée vers le nouveau centre, rue Corselle, le Parking Neukirchen et le Parking Pasteur.\\n\\nLe 1er Mai, de 6 h à 7 h 45, accueil des exposants. L’ouverture aux visiteurs à partir de 8h00, jusqu’à 13h00.\"}', '{\"fr\":[\"braderie\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_grande-braderie-de-mouvaux-du-1er-mai_490173.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_grande-braderie-de-mouvaux-du-1er-mai_490173.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_grande-braderie-de-mouvaux-du-1er-mai_490173.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T06:00:00.000Z\",\"end\":\"2018-05-01T11:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":12,\"max\":99}', '[]', '2018-04-25 13:39:52', '2018-04-26 08:16:03', NULL, '6226e841dbbd461694488b78c07d9181', NULL, NULL),
(350331, 90070604, 31745822, 31745822, 89904399, 3538333, 'brocante-et-marche-aux-fleurs', '{\"fr\":\"Brocante et marché aux fleurs à Wasquehal\"}', '{\"fr\":\"Retrouvez la traditionnelle brocante organisée par l’association R’Éveil. Devenue un passage obligé pour les chineurs de la Métropole, vous y découvrirez également le marché aux fleurs.\"}', '{\"fr\":\"Retrouvez la traditionnelle brocante organisée par l’association R’Éveil. Réservé aux particuliers, ce vide-grenier rassemble 2 000 exposants sur plus de 5 km d’étals et près de 100 000 visiteurs. Celle-ci partira du bas de l’avenue Jean- Paul-Sartre jusqu’à la rue Voltaire à Croix. L’occasion de dénicher des perles rares à bas prix. Devenu un passage obligé pour les chineurs de la Métropole, vous y découvrirez également, à l’entrée, face à la caserne des Pompiers, le coloré marché aux fleurs qui tombe à pic en ce jour du 1er mai. Plusieurs exposants de qualité présenteront leurs plantes annuelles et vivaces. Les fervents de nature n’auront que l’embarras du choix sur les compositions florales sans oublier le porte-bonheur du jour : le brin de muguet ! Venez flânez à la braderie du 1er mai !\\n\\nMardi 1er mai de 8 h à 16 h. Brocante avenue Jean-Paul-Sartre jusqu’à la rue Voltaire à Croix. Réservé aux particuliers.  \\nInformations et inscriptions pour le vide-grenier : Mme Cattoire au 06.50.57.86.45.\"}', '{\"fr\":[\"brocante\",\"braderie\",\"marché\",\"fleurs\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_brocante-et-marche-aux-fleurs_240504.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_brocante-et-marche-aux-fleurs_240504.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_brocante-et-marche-aux-fleurs_240504.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T06:00:00.000Z\",\"end\":\"2018-05-01T14:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-25 13:27:17', '2018-04-25 14:38:57', NULL, '22c9009722114c4fa5aa46f26c137157', NULL, NULL),
(350312, 53655248, 1279575, 1279575, 89904399, 31190176, 'vide-grenier-de-sequedin', '{\"fr\":\"Vide grenier de Sequedin\"}', '{\"fr\":\"Le Comité des fêtes, en partenariat avec la Ville, organise comme chaque année le vide greniers dans les rues de Sequedin, le Dimanche 27 mai 2018, de 8h à 17h.\"}', '{\"fr\":\"Le Comité des fêtes, en partenariat avec la Ville, organise comme chaque année le vide greniers dans les rues de Sequedin, le Dimanche 27 mai 2018, de 8h à 17h.\"}', '{\"fr\":[\"braderie\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_vide-grenier-de-sequedin_191673.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_vide-grenier-de-sequedin_191673.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_vide-grenier-de-sequedin_191673.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-27T06:00:00.000Z\",\"end\":\"2018-05-27T15:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-25 13:12:56', '2018-04-25 13:12:58', NULL, '53ee7202cf494c92b15ea1897f30778c', NULL, NULL),
(350307, 68819221, 31745822, 31745822, 89904399, 16417149, 'braderie-hannart-a-croix', '{\"fr\":\"Braderie Hannart à Croix\"}', '{\"fr\":\"Braderie et vide-grenier par l\'association R\'ÉVEIL\"}', '{\"fr\":\"Avenue Hannart, avenue de l’Europe, rue Dubled jusqu\'à la rue Perdue, rue du Gaz, rue Voltaire et rue de la Brasserie\\n\\nRenseignements :  \\nAssociation R\'ÉVEIL  \\nMadame Myriam CATTOIRE  \\nTel : 06 50 57 86 45\"}', '{\"fr\":[\"braderie\",\"vide-grenier\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_braderie-hannart-a-croix_514588.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_braderie-hannart-a-croix_514588.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_braderie-hannart-a-croix_514588.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T06:00:00.000Z\",\"end\":\"2018-05-01T14:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-25 13:09:28', '2018-04-25 13:15:18', NULL, '00e7eaaa072a4a86af716b31260a1273', NULL, NULL),
(350301, 56199151, 31745822, 31745822, 89904399, 72943434, 'braderie-de-bouvines', '{\"fr\":\"Braderie de Bouvines\"}', '{\"fr\":\"Braderie et brocante dans le centre ville de Bouvines\"}', '{\"fr\":\"Braderie et brocante dans le centre ville de Bouvines avec une centaine d\'exposants.\"}', '{\"fr\":[\"braderie\",\"brocante\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_braderie-de-bouvines_192985.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_braderie-de-bouvines_192985.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_braderie-de-bouvines_192985.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T06:00:00.000Z\",\"end\":\"2018-05-01T11:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-25 13:00:28', '2018-04-25 13:00:29', NULL, '8ff4ad4c92c642abb6c7da240726902b', NULL, NULL),
(349495, 1081583, 1279575, 1279575, 89904399, 78565176, 'fete-de-la-pierre-2018', '{\"fr\":\"Fête de la Pierre 2018\"}', '{\"fr\":\"Le samedi 9 juin aura lieu à Lezennes la Fête de la Pierre. Cette année est particulière puisque nous fêterons les 18 ans du géant Isidore Courtorelle.\"}', '{\"fr\":\"Pour fêter les 18 ans du géant Isidore Courtorelle, une grande fête est organisée à Lezennes. Plus de 110 géants de différentes nationalités, une vingtaine d\'orchestres et 1200 personnes composeront le cortège.\\n\\nProgramme des festivités\\n\\n*   Dès 14 h : Accueil des géants sur les 3 sites de montage\\n*   Dès 15h30 : départ des 3 cortèges dans toute la ville\\n*   18h : Rigodon géant au complexe Philippe Berthe\\n*   20h : Concert frogits & De Laaste Drop au complexe Philippe Berthe\\n*   23h : Feu d\'artifice géant au complexe Philippe Berthe\"}', '{\"fr\":[\"géants\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_fete-de-la-pierre-2018_104837.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_fete-de-la-pierre-2018_104837.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_fete-de-la-pierre-2018_104837.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-09T12:00:00.000Z\",\"end\":\"2018-06-08T22:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-24 09:58:19', '2018-04-25 08:33:03', NULL, '1f3114085f8d445d9acb5ee85e9b47fe', NULL, NULL),
(343492, 87172240, 31745822, 31745822, 89904399, 8120921, 'top-depart-du-challenge-metropolitain-du-velo-avec-la-fun-rando-velo', '{\"fr\":\"Top départ du Challenge métropolitain !\"}', '{\"fr\":\"Du 1er mai au 31 mai, enfourchez votre vélo et parcourez le plus de kilomètres possibles pour faire gagner votre équipe et votre métropole.\"}', '{\"fr\":\"Pour poursuivre sur la lancée de la Fun Rando Vélo, la métropole vous invite à vous engager à ses côtés dans le challenge métropolitain du vélo durant tout le mois de mai.\\n\\nUtilisez votre vélo pour aller au travail ou à l\'école, faire vos courses, vous promener le week-end... chaque kilomètre compte ! Inscrivez-vous seul ou en équipe et enregistrez vos trajets sur l\'application Naviki.\\n\\nDe nombreux lots sont à gagner avec une remise de prix à l\'issue du challenge !\\n\\nRendez-vous le 1er mai pour débuter en beauté ce mois de vélo !\"}', '{\"fr\":[\"vélo\",\"challenge\",\"concours\",\"métropole\",\"randonnée\"]}', '{\"fr\":\"Sur inscription\"}', '{\"filename\":\"event_top-depart-du-challenge-metropolitain-du-velo-avec-la-fun-rando-velo_496069.jpg\",\"credits\":\"Alexandre Traisnel\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_top-depart-du-challenge-metropolitain-du-velo-avec-la-fun-rando-velo_496069.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_top-depart-du-challenge-metropolitain-du-velo-avec-la-fun-rando-velo_496069.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T07:30:00.000Z\",\"end\":\"2018-05-01T08:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"http://www.lillemetropole.fr/mel/decouverte/grands-evenements/challenge-metropolitain-du-velo/creer-une-equipe-edition-2018.html\"]', '2018-04-16 14:53:59', '2018-04-16 14:58:31', NULL, 'ec752eb08f55491e837cb21088e37b04', NULL, NULL),
(343449, 73897074, 31745822, 31745822, 89904399, 27837397, 'choeur-de-l-opera-de-lille-on-connait-la-chanson', '{\"fr\":\"Chœur de l\'Opéra de Lille - On connaît la chanson\"}', '{\"fr\":\"Le Chœur de l\'Opéra de Lille promet un concert convivial et familial avec une sélection de chansons dont on ne se lasse pas !\"}', '{\"fr\":\"Le chœur lyrique de l\'Opéra de Lille vous invite à écouter leurs chansons favorites, incontournables, qui ont \\\"un truc en plus\\\" et qu\'on ne se lasse pas d\'entendre. \\n\\nClaude Nougaro, les Beatles, Henri Salvador, Frank Sinatra, Charles Trenet, Edith Piaf : il y en a pour tous les goûts. Petits et grands seront charmés par les chanteurs du chœur !\"}', '{\"fr\":[\"concert\",\"opéra\",\"chant\",\"choeur\",\"musique\",\"culture\"]}', '{\"fr\":\"Réservation obligatoire\"}', '{\"filename\":\"event_choeur-de-l-opera-de-lille-on-connait-la-chanson_709248.jpg\",\"credits\":\"Pascaline Chombart\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_choeur-de-l-opera-de-lille-on-connait-la-chanson_709248.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_choeur-de-l-opera-de-lille-on-connait-la-chanson_709248.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-09T16:00:00.000Z\",\"end\":\"2018-06-09T18:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"https://www.opera-lille.fr/fr/-saison-17-18/bdd/cat/concert/sid/99719_ch-ur-de-l-opera-de-lille\"]', '2018-04-16 14:19:31', '2018-04-16 14:19:32', NULL, '72f91c31a8ee4cfcbc413159e007e76b', NULL, NULL),
(343380, 85152275, 31745822, 31745822, 89904399, 4567843, 'traviata-vous-meritez-une-avenir-meilleur', '{\"fr\":\"Traviata - vous méritez une avenir meilleur !\"}', '{\"fr\":\"L\'Opéra de Lille s\'associe au Théâtre du Nord pour proposer une revisite théâtrale du célèbre opéra de Verdi, la Traviata.\"}', '{\"fr\":\"Le metteur en scène Benjamin Lazar a revisité l’opéra classique de Verdi en une version modernisée. A mi-chemin entre l’opéra et le théâtre, c’est une Traviata plus intimiste que vous découvrirez au Théâtre du Nord. Les musiciens, acteurs et chanteurs vous transporteront dans une histoire d’amour, entre passion et sacrifice, pleine de sensibilité et de romantisme.\\n\\nL’œuvre a déjà remporté un franc succès à Paris en créant un lien sentimental et profond avec le public. Redécouvrez ce classique grâce à cette adaptation singulière !\"}', '{\"fr\":[\"opéra\",\"théâtre\"]}', '{\"fr\":\"Réservation obligatoire\"}', '{\"filename\":\"event_traviata-vous-meritez-une-avenir-meilleur_991733.jpg\",\"credits\":\"Pascaline Chombart\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_traviata-vous-meritez-une-avenir-meilleur_991733.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_traviata-vous-meritez-une-avenir-meilleur_991733.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-04-17T18:00:00.000Z\",\"end\":\"2018-04-17T20:30:00.000Z\"},{\"begin\":\"2018-04-18T18:00:00.000Z\",\"end\":\"2018-04-18T20:30:00.000Z\"},{\"begin\":\"2018-04-20T18:00:00.000Z\",\"end\":\"2018-04-20T20:30:00.000Z\"},{\"begin\":\"2018-04-21T17:00:00.000Z\",\"end\":\"2018-04-21T19:30:00.000Z\"},{\"begin\":\"2018-04-25T18:00:00.000Z\",\"end\":\"2018-04-25T20:30:00.000Z\"},{\"begin\":\"2018-04-26T17:00:00.000Z\",\"end\":\"2018-04-26T19:30:00.000Z\"},{\"begin\":\"2018-04-28T17:00:00.000Z\",\"end\":\"2018-04-28T19:30:00.000Z\"},{\"begin\":\"2018-04-29T14:00:00.000Z\",\"end\":\"2018-04-29T16:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"https://www.opera-lille.fr/fr/archives/bdd/cat/opera/sid/99697_traviata-vous-meritez-un-avenir-meilleur\"]', '2018-04-16 13:43:27', '2018-04-16 14:28:29', NULL, '4093ac91e77245f3bbdccbc9b5e603e5', NULL, NULL),
(343345, 60869659, 31745822, 31745822, 89904399, 27837397, 'happy-day-viva-nabucco-journee-europeenne-de-l-opera', '{\"fr\":\"Happy Day Viva Nabucco ! Journée Européenne de l\'Opéra\"}', '{\"fr\":\"Participez à une journée d\'animations et de découvertes en famille à l\'Opéra de Lille.\"}', '{\"fr\":\"L\'Opéra de Lille vous ouvre ses portes toute la journée à l\'occasion de la Journée Européenne de l\'Opéra. Vous pouvez visiter le bâtiment ainsi que les coulisses des préparatifs de l\'opéra Nabucco. De nombreuses surprises et animations vous attendent en musique pour découvrir l\'opéra sous un nouveau jour.\"}', '{\"fr\":[\"opéra\",\"famille\",\"visite\",\"musique\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_happy-day-viva-nabucco-journee-europeenne-de-l-opera_228614.jpg\",\"credits\":\"Vincent Lecigne\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_happy-day-viva-nabucco-journee-europeenne-de-l-opera_228614.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_happy-day-viva-nabucco-journee-europeenne-de-l-opera_228614.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-06T09:00:00.000Z\",\"end\":\"2018-05-06T15:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-04-16 13:12:14', '2018-04-16 13:14:08', NULL, '36808b2cf7b74a38ab8643c669f7ca7f', NULL, NULL),
(327150, 43263195, 56673351, 56673351, 89904399, 25376668, 'balade-en-tramway-touristique_404', '{\"fr\":\"Balade en tramway touristique au départ de Marquette-lez-Lille\"}', '{\"fr\":\"Au départ de Marquette-lez-Lille, longez la Deûle à bord d\'un tramway touristique jusqu\'à Wambrechies, selon un parcours organisé par l\'association AMITRAM.\"}', '{\"fr\":\"À partir du dimanche 1er avril et jusqu’au dimanche 30 septembre 2018, longez la Deûle à bord d\'un tramway touristique entre Wambrechies et Marquette-lez-Lille.\\n\\nL’association AMITRAM orgnanise ce parcours touristique dont les départs sont programmés toutes les 20 minutes entre 14h32 et 18h12 le dimanche et entre 15h30 et 17h les mercredis prévus, à partir de l\'arrêt \\\"Dépôt du tram\\\" (Deûle) à Marquette-lez-Lille.\"}', '{\"fr\":[\"tramway\",\"deûle\"]}', '{\"fr\":\"Aller-retour : 5€ (adultes), 1€ (4-12 ans accompagnés) / Aller : 3€ (adultes), 1€ (4-12 ans accompagnés)\"}', '{\"filename\":\"event_balade-en-tramway-touristique_404_219809.jpg\",\"credits\":\"Pascaline Chombart/MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_balade-en-tramway-touristique_404_219809.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_balade-en-tramway-touristique_404_219809.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-04-01T12:32:00.000Z\",\"end\":\"2018-04-01T16:12:00.000Z\"},{\"begin\":\"2018-04-08T12:32:00.000Z\",\"end\":\"2018-04-08T16:12:00.000Z\"},{\"begin\":\"2018-04-15T12:32:00.000Z\",\"end\":\"2018-04-15T16:12:00.000Z\"},{\"begin\":\"2018-04-22T12:32:00.000Z\",\"end\":\"2018-04-22T16:12:00.000Z\"},{\"begin\":\"2018-04-25T13:30:00.000Z\",\"end\":\"2018-04-25T15:00:00.000Z\"},{\"begin\":\"2018-04-29T12:32:00.000Z\",\"end\":\"2018-04-29T16:12:00.000Z\"},{\"begin\":\"2018-05-02T11:30:00.000Z\",\"end\":\"2018-05-02T12:30:00.000Z\"},{\"begin\":\"2018-05-06T12:32:00.000