(327141, 32316532, 56673351, 56673351, 89904399, 91506640, 'balade-en-tramway-touristique', '{\"fr\":\"Balade en tramway touristique au départ de Wambrechies\"}', '{\"fr\":\"Au départ de Wambrechies, longez la Deûle à bord d\'un tramway touristique jusqu\'à Marquette-lez-Lille, selon un parcours organisé par l\'association AMITRAM.\"}', '{\"fr\":\"À partir du dimanche 1er avril et jusqu’au dimanche 30 septembre 2018, longez la Deûle à bord d\'un tramway touristique entre Wambrechies et Marquette-lez-Lille.\\n\\nL’association AMITRAM orgnanise ce parcours touristique dont les départs sont programmés toutes les 20 minutes entre 14h30 et 18h30 le dimanche et entre 15h et 16h30 les mercredis prévus, à partir de l\'arrêt Vent de Bise à Wambrechies.\\n\\n**Les horaires de 18h10 et 18h30 le dimanche sont sans retour vers Wambrechies.**\"}', '{\"fr\":[\"tramway\",\"deûle\"]}', '{\"fr\":\"Aller-retour : 5€ (adultes), 1€ (4-12 ans accompagnés) / Aller : 3€ (adultes), 1€ (4-12 ans accompagnés)\"}', '{\"filename\":\"event_balade-en-tramway-touristique_554435.jpg\",\"credits\":\"Pascaline Chombart/MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_balade-en-tramway-touristique_554435.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_balade-en-tramway-touristique_554435.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-04-01T12:30:00.000Z\",\"end\":\"2018-04-01T16:30:00.000Z\"},{\"begin\":\"2018-04-08T12:30:00.000Z\",\"end\":\"2018-04-08T16:30:00.000Z\"},{\"begin\":\"2018-04-15T12:30:00.000Z\",\"end\":\"2018-04-15T16:30:00.000Z\"},{\"begin\":\"2018-04-22T12:30:00.000Z\",\"end\":\"2018-04-22T16:30:00.000Z\"},{\"begin\":\"2018-04-25T13:00:00.000Z\",\"end\":\"2018-04-25T14:30:00.000Z\"},{\"begin\":\"2018-04-29T12:30:00.000Z\",\"end\":\"2018-04-29T16:30:00.000Z\"},{\"begin\":\"2018-05-02T13:00:00.000Z\",\"end\":\"2018-05-02T14:30:00.000Z\"