(326023, 93452149, 56673351, 56673351, 89904399, 35314046, 'tracteurs-en-weppes-fete-de-printemps', '{\"fr\":\"Tracteurs en Weppes - Fête de printemps\"}', '{\"fr\":\"Fêtez le printemps à Beaucamps-Ligny avec l\'événement Tracteurs en Weppes : mise en valeur du patrimoine agricole, exposition, animations culturelles et ludiques, marché du terroir...\"}', '{\"fr\":\"L\'association TEW (Tracteurs en Weppes) organise la fête de printemps à Beaucamps-Ligny.\\n\\nPlus de **4000 visiteurs** sont attendus cette année pour cet événement à la programmation riche, dans une ambiance familiale.\\n\\nLes enfants pourront notamment approcher des animaux de la ferme, participer à un concours de dessin ou encore faire des courses de tracteurs à pédales.\\n\\n*   Exposition traditionnelle de tracteurs et matériels de collection\\n*   Exposition consacrée aux hommes et aux femmes employés aux travaux de moisson et de battage\\n*   Diverses animations culturelles et ludiques pour tous publics : spectacles, fanfare de la région, expositions et animations diverses\\n*   Programmation historique : œuvres d’artistes, exposition de miniatures, visite du site en charrette ou à dos d\'ânes, parcours en micro tracteur, défilé de tracteurs, battage à l’ancienne, marché du terroir...\"}', '{\"fr\":[\"printemps\",\"tracteur\",\"patrimoine\"]}', '{\"fr\":\"Adultes : 5€ / Réduit : 2.50€ / Gratuit pour les moins de 11 ans\"}', '{\"filename\":\"event_tracteurs-en-weppes-fete-de-printemps_913309.jpg\",\"credits\":\"Vincent Lecigne/MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_tracteurs-en-weppes-fete-de-printemps_913309.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_tracteurs-en-weppes-fete-de-printemps_913309.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-04-28T07:30:00.000Z\",\"end\":\"2018-04-28T15:00:00.000Z\"},{\"begin\":\"2018-04-29T07:30:00.000Z\",\"end\":\"2018-04-29T15:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"http://tracteursenweppes.chez.com\"]', '2018-03-28 14:53:19', '2018-04-24 09:47:17', NULL, 'eb546322a6b944f4bc40995d23ddcef2', NULL, NULL),
(317708, 92052092, 3068625, 3068625, 89904399, 70075295, 'paris-roubaix-2018_35', '{\"fr\":\"Paris-Roubaix 2018\"}', '{\"fr\":\"Course cycliste\"}', '{\"fr\":\"116e édition de la célèbre course cycliste [Paris-Roubaix](https://www.paris-roubaix.fr/fr/), \\\"L\'enfer du Nord\\\", sur les secteurs pavés de la région !\\n\\nDépart de Compiègne vers 11h, arrivée prévue à Roubaix vers 17h.\\n\\n[Voir le parcours](https://www.paris-roubaix.fr/fr/parcours-general)\"}', '{\"fr\":[\"Cyclisme\",\"Vélo\"]}', '{}', '{\"filename\":\"event_paris-roubaix-2018_35_514498.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_paris-roubaix-2018_35_514498.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_paris-roubaix-2018_35_514498.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-04-08T09:00:00.000Z\",\"end\":\"2018-04-08T15:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-03-21 16:33:22', '2018-03-21 16:33:23', NULL, 'a923a3063c734ff7af414e8e16673701', NULL, NULL),
