(317591, 34468986, 3068625, 3068625, 89904399, 97306831, 'les-foulees-nature-2018', '{\"fr\":\"Les Foulées Nature 2018\"}', '{\"fr\":\"Course à pied - Hors stade\"}', '{\"fr\":\"Organisées par le [JAR](http://www.jaroncq.org) (Jogging Aventure Roncquoise), plusieurs distances sont proposées.\\n\\nFoulées découverte : 5 km (6 €)\\n\\nFoulées Nature: 10 km (8 €)\\n\\nSemi-marathon: 21 km (10 €)\"}', '{\"fr\":[\"Course à pied\",\"running\"]}', '{}', '{\"filename\":\"event_les-foulees-nature-2018_83013.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_les-foulees-nature-2018_83013.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_les-foulees-nature-2018_83013.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-04-01T07:00:00.000Z\",\"end\":\"2018-04-01T10:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"http://www.prolivesport.fr\"]', '2018-03-21 14:50:38', '2018-03-21 14:52:53', NULL, 'f900df124ca54ecead3e1e9ac8b922c7', NULL, NULL),
(317576, 30174761, 3068625, 3068625, 89904399, 71947591, 'swing-ton-handicap', '{\"fr\":\"Swing ton handicap\"}', '{\"fr\":\"Handigolf\"}', '{\"fr\":\"Compétition de handigolf organisée par l\'association DEUST / Staps Lille 2, par équipe de 4 joueurs (scramble à 4): un handigolfeur, un étudiant, un membre du [Golf Lille Métropole](https://golf-lille-metropole.fr/), un partenaire.\\n\\nLes meilleurs joueurs français et européens de handigolf seront présents.\\n\\nJournée du vendredi 30 mars consacrée aux scolaires.\\n\\n**Des initiations et animations gratuites sont prévues pour tous le samedi 31 mars**.\\n\\n[Voir le programme](http://swing.univ-lille.fr/)\"}', '{\"fr\":[\"Handisport\",\"golf\"]}', '{\"fr\":\"Entrée libre\"}', '{\"filename\":\"event_swing-ton-handicap_719920.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_swing-ton-handicap_719920.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_swing-ton-handicap_719920.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-03-30T07:30:00.000Z\",\"end\":\"2018-03-30T16:30:00.000Z\"},{\"begin\":\"2018-03-31T07:00:00.000Z\",\"end\":\"2018-03-31T16:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-03-21 14:16:58', '2018-03-21 14:16:58', NULL, 'd8156902b6ba4013a828b202acfe22b5', NULL, NULL),
