(288140, 71339230, 8140284, 8140284, 89904399, 22687618, 'video-mapping-au-lam', '{\"fr\":\"Video Mapping au LaM\"}', '{\"fr\":\"Pour les 50 ans de la MEL, un vidéo mapping exceptionnel aura lieu au LaM le 19 mai à partir de 22h.\"}', '{\"fr\":\"Le 19 mai, pour célébrer les 50 ans de la Métropole Européenne de Lille, rendez-vous au LaM pour un vidéo mapping décoiffant sur le bâtiment et ses abords ! Une occasion originale et inédite de découvrir ou redécouvrir ce fleuron de l’architecture moderne et lieu emblématique de la métropole.\\n\\nUne série de micro-mapping dans le parc, sur les végétaux ou les sculptures, mènera le spectateur jusqu’à un mapping monumental sur le bâtiment du musée. Cette création s’inspirera de la collection permanente du LaM : le spectateur pourra y retrouver des univers, des motifs, des « à la manière de » d’œuvres phares ou plus discrètes du musée\\n\\nL’événement a lieu dans le cadre de la première édition du Video Mapping Festival en région Hauts-de-France, organisé par l’association Rencontre Audiovisuelles, qui aura lieu de mars à septembre 2018\\\\. Il s’agit du premier festival international dédié à cette technique consistant à projeter des films d’animation sur des volumes en jouant avec leurs formes et leurs reliefs. Au programme : une dizaine de vidéo mapping sur des monuments historiques de la région, des ateliers participatifs autour du vidéo mapping, des contenus dédiés aux professionnels et étudiants…\"}', '{\"fr\":[\"Video mapping festival\",\"video mapping\"]}', '{\"fr\":\"Entrée libre et gratuite\"}', '{\"filename\":\"event_video-mapping-au-lam_128153.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_video-mapping-au-lam_128153.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_video-mapping-au-lam_128153.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-19T20:00:00.000Z\",\"end\":\"2018-05-18T23:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-02-26 13:38:43', '2018-04-17 15:03:43', NULL, 'efb0f9ceea50468ca17ff46a64bd8245', NULL, NULL),
(287018, 11624167, 34181411, 34181411, 89904399, 95213580, 'vert-par-nature-legumes-d-antan', '{\"fr\":\"Vert par nature : légumes d\'antan\"}', '{\"fr\":\"Notre région a une vraie tradition potagère : Lingot du Nord, laitue Lilloise, poireau Leblond, cresson du Pas de Calais, ail du Nord, carotte de Tilques, et bien d’autres !\"}', '{\"fr\":\"Avec Le Jardin Voyageur, faites connaissance avec ces légumes et apprenez à les faire pousser chez vous.\"}', '{\"fr\":[\"santes\",\"relais nature\",\"ENM\"]}', '{\"fr\":\"sur inscription\"}', '{\"filename\":\"event_vert-par-nature-legumes-d-antan_943001.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_vert-par-nature-legumes-d-antan_943001.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_vert-par-nature-legumes-d-antan_943001.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-05T07:30:00.000Z\",\"end\":\"2018-05-05T09:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"03 20 63 1124\"]', '2018-02-22 15:34:55', '2018-02-22 15:34:57', NULL, '8431a47f51a14b14841be8395e07ac0c', NULL, NULL),
(287009, 85403662, 34181411, 34181411, 89904399, 67780783, 'tonds-ton-mouton', '{\"fr\":\"Tonds ton mouton\"}', '{\"fr\":\"Les moutons boulonnais du Musée passent chez le coiffeur pour une petite coupe de printemps ! Pour cette journée de fête, un programme chargé attend les visiteurs.\"}', '{\"fr\":\"Pour cette journée de fête, un programme chargé attend les visiteurs : démonstrations de tonte toutes les heures, chiens de berger à l’ouvrage, ateliers et jeux de laine et de tissage, spectacle autour de la teinture et déambulation des bergères de rêves de la compagnie Arzapar…\"}', '{\"fr\":[\"ENM\",\"musée de plein air\"]}', '{}', '{\"filename\":\"event_tonds-ton-mouton_370208.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_tonds-ton-mouton_370208.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_tonds-ton-mouton_370208.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-01T08:00:00.000Z\",\"end\":\"2018-05-01T16:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":false}', '{\"min\":null,\"max\":null}', '[\"presduhem@lillemetropole.fr\"]', '2018-02-22 15:27:04', '2018-04-20 14:20:30', NULL, '9d7ace9a0c9b46e2b8aee168690c9bfe', NULL, NULL),
(284796, 19151211, 1279575, 1279575, 89904399, 21463087, 'le-grand-barouf-numerique-2018', '{\"fr\":\"Le Grand Barouf Numérique 2018\"}', '{\"fr\":\"La Métropole Européenne de Lille lance la seconde édition du Grand Barouf Numérique les 22 et 23 mars 2018.\"}', '{\"fr\":\"Les 22 et 23 mars 2018, la Métropole Européenne de Lille, en partenariat avec OuiShare, le collectif international spécialisé dans les émergences numériques et collaboratives et POP, spécialiste de l\'innovation sociale, vous invite à vivre deux jours d’expériences et de controverses sur l\'éducation et les savoirs numériques.\\n\\nParticipatif et prospectif, le Grand Barouf Numérique s’organise cette année comme une “assemblée parlementaire”, où les “participants-députés” sont réunis pour examiner et amender un projet de loi numérique d’anticipation.\\n\\nPour la première fois en Europe, une Métropole constitue un gouvernement fictif pour élaborer un projet de loi numérique lors d\'un débat public.\\n\\nDécouvrez le site web de l\'évènement : [http://www.legrandbarouf.fr/](http://www.legrandbarouf.fr/)\\n\\nhttps://www.youtube.com/watch?v=RQ6hUAkNiSw&t=0s&list=PLHBw52p5BT-ae--nSP3GL9HbP825rOFVv&index=19\"}', '{\"fr\":[\"numérique\",\"économie circulaire\",\"éducation\"]}', '{\"fr\":\"Entrée gratuite sur inscription\"}', '{\"filename\":\"event_le-grand-barouf-numerique-2018_275856.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_le-grand-barouf-numerique-2018_275856.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_le-grand-barouf-numerique-2018_275856.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-03-22T13:00:00.000Z\",\"end\":\"2018-03-22T20:00:00.000Z\"},{\"begin\":\"2018-03-23T07:30:00.000Z\",\"end\":\"2018-03-23T17:15:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":18,\"max\":99}', '[]', '2018-02-20 14:21:22', '2018-03-06 09:52:54', NULL, '90d4e297181e4815916f490dbc8fd6b8', NULL, NULL),
(283101, 53327247, 1279575, 1279575, 89904399, 44062877, 'concert-glenn-miller', '{\"fr\":\"Concert Glenn Miller\"}', '{\"fr\":\"Cette année le Grand Orchestre de Marcq en Baroeul vous propose un concert \\\"Glenn Miller\\\" autour de mélodies et thématiques connues de tous.\"}', '{\"fr\":\"Le GOM joue au théâtre Raymond DEVOS de Tourcoing pour l\'association \\\"Changeons de regard\\\" en partenariat avec le \\\"Lions Club de Roubaix Sart\\\".\\n\\nLe GOM, dirigé par Marc BOLLEN, est une grande formation de Jazz agrémentés de quelques bois. Fort de ses 30 musiciens et de ses solistes qui font partie des meilleurs du département, le Grand Orchestre de Marcq en Baroeul se produit dans la région du Nord depuis de nombreuses années avec succès.\\n\\nAu programme de ce concert, les grands succès joué par le Glenn Miller Orchestra : In the mood, Moonlight sérenade, American Patrol, Take the « a » train, Pennsylvania 6.500 …\"}', '{\"fr\":[]}', '{\"fr\":\"Adultes et enfants de plus de 12 ans : 10 euros. Enfants de moins de 12 ans : 5 euros. Moins de 2 ans : gratuit. Billetterie : maison Folie hospice d\'Havré 100 rue de Tournai à Tourcoing.\"}', '{\"filename\":\"event_concert-glenn-miller_573657.jpg\",\"credits\":\"Grand Orchestre Marcq-en-Baroeul\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_concert-glenn-miller_573657.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_concert-glenn-miller_573657.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-02-22T19:00:00.000Z\",\"end\":\"2018-02-22T21:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[\"03 20 26 86 34\"]', '2018-02-15 15:48:24', '2018-02-15 15:48:25', NULL, '8a39fe6ca96c4dca9ef55e619d80ad54', NULL, NULL),
(279333, 98195487, 34181411, 34181411, 89904399, 78093466, 'le-patrimoine-fete-les-50-ans-de-la-mel', '{\"fr\":\"Le patrimoine fête les 50 ans de la MEL\"}', '{\"fr\":\"En apothéose de ce 50e anniversaire et à l’occasion des Journées du patrimoine les 15 et 16 septembre, tout est ouvert.\"}', '{\"fr\":\"Partout dans la métropole, de l’hôtel métropolitain aux centres techniques, on ouvre grand les portes et on vous fait découvrir tous les métiers qui oeuvrent chaque jour à votre service. Une occasion unique de découvrir toutes les missions et services accomplis à votre intention par les 3 000 agents de la MEL.\"}', '{\"fr\":[\"MEL\",\"50 ans\",\"50 ans de la MEL\",\"journées du patrimoine\"]}', '{}', '{\"filename\":\"event_le-patrimoine-fete-les-50-ans-de-la-mel_476714.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_le-patrimoine-fete-les-50-ans-de-la-mel_476714.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_le-patrimoine-fete-les-50-ans-de-la-mel_476714.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-09-15T08:00:00.000Z\",\"end\":\"2018-09-15T16:00:00.000Z\"},{\"begin\":\"2018-09-16T08:00:00.000Z\",\"end\":\"2018-09-16T16:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-02-02 15:15:38', '2018-09-12 08:56:32', NULL, '7a9d30332d784f549f7c07492e8142b9', NULL, NULL),
(279330, 28363954, 34181411, 34181411, 89904399, 22687618, 'debris-collages-au-lam', '{\"fr\":\"Débris-collages au LaM\"}', '{\"fr\":\"Une exposition transversale qui s’appuie essentiellement sur la collection au travers de ses trois domaines que sont l’art moderne, l’art brut et l’art contemporain.\"}', '{\"fr\":\"Elle mêle de façon originale la pratique du collage en art avec celle de la récupération, mais aussi la pratique du démontage, de la déconstruction, voire de la destruction.\"}', '{\"fr\":[\"LaM\",\"50 ans\",\"50 ans au service des métropolitains\",\"villeneuve d\'ascq\"]}', '{}', '{\"filename\":\"event_debris-collages-au-lam_491909.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_debris-collages-au-lam_491909.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_debris-collages-au-lam_491909.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-21T08:00:00.000Z\",\"end\":\"2018-06-21T16:00:00.000Z\"},{\"begin\":\"2018-06-22T08:00:00.000Z\",\"end\":\"2018-06-22T16:00:00.000Z\"},{\"begin\":\"2018-06-23T08:00:00.000Z\",\"end\":\"2018-06-23T16:00:00.000Z\"},{\"begin\":\"2018-06-24T08:00:00.000Z\",\"end\":\"2018-06-24T16:00:00.000Z\"},{\"begin\":\"2018-06-28T08:00:00.000Z\",\"end\":\"2018-06-28T16:00:00.000Z\"},{\"begin\":\"2018-06-29T08:00:00.000Z\",\"end\":\"2018-06-29T16:00:00.000Z\"},{\"begin\":\"2018-06-30T08:00:00.000Z\",\"end\":\"2018-06-30T16:00:00.000Z\"},{\"begin\":\"2018-07-01T08:00:00.000Z\",\"end\":\"2018-07-01T16:00:00.000Z\"},{\"begin\":\"2018-07-05T08:00:00.000Z\",\"end\":\"2018-07-05T16:00:00.000Z\"},{\"begin\":\"2018-07-06T08:00:00.000Z\",\"end\":\"2018-07-06T16:00:00.000Z\"},{\"begin\":\"2018-07-07T08:00:00.000Z\",\"end\":\"2018-07-07T16:00:00.000Z\"},{\"begin\":\"2018-07-08T08:00:00.000Z\",\"end\":\"2018-07-08T16:00:00.000Z\"},{\"begin\":\"2018-07-12T08:00:00.000Z\",\"end\":\"20