(279311, 20327240, 34181411, 34181411, 89904399, 95628448, 'les-espaces-naturels-metropolitains-fetent-les-50-ans-de-la-mel', '{\"fr\":\"Mosaïc fête les 50 ans de la MEL\"}', '{\"fr\":\"Mosaïc ouvre ses portes gratuitement, pour tous et pour toute la journée ! Autour d’un programme festif et animé, venez fêter les 50 ans de la MEL… au vert !\"}', '{}', '{\"fr\":[\"ENM\",\"Espaces Naturels métropolitains\",\"50 ans\",\"50 ans de la MEL\",\"mosaïc\"]}', '{}', '{\"filename\":\"event_les-espaces-naturels-metropolitains-fetent-les-50-ans-de-la-mel_627308.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_les-espaces-naturels-metropolitains-fetent-les-50-ans-de-la-mel_627308.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_les-espaces-naturels-metropolitains-fetent-les-50-ans-de-la-mel_627308.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-07-01T08:00:00.000Z\",\"end\":\"2018-07-01T18:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-02-02 14:52:54', '2018-04-10 12:25:47', NULL, 'bff3d080202d47709611b3bbb8bd2fe8', NULL, NULL),
(279310, 569480, 8140284, 8140284, 89904399, 82791038, 'armelle-blary_781', '{\"fr\":\"Armelle Blary\"}', '{\"fr\":\"A l’occasion de son exposition monographique à la Manufacture, Armelle Blary dévoile un ensemble inédit de sculptures nées d’une conversation plastique avec l’oeuvre de Camille Claudel\"}', '{\"fr\":\"A l’occasion de son exposition monographique à la Manufacture, Armelle Blary dévoile un ensemble inédit de sculptures nées d’une conversation plastique avec l’oeuvre de Camille Claudel, conversation qui puise son origine dans une rencontre, voici près de trente ans, avec Marie-Victoire Nantet, petite-nièce de Camille. La Clotho constitue le point de départ de cet échange d’artiste à artiste, mené par-delà le temps, sur des thèmes et questionnements esthétiques communs. Au fil des années, ce rapprochement a permis la création d’une collection spécifique où la figure, le corps et le matériau fibre occupent une place essentielle. Créées entre 2014 et 2018, ces pièces sont présentées à la Manufacture en vis-à-vis de deux oeuvres issues de la collection du musée La Piscine : Torse de femme accroupie et Étude pour l’Implorante.\"}', '{\"fr\":[\"Armelle Blary\",\"La Manufacture\",\"Roubaix\",\"Camille Claudel\"]}', '{}', '{\"filename\":\"event_armelle-blary_781_745569.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_armelle-blary_781_745569.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_armelle-blary_781_745569.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-04-14T12:00:00.000Z\",\"end\":\"2018-04-14T16:00:00.000Z\"},{\"begin\":\"2018-04-15T12:00:00.000Z\",\"end\":\"2018-04-15T16:00:00.000Z\"},{\"begin\":\"2018-04-17T12:00:00.000Z\",\"end\":\"2018-04-17T17:00:00.000Z\"},{\"begin\":\"2018-04-18T12:00:00.000Z\",\"end\":\"2018-04-18T17:00:00.000Z\"},{\"begin\":\"2018-04-19T12:00:00.000Z\",\"end\"