(279306, 42836935, 34181411, 34181411, 89904399, 4559704, 'la-jeunesse-fete-les-50-ans-de-la-mel', '{\"fr\":\"La jeunesse fête les 50 ans de la MEL\"}', '{\"fr\":\"Le 23 juin, la jeunesse se retrouve au stade Pierre-Mauroy. Avec une ribambelle de stars de la musique électro.\"}', '{\"fr\":\"L’Arena accueillera des concerts géants avec Dimitri Vegas & Like Mike, le duo de frères Belgo-Grecs qui ont boosté la scène house, le DJ Martin Solveig, qui collabora avec Madonna et  Nicki Minaj, Kungs, le DJ et compositeur d’Aix en Provence, Victoire de la musique 2017 avec un premier album salué par la critique et n°1 des ventes. Mais aussi Alan Walker, le DJ anglo-norvégien qui collectionne les disques de platine, et le jeune duo parisien prometteur Ofenbach.\"}', '{\"fr\":[\"50 ans\",\"50 ans de la MEL\",\"north summer festival\",\"stade pierre-mauroy\",\"villeneuve d\'ascq\"]}', '{\"fr\":\"Billetterie ouverte\"}', '{\"filename\":\"event_la-jeunesse-fete-les-50-ans-de-la-mel_82989.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_la-jeunesse-fete-les-50-ans-de-la-mel_82989.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_la-jeunesse-fete-les-50-ans-de-la-mel_82989.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-06-23T14:00:00.000Z\",\"end\":\"2018-06-22T23:00:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-02-02 14:47:42', '2018-02-02 15:51:10', NULL, 'b34b80f56157476d9f014898acf2fcb8', NULL, NULL),
(279303, 84813376, 8140284, 8140284, 89904399, 49524844, 'open-museum-5', '{\"fr\":\"Open Museum #5\"}', '{\"fr\":\"Cette année le Palais des Beaux-Arts convie non pas une personnalité mais un genre audiovisuel : la série télé.\"}', '{\"fr\":\"Cette année le Palais des Beaux-Arts convie non pas une personnalité mais un genre audiovisuel, le plus populaire et aussi le plus créatif de ces dernières années : la série télé. L’installation du festival Sériesmania à Lille est une magnifique occasion de montrer comment les séries télé puisent une partie de leur inspiration scénaristique, esthétique et sociologique dans le monde de l’art et des musées. De Belphégor à Mad Men, en passant par Sherlock, P’tit Quinquin ou Game of Thrones, jusqu’aux cartoons américains ou aux Simpson, des extraits, costumes et objets révèleront la présence des arts sur le petit écran à travers les collections du musée.\"}', '{\"fr\":[\"séries TV\",\"Palais des Beaux Arts\",\"Lille\",\"Open Museum\",\"#5\"]}', '{}', '{\"filename\":\"event_open-museum-5_689972.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_open-museum-5_689972.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_open-museum-5_689972.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-04-14T08:00:00.000Z\",\"end\":\"2018-04-14T16:00:00.000Z\"},{\"begin\":\"2018-04-15T08:00:00.000Z\",\"end\":\"2018-04-15T16:00:00.000Z\"},{\"begin\":\"2018-04-16T12:00:00.000Z\",\"end\":\"2018-04-16T16:00:00.000Z\"},{\"begin\":\"2018-04-18T08:00:00.000Z\",\"end\":\"2018-04-18T16:00:00.000Z\"},{\"begin\":\"2018-04-19T08:00:00.000Z\",\"end\":\"2018-04-19T16:00:00.000Z\"},{\"begin\":\"2018-04-20T08:00:00.000Z\",\"end\":\"2018-04-20T16:00:00.000Z\"},{\"begin\":\"2018-04-21T08:00:00.000Z\",\"end\":\"2018-04-21T16:00:00.000Z\"},{\"begin\":\"2018-04-22T08:00:00.000Z\",\"end\":\"2018-04-22T16:00:00.