(279299, 51829790, 34181411, 34181411, 89904399, 95628448, 'le-parc-mosaic-fete-les-50-ans-de-la-mel', '{\"fr\":\"Mosaïc fête les 50 ans de la MEL\"}', '{\"fr\":\"Le Nabucco de Verdi, bien connu du grand public, c’est à l’Opéra de Lille (soutenu chaque année par la MEL), et retransmis en live et en plein air le 26 mai à 18 h au Parc Mosaïc - Jardin des cultures\"}', '{}', '{\"fr\":[\"ENM\",\"mosaic\",\"houplin-ancoisne\",\"parc\",\"50 ans\",\"50 ans de la MEL\"]}', '{\"fr\":\"Gratuit, ouvert à tous\"}', '{\"filename\":\"event_le-parc-mosaic-fete-les-50-ans-de-la-mel_90850.jpg\",\"credits\":\"MEL\",\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_le-parc-mosaic-fete-les-50-ans-de-la-mel_90850.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_le-parc-mosaic-fete-les-50-ans-de-la-mel_90850.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-05-26T16:00:00.000Z\",\"end\":\"2018-05-26T21:30:00.000Z\"}]', '{\"mi\":true,\"hi\":true,\"pi\":true,\"vi\":true}', '{\"min\":null,\"max\":null}', '[]', '2018-02-02 14:39:44', '2018-02-22 14:50:03', NULL, 'a81bc9ea64874e12a6b51db215a70e67', NULL, NULL);
