(279290, 75670540, 8140284, 8140284, 89904399, 22687618, 'nicolas-shoffer-retrospective', '{\"fr\":\"Nicolas Shöffer- Retroprospective\"}', '{\"fr\":\"Cette exposition explore l’oeuvre foisonnante de l’artiste français d’origine hongroise Nicolas Schöffer et seront présentés ses projets les plus exploratoires et ses collaborations expérimentales\"}', '{\"fr\":\"Cette exposition explore l’oeuvre foisonnante de l’artiste français d’origine hongroise Nicolas Schöffer (1912-1992), l’un des principaux acteurs de l’art cybernétique. Pour la première fois dans un musée français depuis près de 50 ans seront présentés ses projets les plus exploratoires et ses collaborations expérimentales avec les architectes, les musiciens, les chorégraphes, les scientifiques et les industriels de son temps. A l’heure où de nouvelles anticipations cybernétiques façonnent notre univers matériel (la société de l’information, les nouvelles cultures numériques) comme nos imaginaires (le village global, le post-humain), l’exposition mettra en lumière la manière dont le travail de Schöffer fait écho aux préoccupations de la jeune création contemporaine.\"}', '{\"fr\":[\"Nicolas Shoffer\",\"Retrospective\",\"LaM\",\"Villeneuve d\'Ascq\",\"art cybernétique\"]}', '{}', '{\"filename\":\"event_nicolas-shoffer-retrospective_227534.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_nicolas-shoffer-retrospective_227534.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_nicolas-shoffer-retrospective_227534.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-02-23T09:00:00.000Z\",\"end\":\"2018-02-23T18:00:00.000Z\"},{\"begin\":\"2018-02-24T09:00:00.000Z\",\"end\":\"2018-02-24T18:00:00.000Z\"},{\"begin\":\"2018-02-25T09:00:00.000Z\",\"end\":\"2018-02-25T18:00:00.000Z\"},{\"begin\":\"2018-02-27T09:00:00.000Z\",\"end\":\"2018-02-27T17:00:00.000Z\"},{