(279286, 17713084, 8140284, 8140284, 89904399, 62425931, 'chretiens-d-orient-2000-ans-d-histoire', '{\"fr\":\"Chrétiens d\'Orient 2000 ans d\'histoire\"}', '{\"fr\":\"Cette exposition propose un voyage au cœur de la culture et origines des communautés chrétiennes du monde arabe de l’Antiquité à nos jours, coproduite avec l’Institut de monde arabe à Paris\"}', '{\"fr\":\"Consacrée aux origines, au développement et à l’avenir des communautés chrétiennes du monde arabe, et coproduite avec l’Institut du monde arabe à Paris, cette exposition met en avant la naissance de ces communautés, la constitution des églises orientales et des patriarcats. Une place importante est réservée aux langues, véhicules de la liturgie, ainsi qu’à l’implication des chrétiens dans la vie culturelle, politique et économique du monde arabe. Enfin, l’exposition présente le renouveau religieux et culturel contemporain qui s’exprime tant dans les pratiques populaires que les expressions artistiques\"}', '{\"fr\":[\"chrétiens d\'orient\",\"MUba\",\"Tourcoing\",\"histoire\",\"origines\",\"communautés chrétiennes\"]}', '{}', '{\"filename\":\"event_chretiens-d-orient-2000-ans-d-histoire_70913.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_chretiens-d-orient-2000-ans-d-histoire_70913.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_chretiens-d-orient-2000-ans-d-histoire_70913.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-03-22T12:00:00.000Z\",\"end\":\"2018-03-22T18:00:00.000Z\"},{\"begin\":\"2018-03-23T12:00:00.000Z\",\"end\":\"2018-03-23T18:00:00.000Z\"},{\"begin\":\"2018-03-24T12:00:00.000Z\",\"end\":\"2018-03-24T18:00:00.000Z\"},{\"begin\":\"2018-03-25T11:00:00.000Z\",\"end\":\"2018-03-25T17:00:00.000Z\"},{\"begin\":\"2018-03-28T11:00:00.000Z\",\"end\":\"2018-03-28T17:00:00.000Z\"},{\"begin\":\"2018-03-29T11:00:00.000Z\",\"end\"