(279280, 46331945, 8140284, 8140284, 89904399, 75269631, 'oceans', '{\"fr\":\"Océans\"}', '{\"fr\":\"L’exposition présente des artistes dont les oeuvres originales offrent des perspectives océaniques sur les dimensions culturelles, politiques et biologiques de la planète.\"}', '{\"fr\":\"Le Fresnoy et la TBA21-Academy s’associent pour présenter l’exposition Océans. Une vision du monde au rythme des vagues. L’exposition présente des artistes dont les œuvres originales offrent des perspectives océaniques sur les dimensions culturelles, politiques et biologiques de l’hydrosphère de la planète, examinant les effets des problèmes engendrés par les humains, comme le changement climatique et la montée du niveau de la mer, tout en réinventant des relations humaines et « plus qu’humaines ». L’exposition présente des œuvres nouvellement commandées, dont beaucoup sont le résultat des expéditions de l’Académie dans l’océan Pacifique, ainsi que des pièces exceptionnelles de la collection de la TBA21 et des œuvres d’artistes dont la pratique est profondément ancrée dans l’espace océanique.\"}', '{\"fr\":[\"le fresnoy\",\"tourcoing\",\"vages\",\"planète\",\"océan pacifique\",\"espace océanique\"]}', '{}', '{\"filename\":\"event_oceans_464664.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_oceans_464664.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_oceans_464664.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2018-02-10T13:00:00.000Z\",\"end\":\"2018-02-10T19:00:00.000Z\"},{\"begin\":\"2018-02-11T13:00:00.000Z\",\"end\":\"2018-02-11T19:00:00.000Z\"},{\"begin\":\"2018-02-14T13:00:00.000Z\",\"end\":\"2018-02-14T18:00:00.000Z\"},{\"begin\":\"2018-02-15T13:00:00.000Z\",\"end\":\"2018-02-15T18:00:00.000Z\"},{\"begin\":\"2018-02-16T13:00:00.000Z\",\"end\":\"2018-02-16T18:00:00.000Z\"},{\"begin\":\"2018-02-17T13:00:00.000Z\