(263742, 41300170, 56673351, 56673351, 89904399, 70547589, 'bleu', '{\"fr\":\"Bleu !\"}', '{\"fr\":\"Venez voir la vie en bleu au Musée d’Histoire Naturelle de Lille : de la physique, de la biologie, de l’histoire, de la symbolique, des arts et bien sûr du bleu, du bleu, du bleu…\"}', '{\"fr\":\"Venez voir la vie en bleu au Musée d’Histoire Naturelle de Lille du 20 octobre 2017 au 02 avril 2018\\\\. De la physique, de la biologie, de l’histoire, de la symbolique, des arts et bien sûr du bleu, du bleu, du bleu…\\n\\nPour vous raconter cette couleur fascinante, l’exposition, organisée en cinq espaces-thèmes, vous propose plus de 120 objets à découvrir lors d\'une immersion inédite dans le bleu: oiseaux, insectes, costumes, bijoux, parures, minéraux, pigments, peintures et objets d’art… vous connaitrez tout de cette couleur emblématique !\"}', '{\"fr\":[\"bleu\",\"MHN\",\"physique\",\"biologie\",\"histoire\"]}', '{\"fr\":\"Plein tarif : 5€ / Tarif réduit : 3€ / Gratuit pour les moins de 12 ans\"}', '{\"filename\":\"event_bleu_313730.jpg\",\"credits\":null,\"size\":{\"height\":null,\"width\":null},\"variants\":[{\"type\":\"full\",\"filename\":\"evfevent_bleu_313730.jpg\",\"size\":{\"height\":null,\"width\":null}},{\"type\":\"thumbnail\",\"filename\":\"evtbevent_bleu_313730.jpg\",\"size\":{\"height\":null,\"width\":null}}]}', 0, 0, 'Europe/Paris', '[{\"begin\":\"2017-10-20T07:30:00.000Z\",\"end\":\"2017-10-20T15:00:00.000Z\"},{\"begin\":\"2017-10-21T08:00:00.000Z\",\"end\":\"2017-10-21T16:00:00.000Z\"},{\"begin\":\"2017-10-22T08:00:00.000Z\",\"end\":\"2017-10-22T16:00:00.000Z\"},{\"begin\":\"2017-10-23T07:30:00.000Z\",\"end\":\"2017-10-23T15:00:00.000Z\"},{\"begin\":\"2017-10-25T07:30:00.000Z\",\"end\":\"2017-10-25T15:00:00.000Z\"},{\"begin\":\"2017-10-26T07:30:00.000Z\",\"end\":\"2017-10-26T15:00:00.000Z\"},{\"begin\":\"2017-10-27T07:30:00.000Z\",\"end\":\"2017-10-27T15:00:00.000Z\"},{\"begin\":\"2017-10-28T08:00:00.000Z\",\"end\":\"2017-10-28T16:00:00.000Z\"},{\"begin\